window.PACTO.acts["reg-2018-1046"]={"label": "REGOLAMENTO (UE, Euratom) 2018/1046 DEL PARLAMENTO EUROPEO E DEL CONSIGLIO", "short": "Reg. 2018/1046", "file": "ext-reg-2018-1046.html", "external": true, "version": "consolidato 2022-12-14", "eurlex": "https://eur-lex.europa.eu/eli/reg/2018/1046/oj/ita", "articles": {"1": {"label": "Articolo 1", "heading": "Oggetto", "anchor": "art_1", "frags": [[null, "<p class=\"norm\">Il presente regolamento specifica le norme relative alla formazione e all’esecuzione del bilancio generale dell’Unione europea e della Comunità europea dell’energia atomica («bilancio») e alla presentazione e alla revisione dei loro conti.</p>"]]}, "2": {"label": "Articolo 2", "heading": "Definizioni", "anchor": "art_2", "frags": [[null, "<p class=\"norm\">Ai fini del presente regolamento si applicano le definizioni seguenti:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>1) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«richiedente», una persona fisica o un’entità, dotata o meno di personalità giuridica, che ha presentato domanda nell’ambito di una procedura di attribuzione di una sovvenzione o di un concorso a premi;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>2) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«fascicolo di partecipazione», un’offerta, una domanda di partecipazione, una domanda di sovvenzione o una domanda nell’ambito di un concorso a premi;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>3) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«procedura di aggiudicazione o di attribuzione», una procedura di appalto, una procedura di attribuzione di sovvenzioni, un concorso a premi o una procedura di selezione di esperti o persone o entità che eseguono il bilancio conformemente all’articolo 62, paragrafo 1, primo comma, lettera c);</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>4) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«atto di base», un atto giuridico, diverso da una raccomandazione o da un parere, che fornisce una base giuridica per un’azione e per l’esecuzione delle spese corrispondenti iscritte in bilancio o della garanzia di bilancio ovvero dell’assistenza finanziaria a carico del bilancio e che può assumere una delle seguenti forme:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">in applicazione del trattato sul funzionamento dell’Unione europea (TFUE) e del trattato che istituisce la Comunità europea per l’energia atomica (trattato Euratom), la forma di un regolamento, di una direttiva o di una decisione ai sensi dell’articolo 288 TFUE; oppure</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">in applicazione del titolo V del trattato sull’Unione europea (TUE), una delle forme specificate agli articoli 28, paragrafo 1, e 31, paragrafo 2, all’articolo 33 e agli articoli 42, paragrafo 4, e 43, paragrafo 2, TUE;</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>5) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«beneficiario», una persona fisica o un’entità, dotata o meno di personalità giuridica, con cui è stata firmata una convenzione di sovvenzione;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>6) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«meccanismo o piattaforma di finanziamento misto», un quadro di cooperazione creato tra la Commissione e le istituzioni di finanziamento allo sviluppo o altri istituti di finanziamento pubblici al fine di combinare forme di aiuto non rimborsabile e/o strumenti finanziari e/o garanzie finanziarie a titolo del bilancio con forme rimborsabili di aiuto di istituzioni di finanziamento allo sviluppo o altri istituti di finanziamento pubblici, nonché di istituti di finanziamento del settore privato e investitori del settore privato;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>7) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«esecuzione del bilancio», lo svolgimento di attività correlate alla gestione, alla sorveglianza, al controllo e alla revisione degli stanziamenti di bilancio secondo i metodi previsti all’articolo 62;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>8) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«impegno di bilancio», l’operazione con cui l’ordinatore responsabile riserva gli stanziamenti di bilancio necessari per coprire pagamenti successivi in adempimento di impegni giuridici;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>9) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«garanzia di bilancio», un impegno giuridico dell’Unione a finanziare un programma di azioni assumendo a carico del bilancio un’obbligazione finanziaria a cui si possa ricorrere nell’eventualità che si verifichi un determinato evento nel corso dell’attuazione del programma e che rimane valida per la durata degli impegni assunti nell’ambito del programma finanziato, fino a scadenza;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>10) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«appalto immobiliare», un appalto che ha per oggetto l’acquisto, lo scambio, l’enfiteusi, l’usufrutto, il leasing finalizzato all’acquisto, la locazione o l’acquisto a riscatto, con o senza opzione per l’acquisto, di terreni, fabbricati o altri beni immobili. Esso riguarda i fabbricati esistenti e i fabbricati non ancora completati, a condizione che il candidato abbia ottenuto un permesso di costruire valido. Non riguarda fabbricati progettati conformemente alle specifiche dell’amministrazione aggiudicatrice contemplati da appalti di lavori;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>11) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«candidato», un operatore economico che ha sollecitato un invito o è stato invitato a partecipare a una procedura ristretta, a una procedura competitiva con negoziazione, a un dialogo competitivo, a un partenariato per l’innovazione, a un concorso di progettazione o a una procedura negoziata;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>12) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«centrale di committenza», un’amministrazione aggiudicatrice che fornisce attività di centralizzazione delle committenze e, se del caso, attività di committenza ausiliarie;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>13) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«verifica», la verifica di un aspetto specifico di un’operazione di entrata o di spesa;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>14) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«contratto di concessione», un contratto a titolo oneroso, concluso per iscritto tra uno o più operatori economici e una o più amministrazioni aggiudicatrici ai sensi degli articoli 174 e 178, per affidare a un operatore economico l’esecuzione di lavori o la prestazione e gestione di servizi («concessione»), ove:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la remunerazione consista unicamente nel diritto di gestire i lavori o i servizi, o in tale diritto accompagnato da un prezzo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’aggiudicazione del contratto di concessione comporti il trasferimento al concessionario di un rischio operativo legato alla gestione dei lavori o dei servizi, comprendente un rischio sul lato della domanda o sul lato dell’offerta, o entrambi. Si considera che il concessionario assuma un rischio operativo nel caso in cui, in condizioni operative normali, non sia garantito il recupero degli investimenti effettuati o dei costi sostenuti per la gestione dei lavori o dei servizi interessati;</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>15) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«passività potenziale», un’obbligazione finanziaria potenziale cui si potrebbe incorrere in funzione dell’esito di un evento futuro;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>16) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«contratto», un appalto pubblico o un contratto di concessione;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>17) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«contraente», un operatore economico con cui è stato firmato un appalto pubblico;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>18) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«accordo di contributo», un accordo concluso con persone o entità che eseguono fondi dell’Unione ai sensi dell’articolo 62, paragrafo 1, primo comma, lettera c), punti da ii) a viii);</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>19) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«controllo», qualsiasi misura adottata al fine di garantire con ragionevole sicurezza l’efficacia, l’efficienza e l’economia delle operazioni, l’affidabilità delle relazioni, la salvaguardia degli attivi e l’informazione, la prevenzione, l’individuazione e la rettifica di frodi e irregolarità e il seguito dato a tali frodi e irregolarità, nonché l’adeguata gestione dei rischi connessi alla legittimità e alla regolarità delle operazioni sottostanti, tenendo conto del carattere pluriennale dei programmi e della natura dei pagamenti in questione. I controlli possono comportare varie verifiche, nonché l’attuazione delle politiche e delle procedure per raggiungere gli obiettivi di cui alla prima frase;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>20) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«controparte», la parte cui è concessa una garanzia di bilancio;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>21) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«crisi»,</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una situazione di pericolo immediato o imminente che rischia di degenerare in conflitto armato o di destabilizzare un paese o il suo vicinato;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una situazione derivante da calamità naturali, da crisi provocate dall’uomo, come guerre o altri conflitti, o da circostanze straordinarie con effetti analoghi riguardanti, fra l’altro, il cambiamento climatico, il degrado ambientale, la privazione dell’accesso all’energia e alle risorse naturali o l’estrema povertà;</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>22) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«disimpegno», l’operazione con la quale l’ordinatore responsabile annulla, integralmente o parzialmente, l’imputazione di stanziamenti precedentemente effettuata per mezzo di un impegno di bilancio.</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>23) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«sistema dinamico di acquisizione», un processo di acquisizione interamente elettronico per acquisti di uso corrente di beni generalmente disponibili sul mercato;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>24) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«operatore economico», una persona fisica o giuridica, inclusi gli enti pubblici, o un raggruppamento di tali persone che, che offra la fornitura di prodotti, l’esecuzione di lavori, la prestazione di servizi o la fornitura di beni immobili;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>25) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«investimento azionario», il conferimento di capitale in una società, investito direttamente o indirettamente in contropartita della totale o parziale proprietà di tale società, in cui l’investitore azionario può assumere un certo controllo della gestione e condividere gli utili;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>26) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«ufficio europeo», una struttura amministrativa creata dalla Commissione, o dalla Commissione insieme a una o più altre istituzioni dell’Unione, per svolgere funzioni orizzontali specifiche;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>27) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«decisione amministrativa definitiva», una decisione di un’autorità amministrativa avente effetto definitivo e vincolante conformemente al diritto applicabile;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>28) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«attivo finanziario», qualsiasi attivo sotto forma di denaro contante, uno strumento di capitale di un’entità di proprietà pubblica o privata oppure un diritto contrattuale a ricevere denaro contante o altro attivo finanziario da detta entità;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>29) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«strumento finanziario», una misura di sostegno finanziario dell’Unione fornita dal bilancio per conseguire uno o più obiettivi strategici specifici dell’Unione che può assumere la forma di investimenti azionari o quasi-azionari, prestiti o garanzie, o altri strumenti di condivisione del rischio, e che possono, se del caso, essere combinati con altre forme di sostegno finanziario, con fondi in regime di gestione concorrente o fondi del Fondo europeo di sviluppo (FES);</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>30) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«passività finanziaria», un’obbligazione contrattuale a erogare denaro contante o altro attivo finanziario a un’altra entità;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>31) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«contratto quadro», un appalto pubblico concluso tra uno o più operatori economici e una o più amministrazioni aggiudicatrici il cui scopo è quello di stabilire le clausole relative ad appalti specifici basati su di esso da aggiudicare durante un dato periodo, in particolare per quanto riguarda i prezzi e, se del caso, le quantità previste;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>32) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«copertura globale», l’importo totale delle risorse ritenute necessarie nel corso dell’intera durata di una garanzia di bilancio risultante dall’applicazione del tasso di copertura di cui all’articolo 211, paragrafo 1, all’importo della garanzia di bilancio autorizzata dall’atto di base di cui all’articolo 210, paragrafo 1, lettera b);</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>33) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«sovvenzione», un contributo finanziario accordato a titolo di liberalità. Se fornito in regime di gestione diretta, tale contributo è disciplinato dal titolo VIII;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>34) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«garanzia», l’impegno scritto ad assumersi, in parte o nella sua interezza, la responsabilità del debito o dell’obbligazione di un terzo o del risultato positivo da parte di un terzo dei propri obblighi nel caso di un evento che attivi tale garanzia, come un inadempimento nel rimborso del prestito;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>35) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«garanzia su richiesta», una garanzia che deve essere onorata dal garante su richiesta della controparte, nonostante eventuali carenze nell’adempimento dell’obbligazione sottostante;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>36) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«contributo in natura», le risorse non finanziarie messe gratuitamente a disposizione di un beneficiario da terzi;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>37) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«impegno giuridico», un atto con il quale l’ordinatore responsabile assume o crea un’obbligazione dalla quale derivano uno o più pagamenti successivi e il riconoscimento della spesa imputata al bilancio e che comprende accordi e contratti specifici conclusi nell’ambito di accordi quadro relativi ai partenariati finanziari e di contratti quadro;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>38) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«effetto leva», l’importo del finanziamento rimborsabile fornito ai destinatari finali ammissibili diviso per l’importo del contributo dell’Unione;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>39) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«rischio di liquidità», il rischio che un attivo finanziario detenuto nel fondo comune di copertura non possa essere venduto per un determinato periodo di tempo senza incorrere in una perdita significativa;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>40) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«prestito», un accordo ai sensi del quale il mutuante è tenuto a mettere a disposizione del mutuatario un importo convenuto di denaro per un periodo concordato e in forza del quale il mutuatario è tenuto a ripagare tale importo entro il periodo concordato;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>41) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«sovvenzione di valore modesto», una sovvenzione di valore pari o inferiore a 60 000  EUR;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>42) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«organizzazione di uno Stato membro», un’entità stabilita in uno Stato membro quale organismo di diritto pubblico o quale organismo di diritto privato investito di attribuzioni di servizio pubblico che presenta sufficienti garanzie finanziarie fornite dallo Stato membro;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>43) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«metodo di esecuzione», i metodi di esecuzione del bilancio di cui all’articolo 62, vale a dire la gestione diretta, la gestione indiretta e la gestione concorrente;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>44) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«azione finanziata da una pluralità di donatori», un’azione nell’ambito della quale i fondi dell’Unione sono messi in comune con almeno un altro donatore;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>45) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«effetto moltiplicatore», l’investimento effettuato dai destinatari finali ammissibili diviso per l’importo del contributo dell’Unione;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>46) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«realizzazione», i risultati generati dall’azione determinati in conformità della normativa settoriale;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>47) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«partecipante», un candidato od offerente in una procedura di appalto, un richiedente in una procedura di attribuzione di una sovvenzione, un esperto in una procedura di selezione di esperti, un richiedente in un concorso a premi o una persona o un’entità che partecipa a una procedura per l’esecuzione di fondi dell’Unione ai sensi dell’articolo 62, paragrafo 1, primo comma, lettera c);</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>48) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«premio», contributo finanziario attribuito a titolo di ricompensa in seguito a un concorso. Se fornito in regime di gestione diretta, tale contributo è disciplinato dal titolo IX;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>49) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«appalto», l’acquisizione da parte di una o più amministrazioni aggiudicatrici, mediante un contratto di lavori, forniture o servizi, e l’acquisto o la locazione di terreni, fabbricati o altri beni immobili, da operatori economici scelti dalle amministrazioni aggiudicatrici stesse;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>50) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«documento di gara», qualsiasi documento prodotto dall’amministrazione aggiudicatrice o al quale l’amministrazione aggiudicatrice fa riferimento per descrivere o determinare elementi della procedura di appalto, ivi compresi:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le misure di pubblicità stabilite nell’articolo 163;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’invito a presentare offerte;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il capitolato d’oneri, compresi le specifiche tecniche e i pertinenti criteri, o i documenti descrittivi nel caso di un dialogo competitivo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il progetto di contratto;</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>51) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«appalto pubblico», un contratto a titolo oneroso, concluso per iscritto tra uno o più operatori economici e una o più amministrazioni aggiudicatrici ai sensi degli articoli 174 e 178 per ottenere, contro pagamento di un prezzo in tutto o in parte a carico del bilancio, la fornitura di un bene mobile o immobile, l’esecuzione di lavori o la prestazione di servizi, e che comprende:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli appalti immobiliari;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli appalti di forniture;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli appalti di lavori;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli appalti di servizi;</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>52) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«investimento quasi azionario», un tipo di finanziamento che si colloca tra capitale e debito, con un rischio più elevato del debito privilegiato e un rischio inferiore rispetto al capitale azionario e che può essere strutturato come debito, di norma non garantito e subordinato e in alcuni casi convertibile in azioni o in azioni privilegiate;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>53) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«destinatario», un beneficiario, un contraente, un esperto esterno retribuito o un’altra persona o entità destinataria di premi o fondi a titolo di uno strumento finanziario o che esegue fondi dell’Unione ai sensi dell’articolo 62, paragrafo 1, primo comma, lettera c);</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>54) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«contratto di vendita con patto di opzione», la vendita di titoli a pronti con l’accordo di riacquistarli a una specifica data futura oppure su richiesta;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>55) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«stanziamento per la ricerca e lo sviluppo tecnologico», uno stanziamento iscritto in uno dei titoli del bilancio relativo ai settori connessi alla «Ricerca indiretta» o alla «Ricerca diretta» o in un capitolo relativo alle attività di ricerca inserito in un titolo diverso;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>56) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«risultato», gli effetti dell’attuazione di un’azione determinati in conformità della normativa settoriale;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>57) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«strumento di condivisione del rischio», uno strumento finanziario che consente la condivisione di un determinato rischio tra due o più entità, se del caso in contropartita di una remunerazione convenuta;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>58) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«appalto di servizi», un appalto che ha per oggetto tutte le prestazioni intellettuali e non intellettuali non contemplate dagli appalti di forniture, di lavori e dagli appalti immobiliari;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>59) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«sana gestione finanziaria», l’esecuzione del bilancio secondo i principi di economia, efficienza ed efficacia;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>60) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«statuto», lo statuto dei funzionari dell’Unione europea e il regime applicabile agli altri agenti dell’Unione europea definiti dal regolamento (CEE, Euratom, CECA) n. 259/68;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>61) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«subappaltatore», un operatore economico proposto da un candidato od offerente o contraente per eseguire parte di un contratto o da un beneficiario per eseguire parte dei compiti cofinanziati da una sovvenzione;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>62) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«sottoscrizione», le somme versate a organismi cui aderisce l’Unione, in base alle decisioni finanziarie e alle condizioni di pagamento degli organismi in questione;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>63) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«appalto di forniture», un appalto che ha per oggetto l’acquisto, il leasing finalizzato all’acquisto, la locazione o l’acquisto a riscatto, con o senza opzione per l’acquisto, di prodotti e che può includere, a titolo accessorio, lavori di posa in opera e di installazione;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>64) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«assistenza tecnica», fatta salva la normativa settoriale, le attività di sostegno e di potenziamento delle capacità necessarie per l’attuazione di un programma o di un’azione, segnatamente le attività di preparazione, gestione, sorveglianza, valutazione, audit e controllo;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>65) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«offerente», un operatore economico che ha presentato un’offerta;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>66) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«Unione», l’Unione europea, la Comunità europea dell’energia atomica, o ambedue, a seconda del contesto;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>67) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«istituzione dell’Unione», il Parlamento europeo, il Consiglio europeo, il Consiglio, la Commissione, la Corte di giustizia dell’Unione europea, la Corte dei conti, il Comitato economico e sociale europeo, il Comitato delle regioni, il Mediatore europeo, il Garante europeo della protezione dei dati o il Servizio europeo per l’azione esterna («SEAE»); la Banca centrale europea non è considerata un’istituzione dell’Unione;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>68) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«potenziale offerente», un operatore economico iscritto in un elenco di potenziali offerenti da invitare a presentare domande di partecipazione od offerte;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>69) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«volontario», una persona che lavora per un’organizzazione senza averne l’obbligo e senza essere remunerata;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>70) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«opera», il risultato di un insieme di lavori edilizi o di genio civile che di per sé esplichi una funzione economica o tecnica;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>71) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">«appalto di lavori», un appalto che ha per oggetto:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’esecuzione o, congiuntamente, l’esecuzione e la progettazione di un’opera;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’esecuzione o, congiuntamente, l’esecuzione e la progettazione di un’opera relativi a una delle attività di cui all’allegato II della direttiva 2014/24/UE; oppure</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la realizzazione, con qualsiasi mezzo, di un’opera corrispondente alle esigenze specificate dall’amministrazione aggiudicatrice che esercita un’influenza determinante sul tipo o sulla progettazione dell’opera.</p>\n</div>\n</div>\n</div>\n</div>"]]}, "3": {"label": "Articolo 3", "heading": "Conformità della legislazione secondaria al presente regolamento", "anchor": "art_3", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le disposizioni relative all’esecuzione del bilancio in entrate e in spese e contenute in un atto di base si conformano ai principi di bilancio enunciati nel titolo II.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Fatto salvo il paragrafo 1, ogni proposta o modifica di proposta presentata all’autorità legislativa comportante deroghe alle disposizioni del presente regolamento diverse da quelle di cui al titolo II, o agli atti delegati adottati a norma del presente regolamento, indica con chiarezza tali deroghe e precisa nei considerando e nella relazione di ciascuna proposta o modifica i motivi specifici che giustificano tali deroghe.</div>\n</div>"]]}, "4": {"label": "Articolo 4", "heading": "Periodi di tempo, date e termini", "anchor": "art_4", "frags": [[null, "<p class=\"norm\">Salvo che sia altrimenti disposto nel presente regolamento, ai termini fissati dal presente regolamento si applica il regolamento (CEE, Euratom) n. 1182/71 del Consiglio (\n<span class=\"superscript\">1</span>\n).</p>"]]}, "5": {"label": "Articolo 5", "heading": "Protezione dei dati personali", "anchor": "art_5", "frags": [[null, "<p class=\"norm\">Il presente regolamento fa salvi i regolamenti (CE) N. 45/2001 e (UE) 2016/679.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "6": {"label": "Articolo 6", "heading": "Rispetto dei principi di bilancio", "anchor": "art_6", "frags": [[null, "<p class=\"norm\">La formazione e l’esecuzione del bilancio rispettano i principi dell’unità, della verità del bilancio, dell’annualità, del pareggio, dell’unità di conto, dell’universalità, della specializzazione, della sana gestione finanziaria e della trasparenza di cui al presente regolamento.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "7": {"label": "Articolo 7", "heading": "Ambito di applicazione del bilancio", "anchor": "art_7", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Il bilancio prevede e autorizza, per ciascun esercizio, tutte le entrate e le spese ritenute necessarie per l’Unione. Esso comprende quanto segue:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le entrate e le spese dell’Unione, comprese le spese amministrative che derivano dall’attuazione delle disposizioni del TUE nel settore della politica estera e di sicurezza comune (PESC), nonché le spese operative connesse con l’attuazione di dette disposizioni, quando sono a carico del bilancio;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le entrate e le spese della Comunità europea dell’energia atomica.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il bilancio comporta stanziamenti dissociati, che danno luogo a stanziamenti di impegno e a stanziamenti di pagamento, e stanziamenti non dissociati.</div>\n</div>"], [null, "<p class=\"norm inline-element\">Gli stanziamenti autorizzati per l’esercizio constano di:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">stanziamenti iscritti in bilancio, anche mediante bilancio rettificativo;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">stanziamenti riportati dagli esercizi precedenti;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">stanziamenti ricostituiti conformemente all’articolo 15;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">stanziamenti provenienti da rimborsi di prefinanziamenti conformemente all’articolo 12, paragrafo 4, lettera b);</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">stanziamenti aperti a seguito del percepimento di entrate con destinazione specifica nel corso dell’esercizio o riportati da esercizi precedenti.</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Gli stanziamenti di impegno coprono il costo totale degli impegni giuridici sottoscritti durante l’esercizio, alle condizioni di cui l’articolo 114, paragrafo 2.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Gli stanziamenti di pagamento coprono i pagamenti derivanti dall’adempimento degli impegni giuridici assunti durante l’esercizio o durante gli esercizi precedenti.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">I paragrafi 2 e 3 del presente articolo non precludono la facoltà di impegnare gli stanziamenti globalmente o di procedere a impegni di bilancio per frazioni annue come stabilito rispettivamente all’articolo 112, paragrafo 1, primo comma, lettera b), e all’articolo 112, paragrafo 2.</div>\n</div>"]]}, "8": {"label": "Articolo 8", "heading": "Norme specifiche sui principi dell’unità e della verità del bilancio", "anchor": "art_8", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Tutte le entrate e tutte le spese sono imputate a una linea del bilancio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Fatte salve le spese autorizzate risultanti dalle passività potenziali previste all’articolo 210, paragrafo 2, nessuna spesa può essere impegnata né oggetto di un ordine di pagamento in eccedenza rispetto agli stanziamenti autorizzati.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Uno stanziamento è iscritto in bilancio solo se corrisponde a una spesa ritenuta necessaria.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Gli interessi generati dai versamenti di prefinanziamenti effettuati a titolo del bilancio non sono dovuti all’Unione, salvo diversamente disposto negli accordi di contributo o nelle convenzioni di finanziamento in questione.</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "9": {"label": "Articolo 9", "heading": "Definizione", "anchor": "art_9", "frags": [[null, "<p class=\"norm\">Gli stanziamenti iscritti in bilancio sono autorizzati per la durata di un esercizio, che inizia il 1<span class=\"superscript\">o</span> gennaio e termina il 31 dicembre.</p>"]]}, "10": {"label": "Articolo 10", "heading": "Contabilità di bilancio per entrate e stanziamenti", "anchor": "art_10", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le entrate sono imputate a un esercizio sulla base degli importi riscossi nel corso dell’esercizio stesso. Tuttavia, le risorse proprie del mese di gennaio dell’esercizio successivo possono essere rese disponibili a titolo di anticipo conformemente al regolamento (UE, Euratom) n. 609/2014.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le iscrizioni delle risorse proprie provenienti dall’imposta sul valore aggiunto (IVA) e dal prodotto nazionale lordo possono essere rettificate conformemente al regolamento (UE, Euratom) n. 609/2014.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Gli impegni sono contabilizzati a titolo di un esercizio sulla base degli impegni giuridici contratti fino al 31 dicembre di tale esercizio. Ciononostante, gli impegni globali di bilancio di cui all’articolo 112, paragrafo 4, sono contabilizzati a titolo di un esercizio sulla base degli impegni di bilancio contratti fino al 31 dicembre di detto esercizio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">I pagamenti sono contabilizzati a titolo di un esercizio sulla base dei pagamenti effettuati dal contabile entro il 31 dicembre dell’esercizio stesso.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">In deroga ai paragrafi 3 e 4:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le spese del Fondo europeo agricolo di garanzia (FEAGA) sono contabilizzate in un esercizio sulla base dei rimborsi effettuati dalla Commissione agli Stati membri entro il 31 dicembre dell’esercizio in questione, purché l’ordine di pagamento sia pervenuto al contabile entro il 31 gennaio dell’esercizio successivo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le spese eseguite in regime di gestione concorrente, tranne quelle del FEAGA, sono contabilizzate in un esercizio sulla base dei rimborsi effettuati dalla Commissione agli Stati membri entro il 31 dicembre dell’esercizio in questione, comprese le spese imputate entro il 31 gennaio dell’esercizio successivo, conformemente agli articoli 30 e 31.</p>\n</div>\n</div>\n</div>\n</div>"]]}, "11": {"label": "Articolo 11", "heading": "Impegno di stanziamenti", "anchor": "art_11", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli stanziamenti iscritti in bilancio possono essere impegnati con decorrenza di effetti dal 1<span class=\"superscript\">o</span> gennaio, non appena il bilancio è stato definitivamente adottato.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">A partire dal 15 ottobre dell’esercizio le seguenti spese possono essere oggetto di impegni anticipati a carico degli stanziamenti previsti per l’esercizio successivo:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">spese correnti di natura amministrativa, a condizione che siano state approvate nell’ultimo bilancio regolarmente adottato, e solo fino a massimo un quarto del totale corrispondente agli stanziamenti decisi dal Parlamento europeo e dal Consiglio per l’esercizio in corso;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">spese di gestione corrente del FEAGA, a condizione che il loro fondamento sia un atto di base esistente, e solo fino a massimo tre quarti del totale dei corrispondenti stanziamenti decisi dal Parlamento europeo e dal Consiglio per l’esercizio in corso.</p>\n</div>\n</div>\n</div>\n</div>"]]}, "12": {"label": "Articolo 12", "heading": "Annullamento e riporto di stanziamenti", "anchor": "art_12", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli stanziamenti non utilizzati entro la fine dell’esercizio per il quale sono stati iscritti sono annullati, a meno che non siano riportati conformemente ai paragrafi da 2 a 8.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">I seguenti stanziamenti possono essere oggetto di riporto mediante una decisione adottata a norma del paragrafo 3, ma unicamente all’esercizio successivo:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli stanziamenti di impegno e gli stanziamenti non dissociati, per i quali la maggior parte delle fasi preparatorie della procedura di impegno è stata completata al 31 dicembre dell’esercizio. Tali stanziamenti possono essere impegnati fino al 31 marzo dell’esercizio successivo, ad eccezione degli stanziamenti non dissociati relativi a progetti immobiliari, che possono essere impegnati fino al 31 dicembre dell’esercizio successivo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli stanziamenti che risultano necessari quando l’autorità legislativa ha adottato un atto di base nel corso dell’ultimo trimestre dell’esercizio e la Commissione non ha potuto stanziare gli impegni previsti a tale scopo entro il 31 dicembre di detto esercizio. Tali stanziamenti possono essere impegnati fino al 31 dicembre dell’esercizio successivo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli stanziamenti di pagamento necessari per coprire impegni anteriori o impegni connessi a stanziamenti di impegno riportati, se gli stanziamenti di pagamento previsti alle rispettive linee del bilancio dell’esercizio successivo sono insufficienti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli stanziamenti non impegnati relativi alle azioni di cui all’articolo 4, paragrafo 1, del regolamento (UE) n. 1306/2013 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">2</span>\n).</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Con riguardo al primo comma, lettera c), l’istituzione dell’Unione interessata impiega in via prioritaria gli stanziamenti autorizzati per l’esercizio in corso e ricorre agli stanziamenti riportati soltanto quando i primi siano esauriti.</p>"], [null, "<p class=\"norm\">I riporti degli stanziamenti non impegnati di cui al primo comma, lettera d), del presente paragrafo, non possono superare, entro il limite del 2 % degli stanziamenti iniziali votati dal Parlamento europeo e dal Consiglio, l’importo dell’adattamento dei pagamenti diretti applicato conformemente all’articolo 26 del regolamento (UE) n. 1306/2013 nell’esercizio precedente. Gli stanziamenti riportati sono riversati nelle linee di bilancio che coprono le azioni di cui all’articolo 4, paragrafo 1, lettera b), del regolamento (UE) n. 1306/2013.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">L’istituzione dell’Unione interessata adotta la sua decisione sui riporti di cui al paragrafo 2 entro il 15 febbraio dell’esercizio successivo. Essa informa il Parlamento europeo e il Consiglio entro il 15 marzo di tale esercizio in merito alla decisione di riporto che ha adottato. Inoltre precisa, per ogni linea di bilancio, in quale modo i criteri di cui al paragrafo 2, primo comma, lettere a), b) e c), sono stati applicati a ciascun riporto.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Gli stanziamenti sono riportati di diritto per quanto riguarda:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli stanziamenti di impegno per la riserva per gli aiuti d’urgenza e per il fondo di solidarietà dell’Unione europea. Tali stanziamenti possono essere riportati unicamente all’esercizio successivo e possono essere impegnati fino al 31 dicembre di tale esercizio;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli stanziamenti corrispondenti alle entrate con destinazione specifica interne. Tali stanziamenti possono essere riportati unicamente all’esercizio successivo e possono essere impegnati fino al 31 dicembre di tale esercizio, fatta eccezione per le entrate con destinazione specifica interne provenienti da indennità locative e dalla vendita dei fabbricati e terreni che possono essere riportate fino a quando non siano utilizzate integralmente. Gli stanziamenti di impegno di cui al regolamento (UE) n. 1303/2013 e al regolamento (UE) n. 514/2014 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">3</span>\n), disponibili al 31 dicembre e derivanti da riversamenti di versamenti di prefinanziamenti, possono essere oggetto di riporto fino al termine del programma e utilizzati quando necessario, a condizione che non vi siano più altri stanziamenti di impegno disponibili;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli stanziamenti corrispondenti alle entrate con destinazione specifica esterne. Tali stanziamenti sono utilizzati integralmente entro il completamento di tutte le operazioni connesse al programma o all’azione cui sono destinati o possono essere riportati e utilizzati per il programma o l’azione successivi. Questa disposizione non si applica alle entrate di cui all’articolo 21, paragrafo 2, lettera g), punto iii), per le quali gli stanziamenti non impegnati entro cinque anni sono annullati;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli stanziamenti di pagamento relativi al FEAGA provenienti da sospensioni a norma dell’articolo 41 del regolamento (UE) n. 1306/2013.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Il trattamento delle entrate con destinazione specifica esterne di cui al paragrafo 4, lettera c), del presente articolo provenienti dalla partecipazione degli Stati dell’Associazione europea di libero scambio (EFTA) a taluni programmi dell’Unione a norma dell’articolo 21, paragrafo 2, lettera e), è conforme al protocollo n. 32 allegato all’accordo sullo spazio economico europeo (accordo SEE).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Oltre alle informazioni di cui al paragrafo 3, l’istituzione dell’Unione interessata informa il Parlamento europeo e il Consiglio degli stanziamenti che sono stati oggetto di riporto di diritto, inclusi gli importi in questione e la disposizione del presente articolo a norma della quale gli stanziamenti sono stati riportati.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Gli stanziamenti non dissociati giuridicamente impegnati alla fine dell’esercizio sono oggetto di pagamento fino alla fine dell’esercizio successivo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">Fatto salvo il paragrafo 4, gli stanziamenti iscritti in riserva e gli stanziamenti relativi alle spese per il personale non sono oggetto di riporto. Ai fini del presente articolo, le spese per il personale comprendono retribuzioni e indennità dei membri e del personale delle istituzioni dell’Unione soggetto allo statuto.</div>\n</div>"]]}, "13": {"label": "Articolo 13", "heading": "Disposizioni dettagliate in materia di annullamento e riporto di stanziamenti", "anchor": "art_13", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli stanziamenti di impegno e gli stanziamenti non dissociati di cui all’articolo 12, paragrafo 2, primo comma, lettera a), possono essere riportati soltanto se gli impegni non hanno potuto essere assunti prima del 31 dicembre dell’esercizio per motivi non imputabili all’ordinatore e se le fasi preparatorie sono sufficientemente avanzate da permettere ragionevolmente di prevedere che l’impegno sia assunto entro il 31 marzo dell’esercizio successivo, ovvero, relativamente ai progetti immobiliari, il 31 dicembre dell’esercizio successivo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Le fasi preparatorie di cui all’articolo 12, paragrafo 2, primo comma, lettera a), che devono essere completate al 31 dicembre dell’esercizio ai fini del riporto all’esercizio successivo sono in particolare le seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per gli impegni di bilancio specifici ai sensi dell’articolo 112, paragrafo 1, primo comma, lettera a), la conclusione della fase di selezione dei potenziali contraenti, dei beneficiari, dei vincitori di premi o dei soggetti delegati;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per gli impegni di bilancio globali ai sensi dell’articolo 112, paragrafo 1, primo comma, lettera b), l’adozione di una decisione di finanziamento o la conclusione della consultazione dei servizi interessati di ciascuna istituzione dell’Unione in vista dell’adozione della decisione relativa al finanziamento.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Gli stanziamenti riportati conformemente all’articolo 12, paragrafo 2, primo comma, lettera a), non impegnati al 31 marzo dell’esercizio successivo, o al 31 dicembre dell’esercizio successivo per gli importi relativi ai progetti immobiliari, sono annullati di diritto.</div>\n</div>"], [null, "<p class=\"norm\">La Commissione informa il Parlamento europeo e il Consiglio degli stanziamenti annullati conformemente al primo comma entro un mese dall’annullamento.</p>"]]}, "14": {"label": "Articolo 14", "heading": "Disimpegni", "anchor": "art_14", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Qualora gli impegni di bilancio siano oggetto di disimpegno nel corso degli esercizi successivi a quello nel quale erano stati assunti, in seguito all’inesecuzione totale o parziale delle azioni alle quali erano stati assegnati, gli stanziamenti corrispondenti a tali disimpegni sono annullati, salvo se diversamente disposto nei regolamenti (UE) n. 1303/2013 e (UE) n. 514/2014 e fatto salvo l’articolo 15 del presente regolamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Gli stanziamenti di impegno di cui ai regolamenti (UE) n. 1303/2013 e (UE) n. 514/2014 sono disimpegnati di diritto conformemente a tali regolamenti.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il presente articolo non si applica alle entrate con destinazione specifica esterne di cui all’articolo 21, paragrafo 2.</div>\n</div>"]]}, "15": {"label": "Articolo 15", "heading": "Ricostituzione degli stanziamenti corrispondenti ai disimpegni", "anchor": "art_15", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli stanziamenti corrispondenti ai disimpegni di cui ai regolamenti (UE) n. 1303/2013, (UE) n. 223/2014 e (UE) n. 514/2014 possono essere ricostituiti in caso di errore manifesto imputabile alla sola Commissione.</div>\n</div>"], [null, "<p class=\"norm\">A tale scopo, la Commissione esamina i disimpegni intervenuti nel corso dell’esercizio precedente e decide, entro il 15 febbraio dell’esercizio in corso e in funzione del fabbisogno, se sia necessario ricostituire gli stanziamenti corrispondenti.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">In aggiunta al caso di cui al paragrafo 1 del presente articolo, gli stanziamenti corrispondenti ai disimpegni sono ricostituiti se:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i disimpegni riguardano un programma interessato dalle modalità di applicazione della riserva di efficacia dell’attuazione dei programmi di cui all’articolo 20 del regolamento (UE) n. 1303/2013;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i disimpegni riguardano un programma dedicato a uno strumento finanziario specifico a favore delle piccole e medie imprese (PMI) a seguito della cessazione della partecipazione di uno Stato membro allo strumento finanziario, di cui all’articolo 39, paragrafo 2, settimo comma, del regolamento (UE) n. 1303/2013.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Anche gli stanziamenti di impegno corrispondenti all’importo dei disimpegni intervenuti in seguito all’inesecuzione totale o parziale di corrispondenti progetti di ricerca possono essere ricostituiti a beneficio del programma di ricerca cui appartengono i progetti o del programma successivo nell’ambito della procedura di bilancio.</div>\n</div>"]]}, "16": {"label": "Articolo 16", "heading": "Norme applicabili in caso di tardiva adozione del bilancio", "anchor": "art_16", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Se all’inizio dell’esercizio il bilancio non è stato ancora definitivamente adottato, si applica la procedura di cui all’articolo 315, primo comma, TFUE (regime dei dodicesimi provvisori). Le operazioni di impegno e di pagamento possono essere effettuate entro i limiti stabiliti al paragrafo 2 del presente articolo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le operazioni di impegno possono essere effettuate, per capitolo, entro i limiti di un quarto dell’insieme degli stanziamenti autorizzati per il pertinente capitolo del bilancio per l’esercizio precedente, aumentato di un dodicesimo per ciascun mese trascorso.</div>\n</div>"], [null, "<p class=\"norm\">Il limite degli stanziamenti previsti nel progetto di bilancio non è superato.</p>"], [null, "<p class=\"norm\">Le operazioni di pagamento possono essere effettuate mensilmente, per capitolo, entro i limiti di un dodicesimo degli stanziamenti autorizzati per il pertinente capitolo del bilancio per l’esercizio precedente, senza poter superare il dodicesimo degli stanziamenti previsti nello stesso capitolo del progetto di bilancio.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Per stanziamenti autorizzati nel pertinente capitolo del bilancio per l’esercizio precedente, di cui ai paragrafi 1 e 2, si intendono gli stanziamenti votati in bilancio, compresi i bilanci rettificativi, dopo le rettifiche apportate in funzione degli storni effettuati nel corso di tale esercizio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Se richiesto dalla continuità dell’azione dell’Unione e dalle esigenze di gestione, il Consiglio, deliberando a maggioranza qualificata su proposta della Commissione, può autorizzare spese superiori a un dodicesimo provvisorio, ma non superiori a un totale di quattro dodicesimi provvisori, salvo in casi debitamente giustificati, sia per le operazioni di impegno sia per le operazioni di pagamento in aggiunta a quelli resi disponibili di diritto a norma dei paragrafi 1 e 2. Il Consiglio trasmette senza indugio la sua decisione di autorizzazione al Parlamento europeo.</div>\n</div>"], [null, "<p class=\"norm inline-element\">La decisione di cui al primo comma entra in vigore 30 giorni dopo l’adozione, salvo che il Parlamento europeo:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">deliberando a maggioranza dei membri che lo compongono, decida di ridurre dette spese prima della scadenza dei 30 giorni, nel qual caso la Commissione presenta una nuova proposta;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">informi il Consiglio e la Commissione che non intende ridurre le spese, nel qual caso la decisione entra in vigore prima della scadenza del termine di 30 giorni.</p>\n</div>\n</div>"], [null, "<p class=\"norm\">I dodicesimi supplementari sono autorizzati per intero e non sono frazionabili.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Se, per un determinato capitolo, l’autorizzazione di quattro dodicesimi provvisori, accordata conformemente al paragrafo 4, non è sufficiente a fare fronte alle spese necessarie per evitare un’interruzione della continuità dell’azione dell’Unione nel settore contemplato dal capitolo in questione, può essere autorizzato, a titolo eccezionale, il superamento dell’importo degli stanziamenti iscritti nel corrispondente capitolo del bilancio per l’esercizio precedente. Il Parlamento europeo e il Consiglio deliberano secondo le procedure di cui al paragrafo 4. L’importo globale degli stanziamenti disponibile nel bilancio dell’esercizio precedente o nel progetto di bilancio proposto non è tuttavia in nessun caso superato.</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "17": {"label": "Articolo 17", "heading": "Definizione e portata", "anchor": "art_17", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Entrate e stanziamenti di pagamento risultano in pareggio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L’Unione e gli organismi dell’Unione di cui agli articoli 70 e 71 non accendono prestiti entro il quadro del bilancio.</div>\n</div>"]]}, "18": {"label": "Articolo 18", "heading": "Saldo dell’esercizio", "anchor": "art_18", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il saldo di ogni esercizio è iscritto nel bilancio dell’esercizio successivo, in entrate o in stanziamenti di pagamento a seconda che si tratti di un’eccedenza o, rispettivamente, di un disavanzo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le stime delle entrate o degli stanziamenti di pagamento di cui al paragrafo 1 del presente articolo sono iscritte in bilancio nel corso della procedura di bilancio e mediante una lettera rettificativa presentata a norma dell’articolo 42 del presente regolamento. Le stime sono determinate conformemente all’articolo 1 del regolamento (UE, Euratom) n. 608/2014 del Consiglio (\n<span class=\"superscript\">4</span>\n).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Dopo la presentazione dei conti provvisori di ogni esercizio, la differenza tra questi conti e le stime è iscritta nel bilancio dell’esercizio successivo mediante un bilancio rettificativo riguardante esclusivamente tale differenza. In tal caso, la Commissione presenta il progetto di bilancio rettificativo contemporaneamente al Parlamento europeo e al Consiglio entro 15 giorni dalla presentazione dei conti provvisori.</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "19": {"label": "Articolo 19", "heading": "Utilizzo dell’euro", "anchor": "art_19", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il quadro finanziario pluriennale e il bilancio sono formati, sono eseguiti e sono oggetto di rendiconto in euro. Tuttavia, per le esigenze della tesoreria di cui all’articolo 77, il contabile e, nel caso delle casse di anticipi, l’amministratore degli anticipi e, per le esigenze della gestione amministrativa della Commissione e del SEAE, l’ordinatore responsabile sono autorizzati a effettuare operazioni in altre valute.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Fatte salve le disposizioni specifiche stabilite nelle norme settoriali o in contratti, convenzioni di sovvenzione, accordi di contributo e convenzioni di finanziamento specifici, l’ordinatore responsabile effettua la conversione applicando il tasso giornaliero di cambio dell’euro pubblicato nella <span class=\"italics\">Gazzetta ufficiale dell’Unione europea</span>, serie C, del giorno nel quale il servizio ordinatore redige l’ordine di pagamento o l’ordine di riscossione.</div>\n</div>"], [null, "<p class=\"norm\">Se tale tasso giornaliero non è pubblicato, l’ordinatore responsabile applica il tasso di cui al paragrafo 3.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Ai fini della contabilità di cui agli articoli 82, 83 e 84, la conversione tra l’euro e un’altra valuta è effettuata applicando il tasso di cambio contabile mensile dell’euro, il quale è stabilito dal contabile della Commissione mediante ogni fonte d’informazione considerata affidabile, sulla base del tasso in vigore il penultimo giorno lavorativo del mese precedente quello per il quale si deve determinare il tasso suddetto.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Le operazioni di conversione delle valute sono effettuate in modo tale da evitare che abbiano effetti di rilievo sull’entità del cofinanziamento dell’Unione o incidano negativamente sul bilancio. Se del caso, la conversione tra l’euro e altre valute può essere effettuata applicando la media dei tassi di cambio giornalieri registrati in un determinato periodo.</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "20": {"label": "Articolo 20", "heading": "Portata", "anchor": "art_20", "frags": [[null, "<p class=\"norm\">Fatto salvo l’articolo 21, l’insieme delle entrate copre l’insieme degli stanziamenti di pagamento. Fatto salvo l’articolo 27, tutte le entrate e le spese sono iscritte nel bilancio senza compensazione fra di esse.</p>"]]}, "21": {"label": "Articolo 21", "heading": "Entrate con destinazione specifica", "anchor": "art_21", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le entrate con destinazione specifica esterne e le entrate con destinazione specifica interne sono destinate a finanziare spese determinate.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Costituiscono entrate con destinazione specifica esterne:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i contributi finanziari aggiuntivi specifici da parte degli Stati membri per i seguenti tipi di azioni e programmi:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">taluni programmi complementari di ricerca e sviluppo tecnologico;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">talune azioni o taluni programmi di aiuti esterni finanziati dall’Unione e gestiti dalla Commissione;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli stanziamenti relativi alle entrate risultanti dal Fondo di ricerca carbone e acciaio, di cui al protocollo n. 37 relativo alle conseguenze finanziarie della scadenza del trattato CECA e al Fondo di ricerca carbone e acciaio allegato al TUE e al TFUE;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli interessi sui depositi e le ammende previsti dal regolamento (CE) n. 1467/97 del Consiglio (\n<span class=\"superscript\">5</span>\n);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le entrate aventi una destinazione specifica, quali redditi da fondazioni, sussidi, donazioni e legati, comprese le entrate aventi una destinazione specifica proprie di ciascuna istituzione dell’Unione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i contributi finanziari ad attività dell’Unione provenienti da paesi terzi o da organismi diversi da quelli istituiti conformemente al TFUE o al trattato Euratom;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le entrate con destinazione specifica interne di cui al paragrafo 3, nella misura in cui siano accessorie rispetto alle entrate con destinazione specifica esterne di cui al presente paragrafo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le entrate provenienti dalle attività di natura concorrenziale svolte dal Centro comune di ricerca (JRC), che consistono in quanto segue:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">procedure di attribuzione di sovvenzioni e di aggiudicazione di appalti alle quali partecipa il JRC;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">attività del JRC per conto di terzi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">attività intraprese sulla base di un accordo amministrativo con altre istituzioni dell’Unione o altri servizi della Commissione, conformemente all’articolo 59, per la prestazione di servizi tecnico-scientifici.</p>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Costituiscono entrate con destinazione specifica interne:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le entrate provenienti da terzi per forniture, prestazioni di servizi o lavori effettuati su loro richiesta;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le entrate provenienti dalla restituzione, a norma dell’articolo 101, di somme indebitamente pagate;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i proventi di forniture, prestazioni di servizi e lavori effettuati a favore di altri servizi all’interno di un’istituzione o di altre istituzioni od organismi dell’Unione, compreso l’importo delle indennità di missione pagate per conto di altre istituzioni od organismi dell’Unione e da questi rimborsate;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’importo delle indennità di assicurazione riscosse;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le entrate provenienti da indennità locative e dalla vendita di fabbricati e terreni;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i rimborsi a strumenti finanziari o garanzie di bilancio a norma dell’articolo 209, paragrafo 3, secondo comma;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le entrate provenienti da successivi rimborsi di oneri fiscali a norma dell’articolo 27, paragrafo 3, primo comma, lettera b).</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Le entrate con destinazione specifica sono oggetto di riporti e di storni conformemente all’articolo 12, paragrafo 4, lettere b) e c), e all’articolo 32.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Un atto di base può prescrivere di destinare le entrate da esso previste a spese determinate. Salvo che sia diversamente specificato nell’atto di base, tali entrate costituiscono entrate con destinazione specifica interne.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Il bilancio prevede apposite linee per la registrazione delle entrate con destinazione specifica esterne e delle entrate con destinazione specifica interne e, per quanto possibile, ne indica l’importo.</div>\n</div>"]]}, "22": {"label": "Articolo 22", "heading": "Struttura per la registrazione in bilancio delle entrate con destinazione specifica e apertura dei corrispondenti stanziamenti", "anchor": "art_22", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Fatto salvo il paragrafo 2, primo comma, lettera c), del presente articolo e l’articolo 24, la struttura per la registrazione in bilancio delle entrate con destinazione specifica comporta quanto segue:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nello stato delle entrate della sezione di ciascuna istituzione dell’Unione, un’apposita linea di bilancio in cui sono registrate tali entrate;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nello stato delle spese, i commenti, compresi quelli generali, che indicano in quali linee di bilancio registrare gli stanziamenti corrispondenti alle entrate con destinazione specifica che sono rese disponibili.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Nel caso di cui al primo comma, lettera a), la linea è compilata con la menzione «per memoria» e le entrate stimate sono indicate a titolo informativo nei commenti.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Gli stanziamenti corrispondenti a entrate con destinazione specifica sono aperti automaticamente, sia come stanziamenti di impegno sia come stanziamenti di pagamento, quando l’entrata è stata riscossa dall’istituzione dell’Unione, tranne nei seguenti casi:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nel caso di cui all’articolo 21, paragrafo 2, lettera a), per i contributi finanziari da parte degli Stati membri e ove l’accordo di contributo sia espresso in euro, gli stanziamenti di impegno possono essere aperti al momento della firma dell’accordo di contributo da parte dello Stato membro;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nei casi di cui all’articolo 21, paragrafo 2, lettera b), e all’articolo 21, paragrafo 2, lettera g), punti i) e iii), gli stanziamenti di impegno sono aperti a partire dalla previsione di crediti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nel caso di cui all’articolo 21, paragrafo 2, lettera c), l’iscrizione degli importi nello stato delle entrate dà luogo all’apertura, nello stato delle spese, di stanziamenti di impegno e di pagamento.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Gli stanziamenti di cui al primo comma, lettera c), del presente paragrafo sono eseguiti conformemente all’articolo 20.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Le previsioni di crediti di cui all’articolo 21, paragrafo 2, lettere b) e g), sono trasmesse al contabile affinché siano registrate.</div>\n</div>"]]}, "23": {"label": "Articolo 23", "heading": "Contributi degli Stati membri a programmi di ricerca", "anchor": "art_23", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">I contributi degli Stati membri al finanziamento di taluni programmi complementari di ricerca, di cui all’articolo 5 del regolamento (UE, Euratom) n. 609/2014, sono versati:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">a concorrenza dei sette dodicesimi dell’importo iscritto in bilancio, entro il 31 gennaio dell’esercizio in corso;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">a concorrenza dei restanti cinque dodicesimi, entro il 15 luglio dell’esercizio in corso.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Quando il bilancio non è approvato definitivamente prima dell’inizio dell’esercizio, i contributi previsti al paragrafo 1 sono versati sulla base dell’importo iscritto nel bilancio dell’esercizio precedente.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Qualsiasi contributo o qualsiasi pagamento supplementare dovuto dagli Stati membri a titolo del bilancio deve essere iscritto nel conto o nei conti della Commissione nei 30 giorni di calendario che seguono la richiesta di fondi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">I pagamenti effettuati sono iscritti nel conto previsto dal regolamento (UE, Euratom) n. 609/2014 e sono soggetti alle condizioni enunciate dal medesimo.</div>\n</div>"]]}, "24": {"label": "Articolo 24", "heading": "Entrate con destinazione specifica derivanti dalla partecipazione degli Stati EFTA a taluni programmi dell’Unione", "anchor": "art_24", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La struttura per la registrazione in bilancio delle entrate derivanti dalla partecipazione degli Stati EFTA a taluni programmi dell’Unione comporta quanto segue:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nello stato delle entrate, è inserita una linea di bilancio con la menzione «per memoria», in cui è registrato l’importo globale, per l’esercizio, di ciascun contributo dello Stato EFTA;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nello stato delle spese, un allegato, che è parte integrante del bilancio, elenca tutte le linee di bilancio relative alle attività dell’Unione alle quali partecipano gli Stati EFTA e comprende informazioni sull’importo previsto della partecipazione di ciascuno Stato EFTA.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">A norma dell’articolo 82 dell’accordo SEE, gli importi relativi alla partecipazione annuale degli Stati EFTA, quali confermati alla Commissione dal comitato misto dello Spazio economico europeo a norma dell’articolo 1, paragrafo 5, del protocollo n. 32 allegato all’accordo SEE, danno luogo all’apertura integrale, dall’inizio dell’esercizio, dei corrispondenti stanziamenti di impegno e stanziamenti di pagamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">L’impiego delle entrate provenienti dal contributo finanziario di Stati EFTA è sottoposto a un controllo separato.</div>\n</div>"]]}, "25": {"label": "Articolo 25", "heading": "Atti di liberalità", "anchor": "art_25", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le istituzioni dell’Unione possono accettare qualsiasi atto di liberalità a favore dell’Unione, quali redditi da fondazioni, sussidi, donazioni e legati.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L’accettazione di una liberalità per un valore pari o superiore a 50 000  EUR comportante oneri finanziari, compresi i costi correlati all’accettazione, superiori al 10 % del valore della liberalità effettuata, è soggetta all’autorizzazione del Parlamento europeo e del Consiglio. Il Parlamento europeo e il Consiglio si pronunciano entro due mesi dal ricevimento di una domanda per tale autorizzazione da parte delle istituzioni dell’Unione interessate. Se entro questo termine non è formulata alcuna obiezione, le istituzioni dell’Unione interessate deliberano in via definitiva sull’accettazione della donazione. Nella loro richiesta al Parlamento europeo e al Consiglio, le istituzioni dell’Unione interessate illustrano gli oneri finanziari correlati all’accettazione di liberalità a favore dell’Unione.</div>\n</div>"]]}, "26": {"label": "Articolo 26", "heading": "Sponsorizzazione da parte di imprese", "anchor": "art_26", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Per «sponsorizzazione da parte di imprese» si intende un accordo mediante il quale una persona giuridica fornisce un sostegno in natura a una manifestazione o un’attività a fini promozionali o ai fini della responsabilità sociale delle imprese.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Sulla base di regole interne specifiche, che sono pubblicate sui rispettivi siti web, le istituzioni e gli organismi dell’Unione possono, in via straordinaria, accettare le sponsorizzazioni da parte di imprese, a condizione che:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">siano debitamente rispettati i principi di non discriminazione, proporzionalità, parità di trattamento e trasparenza in tutte le fasi della procedura di accettazione della sponsorizzazione da parte di imprese;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">contribuiscano all’immagine positiva dell’Unione e siano direttamente collegate all’obiettivo primario della manifestazione o dell’attività;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">non generino conflitti d’interessi e non riguardino eventi di natura esclusivamente sociale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’evento o l’attività non siano finanziati esclusivamente mediante la sponsorizzazione da parte di imprese;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il servizio fornito per la sponsorizzazione da parte di imprese si limiti alla visibilità pubblica del marchio o del nome dello sponsor;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">al momento della procedura di sponsorizzazione, lo sponsor non si trovi in una delle situazioni di cui all’articolo 136, paragrafo 1, e all’articolo 141, paragrafo 1, né sia registrato come escluso nella banca dati di cui all’articolo 142, paragrafo 1.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Se il valore della sponsorizzazione da parte di imprese è superiore a 5 000  EUR lo sponsor è inserito in un registro pubblico che comprende informazioni sul tipo di evento o attività sponsorizzata.</div>\n</div>"]]}, "27": {"label": "Articolo 27", "heading": "Norme in materia di detrazioni e compensazioni del tasso di cambio", "anchor": "art_27", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Si possono effettuare le seguenti detrazioni dall’importo oggetto delle richieste di pagamento, che in tal caso sono oggetto di un ordine di pagamento al netto:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sanzioni irrogate alle parti di contratti o ai beneficiari;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sconti, rimborsi e ribassi concessi su singole fatture e rendiconti di spesa;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">interessi prodotti da versamenti di prefinanziamenti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">ripetizioni di somme indebitamente pagate.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Le ripetizioni di cui al primo comma, lettera d), possono essere operate mediante detrazione diretta, in occasione di un nuovo pagamento intermedio o del pagamento a saldo a favore del medesimo beneficiario, effettuata sullo stesso capitolo, articolo ed esercizio ai quali l’indebito pagamento è stato imputato.</p>"], [null, "<p class=\"norm\">Le norme contabili dell’Unione si applicano alle detrazioni di cui al primo comma, lettere c) e d).</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">I prezzi di prodotti o servizi forniti all’Unione che comprendono oneri fiscali oggetto di rimborso da parte degli Stati membri in forza del protocollo n. 7 sui privilegi e sulle immunità dell’Unione europea, allegati al TUE e al TFUE, sono imputati in bilancio con il loro importo al netto delle tasse.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">I prezzi di prodotti o servizi forniti all’Unione che comprendono oneri fiscali oggetto di rimborso da parte di paesi terzi in forza delle pertinenti convenzioni possono essere imputati in bilancio con il loro importo:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">al netto degli oneri fiscali, oppure</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">al lordo degli oneri fiscali.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Nel caso di cui al primo comma, lettera b), i successivi rimborsi di oneri fiscali sono assimilati a entrate con destinazione specifica interne.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Differenze di cambio registrate nel corso dell’esecuzione del bilancio possono essere adattate. Il risultato finale, positivo o negativo, è ripreso nel saldo dell’esercizio.</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "28": {"label": "Articolo 28", "heading": "Disposizioni generali", "anchor": "art_28", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli stanziamenti sono specificati per titoli e per capitoli. I capitoli sono suddivisi in articoli e in voci.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La Commissione e le altre istituzioni dell’Unione possono procedere a storni di stanziamenti all’interno del bilancio alle condizioni specifiche stabilite agli articoli da 29 a 32.</div>\n</div>"], [null, "<p class=\"norm\">Possono essere dotate di stanziamenti mediante storno solo le linee di bilancio per le quali il bilancio autorizza uno stanziamento o che recano la menzione «per memoria».</p>"], [null, "<p class=\"norm\">I limiti di cui agli articoli 29, 30 e 31 sono calcolati al momento della domanda di storno, con riferimento agli stanziamenti previsti nel bilancio ed eventualmente nei bilanci rettificativi.</p>"], [null, "<p class=\"norm\">L’importo da prendere in considerazione ai fini del calcolo dei limiti di cui agli articoli 29, 30 e 31 è la somma degli storni da effettuare sulla linea di bilancio dalla quale si procede agli storni stessi, previa correzione per storni effettuati in precedenza. Non si prende in considerazione l’importo degli storni effettuati autonomamente dalla Commissione o da altre istituzioni dell’Unione interessate senza una decisione del Parlamento europeo e del Consiglio.</p>"], [null, "<p class=\"norm\">Le proposte di storno e tutte le informazioni destinate al Parlamento europeo e al Consiglio relative agli storni effettuati a norma degli articoli 29, 30 e 31 sono corredate di documenti giustificativi adeguati e dettagliati dai quali risultino le informazioni più recenti disponibili sull’esecuzione degli stanziamenti e sul fabbisogno previsto sino a fine esercizio, sia per le linee di bilancio da rafforzare sia per quelle dalle quali provengono gli stanziamenti.</p>"]]}, "29": {"label": "Articolo 29", "heading": "Storni a opera di istituzioni dell’Unione diverse dalla Commissione", "anchor": "art_29", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Ogni istituzione dell’Unione diversa dalla Commissione può procedere, all’interno della propria sezione di bilancio, a storni di stanziamenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">da titolo a titolo, fino a un massimo del 10 % degli stanziamenti dell’esercizio iscritti alla linea di bilancio dalla quale è effettuato lo storno;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">da capitolo a capitolo, senza limiti.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Fatto salvo il paragrafo 4 del presente articolo, tre settimane prima di procedere a uno storno di cui al paragrafo 1, l’istituzione dell’Unione informa il Parlamento europeo e il Consiglio della sua intenzione. Se durante tale periodo il Parlamento europeo o il Consiglio formula obiezioni debitamente giustificate, si applica la procedura di cui all’articolo 31.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Ogni istituzione dell’Unione diversa dalla Commissione può proporre al Parlamento europeo e al Consiglio, all’interno della propria sezione di bilancio, storni da titolo a titolo superiori al limite di cui al paragrafo 1, lettera a), del presente articolo. Tali storni sono soggetti alla procedura di cui all’articolo 31.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Ogni istituzione dell’Unione diversa dalla Commissione può procedere, all’interno della propria sezione di bilancio, a storni da articolo ad articolo senza informarne preventivamente il Parlamento europeo e il Consiglio.</div>\n</div>"]]}, "30": {"label": "Articolo 30", "heading": "Storni a opera della Commissione", "anchor": "art_30", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La Commissione può procedere autonomamente, all’interno della propria sezione di bilancio:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">a storni di stanziamenti all’interno di ciascun capitolo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">con riguardo alle spese per il personale e per l’amministrazione comuni a diversi titoli, a storni di stanziamenti da titolo a titolo fino a un massimo del 10 % degli stanziamenti dell’esercizio iscritti alla linea di bilancio dalla quale si procede allo storno e fino a un massimo del 30 % degli stanziamenti dell’esercizio iscritti alla linea di bilancio verso la quale è effettuato lo storno;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">con riguardo alle spese operative, a storni di stanziamenti tra capitoli all’interno dello stesso titolo fino a un massimo del 10 % degli stanziamenti dell’esercizio iscritti alla linea di bilancio dalla quale si procede allo storno;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">con riguardo agli stanziamenti per la ricerca e lo sviluppo tecnologico eseguiti dal JRC, all’interno del titolo del bilancio relativo al settore «Ricerca diretta», a storni di stanziamenti fra capitoli fino a un massimo del 15 % degli stanziamenti iscritti alla linea di bilancio dalla quale si procede allo storno;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">con riguardo alla ricerca e allo sviluppo tecnologico, a storni di stanziamenti operativi da titolo a titolo, purché si tratti di stanziamenti utilizzati per gli stessi fini;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">con riguardo alle spese operative dei fondi eseguiti in regime di gestione concorrente, tranne che per il FEAGA, a storni di stanziamenti da titolo a titolo, a condizione che si tratti di stanziamenti destinati allo stesso obiettivo conformemente al regolamento istitutivo del fondo interessato o che costituiscano spese di assistenza tecnica;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">a storni di stanziamenti dalla voce di bilancio di una garanzia di bilancio verso la voce di bilancio di un’altra garanzia di bilancio, nei casi eccezionali in cui le risorse accantonate nel fondo comune di copertura di quest’ultima siano insufficienti per l’attivazione di una garanzia e fatto salvo il successivo ripristino dell’importo stornato secondo la procedura di cui all’articolo 212, paragrafo 4.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Le spese di cui al primo comma, lettera b), del presente paragrafo coprono, per ciascun settore, le voci di cui all’articolo 47, paragrafo 4.</p>"], [null, "<p class=\"norm\">Quando procede a storni di stanziamenti del FEAGA a norma del primo comma dopo il 31 dicembre, la Commissione adotta la decisione entro il 31 gennaio dell’esercizio successivo. La Commissione informa il Parlamento europeo e il Consiglio nelle due settimane successive alla decisione relativa a tali storni.</p>"], [null, "<p class=\"norm\">Tre settimane prima di procedere agli storni di cui al primo comma, lettera b), del presente paragrafo, la Commissione informa il Parlamento europeo e il Consiglio della sua intenzione. Se durante tale periodo il Parlamento europeo o il Consiglio formula obiezioni debitamente giustificate, si applica la procedura di cui all’articolo 31.</p>"], [null, "<p class=\"norm\">In deroga al quarto comma, la Commissione può, negli ultimi due mesi dell’esercizio, trasferire autonomamente stanziamenti relativi a spese per il personale, per il personale esterno e per altri agenti da titolo a titolo entro un limite complessivo pari al 5 % degli stanziamenti per quell’esercizio. La Commissione informa il Parlamento europeo e il Consiglio nelle due settimane successive alla decisione relativa a tali storni.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La Commissione può decidere di procedere, all’interno della propria sezione di bilancio, ai seguenti storni di stanziamenti da titolo a titolo, purché comunichi immediatamente la sua decisione al Parlamento europeo e al Consiglio:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">storni di stanziamenti dal titolo «stanziamenti accantonati» di cui all’articolo 49 del presente regolamento, ove l’unica condizione per sciogliere la riserva è l’adozione di un atto di base a norma dell’articolo 294 TFUE;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">in casi eccezionali debitamente giustificati, quali catastrofi umanitarie e crisi internazionali, che si verifichino dopo il 1<span class=\"superscript\">o</span> dicembre dell’esercizio, storni di stanziamenti non utilizzati di detto esercizio ancora disponibili dai titoli della rubrica del quadro finanziario pluriennale relativa all’azione esterna dell’Unione ai titoli riguardanti gli aiuti erogati per situazioni di crisi e operazioni di aiuto umanitario.</p>\n</div>\n</div>\n</div>\n</div>"]]}, "31": {"label": "Articolo 31", "heading": "Proposte di storni sottoposte al Parlamento europeo e al Consiglio dalle istituzioni dell’Unione", "anchor": "art_31", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ogni istituzione dell’Unione presenta le sue proposte di storno contemporaneamente al Parlamento europeo e al Consiglio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La Commissione può proporre gli storni di stanziamenti di pagamento a favore dei fondi eseguiti in regime di gestione concorrente, tranne che per il FEAGA, al Parlamento europeo e al Consiglio entro il 10 gennaio dell’esercizio successivo. Gli storni di stanziamenti di pagamento possono essere effettuati a partire da qualsiasi voce del bilancio. In tali casi, il periodo di sei settimane di cui al paragrafo 4 è ridotto a tre settimane.</div>\n</div>"], [null, "<p class=\"norm\">Se il Parlamento europeo e il Consiglio non approvano, o approvano solo parzialmente, gli storni, la parte corrispondente delle spese di cui all’articolo 10, paragrafo 5, lettera b), è imputata agli stanziamenti di pagamento dell’esercizio successivo.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il Parlamento europeo e il Consiglio decidono gli storni di stanziamenti conformemente ai paragrafi da 4 a 8.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Salvo in casi urgenti, il Parlamento europeo e il Consiglio, deliberando quest’ultimo a maggioranza qualificata, si pronunciano su ciascuna proposta di storno entro sei settimane dalla sua ricezione da parte delle due istituzioni. In circostanze urgenti il Parlamento europeo e il Consiglio si pronunciano entro tre settimane dalla ricezione della proposta.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Quando intende procedere a storni di stanziamenti del FEAGA a norma del presente articolo, la Commissione presenta le proposte di storni al Parlamento europeo e al Consiglio entro il 10 gennaio dell’esercizio successivo. In tali casi il periodo di sei settimane di cui al paragrafo 4 è ridotto a tre settimane.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Una proposta di storno è approvata o considerata approvata se, entro il periodo di sei settimane, si verifica una delle situazioni seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il Parlamento europeo e il Consiglio approvano la proposta;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il Parlamento europeo o il Consiglio approva la proposta e l’altra istituzione si astiene dal deliberare;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">né il Parlamento europeo né il Consiglio adotta una decisione per modificare o respingere la proposta di storno.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Salvo richiesta contraria del Parlamento europeo o del Consiglio, il periodo di sei settimane di cui al paragrafo 4 è ridotto a tre settimane nei casi seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">lo storno rappresenta meno del 10 % degli stanziamenti della linea di bilancio da cui è effettuato e non supera i 5 000 000  EUR;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">lo storno riguarda unicamente stanziamenti di pagamento e il suo importo globale non supera i 100 000 000  EUR.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">Se il Parlamento europeo o il Consiglio ha modificato l’importo dello storno, mentre l’altra istituzione lo ha approvato o si è astenuta dal deliberare, oppure se il Parlamento europeo e il Consiglio hanno entrambi modificato l’importo dello storno, si considera approvato il minore dei due importi, a meno che l’istituzione dell’Unione interessata non ritiri la sua proposta di storno.</div>\n</div>"]]}, "32": {"label": "Articolo 32", "heading": "Storni oggetto di disposizioni particolari", "anchor": "art_32", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli stanziamenti corrispondenti a entrate con destinazione specifica possono essere oggetto di storno solo a condizione che tali entrate conservino la loro destinazione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Gli storni destinati a consentire l’impiego della riserva per gli aiuti d’urgenza sono decisi dal Parlamento europeo e dal Consiglio su proposta della Commissione.</div>\n</div>"], [null, "<p class=\"norm\">Ai fini del presente paragrafo si applica la procedura di cui all’articolo 31, paragrafi 3 e 4. Se il Parlamento europeo e il Consiglio non approvano la proposta della Commissione e se non si può raggiungere una posizione comune sull’impiego della riserva per gli aiuti d’urgenza, essi si astengono dal deliberare sul tale proposta.</p>"], [null, "<p class=\"norm inline-element\">Le proposte di storno dalla riserva per gli aiuti d’urgenza sono corredate di documenti giustificativi adeguati e dettagliati che presentino:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le informazioni più recenti disponibili sull’esecuzione degli stanziamenti e sulle previsioni del fabbisogno sino a fine esercizio per la linea di bilancio alla quale lo storno è destinato;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’esame delle possibilità di riassegnazione degli stanziamenti.</p>\n</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "33": {"label": "Articolo 33", "heading": "Performance e principi di economia, efficienza ed efficacia", "anchor": "art_33", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Gli stanziamenti sono utilizzati in conformità del principio della sana gestione finanziaria e sono pertanto eseguiti nel rispetto dei seguenti principi:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il principio dell’economia, in base al quale le risorse impiegate dall’istituzione dell’Unione interessata nella realizzazione delle proprie attività sono messe a disposizione in tempo utile, nella quantità e qualità appropriate e al prezzo migliore;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il principio dell’efficienza, in base al quale deve essere ricercato il miglior rapporto tra le risorse impiegate, le attività intraprese e il conseguimento degli obiettivi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il principio dell’efficacia, che determina in quale misura gli obiettivi perseguiti sono raggiunti mediante le attività intraprese.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Conformemente al principio della sana gestione finanziaria, l’esecuzione degli stanziamenti è orientata alla performance e a tale scopo:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli obiettivi dei programmi e delle attività sono stabiliti ex ante;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i progressi compiuti verso il conseguimento degli obiettivi sono verificati mediante indicatori di performance;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i progressi compiuti verso il conseguimento di obiettivi e i problemi riscontrati in questo contesto sono comunicati al Parlamento europeo e al Consiglio conformemente all’articolo 41, paragrafo 3, primo comma, lettera h), e all’articolo 247, paragrafo 1, lettera e).</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Sono stabiliti, laddove appropriato, obiettivi specifici, misurabili, attuabili, pertinenti e temporalmente definiti di cui ai paragrafi 1 e 2 e indicatori pertinenti, accettati, credibili, facili e solidi.</div>\n</div>"]]}, "34": {"label": "Articolo 34", "heading": "Valutazioni", "anchor": "art_34", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">I programmi e le attività che comportano spese importanti sono oggetto di una valutazione ex ante e di una valutazione retrospettiva, che sono proporzionate agli obiettivi e alla spesa.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le valutazioni ex ante che sostengono la preparazione dei programmi e delle attività si fondano su dati concreti sulla performance dei programmi o delle attività collegati e identificano e analizzano i problemi da affrontare, il valore aggiunto dell’intervento dell’Unione, gli obiettivi, gli effetti attesi delle diverse opzioni, nonché le modalità di vigilanza e valutazione.</div>\n</div>"], [null, "<p class=\"norm\">Per i programmi o le attività principali, che si prevede abbiano un impatto economico, ambientale o sociale significativo, la valutazione ex ante può assumere la forma di una valutazione d’impatto che, in aggiunta ai requisiti di cui al primo comma, analizza le diverse opzioni relative ai metodi di esecuzione.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Le valutazioni retrospettive analizzano la performance del programma o dell’attività, anche per quanto riguarda aspetti quali l’efficacia, l’efficienza, la coerenza, la pertinenza e il valore aggiunto dell’UE. Le valutazioni retrospettive sono basate sulle informazioni generate dalle modalità di sorveglianza e dagli indicatori stabiliti per l’azione interessata. Esse sono effettuate almeno una volta nella durata di ogni quadro finanziario pluriennale e, se possibile, in tempo utile affinché si possa tenere conto delle relative conclusioni nelle valutazioni ex ante o nelle valutazioni d’impatto che sostengono la preparazione dei programmi e delle attività collegati.</div>\n</div>"]]}, "35": {"label": "Articolo 35", "heading": "Scheda finanziaria obbligatoria", "anchor": "art_35", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le proposte o iniziative presentate all’autorità legislativa dalla Commissione, dall’alto rappresentante dell’Unione per gli affari esteri e la politica di sicurezza («alto rappresentante») o da uno Stato membro, che possano avere un’incidenza sul bilancio, compresa un’incidenza sul numero dei posti, sono corredate di una scheda finanziaria che illustra le stime in termini di i stanziamenti di pagamento e di impegno, di una valutazione delle varie opzioni di finanziamento disponibili, nonché della valutazione ex ante o della valutazione d’impatto di cui all’articolo 34.</div>\n</div>"], [null, "<p class=\"norm\">Le modifiche a una proposta o iniziativa presentate all’autorità legislativa che possano avere un’incidenza rilevante sul bilancio, compresa un’incidenza sul numero dei posti, sono corredate di una scheda finanziaria preparata dall’istituzione dell’Unione che propone la modifica.</p>"], [null, "<p class=\"norm\">La scheda finanziaria contiene gli elementi finanziari ed economici necessari alla valutazione da parte dell’autorità legislativa della necessità di un intervento dell’Unione. Essa fornisce informazioni utili sulla coerenza e sull’eventuale sinergia con altre attività dell’Unione.</p>"], [null, "<p class=\"norm\">Quando si tratta di azioni pluriennali, la scheda finanziaria comporta lo scadenzario prevedibile dei fabbisogni annuali di stanziamenti di impegno e di pagamento e di personale, compreso il personale esterno, e una valutazione della loro incidenza sul piano finanziario a medio e, se possibile, a lungo termine.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Nel corso della procedura di bilancio la Commissione fornisce tutte le informazioni necessarie per un raffronto tra l’evoluzione del fabbisogno di stanziamenti e le previsioni iniziali riportate nella scheda finanziaria in funzione dello stato di avanzamento dei lavori sulla proposta o sull’iniziativa presentata all’autorità legislativa.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Al fine di ridurre i rischi di frode, irregolarità e mancato conseguimento degli obiettivi, la scheda finanziaria riporta informazioni sul sistema di controllo interno istituito, una stima dei costi e dei benefici dei controlli che tale sistema comporta e una valutazione del livello di rischio di errore previsto, nonché informazioni sulle misure di prevenzione e di tutela esistenti e previste nei confronti delle frodi.</div>\n</div>"], [null, "<p class=\"norm\">Tale valutazione tiene conto della probabile portata e tipologia degli errori, nonché delle particolari condizioni del settore interessato e delle norme a esso applicabili.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">All’atto della presentazione di proposte di spesa riviste o nuove, la Commissione stima i costi e i benefici dei sistemi di controllo, nonché il livello di rischio di errore atteso di cui al paragrafo 3.</div>\n</div>"]]}, "36": {"label": "Articolo 36", "heading": "Controllo interno dell’esecuzione del bilancio", "anchor": "art_36", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Conformemente al principio della sana gestione finanziaria, il bilancio è eseguito secondo il principio del controllo interno efficace ed efficiente, adeguato a ogni metodo di esecuzione, e in conformità della normativa settoriale pertinente.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Ai fini dell’esecuzione del bilancio, il controllo interno si applica a tutti i livelli di gestione ed è destinato a fornire ragionevoli garanzie quanto al conseguimento dei seguenti obiettivi:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">efficacia, efficienza ed economia delle operazioni;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">affidabilità delle relazioni;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">salvaguardia degli attivi e informazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">prevenzione, individuazione e rettifica di frodi e irregolarità e seguito dato a tali frodi e irregolarità;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">adeguata gestione dei rischi connessi alla legittimità e regolarità delle operazioni sottostanti, tenendo conto del carattere pluriennale dei programmi, nonché della natura dei pagamenti in questione.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Un controllo interno efficace si basa sulle migliori prassi internazionali e include, in particolare, i seguenti elementi:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">separazione dei compiti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un’adeguata strategia di gestione e controllo dei rischi, che comprenda i controlli presso i destinatari;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">prevenzione dei conflitti d’interessi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">adeguate piste di controllo e integrità dei dati nei sistemi informatici;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">procedure per la vigilanza sull’efficacia e sull’efficienza;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">procedure per dare seguito alle inadeguatezze e lacune individuate nei controlli interni;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">valutazione periodica del valido funzionamento del sistema di controllo interno.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Un controllo interno efficiente si basa sugli elementi seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">attuazione di un’adeguata strategia di gestione e controllo dei rischi, coordinata tra le persone addette alle varie fasi del controllo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">accessibilità per tutte le persone addette alle varie fasi del controllo ai risultati dei controlli svolti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">ricorso, se del caso, alle dichiarazioni di gestione redatte dai partner di esecuzione e a pareri indipendenti sull’audit, a condizione che la qualità del lavoro sottostante sia adeguata e accettabile e che esso sia stato svolto conformemente alle norme convenute;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">applicazione tempestiva di misure correttive, comprese, ove opportuno, sanzioni dissuasive;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">legislazione chiara e inequivocabile a fondamento degli interventi interessati, compresi atti di base a fondamento degli elementi del controllo interno;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">eliminazione di controlli multipli;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">miglioramento del rapporto costi-benefici dei controlli.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Se, durante l’esecuzione, il livello di errore è persistentemente elevato, la Commissione identifica le lacune nei sistemi di controllo, analizza i costi e i benefici delle possibili misure correttive e adotta o propone i provvedimenti adeguati, quali la semplificazione delle disposizioni applicabili, il rafforzamento dei sistemi di controllo e la riprogettazione del programma o dei sistemi di attuazione.</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "37": {"label": "Articolo 37", "heading": "Pubblicazione dei conti e dei bilanci", "anchor": "art_37", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il bilancio è formato, eseguito ed è oggetto di rendiconto conformemente al principio della trasparenza.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il bilancio e i bilanci rettificativi definitivamente adottati sono pubblicati nella <span class=\"italics\">Gazzetta ufficiale dell’Unione europea</span> a cura del presidente del Parlamento europeo.</div>\n</div>"], [null, "<p class=\"norm\">La pubblicazione avviene entro tre mesi dalla data della constatazione dell’adozione definitiva dei bilanci.</p>"], [null, "<p class=\"norm\">In attesa della pubblicazione ufficiale nella <span class=\"italics\">Gazzetta ufficiale dell’Unione europea</span> i dati particolareggiati definitivi del bilancio sono pubblicati in tutte le lingue sul sito web delle istituzioni dell’Unione, su iniziativa della Commissione, non appena possibile e comunque entro quattro settimane dall’adozione definitiva del bilancio.</p>"], [null, "<p class=\"norm\">I conti annuali consolidati sono pubblicati nella <span class=\"italics\">Gazzetta ufficiale dell’Unione europea</span>, e sul sito web delle istituzioni dell’Unione.</p>"]]}, "38": {"label": "Articolo 38", "heading": "Pubblicazione di informazioni sui destinatari e di altre informazioni", "anchor": "art_38", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La Commissione mette a disposizione, nella forma appropriata e in modo tempestivo, le informazioni sui destinatari dei fondi finanziati a titolo del bilancio, laddove quest’ultimo sia eseguito dai propri servizi conformemente all’articolo 62, paragrafo 1, primo comma, lettera a).</div>\n</div>"], [null, "<p class=\"norm\">Il primo comma del presente paragrafo si applica anche alle altre istituzioni dell’Unione quando eseguono il bilancio a norma dell’articolo 59, paragrafo 1.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Salvo nei casi di cui ai paragrafi 3 e 4, le seguenti informazioni sono pubblicate nel debito rispetto dei requisiti in materia di riservatezza e di sicurezza, in particolare per quanto riguarda la tutela dei dati personali:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nominativo del destinatario;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">ubicazione del destinatario, vale a dire:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’indirizzo del destinatario, se questi è una persona giuridica;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la regione a livello NUTS 2, se il destinatario è una persona fisica;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">importo giuridicamente impegnato;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">natura e finalità della misura.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Le informazioni di cui al primo comma del presente paragrafo sono pubblicate solo in relazione a premi, sovvenzioni e contratti attribuiti in esito a concorsi, procedure di attribuzione di sovvenzioni o procedure di aggiudicazione di appalti e agli esperti selezionati a norma dell’articolo 237, paragrafo 2.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Le informazioni di cui al paragrafo 2, primo comma, non sono pubblicate in relazione a:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">aiuti corrisposti a persone fisiche a fini di istruzione e altri aiuti diretti corrisposti alle persone fisiche estremamente bisognose di cui all’articolo 191, paragrafo 4, lettera b);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">contratti di valore molto modesto aggiudicati a esperti selezionati a norma dell’articolo 237, paragrafo 2, nonché contratti di valore molto modesto al di sotto dell’importo di cui al punto 14.4 dell’allegato I;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sostegno finanziario fornito mediante strumenti finanziari per un importo inferiore a 500 000  EUR;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">quando la divulgazione rischia di minare i diritti e le libertà di persone o entità interessate tutelati dalla Carta dei diritti fondamentali dell’Unione europea o di ledere gli interessi commerciali dei destinatari.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Nei casi di cui al primo comma, lettera c), le informazioni messe a disposizione sono limitate ai dati statistici, aggregati secondo criteri pertinenti come la posizione geografica, la tipologia economica dei destinatari, il tipo di sostegno ricevuto e il settore d’intervento dell’Unione nell’ambito del quale è stato fornito il sostegno.</p>"], [null, "<p class=\"norm\">Qualora si tratti di persone fisiche, la divulgazione delle informazioni di cui al paragrafo 2, primo comma, si basa su criteri pertinenti quali la frequenza ovvero la natura della misura e gli importi in questione.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Le persone o le entità che eseguono fondi dell’Unione ai sensi dell’articolo 62, paragrafo 1, primo comma, lettera c), pubblicano le informazioni sui destinatari conformemente alle loro norme e secondo le loro procedure, nella misura in cui tali norme sono ritenute equivalenti in seguito alla verifica effettuata dalla Commissione a norma dell’articolo 154, paragrafo 4, primo comma, lettera e), e a condizione che la pubblicazione di dati personali sia soggetta a salvaguardie equivalenti a quelle stabilite nel presente articolo.</div>\n</div>"], [null, "<p class=\"norm\">Gli organismi designati a norma dell’articolo 63, paragrafo 3, pubblicano le informazioni in conformità della normativa settoriale. Tale normativa settoriale può, conformemente alla base giuridica pertinente, derogare ai paragrafi 2 e 3 del presente articolo, in particolare per quanto riguarda la pubblicazione di dati personali, se ciò è giustificato sulla base dei criteri di cui al paragrafo 3, terzo comma, del presente articolo, e tenendo conto delle specificità del settore interessato.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Le informazioni di cui al paragrafo 1 sono pubblicate sui siti web delle istituzioni dell’Unione non oltre il 30 giugno successivo all’esercizio in cui i fondi sono stati giuridicamente impegnati.</div>\n</div>"], [null, "<p class=\"norm\">Se le informazioni di cui al paragrafo 1 non sono pubblicate direttamente sui siti web delle istituzioni dell’Unione, tale sito contiene il riferimento all’indirizzo del sito web dove queste sono reperibili.</p>"], [null, "<p class=\"norm\">La Commissione mette a disposizione, nella forma appropriata e in modo tempestivo, le informazioni su un singolo sito web, che comprende un riferimento al suo indirizzo, dove sono reperibili le informazioni fornite dalle persone, dalle entità o dagli organismi di cui al paragrafo 4.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Qualora siano pubblicati dati personali, le informazioni sono soppresse due anni dopo la fine dell’esercizio in cui i fondi sono stati giuridicamente impegnati. Ciò vale anche per i dati personali relativi a persone giuridiche il cui nome ufficiale individua una o più persone fisiche.</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "39": {"label": "Articolo 39", "heading": "Stati di previsione delle entrate e delle spese", "anchor": "art_39", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ogni istituzione dell’Unione diversa dalla Commissione redige uno stato di previsione delle sue entrate e delle sue spese, che trasmette alla Commissione e, in parallelo, a titolo informativo, al Parlamento europeo e al Consiglio, anteriormente al 1<span class=\"superscript\">o</span> luglio di ogni anno.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L’alto rappresentante consulta i membri della Commissione responsabili per la politica di sviluppo, la politica di vicinato, la cooperazione internazionale, gli aiuti umanitari e la risposta alle crisi, relativamente ai loro rispettivi ambiti di competenza.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La Commissione redige il proprio stato di previsione che trasmette, subito dopo la sua adozione, al Parlamento europeo e al Consiglio. Nella preparazione del proprio stato di previsione la Commissione utilizza le informazioni indicate all’articolo 40.</div>\n</div>"]]}, "40": {"label": "Articolo 40", "heading": "Bilancio di previsione degli organismi dell’Unione di cui all’Articolo 70", "anchor": "art_40", "frags": [[null, "<p class=\"norm\">Entro il 31 gennaio di ogni anno ciascun organismo dell’Unione di cui all’articolo 70 trasmette, conformemente allo strumento che l’ha istituito, alla Commissione, al Parlamento europeo e al Consiglio il suo progetto di documento unico di programmazione contenente la sua programmazione annuale e pluriennale con la corrispondente pianificazione relativa alle risorse umane e finanziarie.</p>"]]}, "41": {"label": "Articolo 41", "heading": "Progetto di bilancio", "anchor": "art_41", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Entro il 1<span class=\"superscript\">o</span> settembre dell’anno precedente quello dell’esecuzione del bilancio la Commissione presenta al Parlamento europeo e al Consiglio una proposta contenente il progetto di bilancio. Essa trasmette tale proposta, a titolo informativo, ai parlamenti nazionali.</div>\n</div>"], [null, "<p class=\"norm\">Il progetto di bilancio presenta uno stato generale riassuntivo delle entrate e delle spese dell’Unione e raggruppa gli stati di previsione di cui all’articolo 39. Esso può anche contenere previsioni divergenti da quelle elaborate dalle istituzioni dell’Unione.</p>"], [null, "<p class=\"norm\">Il progetto di bilancio rispetta la struttura e la presentazione stabilite agli articoli da 47 a 52.</p>"], [null, "<p class=\"norm\">Ciascuna sezione del progetto di bilancio è preceduta da un’introduzione redatta dall’istituzione dell’Unione interessata.</p>"], [null, "<p class=\"norm\">La Commissione redige l’introduzione generale al progetto di bilancio. L’introduzione generale comprende tabelle finanziarie che riportano i dati principali per titoli e le motivazioni delle variazioni negli stanziamenti da un esercizio all’altro per categorie di spesa del quadro finanziario pluriennale.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Per fornire previsioni più precise e affidabili riguardo alle implicazioni di bilancio degli atti legislativi in vigore e delle proposte legislative in fase di adozione, la Commissione acclude al progetto di bilancio una programmazione finanziaria indicativa per gli esercizi successivi, articolata per categoria di spesa, settore e linea di bilancio. La programmazione finanziaria complessiva copre le categorie di spesa contemplate dal punto 30 dell’accordo interistituzionale, del 2 dicembre 2013, tra il Parlamento europeo, il Consiglio e la Commissione sulla disciplina di bilancio, sulla cooperazione in materia di bilancio e sulla sana gestione finanziaria (\n<span class=\"superscript\">6</span>\n). Per le categorie di spesa non contemplate dal punto 30 di detto accordo interistituzionale sono forniti dati sintetici.</div>\n</div>"], [null, "<p class=\"norm\">La programmazione finanziaria indicativa è aggiornata dopo l’adozione del bilancio, al fine di incorporare i risultati della procedura di bilancio ed eventuali altre decisioni pertinenti.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La Commissione acclude al progetto di bilancio:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una tabella comparativa contenente il progetto di bilancio per le altre istituzioni dell’Unione e gli stati di previsione originari delle altre istituzioni dell’Unione così come inviati alla Commissione e, se del caso, una spiegazione dei motivi per i quali il progetto di bilancio contiene previsioni divergenti da quelle elaborate dalle altre istituzioni dell’Unione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">qualsiasi documento di lavoro ritenuto utile in relazione alle tabelle dell’organico delle istituzioni dell’Unione, che contenga l’ultima tabella dell’organico approvata e presenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">tutto il personale impiegato dall’Unione, ripartito per tipo di contratto di lavoro;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una dichiarazione sulla politica relativa agli effettivi, al personale esterno e all’equilibrio di genere;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il numero di posti effettivamente coperti l’ultimo giorno dell’anno precedente quello in cui è presentato il progetto di bilancio, nonché la media annuale di equivalenti a tempo pieno effettivamente coperti per detto anno precedente, con indicazione della ripartizione per grado, per genere e per unità amministrativa;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iv) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una ripartizione dei posti per settore;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>v) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per ogni categoria di personale esterno, il numero iniziale stimato di equivalenti a tempo pieno in base agli stanziamenti autorizzati e il numero di persone effettivamente in servizio all’inizio dell’anno in cui è presentato il progetto di bilancio, con indicazione della ripartizione per gruppo di funzioni e, se del caso, per grado;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per gli organismi dell’Unione di cui agli articoli 70 e 71, un documento di lavoro che presenti le entrate e le spese, nonché tutte le informazioni relative al personale di cui alla lettera b) del presente comma;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un documento di lavoro sull’esecuzione degli stanziamenti prevista per l’esercizio e sugli impegni da liquidare;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per quanto riguarda gli stanziamenti per l’amministrazione, un documento di lavoro che presenti le spese amministrative che la Commissione deve eseguire nell’ambito della sua sezione del bilancio;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un documento di lavoro sui progetti pilota e le azioni preparatorie, in cui si valutino altresì i risultati ottenuti e si stabilisca l’eventuale seguito;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per quanto riguarda i finanziamenti a favore delle organizzazioni internazionali, un documento di lavoro contenente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un riepilogo di tutti i contributi, ripartiti per ciascun programma o fondo dell’Unione e per ciascuna organizzazione internazionale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una spiegazione dei motivi per cui è più efficiente per l’Unione finanziare le organizzazioni internazionali, anziché intervenire direttamente;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dichiarazioni programmatiche o qualsiasi altro documento pertinente contenente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un’indicazione delle politiche e degli obiettivi dell’Unione cui il programma contribuisce;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una chiara motivazione dell’intervento a livello dell’Unione, in conformità, tra l’altro, del principio di sussidiarietà;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i progressi nel conseguimento degli obiettivi del programma, come specificato all’articolo 33;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iv) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una giustificazione esauriente, compresa un’analisi costi-benefici, per le modifiche proposte in relazione al livello degli stanziamenti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>v) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">informazioni sui tassi di esecuzione del programma per l’esercizio in corso e per quello precedente;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">uno stato riepilogativo delle scadenze dei pagamenti, che riepiloghi per programma e per rubrica i pagamenti da effettuare nel corso degli esercizi successivi in base agli impegni di bilancio proposti nel progetto di bilancio e assunti nel corso di esercizi precedenti.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Quando i partenariati pubblico-privato ricorrono a strumenti finanziari, le informazioni relative a tali strumenti sono incluse nel documento di lavoro di cui al paragrafo 4.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Quando ricorre a strumenti finanziari, la Commissione acclude al progetto di bilancio un documento di lavoro che presenta, per ciascuno strumento finanziario, quanto segue:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un riferimento allo strumento finanziario e al relativo atto di base, unitamente a una descrizione generale dello strumento, della sua incidenza sul bilancio, della sua durata e del valore aggiunto del contributo dell’Unione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le istituzioni finanziarie coinvolte nell’esecuzione, comprese le questioni relative all’applicazione dell’articolo 155, paragrafo 2;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il contributo dello strumento finanziario al conseguimento degli obiettivi del programma in questione misurato mediante gli indicatori stabiliti, compresa, se del caso, la diversificazione geografica;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le operazioni previste, compresi i volumi obiettivo basati sull’effetto leva obiettivo e il capitale privato che si prevede di mobilitare o, se non disponibile, sull’indice di leva finanziaria risultante dagli strumenti finanziari esistenti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le linee di bilancio corrispondenti alle operazioni in questione e gli impegni e i pagamenti aggregati a titolo del bilancio;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il periodo medio che intercorre tra l’impegno di bilancio relativo agli strumenti finanziari e gli impegni giuridici per i singoli progetti sotto forma di uno strumento di capitale o di debito, quando tale periodo è superiore a tre anni;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i ricavi e i rimborsi di cui all’articolo 209, paragrafo 3, presentati separatamente, compresa una valutazione del loro utilizzo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il valore degli investimenti azionari rispetto agli anni precedenti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’importo totale degli accantonamenti per rischi e oneri, nonché eventuali informazioni sull’esposizione dell’Unione a rischi finanziari, incluse le passività potenziali;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>j) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le riduzioni durevoli di valore delle attività e le garanzie attivate, sia per quanto riguarda l’esercizio precedente che per quanto attiene ai rispettivi dati cumulativi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>k) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la performance dello strumento finanziario, compresi gli investimenti realizzati, l’effetto leva obiettivo e quello conseguito e l’effetto moltiplicatore, nonché l’importo del capitale privato mobilitato;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>l) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le risorse accantonate nel fondo comune di copertura e, se del caso, il saldo del conto fiduciario.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Il documento di lavoro di cui al primo comma contiene anche un prospetto delle spese amministrative derivanti da commissioni di gestione e da altri oneri finanziari e di funzionamento pagati per la gestione degli strumenti finanziari, in totale e per gestore e strumento finanziario gestito.</p>"], [null, "<p class=\"norm\">La Commissione illustra i motivi del periodo di cui al primo comma, lettera f), e se del caso presenta un piano d’azione per la riduzione di tale periodo nell’ambito della proceduta di discarico annuale.</p>"], [null, "<p class=\"norm\">Il documento di lavoro di cui al primo comma riassume in una tabella chiara e concisa le informazioni per strumento finanziario.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Se l’Unione ha concesso una garanzia di bilancio, la Commissione acclude al progetto di bilancio un documento di lavoro che presenta, per ciascuna garanzia di bilancio e per il fondo comune di copertura, quanto segue:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un riferimento alla garanzia di bilancio e al relativo atto di base, unitamente a una descrizione generale della garanzia di bilancio, della sua incidenza sulle passività finanziarie del bilancio, della sua durata e del valore aggiunto del sostegno dell’Unione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le controparti della garanzia di bilancio, comprese le questioni relative all’applicazione dell’articolo 155, paragrafo 2;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il contributo della garanzia di bilancio al conseguimento degli obiettivi della garanzia di bilancio, misurato mediante gli indicatori stabiliti, compresa, se del caso, la diversificazione geografica e la mobilizzazione di risorse del settore privato;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">informazioni sulle operazioni coperte dalla garanzia di bilancio aggregate per settore, paese e strumenti, compresi, se del caso, i portafogli e il sostegno combinato con altre azioni dell’Unione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’importo corrisposto ai beneficiari, nonché una valutazione dell’effetto leva conseguito dai progetti sostenuti a titolo della garanzia di bilancio;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">informazioni aggregate sulla stessa base di cui alla lettera d) riguardanti l’attivazione della garanzia di bilancio, le perdite, gli utili, gli importi recuperati e gli eventuali altri pagamenti ricevuti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">informazioni sulla gestione finanziaria, la performance e il rischio del fondo comune di copertura alla fine del precedente anno civile;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il tasso di copertura effettivo del fondo comune di copertura e, se del caso, le successive operazioni in conformità dell’articolo 213, paragrafo 4;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i flussi finanziari nel fondo comune di copertura nel corso dell’esercizio precedente, nonché le transazioni significative e ogni informazione pertinente sull’esposizione dell’Unione a rischi finanziari;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>j) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">a norma dell’articolo 210, paragrafo 3, una valutazione della sostenibilità delle passività potenziali a carico del bilancio derivanti dalle garanzie di bilancio o dall’assistenza finanziaria.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Quando ricorre ai fondi fiduciari dell’Unione per azioni esterne, la Commissione acclude al progetto di bilancio un documento di lavoro dettagliato sulle attività sostenute da tali fondi fiduciari, che presenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la loro attuazione, contenente tra l’altro le informazioni sulle modalità di sorveglianza definite con le entità che eseguono i fondi fiduciari;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i loro costi di gestione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i contributi di donatori diversi da quelli dell’Unione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una valutazione preliminare della loro performance sulla base delle condizioni di cui all’articolo 234, paragrafo 3;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una descrizione del modo in cui le loro attività hanno contribuito al conseguimento degli obiettivi stabiliti nell’atto di base dello strumento da cui è stato fornito il contributo dell’Unione ai fondi fiduciari.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">La Commissione acclude al progetto di bilancio un elenco delle sue decisioni che irrogano ammende nel settore del diritto della concorrenza e l’importo di ciascuna ammenda irrogata, unitamente all’informazione se le ammende sono divenute definitive o se esse sono o potrebbero diventare oggetto di un ricorso dinanzi alla Corte di giustizia dell’Unione europea, nonché, ove possibile, informazioni relative a quando si prevede che ciascuna ammenda divenga definitiva.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La Commissione acclude al progetto di bilancio un documento di lavoro che indica, per ogni linea di bilancio che riceve entrate con destinazione specifica interne o esterne:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’importo stimato delle entrate che si prevede di ricevere;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’importo stimato di tali entrate riportate dagli esercizi precedenti.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">9.  </span>\n<div class=\"norm inline-element\">La Commissione acclude inoltre al progetto di bilancio qualsiasi documento di lavoro aggiuntivo ritenuto utile al Parlamento europeo e al Consiglio per valutare le richieste di bilancio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">10.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">A norma dell’articolo 8, paragrafo 5, della decisione 2010/427/UE del Consiglio (\n<span class=\"superscript\">7</span>\n), la Commissione trasmette al Parlamento europeo e al Consiglio, unitamente al progetto di bilancio, un documento di lavoro che presenta in modo completo:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">tutte le spese amministrative e operative connesse alle azioni esterne dell’Unione, comprese le missioni PESC e di politica di sicurezza e di difesa comune, che siano finanziate a titolo del bilancio;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la spesa amministrativa globale del SEAE a titolo dell’esercizio precedente, ripartita tra spesa per ciascuna delegazione dell’Unione e spesa per l’amministrazione centrale del SEAE; unitamente alle spese operative, ripartite per zona geografica (regioni, paesi), area tematica, delegazioni e missioni dell’Unione.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">11.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Inoltre, il documento di lavoro di cui al paragrafo 10:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">evidenzia il numero dei posti per grado in ciascuna categoria e il numero dei posti permanenti e temporanei, compreso il personale contrattuale e locale di cui è autorizzata la presa a carico nei limiti degli stanziamenti in ciascuna delegazione dell’Unione e presso l’amministrazione centrale del SEAE;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">indica ogni aumento o riduzione, rispetto all’esercizio precedente, del numero di posti per grado e categoria presso l’amministrazione centrale del SEAE e in tutte le delegazioni dell’Unione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">indica il numero dei posti autorizzati a titolo dell’esercizio e dell’esercizio precedente, nonché il numero dei posti occupati da personale distaccato dai servizi diplomatici degli Stati membri e da funzionari dell’Unione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">fornisce un quadro dettagliato di tutto il personale presente presso delegazioni dell’Unione al momento della presentazione del progetto di bilancio, tra cui una ripartizione per zona geografica, genere, paese e missione, distinguendo tra posti nella tabella dell’organico, agenti contrattuali, agenti locali ed esperti nazionali distaccati, e gli stanziamenti richiesti nel progetto di bilancio per tali categorie di personale, con la relativa stima del numero degli equivalenti a tempo pieno sulla base degli stanziamenti richiesti.</p>\n</div>\n</div>\n</div>\n</div>"]]}, "42": {"label": "Articolo 42", "heading": "Lettera rettificativa del progetto di bilancio", "anchor": "art_42", "frags": [[null, "<p class=\"norm\">Sulla base di qualsiasi nuovo elemento non ancora noto al momento della stesura del progetto di bilancio, la Commissione, di propria iniziativa o su richiesta di un’altra istituzione dell’Unione per quanto concerne la rispettiva sezione, può presentare simultaneamente al Parlamento europeo e al Consiglio una o più lettere rettificative del progetto di bilancio prima della convocazione del comitato di conciliazione di cui all’articolo 314 TFUE. Tali lettere possono comprendere una lettera rettificativa che aggiorna, in particolare, gli stati di previsione della spesa agricola.</p>"]]}, "43": {"label": "Articolo 43", "heading": "Obblighi degli Stati membri risultanti dall’adozione del bilancio", "anchor": "art_43", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il presidente del Parlamento europeo constata che il bilancio è definitivamente adottato secondo la procedura di cui all’articolo 314, paragrafo 9, TFUE e all’articolo 106 <span class=\"italics\">bis</span> del trattato Euratom.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La constatazione dell’adozione definitiva del bilancio comporta, a decorrere dal 1<span class=\"superscript\">o</span> gennaio dell’esercizio successivo, o dalla data della constatazione dell’adozione definitiva del bilancio, se questa è posteriore al 1<span class=\"superscript\">o</span> gennaio, l’obbligo per ciascuno Stato membro di versare all’Unione gli importi dovuti, come specificato nel regolamento (UE, Euratom) n. 609/2014.</div>\n</div>"]]}, "44": {"label": "Articolo 44", "heading": "Progetti di bilancio rettificativo", "anchor": "art_44", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La Commissione può presentare progetti di bilancio rettificativo principalmente basati sulle entrate nelle circostanze seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per iscrivere nel bilancio il saldo dell’esercizio precedente, secondo la procedura di cui all’articolo 18;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per rivedere le previsioni relative alle risorse proprie sulla base di previsioni economiche aggiornate;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per aggiornare le previsioni riviste relative alle risorse proprie e ad altre entrate, come anche per riesaminare la disponibilità il fabbisogno di stanziamenti di pagamento.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">In caso di circostanze inevitabili, eccezionali e impreviste, in particolare in vista della mobilitazione del Fondo di solidarietà dell’Unione europea, la Commissione può presentare progetti di bilancio rettificativo che sono principalmente basati sulle spese.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le richieste di bilancio rettificativo avanzate nelle stesse circostanze di cui al paragrafo 1 dalle istituzioni dell’Unione diverse dalla Commissione sono trasmesse a quest’ultima.</div>\n</div>"], [null, "<p class=\"norm\">Prima di presentare un progetto di bilancio rettificativo, la Commissione e le altre istituzioni dell’Unione interessate esaminano la possibilità di una riassegnazione degli stanziamenti interessati, con particolare riferimento alle previste sottoesecuzioni degli stanziamenti.</p>"], [null, "<p class=\"norm\">L’articolo 43 si applica ai bilanci rettificativi. I bilanci rettificativi sono giustificati con riferimento al bilancio di cui modificano le previsioni.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Salvo in caso di circostanze eccezionali debitamente motivate o di mobilitazione del fondo di solidarietà dell’Unione europea, per cui un progetto di bilancio rettificativo può essere presentato in un momento qualsiasi dell’anno, la Commissione presenta simultaneamente al Parlamento europeo e al Consiglio i propri progetti di bilancio rettificativo entro il 1<span class=\"superscript\">o</span> settembre di ogni esercizio. Essa può accludere un parere alle richieste di bilancio rettificativo delle altre istituzioni dell’Unione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">I progetti di bilancio rettificativo sono accompagnati da motivazioni e da informazioni sull’esecuzione di bilancio dell’esercizio precedente e dell’esercizio in corso disponibili al momento della loro formazione.</div>\n</div>"]]}, "45": {"label": "Articolo 45", "heading": "Trasmissione anticipata degli stati di previsione e del progetto di bilancio", "anchor": "art_45", "frags": [[null, "<p class=\"norm\">La Commissione, il Parlamento europeo e il Consiglio possono convenire di anticipare talune date relative alla trasmissione degli stati di previsione e all’adozione e alla trasmissione del progetto di bilancio. Tale intesa non determina, tuttavia, una riduzione o un’estensione dei periodi previsti per l’esame di tali testi a norma dell’articolo 314 TFUE e dell’articolo 106 <span class=\"italics\">bis</span> del trattato Euratom.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "46": {"label": "Articolo 46", "heading": "Struttura del bilancio", "anchor": "art_46", "frags": [[null, "<p class=\"norm\">Il bilancio presenta la struttura seguente:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">uno stato generale delle entrate e delle spese;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sezioni distinte per ciascuna istituzione dell’Unione, a eccezione del Consiglio europeo e del Consiglio, che rientrano nella stessa sezione del bilancio, divise in stati delle entrate e delle spese.</p>\n</div>\n</div>"]]}, "47": {"label": "Articolo 47", "heading": "Nomenclatura di bilancio", "anchor": "art_47", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le entrate della Commissione nonché le entrate e le spese delle altre istituzioni dell’Unione sono classificate dal Parlamento europeo e dal Consiglio in titoli, capitoli, articoli e voci, secondo la loro natura o la loro destinazione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Lo stato delle spese della sezione del bilancio relativa alla Commissione è presentato secondo una nomenclatura adottata dal Parlamento europeo e dal Consiglio e che comporta una classificazione per finalità di spesa.</div>\n</div>"], [null, "<p class=\"norm\">Ciascun titolo corrisponde a un settore d’intervento e ciascun capitolo corrisponde, di norma, a un programma o a un’attività.</p>"], [null, "<p class=\"norm\">Ciascun titolo può includere stanziamenti operativi e stanziamenti amministrativi. All’interno di ciascun titolo, gli stanziamenti amministrativi sono raggruppati in un unico capitolo.</p>"], [null, "<p class=\"norm\">La nomenclatura di bilancio rispetta i principi della specializzazione, della sana gestione finanziaria e della trasparenza. Essa apporta la chiarezza e la trasparenza necessarie per la procedura di bilancio, agevolando l’individuazione degli obiettivi principali rispecchiati nelle pertinenti basi giuridiche, rendendo possibili le scelte delle priorità politiche e consentendo un’esecuzione efficiente ed efficace.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La Commissione può chiedere l’aggiunta di una menzione «per memoria» a una linea di bilancio priva di stanziamenti autorizzati. Tale richiesta è approvata secondo la procedura di cui all’articolo 31.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Quando sono presentati per destinazione, gli stanziamenti amministrativi per singoli titoli sono classificati come segue:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">spese relative al personale autorizzato dalla tabella dell’organico, che comprendono un importo di stanziamenti e un numero di posti in detta tabella dell’organico corrispondenti a tali spese;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">spese relative al personale esterno e altre spese di cui all’articolo 30, paragrafo 1, primo comma, lettera b), finanziate a titolo della rubrica «amministrazione» del quadro finanziario pluriennale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">spese relative agli immobili e altre spese connesse, comprese la pulizia e la manutenzione, le locazioni e gli affitti, le telecomunicazioni, l’acqua, il gas e l’energia elettrica;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">spese relative al personale esterno e all’assistenza tecnica direttamente legati all’attuazione dei programmi.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Tutte le spese amministrative della Commissione la cui natura è comune a più titoli sono riprese in uno stato riassuntivo distinto, secondo una classificazione per natura.</p>"]]}, "48": {"label": "Articolo 48", "heading": "Entrate negative", "anchor": "art_48", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il bilancio non contiene entrate negative, salvo che queste derivino dalla remunerazione negativa dei depositi in totale.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le risorse proprie riscosse in applicazione della decisione 2014/335/UE, Euratom sono importi netti e sono presentate come tali nello stato riassuntivo delle entrate del bilancio.</div>\n</div>"]]}, "49": {"label": "Articolo 49", "heading": "Stanziamenti accantonati", "anchor": "art_49", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Ogni sezione del bilancio può includere un titolo «stanziamenti accantonati». Gli stanziamenti sono iscritti in tale titolo nei seguenti casi:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">al momento della formazione del bilancio non esiste un atto di base per l’azione interessata; oppure</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">vi è incertezza, sulla base di seri motivi, quanto alla sufficienza degli stanziamenti o alla possibilità di eseguire, in condizioni conformi al principio della sana gestione finanziaria, gli stanziamenti iscritti alle linee di bilancio interessate.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Gli stanziamenti di tale titolo possono essere utilizzati soltanto previ storni effettuati secondo la procedura di cui all’articolo 30, paragrafo 1, primo comma, lettera c), del presente regolamento, nei casi in cui l’adozione dell’atto di base è soggetta alla procedura di cui all’articolo 294 TFUE, e secondo la procedura di cui all’articolo 31 del presente regolamento, in tutti gli altri casi.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">In caso di gravi difficoltà di esecuzione, la Commissione può, nel corso dell’esercizio, proporre uno storno di stanziamenti verso il titolo «stanziamenti accantonati». Il Parlamento europeo e il Consiglio decidono in merito a tali storni conformemente all’articolo 31.</div>\n</div>"]]}, "50": {"label": "Articolo 50", "heading": "Riserva negativa", "anchor": "art_50", "frags": [[null, "<p class=\"norm\">La sezione del bilancio relativa alla Commissione può includere una «riserva negativa», il cui importo massimo è limitato a 200 000 000  EUR. Tale riserva, che è iscritta in un titolo specifico, comprende unicamente stanziamenti di pagamento.</p>"], [null, "<p class=\"norm\">Tale riserva negativa è utilizzata entro la fine dell’esercizio, mediante storni, secondo la procedura di cui agli articoli 30 e 31.</p>"]]}, "51": {"label": "Articolo 51", "heading": "Riserva per gli aiuti d’urgenza", "anchor": "art_51", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La sezione del bilancio relativa alla Commissione comporta una riserva per gli aiuti d’urgenza a favore di paesi terzi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La riserva di cui al paragrafo 1 è utilizzata entro la fine dell’esercizio, mediante storni, secondo la procedura di cui agli articoli 30 e 32.</div>\n</div>"]]}, "52": {"label": "Articolo 52", "heading": "Presentazione del bilancio", "anchor": "art_52", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Il bilancio presenta:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nello stato generale delle entrate e delle spese:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le previsioni di entrate dell’Unione per l’esercizio corrente («anno n»);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le previsioni di entrate per l’esercizio precedente e le entrate dell’anno n-2;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli stanziamenti di impegno e di pagamento per l’anno n;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iv) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli stanziamenti di impegno e di pagamento per l’esercizio precedente;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>v) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le spese impegnate e le spese pagate nel corso dell’anno n-2, queste ultime espresse altresì come percentuale del bilancio dell’anno n;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>vi) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i commenti appropriati a ciascuna sottodivisione prevista all’articolo 47, paragrafo 1, che comprendono i riferimenti all’atto di base, quando esiste, nonché tutte le adeguate spiegazioni sulla natura e sulla destinazione degli stanziamenti;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">in ogni sezione, le entrate e le spese, seguendo la stessa struttura di cui alla lettera a);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">con riguardo al personale:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una tabella dell’organico che fissa, per ogni sezione, il numero dei posti per grado in ciascuna categoria e in ciascun quadro e il numero dei posti permanenti e temporanei di cui è autorizzata la presa a carico nei limiti degli stanziamenti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una tabella dell’organico retribuito a titolo degli stanziamenti per la ricerca e lo sviluppo tecnologico per l’azione diretta e una tabella dell’organico retribuito a titolo degli stessi stanziamenti per l’azione indiretta; le tabelle sono suddivise in categorie e gradi, con la distinzione tra posti permanenti e temporanei, di cui è autorizzata la presa a carico nei limiti degli stanziamenti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una tabella dell’organico che fissa, per ciascun organismo dell’Unione di cui all’articolo 70 che riceve un contributo a carico del bilancio, il numero dei posti, per grado e per categoria. Le tabelle dell’organico indicano, accanto al numero dei posti autorizzati a titolo dell’esercizio, il numero dei posti autorizzati a titolo dell’esercizio precedente. Il personale dell’agenzia d’approvvigionamento Euratom figura in modo distinto nella tabella dell’organico della Commissione;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">con riguardo all’assistenza finanziaria e alle garanzie di bilancio:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nello stato generale delle entrate, le linee di bilancio corrispondenti alle operazioni in questione, destinate a ricevere gli eventuali rimborsi di beneficiari inizialmente inadempienti. Tali linee recano la menzione «per memoria» e sono accompagnate dai commenti del caso;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nella sezione del bilancio relativa alla Commissione:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">le linee di bilancio che presentano le garanzie di bilancio per le operazioni interessate. Tali linee recano la menzione «per memoria», a condizione che non sussista alcun onere effettivo cui si debba far fronte con risorse definitive;</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">commenti che indicano il riferimento all’atto di base e il volume delle operazioni previste, la durata, nonché la garanzia finanziaria che l’Unione fornisce per lo svolgimento di tali operazioni;</div>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">in un documento allegato alla sezione del bilancio relativa alla Commissione, anche indicativamente per quanto riguarda i rischi corrispondenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">le operazioni in capitale e la gestione dell’indebitamento in corso;</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">le operazioni in capitale e la gestione dell’indebitamento per l’anno n;</div>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">con riguardo agli strumenti finanziari da costituire senza un atto di base:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le linee di bilancio corrispondenti alle operazioni in questione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una descrizione generale degli strumenti finanziari, compresi la loro durata e il loro impatto sul bilancio;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le operazioni previste, compresi i volumi obiettivo basati sull’effetto moltiplicatore e sull’effetto leva previsti;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">con riguardo ai fondi eseguiti da persone o entità ai sensi dell’articolo 62, paragrafo 1, primo comma, lettera c):</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un riferimento all’atto di base del programma pertinente;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le linee di bilancio corrispondenti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una descrizione generale dell’azione, compresa la sua durata e la sua incidenza sul bilancio;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’importo totale delle spese della PESC iscritto in un capitolo denominato «PESC», con articoli specifici, che copre la spesa per la PESC e contiene linee di bilancio specifiche che individuano quantomeno le missioni principali.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Oltre ai documenti di cui al paragrafo 1, il Parlamento europeo e il Consiglio possono accludere al bilancio qualsiasi altro documento pertinente.</div>\n</div>"]]}, "53": {"label": "Articolo 53", "heading": "Norme in materia di tabelle dell’organico", "anchor": "art_53", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le tabelle dell’organico di cui all’articolo 52, paragrafo 1, lettera c), costituiscono per ciascuna istituzione od organismo dell’Unione un limite tassativo. Nessuna nomina è fatta oltre detto limite.</div>\n</div>"], [null, "<p class=\"norm inline-element\">Ogni istituzione od organismo dell’Unione può, tuttavia, procedere a modifiche delle tabelle dell’organico fino a concorrenza del 10 % dei posti autorizzati, tranne che per i gradi AD 14, AD 15 e AD 16, alle seguenti condizioni:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il volume degli stanziamenti per il personale corrispondenti a un esercizio pieno non è modificato;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il limite del numero totale di posti autorizzati per tabella dell’organico non è superato;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’istituzione o l’organismo dell’Unione ha partecipato a un esercizio di analisi comparativa con altre istituzioni e organismi dell’Unione quale avviato dall’esercizio di screening del personale della Commissione.</p>\n</div>\n</div>"], [null, "<p class=\"norm\">Tre settimane prima di procedere alle modifiche di cui al secondo comma, l’istituzione dell’Unione informa il Parlamento europeo e il Consiglio della sua intenzione. Se durante tale periodo il Parlamento europeo o il Consiglio avanza obiezioni debitamente giustificate, l’istituzione dell’Unione si astiene dalle modifiche e si applica la procedura di cui all’articolo 44.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">In deroga al paragrafo 1, primo comma, gli effetti dell’attività a orario ridotto autorizzata dall’autorità che ha il potere di nomina conformemente allo statuto possono essere compensati da altre nomine.</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "54": {"label": "Articolo 54", "heading": "Conformità rispetto al quadro finanziario pluriennale e alla decisione 2014/335/UE, Euratom", "anchor": "art_54", "frags": [[null, "<p class=\"norm\">Il bilancio è stabilito nel rispetto del quadro finanziario pluriennale e della decisione 2014/335/UE, Euratom.</p>"]]}, "55": {"label": "Articolo 55", "heading": "Conformità degli atti dell’Unione rispetto al bilancio", "anchor": "art_55", "frags": [[null, "<p class=\"norm\">Se l’attuazione di un atto dell’Unione comporta il superamento degli stanziamenti disponibili nel bilancio, tale atto non è attuato in termini finanziari fintanto che il bilancio non sia stato conseguentemente rettificato.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "56": {"label": "Articolo 56", "heading": "Esecuzione del bilancio in conformità del principio della sana gestione finanziaria", "anchor": "art_56", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La Commissione esegue il bilancio in entrate e in spese conformemente al presente regolamento, sotto la propria responsabilità ed entro i limiti degli stanziamenti autorizzati.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Gli Stati membri cooperano con la Commissione affinché gli stanziamenti siano utilizzati secondo il principio della sana gestione finanziaria.</div>\n</div>"]]}, "57": {"label": "Articolo 57", "heading": "Informazioni sul trasferimento dei dati personali a fini di audit", "anchor": "art_57", "frags": [[null, "<p class=\"norm\">In ogni avviso pubblicato nell’ambito di una procedura di attribuzione di sovvenzioni, appalti o premi eseguita in regime di gestione diretta, i potenziali beneficiari, candidati, offerenti e partecipanti sono informati, a norma del regolamento (CE) n. 45/2001, che per salvaguardare gli interessi finanziari dell’Unione i loro dati personali possono essere trasferiti ai servizi interni di audit, alla Corte dei conti o all’Ufficio europeo per la lotta antifrode (OLAF), nonché scambiati tra gli ordinatori della Commissione, le agenzie esecutive di cui all’articolo 69 del presente regolamento e gli organismi dell’Unione di cui agli articoli 70 e 71 del presente regolamento.</p>"]]}, "58": {"label": "Articolo 58", "heading": "Atto di base e deroghe", "anchor": "art_58", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli stanziamenti iscritti in bilancio per qualsiasi azione dell’Unione sono utilizzati soltanto se è stato adottato un atto di base.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">In deroga al paragrafo 1, e fatte salve le condizioni di cui ai paragrafi 3, 4 e 5, i seguenti stanziamenti possono essere eseguiti senza atto di base, a condizione che le azioni finanziate siano di competenza dell’Unione:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli stanziamenti relativi a progetti pilota di natura sperimentale destinati ad accertare la fattibilità e l’utilità di un’azione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli stanziamenti relativi ad azioni preparatorie nei settori di applicazione del TFUE e del trattato Euratom, destinate all’elaborazione di proposte in vista dell’adozione di azioni future;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli stanziamenti relativi a misure preparatorie nell’ambito del titolo V del TUE;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli stanziamenti relativi ad azioni di natura puntuale o permanente svolte dalla Commissione in esecuzione di compiti connessi alle sue prerogative istituzionali in conformità del TFUE e del trattato Euratom diverse dal diritto di iniziativa legislativa e dal diritto di presentare proposte di cui alla lettera b) del presente paragrafo, nonché in esecuzione di competenze specifiche attribuitele direttamente dagli articoli 154, 156, 159 e 160 TFUE, dagli articoli 168, paragrafo 2, 171, paragrafo 2, e 173, paragrafo 2, TFUE, dall’articolo 175, secondo comma, TFUE, dall’articolo 181, paragrafo 2, TFUE, dall’articolo 190 TFUE, dagli articoli 210, paragrafo 2, e 214, paragrafo 6, TFUE e dagli articoli 70 e da 77 a 85 del trattato Euratom;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli stanziamenti destinati al funzionamento di ciascuna istituzione dell’Unione a titolo della sua autonomia amministrativa.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Con riguardo agli stanziamenti di cui al paragrafo 2, lettera a), i pertinenti stanziamenti di impegno possono essere iscritti in bilancio per non più di due esercizi consecutivi. L’importo totale degli stanziamenti relativi ai progetti pilota non supera i 40 000 000  EUR per esercizio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Con riguardo agli stanziamenti di cui al paragrafo 2, lettera b), le azioni preparatorie obbediscono a un’impostazione coerente e possono rivestire forme diverse. I relativi stanziamenti di impegno possono essere iscritti in bilancio per non più di tre esercizi consecutivi. La procedura per l’adozione dell’atto di base pertinente è conclusa entro la fine del terzo esercizio. Nel corso di detta procedura, l’impegno degli stanziamenti rispetta le caratteristiche proprie dell’azione preparatoria con riguardo alle attività previste, agli obiettivi perseguiti e ai destinatari. Di conseguenza, l’importo degli stanziamenti impegnati non corrisponde all’importo di quelli previsti per il finanziamento dell’azione definitiva stessa.</div>\n</div>"], [null, "<p class=\"norm\">L’importo totale degli stanziamenti relativi alle azioni preparatorie nuove di cui al paragrafo 2, lettera b), non supera i 50 000 000  EUR per esercizio e l’importo totale degli stanziamenti effettivamente impegnati a titolo delle azioni preparatorie non supera i 100 000 000  EUR.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Con riguardo agli stanziamenti di cui al paragrafo 2, lettera c), le misure preparatorie sono limitate a un periodo di tempo ridotto e destinate a creare le condizioni per l’azione dell’Unione volta al conseguimento degli obiettivi della PESC e per l’adozione dei necessari strumenti giuridici.</div>\n</div>"], [null, "<p class=\"norm\">Ai fini delle operazioni dell’Unione di gestione delle crisi, le misure preparatorie sono destinate, fra l’altro, a valutare i requisiti operativi, a consentire una rapida assegnazione iniziale delle risorse o a creare le condizioni in loco per l’avvio dell’operazione. Le misure preparatorie sono approvate dal Consiglio, su proposta dell’alto rappresentante.</p>"], [null, "<p class=\"norm\">Per assicurare la rapida attuazione delle misure preparatorie, l’alto rappresentante informa il Parlamento europeo e la Commissione con la massima tempestività dell’intenzione del Consiglio di avviare una misura preparatoria e comunica, in particolare, una stima delle risorse necessarie a tal fine. La Commissione adotta tutte le misure necessarie per garantire un rapido esborso dei fondi.</p>"], [null, "<p class=\"norm\">Il finanziamento di misure approvate dal Consiglio per la preparazione di operazioni dell’Unione di gestione delle crisi nell’ambito del titolo V del TUE comprende i sovraccosti derivanti direttamente dalla presenza specifica sul campo di una missione o gruppo comprendente anche personale delle istituzioni dell’Unione, inclusi l’assicurazione per rischi gravi, i costi di viaggio e di soggiorno e la diaria.</p>"]]}, "59": {"label": "Articolo 59", "heading": "Esecuzione del bilancio da parte di istituzioni dell’Unione diverse dalla Commissione", "anchor": "art_59", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La Commissione riconosce alle altre istituzioni dell’Unione i poteri necessari all’esecuzione delle rispettive sezioni del bilancio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Al fine di agevolare l’esecuzione dei rispettivi stanziamenti, le istituzioni dell’Unione possono concludere tra loro accordi a livello di servizi stabilendo le condizioni che disciplinano la prestazione di servizi, la fornitura di prodotti, l’esecuzione di lavori o di appalti immobiliari.</div>\n</div>"], [null, "<p class=\"norm\">Tali accordi consentono lo storno di stanziamenti o il recupero dei costi derivanti dalla loro esecuzione.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Gli accordi sul livello dei servizi di cui al paragrafo 2 possono essere conclusi anche tra i servizi delle istituzioni dell’Unione, gli organismi dell’Unione, gli uffici europei e gli organismi e le persone incaricati di attuare azioni specifiche nel settore della PESC a norma del titolo V del TUE e l’Ufficio del segretario generale del Consiglio superiore delle scuole europee. La Commissione e le altre istituzioni dell’Unione riferiscono periodicamente al Parlamento europeo e al Consiglio in merito agli accordi sul livello dei servizi conclusi con altre istituzioni dell’Unione.</div>\n</div>"]]}, "60": {"label": "Articolo 60", "heading": "Delega dei poteri di esecuzione del bilancio", "anchor": "art_60", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La Commissione e ciascuna delle altre istituzioni dell’Unione possono delegare, nell’ambito dei loro servizi, i propri poteri di esecuzione del bilancio conformemente alle condizioni stabilite dal presente regolamento e dalla rispettiva regolamentazione interna ed entro i limiti di cui all’atto di delega. I delegati agiscono entro i limiti dei poteri che sono loro espressamente conferiti.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">In aggiunta al paragrafo 1, la Commissione può delegare i propri poteri di esecuzione del bilancio inerenti gli stanziamenti operativi figuranti nella sua sezione del bilancio ai capi delle delegazioni dell’Unione e, al fine di garantire la continuità operativa in caso di loro assenza, ai vice capi delle delegazioni dell’Unione. Tale delega lascia impregiudicata la responsabilità dei capi delle delegazioni dell’Unione in ordine all’esecuzione del bilancio. Qualora l’assenza del capo di una delegazione dell’Unione superi le quattro settimane, la Commissione rivede la sua decisione di delegare i poteri di esecuzione del bilancio. Quando agiscono in qualità di ordinatori sottodelegati della Commissione, i capi delle delegazioni dell’Unione e, in loro assenza, i vice capi delle delegazioni applicano le norme della Commissione in materia di esecuzione del bilancio e sono soggetti agli stessi doveri, obblighi e responsabilità di tutti gli altri ordinatori sottodelegati della Commissione.</div>\n</div>"], [null, "<p class=\"norm\">La Commissione può revocare la delega dei poteri di cui al primo comma conformemente alla propria regolamentazione.</p>"], [null, "<p class=\"norm\">Ai fini di quanto stabilito al primo comma, l’alto rappresentante adotta i provvedimenti necessari per facilitare la collaborazione tra le delegazioni dell’Unione e i servizi della Commissione.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">In via eccezionale, il SEAE può delegare i propri poteri di esecuzione del bilancio, relativamente agli stanziamenti amministrativi figuranti nella sua sezione del bilancio, al personale della Commissione nelle delegazioni dell’Unione, ove ciò sia necessario per garantire la continuità della gestione delle delegazioni in assenza dell’ordinatore SEAE responsabile dal paese in cui è situata la sua delegazione. Nei casi eccezionali in cui i membri del personale della Commissione nelle delegazioni dell’Unione agiscono in qualità di ordinatori sottodelegati del SEAE, essi applicano la regolamentazione interna del SEAE in materia di esecuzione del bilancio e sono soggetti agli stessi doveri, obblighi e responsabilità di tutti gli altri ordinatori sottodelegati del SEAE.</div>\n</div>"], [null, "<p class=\"norm\">Il SEAE può revocare la delega dei poteri di cui al primo comma conformemente alla propria regolamentazione.</p>"]]}, "61": {"label": "Articolo 61", "heading": "Conflitto d’interessi", "anchor": "art_61", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli agenti finanziari ai sensi del capo 4 del presente titolo e le altre persone, comprese le autorità nazionali a tutti i livelli, che partecipano all’esecuzione in regime di gestione diretta, indiretta e concorrente del bilancio, anche per quanto riguarda i relativi atti preparatori, all’audit o al controllo, non adottano azioni da cui possa derivare un conflitto tra i loro interessi e quelli dell’Unione. Essi adottano inoltre misure adeguate a prevenire l’insorgere di conflitti d’interessi nell’ambito delle funzioni poste sotto la loro responsabilità e per risolvere le situazioni che possono oggettivamente essere percepite come comportanti un conflitto d’interessi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Laddove esista un rischio di conflitto d’interessi che coinvolga un membro del personale di un’autorità nazionale, la persona in questione ne informa il proprio superiore gerarchico. Qualora tale rischio sussista per un membro del personale statutario, la persona in questione ne informa l’ordinatore delegato competente. Il superiore gerarchico competente o l’ordinatore delegato conferma per iscritto se è accertata l’esistenza di un conflitto d’interessi. Laddove esista un conflitto d’interessi, l’autorità che ha il potere di nomina o l’autorità nazionale competente assicura che la persona in questione cessi ogni sua attività nella materia. L’ordinatore delegato o l’autorità nazionale competente assicura che sia intrapresa qualsiasi altra azione appropriata conformemente al diritto applicabile.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Ai fini del paragrafo 1, esiste un conflitto d’interessi quando l’esercizio imparziale e obiettivo delle funzioni di un agente finanziario o di un’altra persona di cui al paragrafo 1 è compromesso da motivi familiari, affettivi, da affinità politica o nazionale, da interesse economico o da qualsiasi altro interesse personale diretto o indiretto.</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "62": {"label": "Articolo 62", "heading": "Metodi di esecuzione del bilancio", "anchor": "art_62", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La Commissione esegue il bilancio secondo uno dei metodi seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">direttamente («gestione diretta») come stabilito agli articoli da 125 a 153, a opera dei suoi servizi, compreso il suo personale presso le delegazioni dell’Unione sotto l’autorità del rispettivo capo delegazione, a norma dell’articolo 60, paragrafo 2, o tramite le agenzie esecutive di cui all’articolo 69;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">in regime di gestione concorrente con gli Stati membri («gestione concorrente») come stabilito all’articolo 63 e agli articoli da 125 a 129;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">indirettamente («gestione indiretta») come stabilito agli articoli da 125 a 149 e da 154 a 159, se l’atto di base lo prevede o nei casi di cui all’articolo 58, paragrafo 2, lettere da a) a d), affidando compiti di esecuzione del bilancio:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">a paesi terzi od organismi da questi designati;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">a organizzazioni internazionali o loro agenzie, ai sensi dell’articolo 156;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">alla Banca europea per gli investimenti («BEI») o al Fondo europeo per gli investimenti («FEI») o a entrambi, agenti come gruppo («gruppo BEI»);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iv) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">agli organismi dell’Unione di cui agli articoli 70 e 71;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>v) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">a organismi di diritto pubblico, incluse organizzazioni degli Stati membri;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>vi) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">a organismi di diritto privato investiti di attribuzioni di servizio pubblico, incluse organizzazioni degli Stati membri, nella misura in cui sono dotati di sufficienti garanzie finanziarie;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>vii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">a organismi di diritto privato di uno Stato membro preposti all’attuazione di un partenariato pubblico-privato e che sono dotati di sufficienti garanzie finanziarie;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>viii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">a organismi o persone incaricati di attuare azioni specifiche della PESC a norma del titolo V del TUE e indicati nel pertinente atto di base.</p>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Con riguardo al primo comma, lettera c), punto vi), l’importo delle garanzie finanziarie richieste può essere stabilito nel pertinente atto di base e può essere limitato all’importo massimo del contributo dell’Unione all’organismo interessato. Qualora vi siano più garanti, la ripartizione dell’importo della passività totale che deve essere coperta dalle garanzie è precisata nell’accordo di contributo, che può prevedere che la responsabilità di ciascun garante sia proporzionata alla quota del rispettivo contributo all’organismo.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Ai fini della gestione diretta, la Commissione può ricorrere agli strumenti di cui ai titoli VII, VIII, IX, X e XII.</div>\n</div>"], [null, "<p class=\"norm\">Ai fini della gestione concorrente, gli strumenti per l’esecuzione del bilancio sono quelli previsti nella normativa settoriale.</p>"], [null, "<p class=\"norm\">Ai fini della gestione indiretta, la Commissione applica il titolo VI e, nel caso di strumenti finanziari e garanzie di bilancio, i titoli VI e X. Le entità incaricate dell’esecuzione si avvalgono degli strumenti per l’esecuzione del bilancio stabiliti nell’accordo di contributo in questione.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La Commissione è responsabile dell’esecuzione del bilancio a norma dell’articolo 317 TFUE e non delega a terzi tali compiti se sottendono un ampio margine di discrezionalità implicante scelte politiche.</div>\n</div>"], [null, "<p class=\"norm\">La Commissione non affida a soggetti esterni, tramite contratti conformi al titolo VII del presente regolamento, compiti comportanti l’esercizio dell’autorità pubblica o di poteri di apprezzamento discrezionali.</p>"]]}, "63": {"label": "Articolo 63", "heading": "Gestione concorrente con gli Stati membri", "anchor": "art_63", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Quando la Commissione esegue il bilancio in regime di gestione concorrente, i compiti relativi all’esecuzione del bilancio sono delegati agli Stati membri. La Commissione e gli Stati membri rispettano i principi di sana gestione finanziaria, trasparenza e non discriminazione e garantiscono la visibilità dell’azione dell’Unione nella gestione dei fondi dell’Unione. A tal fine, la Commissione e gli Stati membri assolvono i rispettivi obblighi in materia di controllo e audit e assumono le conseguenti responsabilità stabilite dal presente regolamento. La normativa settoriale stabilisce disposizioni complementari.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Nell’espletare le funzioni connesse all’esecuzione del bilancio, gli Stati membri adottano tutte le misure necessarie, comprese misure legislative, regolamentari e amministrative, per tutelare gli interessi finanziari dell’Unione, vale a dire:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">assicurano che le azioni finanziate a titolo del bilancio siano attuate in modo corretto, efficace e in conformità della normativa settoriale applicabile;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">designano gli organismi responsabili della gestione e del controllo dei fondi dell’Unione, conformemente al paragrafo 3, e sorvegliano tali organismi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">prevengono, individuano e rettificano le irregolarità e le frodi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">cooperano, in conformità del presente regolamento e della normativa settoriale, con la Commissione, l’OLAF, la Corte dei conti e, per gli Stati membri partecipanti a una cooperazione rafforzata ai sensi del regolamento (UE) 2017/1939 del Consiglio (\n<span class=\"superscript\">8</span>\n), anche con la Procura europea (EPPO).</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Al fine di tutelare gli interessi finanziari dell’Unione, nel rispetto del principio di proporzionalità e in conformità del presente articolo, nonché della normativa settoriale pertinente, gli Stati membri effettuano controlli ex ante ed ex post, comprese, se opportuno, verifiche sul posto su campioni di operazioni rappresentativi e/o basati sul rischio. Essi recuperano inoltre i fondi versati indebitamente e, se necessario, avviano azioni legali a tale riguardo.</p>"], [null, "<p class=\"norm\">Gli Stati membri irrogano sanzioni effettive, proporzionate e dissuasive ai destinatari ove previsto dalla normativa settoriale o da disposizioni specifiche del diritto nazionale.</p>"], [null, "<p class=\"norm\">Nell’ambito della sua valutazione del rischio e in conformità della normativa settoriale, la Commissione sorveglia i sistemi di gestione e di controllo istituiti negli Stati membri. Nell’ambito della sua attività di audit, la Commissione rispetta il principio di proporzionalità e tiene conto del livello di rischio valutato in conformità della normativa settoriale.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Conformemente ai criteri e alle procedure stabiliti nella normativa settoriale, gli Stati membri designano, al livello appropriato, organismi responsabili della gestione e del controllo dei fondi dell’Unione. Tali organismi possono espletare altresì funzioni non connesse alla gestione dei fondi dell’Unione e possono affidare taluni loro compiti ad altri organismi.</div>\n</div>"], [null, "<p class=\"norm\">Per decidere in merito alla designazione degli organismi, gli Stati membri possono considerare se i sistemi di gestione e di controllo siano sostanzialmente gli stessi del periodo precedente e se il loro funzionamento sia stato efficace.</p>"], [null, "<p class=\"norm\">Se dai risultati degli audit e dei controlli emerge che gli organismi designati non rispettano più i criteri stabiliti nella normativa settoriale, gli Stati membri adottano le misure necessarie per assicurare che sia posto rimedio alle carenze nell’espletamento delle funzioni di tali organismi, fra l’altro mettendo fine alla designazione in conformità della normativa settoriale.</p>"], [null, "<p class=\"norm\">La normativa settoriale definisce il ruolo della Commissione nella procedura stabilita nel presente paragrafo.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Gli organismi designati a norma del paragrafo 3:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">istituiscono un sistema di controllo interno efficace ed efficiente e ne garantiscono il funzionamento;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">utilizzano una contabilità che fornisce tempestivamente dati precisi, completi e attendibili;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">forniscono le informazioni richieste ai paragrafi 5, 6 e 7;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">provvedono alla pubblicazione a posteriori conformemente all’articolo 38, paragrafi da 2 a 6.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Il trattamento dei dati personali rispetta il regolamento (UE) 2016/679.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Gli organismi designati a norma del paragrafo 3 trasmettono alla Commissione, entro il 15 febbraio dell’esercizio successivo, la documentazione seguente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i rispettivi conti relativi alle spese che sono state sostenute durante il pertinente periodo di riferimento, quale definito nella normativa settoriale, per l’esecuzione dei loro compiti e che sono state presentate alla Commissione a fini di rimborso;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un riepilogo annuale delle relazioni finali di audit e dei controlli effettuati, comprese un’analisi della natura e della portata degli errori e delle carenze individuati nei sistemi, così come le azioni correttive avviate o programmate.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">I conti di cui al paragrafo 5, lettera a), includono i prefinanziamenti e gli importi per i quali sono in corso o sono state completate procedure di recupero. Essi sono corredati di una dichiarazione di gestione che conferma che, secondo i responsabili della gestione dei fondi:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le informazioni sono presentate correttamente e sono complete ed esatte;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le spese sono state effettuate per le finalità previste, quali definite nella normativa settoriale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i sistemi di controllo predisposti assicurano la legittimità e la regolarità delle operazioni sottostanti.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">I conti di cui al paragrafo 5, lettera a), e il riepilogo di cui alla lettera b) di tale paragrafo sono corredati del parere di un organismo di audit indipendente elaborato conformemente alle pertinenti norme riconosciute a livello internazionale. Detto parere accerta se i conti forniscono un quadro fedele, se le spese per le quali è stato chiesto il rimborso alla Commissione sono legittime e regolari e se i sistemi di controllo istituiti funzionano correttamente. Il parere riferisce altresì se l’esercizio di audit mette in dubbio le affermazioni contenute nella dichiarazione di gestione di cui al paragrafo 6.</div>\n</div>"], [null, "<p class=\"norm\">Il termine del 15 febbraio di cui al paragrafo 5 può essere eccezionalmente prorogato dalla Commissione al 1<span class=\"superscript\">o</span> marzo, previa comunicazione dello Stato membro interessato.</p>"], [null, "<p class=\"norm\">Gli Stati membri possono, al livello appropriato, pubblicare le informazioni di cui ai paragrafi 5 e 6 e al presente paragrafo.</p>"], [null, "<p class=\"norm\">Inoltre, essi possono fornire al Parlamento europeo, al Consiglio e alla Commissione dichiarazioni firmate al livello appropriato sulla base delle informazioni di cui ai paragrafi 5 e 6 e al presente paragrafo.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Al fine di garantire che i fondi dell’Unione siano utilizzati in conformità delle norme applicabili, la Commissione:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">applica procedure ai fini dell’esame e dell’accettazione dei conti degli organismi designati che assicurino la completezza, l’esattezza e la verità dei conti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">esclude dal finanziamento dell’Unione le spese per le quali gli esborsi sono stati effettuati in violazione del diritto applicabile;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">interrompe i termini di pagamento o sospende i pagamenti, se previsto dalla normativa settoriale.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">La Commissione pone fine integralmente o parzialmente all’interruzione dei termini di pagamento o alla sospensione dei pagamenti dopo che uno Stato membro ha presentato le proprie osservazioni e non appena ha adottato le misure necessarie. La relazione annuale di attività di cui all’articolo 74, paragrafo 9, comprende tutti gli obblighi previsti dal presente paragrafo.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">9.  </span>\n<div class=\"norm inline-element\">La normativa settoriale tiene conto delle esigenze dei programmi europei di cooperazione territoriale per quanto riguarda, in particolare, il contenuto della dichiarazione di gestione, il procedimento stabilito al paragrafo 3 e la funzione di audit.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">10.  </span>\n<div class=\"norm inline-element\">La Commissione compila un registro degli organismi responsabili delle attività di gestione, certificazione e audit in conformità della normativa settoriale.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">11.  </span>\n<div class=\"norm inline-element\">Gli Stati membri possono utilizzare le risorse loro assegnate in regime di gestione concorrente in combinazione con le operazioni e gli strumenti attivati ai sensi del regolamento (UE) 2015/1017 alle condizioni stabilite nella normativa settoriale pertinente.</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "64": {"label": "Articolo 64", "heading": "Ambito di competenza degli uffici europei", "anchor": "art_64", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Prima di creare un nuovo ufficio europeo, la Commissione esegue uno studio sul rapporto costi benefici e una valutazione dei rischi associati, informa il Parlamento europeo e il Consiglio dei relativi risultati e propone di iscrivere i necessari stanziamenti in un allegato della sezione del bilancio relativa alla Commissione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Nell’ambito delle loro competenze, gli uffici europei:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">espletano le funzioni obbligatorie previste dal loro atto istitutivo o da altri atti giuridici dell’Unione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">possono, conformemente all’articolo 66, espletare funzioni non obbligatorie, dopo che i propri comitati direttivi le hanno autorizzate, tenendo conto del rapporto costi-benefici e dei rischi associati per le parti interessate.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La presente sezione si applica alle attività dell’OLAF, a eccezione del paragrafo 4 del presente articolo, dell’articolo 66 e dell’articolo 67, paragrafi 1, 2 e 3.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Il revisore interno della Commissione esercita tutte le responsabilità previste dal capo 8 del presente titolo.</div>\n</div>"]]}, "65": {"label": "Articolo 65", "heading": "Stanziamenti relativi agli uffici europei", "anchor": "art_65", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli stanziamenti autorizzati per l’espletamento delle funzioni obbligatorie di ciascun ufficio europeo sono iscritti in una linea di bilancio specifica della sezione del bilancio relativa alla Commissione e sono riportati dettagliatamente in un allegato di detta sezione.</div>\n</div>"], [null, "<p class=\"norm\">L’allegato di cui al primo comma è presentato sotto forma di stato delle entrate e delle spese, suddiviso allo stesso modo delle sezioni del bilancio.</p>"], [null, "<p class=\"norm inline-element\">Gli stanziamenti iscritti in tale allegato:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">coprono tutte le esigenze finanziarie di ciascun ufficio europeo necessarie per l’espletamento delle funzioni obbligatorie previste dall’atto istitutivo o da altri atti giuridici dell’Unione;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">possono coprire le esigenze finanziarie di un ufficio europeo necessarie per l’espletamento dei compiti richiesti dalle istituzioni dell’Unione, dagli organismi dell’Unione, da altri uffici europei e agenzie istituiti dai trattati o sulla base dei trattati e autorizzati conformemente all’atto istitutivo dell’ufficio stesso.</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Per gli stanziamenti iscritti nell’allegato per ciascun ufficio europeo la Commissione delega i poteri di ordinatore al direttore dell’ufficio europeo in questione, a norma dell’articolo 73.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La tabella dell’organico di ciascun ufficio europeo è allegata a quella della Commissione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Il direttore di ciascun ufficio europeo decide gli storni all’interno dell’allegato di cui al paragrafo 1. La Commissione informa il Parlamento europeo e il Consiglio di tali storni.</div>\n</div>"]]}, "66": {"label": "Articolo 66", "heading": "Funzioni non obbligatorie", "anchor": "art_66", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Per quanto concerne le funzioni non obbligatorie di cui all’articolo 64, paragrafo 2, lettera b), un ufficio europeo può:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">ricevere la delega a favore del proprio direttore da parte delle istituzioni dell’Unione, degli organismi dell’Unione e di altri uffici europei, unitamente alla delega dei poteri di ordinatore per gli stanziamenti iscritti nella sezione del bilancio relativa all’istituzione dell’Unione, all’organismo dell’Unione o a un altro ufficio europeo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">concludere accordi ad hoc sul livello dei servizi con istituzioni dell’Unione, organismi dell’Unione, altri uffici europei o terzi.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Nei casi di cui al paragrafo 1, lettera a), le istituzioni dell’Unione, gli organismi dell’Unione e gli altri uffici europei interessati stabiliscono i limiti e le condizioni della delega dei poteri. Tale delega è concordata sulla base dell’atto istitutivo dell’ufficio europeo, in particolare per quanto riguarda le relative condizioni e modalità.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Nei casi di cui al paragrafo 1, lettera b), il direttore dell’ufficio europeo adotta, conformemente all’atto istitutivo, le disposizioni specifiche che disciplinano l’espletamento delle funzioni, il recupero dei costi sostenuti e la tenuta della corrispondente contabilità. L’ufficio europeo riferisce i risultati di tale contabilità alle istituzioni dell’Unione, agli organismi dell’Unione o agli altri uffici europei interessati.</div>\n</div>"]]}, "67": {"label": "Articolo 67", "heading": "Documenti contabili degli uffici europei", "anchor": "art_67", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ciascun ufficio europeo redige documenti contabili relativi alle proprie spese che permettono di determinare la quota dei servizi prestati a favore di ciascuna istituzione dell’Unione, ciascun organismo dell’Unione o altri uffici europei. Il direttore dell’ufficio europeo interessato, previa approvazione del suo comitato direttivo, adotta i criteri secondo i quali sono redatti i documenti contabili.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">I commenti relativi alla specifica linea di bilancio sulla quale è iscritto il totale degli stanziamenti di ciascun ufficio europeo cui sono stati delegati i poteri di ordinatore a norma dell’articolo 66, paragrafo 1, lettera a), presentano una stima dei costi dei servizi prestati da detto ufficio a favore di ciascuna istituzione dell’Unione, ciascun organismo dell’Unione e altri uffici europei interessati, sulla base dei documenti contabili di cui al paragrafo 1 del presente articolo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Ciascun ufficio europeo cui sono stati delegati i poteri di ordinatore a norma dell’articolo 66, paragrafo 1, lettera a), comunica alle istituzioni dell’Unione, agli organismi dell’Unione e agli altri uffici europei interessati i risultati dei documenti contabili di cui al paragrafo 1 del presente articolo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">I documenti contabili di ciascun ufficio europeo sono parte integrante dei conti dell’Unione di cui all’articolo 241.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Il contabile della Commissione, su proposta del comitato direttivo dell’ufficio europeo interessato, può delegare a un membro del personale dell’ufficio europeo alcuni dei suoi compiti relativi all’incasso delle entrate e al pagamento delle spese effettuati direttamente dall’ufficio europeo interessato.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Per le necessità di tesoreria proprie dell’ufficio europeo, la Commissione può, su proposta del comitato direttivo, aprire a nome dell’ufficio europeo conti bancari o conti correnti postali. Il saldo annuale di tesoreria è riconciliato e liquidato a fine esercizio tra l’ufficio europeo interessato e la Commissione.</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "68": {"label": "Articolo 68", "heading": "Applicabilità all’agenzia di approvvigionamento dell’Euratom", "anchor": "art_68", "frags": [[null, "<p class=\"norm\">Il presente regolamento si applica all’esecuzione del bilancio dell’agenzia di approvvigionamento dell’Euratom.</p>"]]}, "69": {"label": "Articolo 69", "heading": "Agenzie esecutive", "anchor": "art_69", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La Commissione può delegare ad agenzie esecutive i poteri di esecuzione integrale o parziale di programmi o progetti dell’Unione, compresi i progetti pilota e le azioni preparatorie, nonché l’esecuzione delle spese amministrative, per proprio conto e sotto la sua responsabilità, a norma del regolamento (CE) n. 58/2003 del Consiglio (\n<span class=\"superscript\">9</span>\n). Le agenzie esecutive sono istituite con decisione della Commissione e hanno personalità giuridica ai sensi del diritto dell’Unione. Esse ricevono un contributo annuale.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">I direttori delle agenzie esecutive fungono da ordinatori delegati per quanto riguarda l’esecuzione degli stanziamenti operativi relativi ai programmi dell’Unione che essi gestiscono integralmente o parzialmente.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il comitato direttivo di un’agenzia esecutiva può convenire con la Commissione che il contabile della Commissione svolga anche le funzioni di contabile dell’agenzia esecutiva interessata. Il comitato direttivo può altresì affidare al contabile della Commissione una parte delle funzioni del contabile dell’agenzia esecutiva interessata, tenendo conto del rapporto costi-benefici. In entrambi i casi sono adottate le disposizioni necessarie per evitare conflitti d’interessi.</div>\n</div>"]]}, "70": {"label": "Articolo 70", "heading": "Organismi istituiti in virtù del TFUE e del trattato Euratom", "anchor": "art_70", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Alla Commissione è conferito il potere di adottare atti delegati conformemente all’articolo 269 del presente regolamento al fine di integrare il presente regolamento con un regolamento finanziario quadro per gli organismi istituiti in conformità del TFUE e del trattato Euratom dotati di personalità giuridica e che ricevono contributi a carico del bilancio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il regolamento finanziario quadro si basa sui principi e sulle norme contenuti nel presente regolamento, tenendo conto delle specificità degli organismi di cui al paragrafo 1.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Le regole finanziarie degli organismi di cui al paragrafo 1 possono discostarsi dal regolamento finanziario quadro soltanto se lo impongono esigenze specifiche e fatto salvo il previo accordo della Commissione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Il discarico per l’esecuzione dei bilanci degli organismi di cui al paragrafo 1 è dato dal Parlamento europeo su raccomandazione del Consiglio. Gli organismi di cui al paragrafo 1 cooperano pienamente con le istituzioni dell’Unione coinvolte nella procedura di discarico e forniscono, se del caso, le informazioni supplementari necessarie, anche partecipando a riunioni degli organi competenti.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Il revisore interno della Commissione esercita nei confronti degli organismi di cui al paragrafo 1 le stesse competenze esercitate nei confronti della Commissione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Un revisore esterno indipendente verifica che i conti annuali di ciascuno degli organismi di cui al paragrafo 1 del presente articolo presentino correttamente le entrate, le spese e la situazione finanziaria dell’organismo in questione prima del consolidamento nei conti definitivi della Commissione. Salvo disposizione contraria del pertinente atto di base, la Corte dei conti elabora una relazione annuale specifica relativa a ciascun organismo conformemente alle prescrizioni dell’articolo 287, paragrafo 1, TFUE. Nell’elaborare tale relazione la Corte dei conti esamina il lavoro di audit svolto dal revisore esterno indipendente e le azioni adottate in risposta alle constatazioni del revisore.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Tutti gli aspetti dell’audit esterno indipendente di cui al paragrafo 6, comprese le constatazioni formulate, rimangono sotto la piena responsabilità della Corte dei conti.</div>\n</div>"]]}, "71": {"label": "Articolo 71", "heading": "Organismi di partenariato pubblico-privato", "anchor": "art_71", "frags": [[null, "<p class=\"norm\">Gli organismi dotati di personalità giuridica che sono istituiti da un atto di base e incaricati di attuare un partenariato pubblico-privato adottano le proprie regole finanziarie.</p>"], [null, "<p class=\"norm\">Tali regole comprendono un insieme di principi necessari ad assicurare la sana gestione finanziaria dei fondi dell’Unione.</p>"], [null, "<p class=\"norm\">Alla Commissione è conferito il potere di adottare atti delegati conformemente all’articolo 269 al fine di integrare il presente regolamento con un regolamento finanziario tipo per gli organismi di partenariato pubblico-privato che stabilisce i principi necessari a garantire la sana gestione finanziaria dei fondi dell’Unione ed è basato sull’articolo 154.</p>"], [null, "<p class=\"norm\">Le regole finanziarie degli organismi di partenariato pubblico-privato si discostano dal regolamento finanziario tipo soltanto se lo impongono esigenze specifiche e previo accordo della Commissione.</p>"], [null, "<p class=\"norm\">Agli organismi di partenariato pubblico-privato si applica l’articolo 70, paragrafi da 4 a 7.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "72": {"label": "Articolo 72", "heading": "Separazione delle funzioni", "anchor": "art_72", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le funzioni di ordinatore e di contabile sono separate e si escludono a vicenda.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Ogni istituzione dell’Unione mette a disposizione di ciascun agente finanziario le risorse necessarie all’assolvimento del suo compito e una carta delle funzioni che descrive in dettaglio compiti, diritti e obblighi.</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "73": {"label": "Articolo 73", "heading": "L’ordinatore", "anchor": "art_73", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le funzioni di ordinatore sono esercitate da ogni istituzione dell’Unione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Ai fini del presente titolo, per «membri del personale» si intendono le persone soggette allo statuto.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Ogni istituzione dell’Unione, nel rispetto delle condizioni previste dal rispettivo regolamento interno, delega le funzioni di ordinatore a membri del personale di livello adeguato. Essa stabilisce nelle proprie regole amministrative interne i membri del personale ai quali delega dette funzioni, i limiti dei poteri delegati e se le persone alle quali sono delegati tali poteri possono sottodelegarli.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Le deleghe e le sottodeleghe delle funzioni di ordinatore sono accordate soltanto a membri del personale.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">L’ordinatore responsabile agisce entro i limiti stabiliti dall’atto di delega o di sottodelega. L’ordinatore responsabile può essere assistito da uno o più membri del personale incaricati di effettuare, sotto la sua responsabilità, determinate operazioni necessarie ai fini dell’esecuzione del bilancio e della produzione delle informazioni finanziarie e di gestione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Ogni istituzione dell’Unione e ogni organismo dell’Unione di cui all’articolo 70 informa entro due settimane il Parlamento europeo, il Consiglio, la Corte dei conti e il contabile della Commissione della nomina e della cessazione dalle funzioni degli ordinatori delegati, dei revisori interni e dei contabili, nonché delle regole interne che adotta in materia finanziaria.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Ogni istituzione dell’Unione informa la Corte dei conti delle deleghe e della nomina degli amministratori degli anticipi a norma degli articoli 79 e 88.</div>\n</div>"]]}, "74": {"label": "Articolo 74", "heading": "Poteri e funzioni dell’ordinatore", "anchor": "art_74", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L’ordinatore è incaricato, nell’istituzione dell’Unione interessata, di eseguire le entrate e le spese secondo il principio della sana gestione finanziaria, anche assicurando la rendicontazione sulla performance, e di garantire il rispetto dei requisiti di legittimità, regolarità e parità di trattamento dei destinatari.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Ai fini del paragrafo 1 del presente articolo, l’ordinatore delegato pone in atto, conformemente all’articolo 36 e alle norme minime stabilite da ogni istituzione dell’Unione e tenendo conto dei rischi inerenti alle caratteristiche della gestione e alla natura delle azioni finanziate, la struttura organizzativa e i sistemi di controllo interno adeguati all’esecuzione dei suoi compiti. L’istituzione della struttura e dei sistemi in questione si fonda su un’analisi globale dei rischi che tiene conto del loro rapporto costi-benefici e della performance.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Per eseguire le spese, l’ordinatore responsabile assume impegni di bilancio e giuridici, convalida le spese, emette ordini di pagamento e pone in essere gli atti preliminari necessari per l’esecuzione degli stanziamenti.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Per eseguire le entrate, l’ordinatore responsabile elabora le previsioni di crediti, accerta i diritti da recuperare ed emette gli ordini di riscossione. Se del caso, l’ordinatore responsabile rinuncia ai crediti accertati.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Per evitare errori e irregolarità prima dell’autorizzazione delle operazioni e ridurre i rischi che comporta il mancato conseguimento degli obiettivi, ogni operazione è sottoposta ad almeno un controllo ex ante concernente gli aspetti operativi e finanziari, nell’ambito di una strategia di controllo pluriennale che tiene conto dei rischi.</div>\n</div>"], [null, "<p class=\"norm\">La portata, in termini di frequenza e intensità, dei controlli ex ante è determinata dall’ordinatore responsabile tenendo conto dei risultati dei controlli precedenti e di valutazioni relative ai rischi e al rapporto costi-benefici, sulla base dell’analisi del rischio dell’ordinatore responsabile medesimo. In caso di dubbio, l’ordinatore incaricato di convalidare le operazioni in questione, nell’ambito del controllo ex ante, richiede informazioni supplementari o effettua un controllo in loco al fine di ottenere un livello di affidabilità ragionevole.</p>"], [null, "<p class=\"norm\">Per una data operazione, la verifica è effettuata da membri del personale diversi da quelli che hanno avviato l’operazione. I membri del personale che effettuano la verifica non sono subordinati ai membri del personale che hanno avviato l’operazione.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">L’ordinatore delegato può predisporre controlli ex post per individuare e correggere errori e irregolarità nelle operazioni dopo la loro autorizzazione. Tali controlli possono essere organizzati come controlli a campione in funzione del rischio, tenendo conto dei risultati dei controlli precedenti, nonché del rapporto costi-benefici e della performance.</div>\n</div>"], [null, "<p class=\"norm\">I controlli ex post sono svolti da membri del personale diversi da quelli responsabili dei controlli ex ante. I membri del personale responsabili dei controlli ex post non sono subordinati ai membri del personale responsabili dei controlli ex ante.</p>"], [null, "<p class=\"norm\">Le norme e le modalità, incluse le indicazioni temporali, per l’esecuzione di audit dei beneficiari sono chiare, coerenti e trasparenti, e sono messe a disposizione dei beneficiari al momento della firma della convenzione di sovvenzione.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Gli ordinatori e i membri del personale responsabili dell’esecuzione del bilancio dispongono delle necessarie competenze professionali.</div>\n</div>"], [null, "<p class=\"norm inline-element\">In ogni istituzione dell’Unione, l’ordinatore delegato garantisce:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">che gli ordinatori sottodelegati e i membri del loro personale ricevano informazioni e una formazione appropriate e periodicamente aggiornate sulle norme di controllo e i metodi e le tecniche disponibili a tal fine;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">che siano adottate, ove necessario, misure atte a garantire il funzionamento efficace ed efficiente dei sistemi di controllo in conformità del paragrafo 2.</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">Se un membro del personale partecipante alla gestione finanziaria e al controllo delle operazioni ritiene irregolare o contraria al principio della sana gestione finanziaria o alle regole deontologiche che è tenuto ad osservare una decisione la cui applicazione o accettazione gli sia stata imposta dal suo superiore, ne informa il proprio superiore gerarchico. Se il membro del personale lo informa per iscritto, il superiore gerarchico risponde per iscritto. In caso d’inerzia del superiore gerarchico, o qualora egli confermi la decisione o l’istruzione iniziale e il membro del personale consideri tale conferma insufficiente rispetto alla sua preoccupazione, il membro del personale ne informa per iscritto l’ordinatore delegato. Se tale ordinatore non risponde entro un termine congruo in considerazione delle circostanze specifiche e in ogni caso entro un mese, il membro del personale ne informa il comitato pertinente di cui all’articolo 143.</div>\n</div>"], [null, "<p class=\"norm\">In caso di attività illecite, di frode o di corruzione che possano ledere gli interessi dell’Unione, il membro del personale informa le autorità e gli organismi designati dallo statuto e dalle decisioni delle istituzioni dell’Unione relative alle condizioni e modalità delle indagini interne in materia di prevenzione delle frodi, di corruzione e di ogni altra attività illecita lesiva degli interessi dell’Unione. I contratti conclusi con revisori esterni che sottopongono ad audit la gestione finanziaria dell’Unione prevedono, per il revisore esterno, l’obbligo di informare l’ordinatore delegato in merito a qualsiasi sospetto di attività illecita, frode o corruzione che possano ledere gli interessi dell’Unione.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">9.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">L’ordinatore delegato rende conto alla propria istituzione dell’Unione dell’esercizio delle proprie funzioni mediante una relazione annuale di attività contenente informazioni finanziarie e di gestione, compresi i risultati dei controlli, dichiarando che, salvo se diversamente specificato nelle riserve collegate a determinati settori di entrate e spese, ha la ragionevole certezza che:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le informazioni figuranti nella relazione forniscono un quadro fedele della situazione reale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le risorse destinate alle attività descritte nella relazione sono state utilizzate per la finalità prevista e conformemente al principio della sana gestione finanziaria e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le procedure di controllo predisposte offrono le necessarie garanzie quanto alla legittimità e regolarità delle operazioni sottostanti.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">La relazione annuale di attività contiene informazioni sulle operazioni svolte in riferimento agli obiettivi e agli indicatori di performance fissati nei piani strategici, sui rischi associati a dette operazioni, sull’impiego delle risorse messe a disposizione e sull’efficienza ed efficacia dei sistemi di controllo interno. La relazione comprende una valutazione globale dei costi e dei benefici dei controlli, così come informazioni sulla misura in cui le spese operative autorizzate contribuiscono al conseguimento degli obiettivi strategici dell’Unione e generano un valore aggiunto per l’UE. La Commissione prepara una sintesi delle relazioni annuali di attività relative all’anno precedente.</p>"], [null, "<p class=\"norm\">Le relazioni annuali di attività per l’esercizio degli ordinatori e, se del caso, degli ordinatori delegati di istituzioni dell’Unione, di organismi dell’Unione, di uffici europei e di agenzie dell’Unione sono pubblicate entro il 1<span class=\"superscript\">o</span> luglio dell’esercizio successivo sul sito web dell’istituzione dell’Unione, dell’organismo dell’Unione, dell’ufficio europeo o dell’agenzia dell’Unione in un modo facilmente accessibile, fatte salve considerazioni debitamente giustificate in materia di riservatezza e di sicurezza.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">10.  </span>\n<div class=\"norm inline-element\">Gli ordinatori delegati, per ogni esercizio, registrano i contratti conclusi mediante procedure negoziate conformemente al punto 11.1, lettere da a) a f), e al punto 39 dell’allegato I. Se la proporzione di procedure negoziate rispetto al numero di contratti aggiudicati dal medesimo ordinatore delegato aumenta significativamente rispetto agli esercizi precedenti, o se tale proporzione è notevolmente più elevata della media registrata al livello dell’istituzione dell’Unione, l’ordinatore responsabile riferisce all’istituzione dell’Unione, esponendo le misure eventualmente adottate per invertire tale tendenza. Ogni istituzione dell’Unione trasmette al Parlamento europeo e al Consiglio una relazione sulle procedure negoziate. Per quanto riguarda la Commissione, tale relazione è allegata alla sintesi delle relazioni annuali di attività di cui al paragrafo 9 del presente articolo.</div>\n</div>"]]}, "75": {"label": "Articolo 75", "heading": "Conservazione dei documenti giustificativi da parte degli ordinatori", "anchor": "art_75", "frags": [[null, "<p class=\"norm\">L’ordinatore istituisce sistemi cartacei o elettronici per la conservazione dei documenti giustificativi originali relativi all’esecuzione del bilancio. Tali documenti sono conservati per un periodo di almeno cinque anni dalla data di concessione del discarico da parte del Parlamento europeo per l’esercizio finanziario al quale i documenti si riferiscono.</p>"], [null, "<p class=\"norm\">Fatto salvo il primo comma, documenti relativi a operazioni sono comunque conservati sino alla fine dell’anno che segue quello in cui dette operazioni sono definitivamente chiuse.</p>"], [null, "<p class=\"norm\">I dati personali contenuti nei documenti giustificativi sono, se possibile, cancellati quando non sono necessari ai fini del discarico del bilancio, di controllo o di audit. Alla conservazione dei dati relativi al traffico delle comunicazioni si applica l’articolo 37, paragrafo 2, del regolamento (CE) n. 45/2001.</p>"]]}, "76": {"label": "Articolo 76", "heading": "Poteri e funzioni dei capi delle delegazioni dell’Unione", "anchor": "art_76", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Quando i capi delle delegazioni dell’Unione agiscono in qualità di ordinatori sottodelegati conformemente all’articolo 60, paragrafo 2, essi fanno capo alla Commissione in quanto istituzione dell’Unione responsabile della definizione, dell’esercizio, della sorveglianza e della valutazione delle loro funzioni e responsabilità di ordinatori sottodelegati e collaborano strettamente con la Commissione con riguardo alla corretta esecuzione dei fondi, al fine di garantire, in particolare, la legittimità e la regolarità delle operazioni finanziarie, il rispetto del principio della sana gestione finanziaria nella gestione dei fondi e l’efficace protezione degli interessi finanziari dell’Unione. Essi sono assoggettati al regolamento interno della Commissione e alla Carta della Commissione nell’ambito dell’esecuzione dei compiti di gestione finanziaria a loro sottodelegati. Nello svolgimento delle loro funzioni essi possono essere assistiti da personale della Commissione delle delegazioni dell’Unione.</div>\n</div>"], [null, "<p class=\"norm\">A tal fine, i capi delle delegazioni dell’Unione adottano i provvedimenti necessari a evitare qualunque situazione che potrebbe mettere a rischio la capacità della Commissione di assolvere alla sua responsabilità relativamente all’esecuzione del bilancio a loro sottodelegata, così come qualunque conflitto di priorità che possa incidere sull’esecuzione dei compiti di gestione finanziaria a loro sottodelegati.</p>"], [null, "<p class=\"norm\">Se viene a crearsi una situazione o un conflitto di cui al secondo comma, i capi delle delegazioni dell’Unione ne informano senza indugio i direttori generali responsabili della Commissione e del SEAE. Tali direttori generali adottano le misure del caso per porre rimedio alla situazione.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Qualora i capi delle delegazioni dell’Unione si trovino in una delle situazioni di cui all’articolo 74, paragrafo 8, essi sottopongono la questione al comitato di cui all’articolo 143. In caso di attività illecite, di frode o di corruzione che possano ledere gli interessi dell’Unione, essi informano le autorità e gli organismi designati dalla legislazione in vigore.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">I capi delle delegazioni dell’Unione che agiscono in qualità di ordinatori sottodelegati conformemente all’articolo 60, paragrafo 2, presentano una relazione al loro ordinatore delegato, in modo che questi possa integrare tali relazioni nella sua relazione annuale di attività di cui all’articolo 74, paragrafo 9. Le relazioni dei capi delle delegazioni dell’Unione contengono informazioni sull’efficienza e sull’efficacia dei sistemi di controllo interno istituiti nella loro delegazione, nonché sulla gestione delle operazioni a loro sottodelegate, e forniscono la dichiarazione attestante l’affidabilità di cui all’articolo 92, paragrafo 5, terzo comma. Tali relazioni sono allegate alla relazione annuale di attività dell’ordinatore delegato e sono messe a disposizione del Parlamento europeo e del Consiglio, tenendo conto, se del caso, del loro carattere riservato.</div>\n</div>"], [null, "<p class=\"norm\">I capi delle delegazioni dell’Unione cooperano pienamente con le istituzioni dell’Unione coinvolte nella procedura di discarico e forniscono, se del caso, ogni informazione supplementare necessaria. In questo contesto, essi possono essere chiamati ad assistere a riunioni degli organismi interessati e a coadiuvare l’ordinatore delegato responsabile.</p>"], [null, "<p class=\"norm\">I capi delle delegazioni dell’Unione che agiscono in qualità di ordinatori sottodelegati conformemente all’articolo 60, paragrafo 2, rispondono a ogni richiesta presentata dall’ordinatore delegato della Commissione su richiesta di quest’ultima o, nel contesto del discarico, su richiesta del Parlamento europeo.</p>"], [null, "<p class=\"norm\">La Commissione si assicura che la sottodelega di poteri ai capi delle delegazioni dell’Unione non sia pregiudizievole per la procedura di discarico di cui all’articolo 319 TFUE.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">I paragrafi 1, 2 e 3 si applicano anche ai vice capi delle delegazioni dell’Unione quando agiscono in qualità di ordinatori sottodelegati in assenza dei capi delle delegazioni dell’Unione.</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "77": {"label": "Articolo 77", "heading": "Poteri e funzioni del contabile", "anchor": "art_77", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Ogni istituzione dell’Unione nomina un contabile che, presso la stessa istituzione, è incaricato di:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">provvedere alla corretta esecuzione dei pagamenti, all’incasso delle entrate e al recupero dei crediti accertati;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">preparare e presentare i conti conformemente al titolo XIII;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">tenere la contabilità conformemente agli articoli 82 e 84;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">definire le norme e le procedure contabili, nonché il piano contabile, conformemente agli articoli da 80 a 84;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">definire e convalidare i sistemi contabili e, se del caso, convalidare i sistemi prescritti dall’ordinatore e destinati a fornire o giustificare informazioni contabili;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gestire la tesoreria.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Con riguardo ai compiti di cui al primo comma, lettera e), il contabile è abilitato a verificare in qualsiasi momento il rispetto dei criteri di convalida.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le responsabilità del contabile del SEAE riguardano esclusivamente la sezione del bilancio relativa al SEAE, eseguita dal SEAE. Il contabile della Commissione rimane responsabile dell’intera sezione del bilancio relativa alla Commissione, comprese le operazioni contabili relative agli stanziamenti la cui esecuzione è stata sottodelegata ai capi delle delegazioni dell’Unione.</div>\n</div>"], [null, "<p class=\"norm\">Il contabile della Commissione svolge anche il ruolo di contabile del SEAE relativamente all’esecuzione della sezione del bilancio relativa al SEAE.</p>"]]}, "78": {"label": "Articolo 78", "heading": "Nomina e cessazione dalle funzioni del contabile", "anchor": "art_78", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il contabile è nominato da ogni istituzione dell’Unione fra i funzionari soggetti allo statuto.</div>\n</div>"], [null, "<p class=\"norm\">Il contabile è scelto dall’istituzione dell’Unione in base alla sua competenza specifica comprovata da titoli o da un’esperienza professionale equivalente.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Due o più istituzioni od organismi dell’Unione possono nominare lo stesso contabile.</div>\n</div>"], [null, "<p class=\"norm\">In tal caso essi adottano le disposizioni necessarie al fine di prevenire qualsiasi situazione di conflitto d’interessi.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">In caso di cessazione dalle funzioni del contabile, si elabora senza indugio la situazione contabile generale.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Il contabile che cessa dalle sue funzioni oppure, in caso di sua impossibilità, un funzionario del suo servizio trasmette al nuovo contabile la situazione contabile generale, corredata di una relazione di passaggio delle consegne.</div>\n</div>"], [null, "<p class=\"norm\">Entro un mese dalla data in cui gli è stata trasmessa la situazione contabile generale, il nuovo contabile la firma, per accettazione, e può formulare riserve.</p>"], [null, "<p class=\"norm\">Nella relazione di passaggio delle consegne figurano il risultato della situazione contabile generale e le eventuali riserve formulate.</p>"]]}, "79": {"label": "Articolo 79", "heading": "Funzioni che il contabile può delegare", "anchor": "art_79", "frags": [[null, "<p class=\"norm\">Ai fini dell’esercizio dei suoi compiti, il contabile può delegare alcune delle proprie funzioni a membri del personale subordinati e ad amministratori degli anticipi designati conformemente all’articolo 89, paragrafo 1.</p>"], [null, "<p class=\"norm\">L’atto di delega definisce tali funzioni.</p>"]]}, "80": {"label": "Articolo 80", "heading": "Norme contabili", "anchor": "art_80", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le norme contabili che devono essere applicate dalle istituzioni dell’Unione, dagli uffici europei e dalle agenzie e dagli organismi dell’Unione di cui al capo 3, sezione 2, del presente titolo si basano sui principi contabili per il settore pubblico riconosciuti a livello internazionale. Tali norme sono adottate dal contabile della Commissione, previa consultazione dei contabili delle altre istituzioni dell’Unione, degli uffici europei e degli organismi dell’Unione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il contabile può discostarsi dai principi di cui al paragrafo 1 se lo reputa necessario per fornire una rappresentazione fedele degli elementi di attivo e di passivo, degli oneri, dei proventi e dei flussi di cassa. Qualora una norma contabile si discosti sensibilmente da detti principi, le note degli stati finanziari indicano tale fatto e i motivi che lo giustificano.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Le norme contabili di cui al paragrafo 1 stabiliscono la struttura e il contenuto degli stati finanziari, nonché i principi contabili su cui si basano i conti.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Le relazioni sull’esecuzione del bilancio di cui all’articolo 241 rispettano i principi di bilancio stabiliti dal presente regolamento. Esse forniscono un quadro dettagliato dell’esecuzione del bilancio e registrano tutte le operazioni in entrate e in spese previste al presente titolo, fornendone una rappresentazione fedele.</div>\n</div>"]]}, "81": {"label": "Articolo 81", "heading": "Organizzazione contabile", "anchor": "art_81", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il contabile di ogni istituzione od organismo dell’Unione elabora e tiene aggiornata una documentazione che descrive l’organizzazione e le procedure contabili della propria istituzione o del proprio organismo dell’Unione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le entrate e le spese sono registrate in un sistema informatico secondo la natura economica dell’operazione, in entrate o in spese correnti o in capitale.</div>\n</div>"]]}, "82": {"label": "Articolo 82", "heading": "Tenuta della contabilità", "anchor": "art_82", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il contabile della Commissione è incaricato di definire i piani contabili armonizzati che devono essere applicati dalle istituzioni dell’Unione, dagli uffici europei e dalle agenzie e dagli organismi dell’Unione di cui al capo 3, sezione 2, del presente titolo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">I contabili ottengono dagli ordinatori tutte le informazioni necessarie all’elaborazione di conti che forniscano una rappresentazione fedele della situazione finanziaria delle istituzioni dell’Unione e dell’esecuzione del bilancio. Gli ordinatori garantiscono l’affidabilità di tali informazioni.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Prima della loro adozione da parte dell’istituzione dell’Unione, o dell’organismo dell’Unione di cui all’articolo 70, il contabile approva i conti, attestando in tal modo con ragionevole certezza che essi forniscono una rappresentazione fedele della situazione finanziaria dell’istituzione dell’Unione o dell’organismo dell’Unione di cui all’articolo 70.</div>\n</div>"], [null, "<p class=\"norm\">A tal fine, il contabile verifica che i conti siano stati preparati nel rispetto delle norme contabili di cui all’articolo 80 e delle procedure contabili di cui all’articolo 77, paragrafo 1, primo comma, lettera d), e che tutte le entrate e le spese siano contabilizzate.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">L’ordinatore delegato, nel rispetto delle regole adottate dal contabile, trasmette a quest’ultimo le informazioni finanziarie e di gestione necessarie all’espletamento delle funzioni del contabile.</div>\n</div>"], [null, "<p class=\"norm\">L’ordinatore trasmette regolarmente al contabile, almeno in occasione della chiusura dei conti, i dati finanziari pertinenti relativi ai conti bancari fiduciari, in modo tale che i conti dell’Unione rispecchino l’utilizzo dei fondi dell’Unione.</p>"], [null, "<p class=\"norm\">Gli ordinatori restano pienamente responsabili dell’utilizzo corretto dei fondi da loro gestiti, della legittimità e regolarità delle spese sotto il loro controllo e della completezza ed esattezza delle informazioni trasmesse al contabile.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">L’ordinatore responsabile comunica al contabile tutti gli sviluppi o le modifiche significative del sistema di gestione finanziaria, del sistema d’inventario o del sistema per la valutazione degli elementi di attivo e di passivo, se forniscono dati alla contabilità dell’istituzione dell’Unione o quando sono destinati a giustificarne i dati, in modo che il contabile possa verificare l’osservanza dei criteri di convalida.</div>\n</div>"], [null, "<p class=\"norm\">In qualsiasi momento il contabile può riesaminare un sistema di gestione finanziaria già convalidato e può chiedere che l’ordinatore responsabile definisca un piano d’azione per correggere in tempo utile le eventuali carenze.</p>"], [null, "<p class=\"norm\">L’ordinatore è responsabile della completezza delle informazioni trasmesse al contabile.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Il contabile è abilitato a verificare le informazioni ricevute, nonché a eseguire qualsiasi verifica supplementare che egli ritenga necessaria per approvare i conti.</div>\n</div>"], [null, "<p class=\"norm\">Il contabile, se necessario, formula riserve illustrando con precisione la natura e la portata di dette riserve.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Un sistema contabile dell’istituzione dell’Unione serve a organizzare le informazioni di bilancio e finanziarie in modo da potervi iscrivere, classificare e registrare dati in cifre.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">Il sistema contabile si compone di una contabilità generale e di una contabilità di bilancio. Le due contabilità sono tenute in euro e per anno civile.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">9.  </span>\n<div class=\"norm inline-element\">L’ordinatore delegato può anche tenere una contabilità dettagliata relativa alla gestione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">10.  </span>\n<div class=\"norm inline-element\">I documenti giustificativi relativi al sistema contabile e alla preparazione dei conti di cui all’articolo 241 sono conservati per un periodo di almeno cinque anni dalla data di concessione del discarico da parte del Parlamento europeo per l’esercizio al quale i documenti si riferiscono.</div>\n</div>"], [null, "<p class=\"norm\">Tuttavia, i documenti relativi a operazioni non definitivamente chiuse sono conservati sino alla fine dell’anno che segue quello della chiusura di dette operazioni. Alla conservazione dei dati relativi al traffico delle comunicazioni si applica l’articolo 37, paragrafo 2, del regolamento (CE) n. 45/2001.</p>"], [null, "<p class=\"norm\">Ciascuna istituzione dell’Unione decide presso quale servizio devono essere conservati i documenti giustificativi.</p>"]]}, "83": {"label": "Articolo 83", "heading": "Contabilità di bilancio", "anchor": "art_83", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Per ogni suddivisione del bilancio la contabilità di bilancio registra quanto segue:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per quanto riguarda le spese:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli stanziamenti autorizzati nel bilancio, compresi gli stanziamenti iscritti nei bilanci rettificativi, gli stanziamenti riportati, gli stanziamenti aperti a seguito della riscossione di entrate con destinazione specifica, gli stanziamenti risultanti da storni e la somma totale degli stanziamenti disponibili;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli stanziamenti di impegno e gli stanziamenti di pagamento dell’esercizio;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per quanto riguarda le entrate:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le previsioni iscritte nel bilancio, comprese le previsioni iscritte nei bilanci rettificativi, le entrate con destinazione specifica e l’importo totale delle entrate stimate;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i diritti accertati e le riscossioni dell’esercizio;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli impegni ancora da pagare e le entrate ancora da recuperare, riportati dagli esercizi precedenti.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Gli stanziamenti di impegno e gli stanziamenti di pagamento di cui al primo comma, lettera a), sono registrati e seguiti separatamente.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La contabilità di bilancio illustra separatamente quanto segue:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’impiego degli stanziamenti riportati e degli stanziamenti dell’esercizio;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la liquidazione degli impegni che restano da liquidare.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Per quanto riguarda le entrate, i crediti ancora da riscuotere degli esercizi precedenti sono seguiti separatamente.</p>"]]}, "84": {"label": "Articolo 84", "heading": "Contabilità generale", "anchor": "art_84", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La contabilità generale riproduce in ordine cronologico, secondo il metodo della partita doppia, tutti gli eventi e le operazioni che intervengono nella situazione economica, finanziaria e patrimoniale delle istituzioni dell’Unione e delle agenzie e degli organismi dell’Unione di cui al capo 3, sezione 2, del presente titolo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">I saldi e i movimenti della contabilità generale sono iscritti nei libri contabili.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Ogni scrittura contabile, comprese le rettifiche contabili, è basata su documenti giustificativi ai quali essa fa riferimento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Il sistema contabile permette di risalire con chiarezza a tutte le scritture contabili.</div>\n</div>"]]}, "85": {"label": "Articolo 85", "heading": "Conti bancari", "anchor": "art_85", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Per le esigenze della gestione della tesoreria, il contabile può aprire o fare aprire conti in nome della sua istituzione dell’Unione presso le istituzioni finanziarie o le banche centrali nazionali. Il contabile è altresì incaricato di chiudere tali conti o di assicurarsi che siano chiusi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le condizioni d’apertura, di esercizio e d’utilizzazione dei conti bancari prevedono, in funzione delle esigenze di controllo interno, per gli assegni, i bonifici e qualsiasi altra operazione bancaria, la firma di uno o più membri del personale provvisti delle deleghe necessarie. Le istruzioni manuali sono firmate da almeno due membri del personale provvisti delle deleghe necessarie o dal contabile.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Nell’ambito dell’attuazione di un programma o di un’azione, possono essere aperti conti fiduciari per conto della Commissione, al fine di consentirne la gestione da parte di un’entità di cui all’articolo 62, paragrafo 1, primo comma, lettera c), punto ii), iii), v) o vi).</div>\n</div>"], [null, "<p class=\"norm\">Tali conti sono aperti sotto la responsabilità dell’ordinatore incaricato dell’attuazione del programma o dell’azione d’intesa con il contabile della Commissione.</p>"], [null, "<p class=\"norm\">Tali conti sono gestiti sotto la responsabilità dell’ordinatore.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Il contabile della Commissione definisce le norme per l’apertura, la gestione e la chiusura dei conti fiduciari, nonché per il loro uso.</div>\n</div>"]]}, "86": {"label": "Articolo 86", "heading": "Gestione della tesoreria", "anchor": "art_86", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Salve le deroghe previste dal presente regolamento, solo il contabile è abilitato a gestire denaro contante ed equivalenti di liquidità. Il contabile è responsabile della custodia dei medesimi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il contabile provvede affinché la propria istituzione dell’Unione disponga di fondi sufficienti per coprire il fabbisogno di tesoreria derivante dall’esecuzione del bilancio nell’ambito delle disposizioni del quadro normativo applicabile e stabilisce le procedure necessarie a garantire che nessuno dei conti aperti in conformità degli articoli 85, paragrafo 1, e 89, paragrafo 3, abbia un saldo debitore.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">I pagamenti sono effettuati mediante bonifico bancario, assegno o dalle casse di anticipi o, su espressa autorizzazione del contabile, mediante carta di debito, addebito diretto o altri mezzi di pagamento, conformemente alle regole stabilite dal contabile.</div>\n</div>"], [null, "<p class=\"norm\">Prima di assumere un impegno nei confronti di terzi, l’ordinatore conferma l’identità del beneficiario, acquisisce i dati relativi alla personalità giuridica e le coordinate di pagamento del beneficiario e li registra nello schedario comune tenuto dall’istituzione dell’Unione di cui è responsabile al fine di garantire la trasparenza, la responsabilità e la corretta esecuzione dei pagamenti.</p>"], [null, "<p class=\"norm\">Il contabile può effettuare pagamenti soltanto se i dati relativi alla personalità giuridica e le coordinate di pagamento del beneficiario sono già stati registrati nello schedario comune tenuto dall’istituzione dell’Unione di cui il contabile è responsabile.</p>"], [null, "<p class=\"norm\">Gli ordinatori comunicano al contabile ogni variazione dei dati relativi alla personalità giuridica e le coordinate di pagamento loro trasmessi dal beneficiario e verificano la validità di tali dati prima di emettere qualsiasi ordine di pagamento.</p>"]]}, "87": {"label": "Articolo 87", "heading": "Inventario delle immobilizzazioni", "anchor": "art_87", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le istituzioni, le agenzie e gli organismi dell’Unione di cui al capo 3, sezione 2, del presente titolo tengono, conformemente al modello stabilito dal contabile della Commissione, inventari in numero e in valore di tutte le immobilizzazioni materiali, immateriali e finanziarie che costituiscono il patrimonio dell’Unione.</div>\n</div>"], [null, "<p class=\"norm\">Essi, inoltre, verificano la concordanza tra le scritture dei rispettivi inventari e la situazione di fatto.</p>"], [null, "<p class=\"norm\">Devono essere iscritti nell’inventario e registrati nei conti delle immobilizzazioni tutti i beni acquisiti, diversi da quelli di consumo, la cui durata d’utilizzo è superiore a un anno e il cui prezzo di acquisto o costo di produzione è superiore a quello indicato nelle procedure contabili di cui all’articolo 77.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La vendita di immobilizzazioni materiali dell’Unione è oggetto di una pubblicità adeguata.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Le istituzioni, le agenzie e gli organismi dell’Unione di cui al capo 3, sezione 2, del presente titolo adottano le disposizioni relative alla conservazione dei beni ripresi nei rispettivi inventari e individuano gli uffici amministrativi responsabili del sistema d’inventario.</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "88": {"label": "Articolo 88", "heading": "Casse di anticipi", "anchor": "art_88", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Possono essere create casse di anticipi per il pagamento di spese per le quali, a causa del carattere limitato degli importi da pagare, risulta materialmente impossibile o inefficiente effettuare le operazioni di pagamento mediante le procedure di bilancio. Possono essere create casse di anticipi anche per l’incasso di entrate diverse dalle risorse proprie.</div>\n</div>"], [null, "<p class=\"norm\">Nelle delegazioni dell’Unione, le casse di anticipi possono inoltre essere utilizzate per eseguire pagamenti di importo limitato mediante le procedure di bilancio, se, alla luce delle norme in vigore localmente, tale soluzione garantisce efficienza ed efficacia.</p>"], [null, "<p class=\"norm\">L’importo massimo che può essere pagato dall’amministratore degli anticipi ove risulti materialmente impossibile o inefficiente effettuare le operazioni di pagamento mediante le procedure di bilancio è stabilito dal contabile e non supera in alcun caso i 60 000  EUR per ogni voce di spesa.</p>"], [null, "<p class=\"norm\">Tuttavia, nel settore degli aiuti erogati per situazioni di crisi e delle operazioni d’aiuto umanitario, si possono utilizzare le casse di anticipi senza limite di importo, rispettando il livello di stanziamenti deciso dal Parlamento europeo e dal Consiglio per la corrispondente linea di bilancio per l’esercizio in corso e conformemente alle norme interne della Commissione.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Nelle delegazioni dell’Unione possono essere create casse di anticipi per il pagamento delle spese iscritte nelle sezioni del bilancio relative alla Commissione e al SEAE, garantendo la piena tracciabilità delle spese.</div>\n</div>"]]}, "89": {"label": "Articolo 89", "heading": "Creazione e gestione delle casse di anticipi", "anchor": "art_89", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La creazione di una cassa di anticipi e la designazione di un amministratore degli anticipi sono oggetto di una decisione del contabile dell’istituzione dell’Unione, sulla base di una proposta debitamente motivata dell’ordinatore responsabile. Tale decisione stabilisce le responsabilità e gli obblighi rispettivi dell’amministratore degli anticipi e dell’ordinatore.</div>\n</div>"], [null, "<p class=\"norm\">Gli amministratori degli anticipi sono scelti tra i funzionari o, se necessario e soltanto in casi debitamente motivati, tra gli altri membri del personale o, alle condizioni stabilite nelle norme interne della Commissione, tra il personale impiegato dalla Commissione nel settore degli aiuti erogati per situazioni di crisi e delle operazioni d’aiuto umanitario, purché i rispettivi contratti di lavoro garantiscano un livello di tutela in termini di responsabilità equivalente a quello applicabile al personale a norma dell’articolo 95. Gli amministratori degli anticipi sono scelti in base alle loro conoscenze, attitudini e competenze particolari comprovate da titoli o da idonea esperienza professionale o risultanti da un programma di formazione adeguato.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Nelle proposte di decisione per creare una cassa di anticipi l’ordinatore responsabile provvede affinché:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">si faccia ricorso in via prioritaria alle procedure di bilancio quando esiste un accesso al sistema informatico contabile centrale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">si ricorra alle casse di anticipi unicamente in casi debitamente motivati.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Nelle decisioni intese a creare una cassa di anticipi, il contabile ne specifica le condizioni di esercizio e di utilizzazione.</p>"], [null, "<p class=\"norm\">Anche la modificazione delle condizioni di esercizio di una cassa di anticipi è oggetto di una decisione del contabile, su proposta debitamente motivata dell’ordinatore responsabile.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">I conti bancari per gli anticipi sono aperti e controllati dal contabile, il quale, inoltre, autorizza, sulla base di una proposta debitamente motivata dell’ordinatore responsabile, le deleghe a operare su di essi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Le casse di anticipi sono alimentate dal contabile dell’istituzione dell’Unione e sono poste sotto la responsabilità degli amministratori degli anticipi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">I pagamenti effettuati sono seguiti da decisioni formali di convalida definitiva o da ordini di pagamento firmati dall’ordinatore responsabile.</div>\n</div>"], [null, "<p class=\"norm\">Le operazioni di anticipo sono regolarizzate dall’ordinatore entro la fine del mese successivo, in modo da assicurare la riconciliazione tra il saldo contabile e il saldo bancario.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Il contabile procede a verifiche o le fa effettuare da un membro del personale del suo servizio o del servizio ordinatore, munito di autorizzazione specifica. Tali verifiche sono, come regola generale, effettuate in loco e, se necessario, senza preavviso, per accertare la disponibilità degli stanziamenti attribuiti agli amministratori degli anticipi, per controllare la contabilità e per assicurarsi che le operazioni di pagamento di anticipi siano regolarizzate entro i termini stabiliti. Il contabile comunica all’ordinatore responsabile i risultati delle sue verifiche.</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "90": {"label": "Articolo 90", "heading": "Revoca della delega dei poteri e sospensione dalle funzioni degli agenti finanziari", "anchor": "art_90", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le autorità che hanno nominato gli ordinatori responsabili possono revocare in qualsiasi momento, temporaneamente o definitivamente, la delega o la sottodelega a essi conferita.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le autorità che hanno nominato il contabile o l’amministratore degli anticipi possono sospendere l’uno o l’altro, o entrambi, in qualsiasi momento, temporaneamente o definitivamente, dalle loro funzioni.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">I paragrafi 1 e 2 fanno salve eventuali misure disciplinari adottate rispetto agli agenti finanziari di cui a tali paragrafi.</div>\n</div>"]]}, "91": {"label": "Articolo 91", "heading": "Responsabilità degli agenti finanziari in caso di attività illecita, frode o corruzione", "anchor": "art_91", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il presente capo fa salva l’eventuale responsabilità penale degli agenti finanziari di cui all’articolo 90, secondo il diritto nazionale applicabile e le disposizioni vigenti concernenti la tutela degli interessi finanziari dell’Unione e la lotta contro la corruzione nella quale sono coinvolti funzionari dell’Unione o degli Stati membri.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Fatti salvi gli articoli 92, 94 e 95 del presente regolamento, ogni ordinatore responsabile, contabile o amministratore degli anticipi è responsabile sotto il profilo disciplinare e patrimoniale conformemente allo statuto o, per quanto riguarda il personale impiegato dalla Commissione nel settore degli aiuti per la gestione delle crisi e le operazioni di aiuto umanitario di cui all’articolo 89, paragrafo 1, del presente regolamento conformemente al contratto di lavoro. In caso di attività illecita, di frode o di corruzione che possano ledere gli interessi dell’Unione, sono adite le autorità e gli organismi designati dalla legislazione vigente, in particolare l’OLAF.</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "92": {"label": "Articolo 92", "heading": "Disposizioni relative agli ordinatori", "anchor": "art_92", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L’ordinatore responsabile è tenuto a risarcire il danno alle condizioni previste dallo statuto.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">L’obbligo di risarcire il danno si applica, in particolare, se l’ordinatore responsabile, intenzionalmente o per negligenza grave da parte sua:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">accerta i diritti da recuperare o emette ordini di riscossione, impegna una spesa o firma un ordine di pagamento senza conformarsi al presente regolamento;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">omette di compilare un documento che dia luogo a un credito, omette o ritarda l’emissione di un ordine di riscossione oppure ritarda l’emissione di un ordine di pagamento, generando in tal modo una responsabilità civile dell’istituzione dell’Unione nei confronti di terzi.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Quando un ordinatore delegato o sottodelegato ritenga che un’istruzione vincolante ricevuta sia inficiata d’irregolarità o contravvenga al principio della sana gestione finanziaria, in particolare perché l’esecuzione è incompatibile con il livello delle risorse assegnategli, ne informa per iscritto l’autorità dalla quale ha ricevuto la delega o la sottodelega. Se l’istruzione è confermata per iscritto e la conferma è ricevuta in tempo utile ed è sufficientemente chiara, in quanto si riferisce esplicitamente agli aspetti posti in dubbio dall’ordinatore delegato o sottodelegato, l’ordinatore delegato o sottodelegato non è ritenuto responsabile. Egli esegue l’istruzione, salvo se essa sia manifestamente illegale o contraria alle pertinenti norme di sicurezza.</div>\n</div>"], [null, "<p class=\"norm\">La stessa procedura si applica nei casi in cui un ordinatore ritenga che una decisione di sua competenza sia inficiata da irregolarità o contravvenga al principio della sana gestione finanziaria o apprenda, in fase di esecuzione di un’istruzione vincolante, che talune circostanze del fascicolo possano condurre a una tale situazione.</p>"], [null, "<p class=\"norm\">Le istruzioni confermate nelle circostanze di cui al presente paragrafo sono registrate dall’ordinatore delegato responsabile e segnalate nella sua relazione annuale di attività.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">In caso di sottodelega all’interno del suo servizio, l’ordinatore delegato resta responsabile dell’efficienza e dell’efficacia dei sistemi di gestione e di controllo interni istituiti e della scelta dell’ordinatore sottodelegato.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">In caso di sottodelega ai capi o ai vice capi delle delegazioni dell’Unione, l’ordinatore delegato è responsabile della definizione dei sistemi di gestione e di controllo interni istituiti, così come della loro efficienza ed efficacia. I capi delle delegazioni dell’Unione sono responsabili della realizzazione e del funzionamento adeguati di tali sistemi, in conformità delle istruzioni impartite dall’ordinatore delegato, nonché della gestione dei fondi e delle operazioni effettuate all’interno della delegazione dell’Unione di cui sono responsabili. Prima di assumere le proprie funzioni, essi frequentano corsi di formazione specifici sui compiti e sulle responsabilità degli ordinatori e sull’esecuzione del bilancio.</div>\n</div>"], [null, "<p class=\"norm\">Conformemente all’articolo 76, paragrafo 3, i capi delle delegazioni dell’Unione riferiscono in merito alle loro responsabilità di cui al primo comma del presente paragrafo.</p>"], [null, "<p class=\"norm\">Ogni anno i capi delle delegazioni dell’Unione forniscono all’ordinatore delegato della Commissione la dichiarazione attestante l’affidabilità dei sistemi di gestione e di controllo interni istituiti nella loro delegazione, nonché della gestione delle operazioni a loro sottodelegate e dei relativi risultati, in modo da consentire all’ordinatore di effettuare la dichiarazione di affidabilità prevista all’articolo 74, paragrafo 9.</p>"], [null, "<p class=\"norm\">Il presente paragrafo si applica anche ai vice capi delle delegazioni dell’Unione quando agiscono in qualità di ordinatori sottodelegati in assenza dei capi delle delegazioni dell’Unione.</p>"]]}, "93": {"label": "Articolo 93", "heading": "Trattamento delle irregolarità finanziarie da parte di un membro del personale", "anchor": "art_93", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Fatti salvi i poteri dell’OLAF e l’autonomia amministrativa delle istituzioni dell’Unione, degli organismi dell’Unione, degli uffici europei o degli organismi o delle persone incaricate di attuare azioni specifiche nel settore della PESC a norma del titolo V del TUE con riguardo ai membri del loro personale e tenendo debitamente conto della tutela dei segnalanti, ogni violazione del presente regolamento o di una disposizione relativa alla gestione finanziaria o alla verifica delle operazioni, derivante da un’azione od omissione di un membro del personale è segnalata per un parere al comitato di cui all’articolo 143 da uno dei seguenti soggetti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’autorità che ha il potere di nomina competente in materia disciplinare;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’ordinatore responsabile, compresi i capi delle delegazioni dell’Unione e i loro vice che, in assenza dei capi delle delegazioni, agiscono in qualità di ordinatori sottodelegati conformemente all’articolo 60, paragrafo 2.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Quando un caso gli è direttamente segnalato da un membro del personale, il comitato trasmette la pratica all’autorità che ha il potere di nomina dell’istituzione dell’Unione, dell’organismo dell’Unione, dell’Ufficio europeo o dell’organismo o della persona interessati e ne informa il membro del personale. L’autorità che ha il potere di nomina può chiedere al comitato di esprimere il proprio parere sul caso.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Una richiesta di parere del comitato conformemente al paragrafo 1, primo comma, è corredata di una descrizione dei fatti e dell’azione od omissione che si chiede al comitato di valutare, nonché dei pertinenti documenti giustificativi, compresi i rapporti delle eventuali indagini condotte. Ove possibile, le informazioni sono fornite in forma anonima.</div>\n</div>"], [null, "<p class=\"norm\">Prima di presentare una richiesta o un’informazione complementare al comitato, l’autorità che ha il potere di nomina o l’ordinatore, se del caso, dà al membro del personale in causa la possibilità di presentare le sue osservazioni, dopo avergli comunicato i documenti giustificativi di cui al primo comma, purché tale comunicazione non comprometta gravemente lo svolgimento di ulteriori indagini.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Nei casi di cui al paragrafo 1 del presente articolo, il comitato di cui all’articolo 143 è competente a valutare se, sulla base degli elementi che gli sono stati trasmessi conformemente al paragrafo 2 del presente articolo e delle eventuali ulteriori informazioni ricevute, si è verificata un’irregolarità finanziaria. Sulla base del parere del comitato, l’istituzione dell’Unione, l’organismo dell’Unione, l’Ufficio europeo o l’organismo o la persona interessati decidono in merito all’opportuno seguito da dare in conformità dello statuto. Se ha individuato problemi sistemici, il comitato presenta una raccomandazione all’ordinatore e all’ordinatore delegato, a meno che non si tratti del membro del personale in causa, nonché al revisore interno.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Se il comitato esprime il parere di cui al paragrafo 1 del presente articolo, esso è composto dai membri di cui all’articolo 143, paragrafo 2, nonché dai seguenti tre membri supplementari, che sono designati tenendo conto della necessità di evitare conflitti d’interessi:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un rappresentante dell’autorità che ha il potere di nomina competente in materia disciplinare dell’istituzione dell’Unione, dell’organismo dell’Unione, dell’Ufficio europeo o dell’organismo o della persona interessati;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un membro designato dal comitato del personale dell’istituzione dell’Unione, dell’organismo dell’Unione, dell’Ufficio europeo o dell’organismo o della persona interessati;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un membro del Servizio giuridico dell’istituzione dell’Unione che impiega il membro del personale interessato.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Se il comitato esprime il parere di cui al paragrafo 1, quest’ultimo è indirizzato all’autorità che ha il potere di nomina dell’istituzione dell’Unione, dell’organismo dell’Unione, dell’Ufficio europeo o dell’organismo o della persona interessati.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Il comitato non ha poteri di indagine. L’istituzione dell’Unione, l’organismo dell’Unione, l’Ufficio europeo o l’organismo o la persona interessati collaborano con il comitato al fine di assicurare che quest’ultimo disponga di tutte le informazioni necessarie per esprimere il suo parere.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Se ritiene che il caso sia di competenza dell’OLAF, conformemente al paragrafo 1 il comitato trasmette senza indugio la pratica alla competente autorità che ha il potere di nomina e ne informa immediatamente l’OLAF.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Gli Stati membri sostengono pienamente l’Unione nella riscossione di eventuali pendenze di cui all’articolo 22 dello statuto a carico degli agenti temporanei cui si applica l’articolo 2, lettera e), del regime applicabile agli altri agenti dell’Unione europea.</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "94": {"label": "Articolo 94", "heading": "Disposizioni relative ai contabili", "anchor": "art_94", "frags": [[null, "<p class=\"norm\">Il contabile è responsabile disciplinarmente e civilmente alle condizioni e secondo le procedure di cui allo statuto. Il contabile può rispondere, in particolare, nelle fattispecie seguenti:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">perdita o deterioramento di fondi, valori o documenti che ha in custodia;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">indebita modificazione di conti bancari o di conti correnti postali;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">recuperi o pagamenti non conformi ai corrispondenti ordini di riscossione o di pagamento;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">mancato incasso di entrate dovute.</p>\n</div>\n</div>"]]}, "95": {"label": "Articolo 95", "heading": "Disposizioni relative agli amministratori degli anticipi", "anchor": "art_95", "frags": [[null, "<p class=\"norm\">L’amministratore degli anticipi può rispondere, in particolare, nelle fattispecie seguenti:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">perdita o deterioramento di fondi, valori o documenti che ha in custodia;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">omessa trasmissione di documenti giustificativi regolari per i pagamenti eseguiti;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">pagamento a soggetti non aventi diritto;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">mancato incasso di entrate dovute.</p>\n</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "96": {"label": "Articolo 96", "heading": "Risorse proprie", "anchor": "art_96", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le entrate costituite dalle risorse proprie di cui alla decisione 2014/335/UE, Euratom sono oggetto di una previsione iscritta nel bilancio ed espressa in euro. Le risorse proprie corrispondenti sono messe a disposizione conformemente al regolamento (UE, Euratom) n. 609/2014.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L’ordinatore stabilisce uno scadenzario di previsione della messa a disposizione della Commissione delle risorse proprie definite nella decisione 2014/335/UE, Euratom.</div>\n</div>"], [null, "<p class=\"norm\">L’accertamento e la riscossione delle risorse proprie si effettuano secondo la normativa d’attuazione di detta decisione.</p>"], [null, "<p class=\"norm\">A fini contabili, l’ordinatore emette un ordine di riscossione per i crediti e i debiti iscritti sul conto relativo alle risorse proprie di cui al regolamento (UE, Euratom) n. 609/2014.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "97": {"label": "Articolo 97", "heading": "Previsione di crediti", "anchor": "art_97", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Allorché l’ordinatore responsabile è in possesso di informazioni sufficienti e attendibili in merito a ogni misura o situazione da cui possa sorgere un credito dell’Unione, egli procede a effettuare una previsione di crediti.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L’ordinatore responsabile adegua la previsione di crediti non appena viene a conoscenza di un evento che modifica la misura o la situazione che ha determinato la formazione della previsione.</div>\n</div>"], [null, "<p class=\"norm\">All’atto della fissazione di un ordine di riscossione relativo a una misura o a una situazione da cui era precedentemente scaturita una previsione di crediti, l’ordinatore responsabile adegua conseguentemente i relativi importi.</p>"], [null, "<p class=\"norm\">Allorché l’ordine di riscossione è emesso per lo stesso importo della previsione di crediti originaria, tale previsione è ridotta a zero.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">In deroga al paragrafo 1, gli importi delle risorse proprie definite nella decisione 2014/335/UE, Euratom, versati a scadenze fisse dagli Stati membri, non sono oggetto di una previsione di crediti prima che siano messi a disposizione della Commissione a cura degli Stati membri. Tali importi sono oggetto di un ordine di riscossione dell’ordinatore responsabile.</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "98": {"label": "Articolo 98", "heading": "Accertamento dei crediti", "anchor": "art_98", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Ai fini dell’accertamento di un credito, l’ordinatore responsabile:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">verifica l’esistenza del debito;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">determina o verifica l’esistenza e l’importo del debito; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">verifica le condizioni di esigibilità del debito.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">L’accertamento di un credito rappresenta il riconoscimento del diritto vantato dall’Unione nei confronti di un debitore e la formazione del titolo a esigere dal debitore il pagamento del debito.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Ogni credito appurato come certo, liquido ed esigibile è oggetto di accertamento mediante un ordine di riscossione con il quale l’ordinatore responsabile dà istruzione al contabile di riscuotere l’importo. A esso fa seguito una nota di addebito indirizzata al debitore, tranne nei casi in cui è immediatamente adottata una procedura di rinuncia conformemente al paragrafo 4, secondo comma. Tanto l’ordine di riscossione quanto la nota di addebito sono emessi dall’ordinatore responsabile.</div>\n</div>"], [null, "<p class=\"norm\">L’ordinatore trasmette la nota di addebito immediatamente dopo l’accertamento del credito e al più tardi entro un periodo di cinque anni a decorrere dal momento in cui l’istituzione dell’Unione è stata normalmente in grado di far valere il proprio credito. Tale termine non si applica qualora l’ordinatore responsabile stabilisca che, malgrado l’impegno dimostrato dall’istituzione dell’Unione, il ritardo nell’azione è dipeso dal comportamento del debitore.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Per accertare un credito l’ordinatore responsabile verifica quanto segue:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il carattere certo del credito, vale a dire che il credito non è soggetto a condizioni;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il carattere liquido del credito, il cui importo deve essere determinato in denaro e con esattezza;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il carattere esigibile del credito, che non deve essere soggetto a un termine;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’esattezza della designazione del debitore;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’esattezza dell’imputazione in bilancio degli importi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la regolarità dei documenti giustificativi; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la conformità al principio della sana gestione finanziaria, in particolare secondo i criteri di cui all’articolo 101, paragrafo 2, primo comma, lettera a) o b).</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Con la nota di addebito il debitore è informato di quanto segue:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’Unione ha accertato il credito;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">non saranno applicati interessi di mora se il pagamento è effettuato entro la scadenza specificata nella nota di addebito;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se il pagamento non è effettuato entro la scadenza di cui alla lettera b) del presente comma, il debito produrrà interessi al tasso indicato all’articolo 99, ferma restando l’applicazione delle pertinenti norme specifiche;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se il pagamento non è effettuato entro la scadenza di cui alla lettera b), l’istituzione dell’Unione procederà al recupero mediante compensazione oppure mediante richiamo dell’eventuale garanzia costituita in precedenza;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se è necessario per tutelare gli interessi finanziari dell’Unione, il contabile può, in circostanze eccezionali, procedere al recupero mediante compensazione prima della scadenza di cui alla lettera b), se ha giustificati motivi di ritenere che altrimenti l’importo dovuto all’Unione andrebbe perduto e dopo aver informato il debitore dei motivi e della data del recupero mediante compensazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">qualora, esperite tutte le fasi di cui alle lettere da a) a e) del presente comma, non si sia ottenuto il recupero integrale del credito, l’istituzione dell’Unione procederà al recupero mediante esecuzione forzata del titolo ottenuto, in conformità dell’articolo 100, paragrafo 2, ovvero in via contenziosa.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Qualora, a seguito della verifica della designazione del debitore o sulla base di altre informazioni pertinenti disponibili al momento, risulti chiaro che l’obbligazione rientra nelle fattispecie di cui all’articolo 101, paragrafo 2, primo comma, lettere a) o b), o che la nota di addebito non è stata inviata conformemente al paragrafo 2 del presente articolo, l’ordinatore decide, dopo avere accertato il credito, di rinunciare direttamente al recupero conformemente all’articolo 101, senza l’invio di una nota di addebito, d’intesa con il contabile.</p>"], [null, "<p class=\"norm\">In tutti gli altri casi l’ordinatore stampa la nota di addebito e la invia al debitore. Il contabile è informato della spedizione della nota di addebito mediante il sistema di informazione finanziaria.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Gli importi indebitamente pagati sono recuperati.</div>\n</div>"]]}, "99": {"label": "Articolo 99", "heading": "Interessi di mora", "anchor": "art_99", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Fatte salve le disposizioni particolari risultanti dall’applicazione di normative specifiche, ogni importo esigibile non rimborsato alla scadenza di cui all’articolo 98, paragrafo 4, primo comma, lettera b), produce interessi a norma dei paragrafi 2 e 3 del presente articolo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Tranne nei casi di cui al paragrafo 4 del presente articolo, il tasso d’interesse da applicare agli importi esigibili non rimborsati alla scadenza di cui all’articolo 98, paragrafo 4, primo comma, lettera b), è quello applicato dalla Banca centrale europea alle sue principali operazioni di rifinanziamento, pubblicato nella <span class=\"italics\">Gazzetta ufficiale dell’Unione europea</span>, serie C, in vigore il primo giorno di calendario del mese della scadenza, maggiorato di:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">otto punti percentuali, quando il credito ha per fatto costitutivo un appalto di forniture o un appalto di servizi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">tre punti e mezzo percentuali, in tutti gli altri casi.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">L’importo degli interessi è calcolato con decorrenza dal giorno di calendario successivo alla scadenza di cui all’articolo 98, paragrafo 4, primo comma, lettera b), sino al giorno di calendario nel quale il debito è rimborsato integralmente.</div>\n</div>"], [null, "<p class=\"norm\">L’ordine di riscossione corrispondente all’importo degli interessi di mora è emesso quando tale interesse è effettivamente percepito.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Nel caso di ammende o altre sanzioni, il tasso d’interesse da applicare agli importi esigibili non rimborsati entro la scadenza di cui all’articolo 98, paragrafo 4, primo comma, lettera b), è quello applicato dalla Banca centrale europea alle sue principali operazioni di rifinanziamento, pubblicato nella <span class=\"italics\">Gazzetta ufficiale dell’Unione europea</span>, serie C, in vigore il primo giorno di calendario del mese in cui è stata adottata la decisione che irroga un’ammenda o altra sanzione, maggiorato di:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un punto e mezzo percentuale, quando il debitore costituisce una garanzia finanziaria accettata dal contabile in sostituzione del pagamento;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">tre punti e mezzo percentuali, in tutti gli altri casi.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Se la Corte di giustizia dell’Unione europea, nell’esercizio delle sue competenze ai sensi dell’articolo 261 TFUE, aumenta l’importo di un’ammenda o altra sanzione, gli interessi sull’importo dell’aumento decorrono dalla data della sentenza della Corte.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Nei casi in cui il tasso di interesse complessivo risulti negativo, esso è fissato allo zero percento.</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "100": {"label": "Articolo 100", "heading": "Ordini di riscossione", "anchor": "art_100", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L’ordinatore responsabile, emettendo un ordine di riscossione, impartisce al contabile l’istruzione di recuperare un credito accertato dall’ordinatore responsabile («autorizzazione del recupero»).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Un’istituzione dell’Unione può formalizzare l’accertamento di un credito a carico di persone diverse dagli Stati membri con una decisione che costituisce titolo esecutivo a norma dell’articolo 299 TFUE.</div>\n</div>"], [null, "<p class=\"norm\">Se la tutela efficace e tempestiva degli interessi finanziari dell’Unione lo impone, le altre istituzioni dell’Unione possono chiedere, in circostanze eccezionali, alla Commissione di adottare una decisione esecutiva di questo tipo a loro favore in riferimento a crediti sorti in relazione a membri del personale o a membri o ex membri di un’istituzione dell’Unione, a condizione che tali istituzioni abbiano concordato con la Commissione le modalità pratiche di applicazione del presente articolo.</p>"], [null, "<p class=\"norm\">Si ritiene sussistano circostanze eccezionali allorché non esiste alcuna prospettiva di recupero del debito da parte dell’istituzione dell’Unione interessata, né tramite il pagamento volontario né mediante compensazione a norma dell’articolo 101, paragrafo 1, e non vi sono le condizioni per rinunciare al recupero ai sensi dell’articolo 101, paragrafi 2 e 3. In ogni caso la decisione esecutiva specifica che il credito è iscritto nella sezione del bilancio relativa all’istituzione dell’Unione interessata, che agisce in veste di ordinatore. Le entrate sono iscritte come entrate generali, tranne qualora costituiscano entrate con destinazione specifica di cui all’articolo 21, paragrafo 3.</p>"], [null, "<p class=\"norm\">L’istituzione dell’Unione richiedente informa la Commissione di ogni evento idoneo ad alterare la riscossione e interviene a sostegno della Commissione in caso di impugnazione della decisione esecutiva.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "101": {"label": "Articolo 101", "heading": "Disposizioni in materia di recupero", "anchor": "art_101", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il contabile prende a carico gli ordini di riscossione dei crediti debitamente accertati dall’ordinatore responsabile. Il contabile è tenuto ad assicurare con la dovuta diligenza l’afflusso delle entrate nell’Unione e garantisce che i diritti di quest’ultima siano tutelati.</div>\n</div>"], [null, "<p class=\"norm\">Il rimborso parziale da parte di un debitore destinatario di vari ordini di riscossione è imputato innanzitutto al credito più remoto, salvo diversamente precisato dal debitore. Ogni pagamento parziale è imputato in primo luogo agli interessi.</p>"], [null, "<p class=\"norm\">Il contabile procede al recupero degli importi dovuti al bilancio mediante compensazione conformemente all’articolo 102.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">L’ordinatore responsabile può rinunciare, in tutto o in parte, a recuperare un credito accertato, soltanto nei casi seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">quando il costo prevedibile del recupero eccederebbe l’importo del credito e la rinuncia non pregiudica l’immagine dell’Unione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">quando è impossibile recuperare il credito a causa della sua vetustà, del ritardo nell’invio della nota di addebito conformemente all’articolo 98, paragrafo 2, dell’insolvenza del debitore o di eventuali altre procedure d’insolvenza;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">quando il recupero lede il principio di proporzionalità.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Qualora l’ordinatore responsabile intenda rinunciare, anche parzialmente, a recuperare un credito accertato, si assicura che la rinuncia sia regolare e conforme ai principi della sana gestione finanziaria e della proporzionalità. La decisione di rinunciare al recupero è motivata. L’ordinatore può delegare il potere di adottare detta decisione.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Nella fattispecie di cui al paragrafo 2, primo comma, lettera c), l’ordinatore responsabile osserva le procedure preventivamente stabilite da sua istituzione dell’Unione e applica in qualsiasi circostanza i seguenti criteri cogenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">natura dei fatti, in considerazione della gravità dell’irregolarità che ha dato luogo all’accertamento del credito (frode, recidiva, dolo, diligenza, buona fede, errore manifesto);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">impatto della rinuncia al recupero sull’attività dell’Unione e sui suoi interessi finanziari (importo in oggetto, rischio di costituire precedenti, lesione dell’autorità della legge).</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">In funzione delle circostanze specifiche, l’ordinatore responsabile tiene conto, se del caso, dei criteri aggiuntivi seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">eventuale distorsione della concorrenza provocata dalla rinuncia al recupero;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">danno economico e sociale che deriverebbe da un recupero totale del credito.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Ciascuna istituzione dell’Unione invia ogni anno al Parlamento europeo e al Consiglio una relazione sulle rinunce concesse dalla medesima a norma dei paragrafi 2, 3 e 4 del presente articolo. Le rinunce di entità inferiore a 60 000  EUR sono comunicate sotto forma di importo totale. Per quanto riguarda la Commissione, detta relazione è allegata alla sintesi delle relazioni annuali di attività di cui all’articolo 74, paragrafo 9.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">L’ordinatore responsabile può annullare, in tutto o in parte, un credito accertato. L’annullamento parziale di un credito accertato non implica la rinuncia al diritto accertato residuo dell’Unione.</div>\n</div>"], [null, "<p class=\"norm\">In caso di errore, l’ordinatore responsabile annulla, in tutto o in parte, il credito accertato e presenta adeguate giustificazioni.</p>"], [null, "<p class=\"norm\">Ogni istituzione dell’Unione stabilisce nel regolamento interno le condizioni e le modalità di delega del potere di annullare un credito accertato.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Spetta innanzitutto agli Stati membri svolgere controlli e audit e recuperare gli importi spesi indebitamente, come prevede la normativa settoriale. Nella misura in cui individuano e correggono le irregolarità per proprio conto, gli Stati membri sono esonerati da rettifiche finanziarie da parte della Commissione in relazione a dette irregolarità.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">La Commissione impone rettifiche finanziarie agli Stati membri al fine di escludere dai finanziamenti dell’Unione le spese sostenute in violazione del diritto applicabile. La Commissione basa le sue rettifiche finanziarie sull’individuazione degli importi spesi indebitamente e sulle implicazioni finanziarie per il bilancio. Se non è possibile un’identificazione precisa di tali importi, la Commissione può applicare rettifiche estrapolate o forfettarie in conformità della normativa settoriale.</div>\n</div>"], [null, "<p class=\"norm\">Nel decidere l’ammontare di una rettifica finanziaria, la Commissione tiene conto della natura e della gravità della violazione del diritto applicabile e delle implicazioni finanziarie per il bilancio, comprese le carenze a livello dei sistemi di gestione e di controllo.</p>"], [null, "<p class=\"norm\">I criteri per stabilire le rettifiche finanziarie e la procedura da seguire possono essere previsti nella normativa settoriale.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">9.  </span>\n<div class=\"norm inline-element\">La metodologia per l’applicazione di rettifiche estrapolate o forfettarie è stabilita conformemente alla normativa settoriale onde consentire alla Commissione di tutelare gli interessi finanziari dell’Unione.</div>\n</div>"]]}, "102": {"label": "Articolo 102", "heading": "Recupero mediante compensazione", "anchor": "art_102", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Quando un debitore vanta nei confronti dell’Unione o di un’agenzia esecutiva, allorché esegue il bilancio, un credito che sia certo, a norma dell’articolo 98, paragrafo 3, lettera a), liquido ed esigibile, corrispondente a un importo indicato in un ordine di pagamento, il contabile procede, dopo la scadenza di cui all’articolo 98, paragrafo 4, primo comma, lettera b), al recupero del credito mediante compensazione.</div>\n</div>"], [null, "<p class=\"norm\">In circostanze eccezionali, se è necessario per tutelare gli interessi finanziari dell’Unione e se ha giustificati motivi di ritenere che altrimenti l’importo dovuto all’Unione andrebbe perduto, il contabile può procedere al recupero mediante compensazione prima della scadenza di cui all’articolo 98, paragrafo 4, primo comma, lettera b).</p>"], [null, "<p class=\"norm\">Il contabile può procedere inoltre al recupero mediante compensazione prima della scadenza di cui all’articolo 98, paragrafo 4, primo comma, lettera b), se il debitore acconsente.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Prima di procedere a un recupero ai sensi del paragrafo 1 del presente articolo, il contabile consulta l’ordinatore responsabile e informa i debitori interessati, anche per quanto riguarda i mezzi di ricorso di cui all’articolo 133.</div>\n</div>"], [null, "<p class=\"norm\">Quando il debitore è un’autorità nazionale o uno dei suoi organi amministrativi, il contabile informa altresì lo Stato membro interessato della sua intenzione di effettuare il recupero mediante compensazione almeno dieci giorni lavorativi prima di procedere in tal senso. Tuttavia, di concerto con lo Stato membro o con l’organo amministrativo interessato, il contabile può procedere al recupero mediante compensazione prima del decorso di tale termine.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La compensazione di cui al paragrafo 1 ha il medesimo effetto del pagamento ed estingue il debito e i relativi interessi eventualmente dovuti dall’Unione.</div>\n</div>"]]}, "103": {"label": "Articolo 103", "heading": "Procedura di recupero in caso di mancato pagamento volontario", "anchor": "art_103", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Fatto salvo l’articolo 102, se l’importo del credito non è stato recuperato integralmente alla scadenza di cui all’articolo 98, paragrafo 4, primo comma, lettera b), il contabile ne informa l’ordinatore responsabile e inizia senza indugio la procedura di recupero mediante ogni mezzo offerto dalla legge, incluso il richiamo dell’eventuale garanzia costituita in precedenza.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Fatto salvo l’articolo 102, quando non è esperibile la modalità di recupero di cui al paragrafo 1 del presente articolo e il debitore non ha eseguito il pagamento malgrado una costituzione in mora inviatagli dal contabile, quest’ultimo procede al recupero mediante esecuzione forzata del titolo ottenuto, in conformità dell’articolo 100, paragrafo 2, ovvero in via contenziosa.</div>\n</div>"]]}, "104": {"label": "Articolo 104", "heading": "Concessione di dilazioni di pagamento", "anchor": "art_104", "frags": [[null, "<p class=\"norm\">Il contabile può, di concerto con l’ordinatore responsabile, accordare dilazioni dei termini di pagamento solamente dietro domanda scritta e motivata del debitore, alle condizioni seguenti:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">che il debitore si impegni a pagare gli interessi, al tasso previsto all’articolo 99, per tutto il periodo della dilazione accordatagli, a decorrere dalla scadenza di cui all’articolo 98, paragrafo 4, primo comma, lettera b);</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">che il debitore costituisca, per tutelare i diritti dell’Unione, una garanzia finanziaria, accettata dal contabile dell’istituzione dell’Unione, che copra il debito insoluto sia in capitale che in interessi.</p>\n</div>\n</div>"], [null, "<p class=\"norm\">La garanzia di cui al primo comma, lettera b), può essere sostituita dalla fideiussione in solido di un terzo approvata dal contabile dell’istituzione dell’Unione.</p>"], [null, "<p class=\"norm\">In circostanze eccezionali, su domanda del debitore, il contabile può rinunciare a richiedere la garanzia di cui al primo comma, lettera b), allorché valuti che il debitore vuole e può effettuare il pagamento entro il periodo della dilazione, ma non è in grado di costituire siffatta garanzia e si trova in una situazione di difficoltà finanziaria.</p>"]]}, "105": {"label": "Articolo 105", "heading": "Prescrizione", "anchor": "art_105", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Fatte salve le disposizioni di normative specifiche e l’applicazione della decisione 2014/335/UE, Euratom, ai crediti dell’Unione nei confronti di terzi e ai crediti di terzi nei confronti dell’Unione si applica un termine di prescrizione di cinque anni.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il termine di prescrizione per i crediti dell’Unione nei confronti di terzi decorre dalla scadenza del termine di cui all’articolo 98, paragrafo 4, primo comma, lettera b).</div>\n</div>"], [null, "<p class=\"norm\">Il termine di prescrizione per i crediti di terzi nei confronti dell’Unione decorre dalla data in cui il pagamento del credito del terzo è esigibile in base al corrispondente impegno giuridico.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il termine di prescrizione per i crediti dell’Unione nei confronti di terzi è interrotto da qualsiasi atto inteso a recuperare il credito compiuto da un’istituzione dell’Unione, ovvero da uno Stato membro su richiesta di un’istituzione dell’Unione, e comunicato al terzo.</div>\n</div>"], [null, "<p class=\"norm\">Il termine di prescrizione per i crediti di terzi nei confronti dell’Unione è interrotto da qualsiasi atto inteso a recuperare il credito comunicato all’Unione dai suoi creditori o per conto di essi.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Un nuovo termine di prescrizione di cinque anni decorre dal giorno successivo alle interruzioni di cui al paragrafo 3.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Interrompe il termine di prescrizione ogni azione legale relativa a un credito ai sensi del paragrafo 2, comprese le azioni intentate dinanzi a un giudice che successivamente declini la propria competenza. Un nuovo periodo di prescrizione di cinque anni comincia a decorrere allorché sia stata pronunciata una sentenza e questa sia passata in giudicato oppure le medesime parti siano giunte a una composizione stragiudiziale riguardo alla medesima azione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">La dilazione di pagamento concessa dal contabile a norma dell’articolo 104 interrompe il termine di prescrizione. Un nuovo termine di prescrizione di cinque anni inizia a decorrere dal giorno successivo alla scadenza del periodo di dilazione del pagamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Non si procede al recupero dei crediti dell’Unione dopo la scadenza del termine di prescrizione di cui ai paragrafi da 2 a 6.</div>\n</div>"]]}, "106": {"label": "Articolo 106", "heading": "Trattamento nazionale dei crediti dell’Unione", "anchor": "art_106", "frags": [[null, "<p class=\"norm\">Nel caso di una procedura d’insolvenza, ai crediti dell’Unione è riservato lo stesso trattamento preferenziale concesso ai crediti di uguale natura dovuti a organismi pubblici degli Stati membri in cui ha luogo il procedimento di recupero.</p>"]]}, "107": {"label": "Articolo 107", "heading": "Ammende, altre penali, sanzioni e interessi irrogati dalle istituzioni dell’Unione", "anchor": "art_107", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli importi riscossi a titolo di ammende, altre penali e sanzioni, nonché gli interessi e altri proventi prodotti, non sono iscritti in bilancio per il periodo in cui le corrispondenti decisioni sono o potrebbero ancora diventare oggetto di ricorso dinanzi alla Corte di giustizia dell’Unione europea.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Gli importi di cui al paragrafo 1 sono iscritti in bilancio con la massima tempestività dopo l’esaurimento di tutti i mezzi di impugnazione. In circostanze eccezionali debitamente giustificate o qualora tutti i mezzi di impugnazione siano stati esperiti dopo il 1<span class=\"superscript\">o</span> settembre dell’esercizio in corso, gli importi possono essere iscritti in bilancio nell’esercizio successivo.</div>\n</div>"], [null, "<p class=\"norm\">Gli importi che, a seguito di una sentenza della Corte di giustizia dell’Unione europea, devono essere restituiti all’entità che li ha versati non sono iscritti in bilancio.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il paragrafo 1 non si applica alle decisioni di liquidazione dei conti o di rettifica finanziaria.</div>\n</div>"]]}, "108": {"label": "Articolo 108", "heading": "Recupero di ammende, altre penali o sanzioni irrogate dalle istituzioni dell’Unione", "anchor": "art_108", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Quando dinanzi alla Corte di giustizia dell’Unione europea è intentata un’azione legale contro la decisione di un’istituzione dell’Unione che irroga un’ammenda o altra penale o sanzione prevista dal TFUE o dal trattato Euratom, e fintantoché non sono stati esperiti tutti i mezzi di impugnazione, il debitore paga, a titolo provvisorio, gli importi corrispondenti sul conto bancario indicato dal contabile della Commissione oppure costituisce una garanzia finanziaria accettabile per il contabile della Commissione. Tale garanzia è distinta dall’obbligo di pagare l’ammenda o altra penale o sanzione ed è richiamata su richiesta. Essa copre il debito sia in capitale che in interessi dovuti a norma dell’articolo 99, paragrafo 4.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La Commissione garantisce gli importi riscossi in via provvisoria investendoli in attivi finanziari, assicurando in tal modo la sicurezza e la liquidità delle somme di denaro e prefiggendosi al tempo stesso di ottenere un rendimento positivo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Una volta che sono esauriti tutti i mezzi di impugnazione e l’ammenda, l’altra penale o la sanzione è stata confermata dalla Corte di giustizia dell’Unione europea, o qualora la decisione che irroga tale ammenda, altra penale o sanzione non possa più diventare oggetto di ricorso dinanzi alla Corte di giustizia dell’Unione europea, è adottata una delle seguenti misure:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli importi riscossi a titolo provvisorio e il rendimento che generano sono iscritti in bilancio conformemente all’articolo 107, paragrafo 2;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se è stata costituita una garanzia finanziaria, questa è richiamata e i relativi importi sono iscritti in bilancio.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Se la Corte di giustizia dell’Unione europea ha aumentato l’importo dell’ammenda, dell’altra penale o della sanzione, si applica il primo comma, lettere a) e b), del presente paragrafo fino a concorrenza degli importi della decisione originaria dell’istituzione dell’Unione o, se del caso, dell’importo definito da una precedente sentenza della Corte di giustizia dell’Unione europea nello stesso procedimento. Il contabile della Commissione riscuote l’importo corrispondente all’aumento e agli interessi dovuti a norma dell’articolo 99, paragrafo 4, che sono iscritti in bilancio.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Quando sono stati esperiti tutti i mezzi di impugnazione e l’ammenda, l’altra penale o sanzione è stata annullata o ne è stato ridotto l’importo, è adottata una delle seguenti misure:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli importi riscossi in via provvisoria o, in caso di una loro riduzione, la parte pertinente di essi, sono rimborsati al terzo interessato, compresi eventuali rendimenti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se è stata costituita una garanzia finanziaria, essa è di conseguenza svincolata.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Nei casi di cui al primo comma, lettera a), se il rendimento complessivo dell’importo riscosso in via provvisoria è negativo, la perdita subita è detratta dall’importo da rimborsare.</p>"]]}, "109": {"label": "Articolo 109", "heading": "Interessi compensativi", "anchor": "art_109", "frags": [[null, "<p class=\"norm\">Fatti salvi l’articolo 99, paragrafo 2, e l’articolo 116, paragrafo 5, e nei casi diversi dalle ammende, altre penali e sanzioni di cui agli articoli 107 e 108, quando un importo deve essere rimborsato a seguito di una sentenza della Corte di giustizia dell’Unione europea o a seguito di una transazione, il tasso d’interesse è quello applicato dalla Banca centrale europea alle sue principali operazioni di rifinanziamento, pubblicato nella <span class=\"italics\">Gazzetta ufficiale dell’Unione europea</span>, serie C, il primo giorno di calendario di ciascun mese. Il tasso d’interesse non deve essere negativo. Gli interessi decorrono dalla data di pagamento dell’importo da rimborsare fino alla data di rimborso stabilita.</p>"], [null, "<p class=\"norm\">Nei casi in cui il tasso di interesse complessivo risulta negativo, esso è fissato allo zero percento.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "110": {"label": "Articolo 110", "heading": "Decisioni di finanziamento", "anchor": "art_110", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Un impegno di bilancio è preceduto da una decisione di finanziamento adottata dall’istituzione dell’Unione o dall’autorità da questa delegata. Le decisioni di finanziamento possono avere valore annuale o pluriennale.</div>\n</div>"], [null, "<p class=\"norm\">Il primo comma del presente paragrafo non si applica agli stanziamenti destinati al funzionamento di ciascuna istituzione dell’Unione a titolo della sua autonomia amministrativa che possono essere eseguiti senza un atto di base, conformemente all’articolo 58, paragrafo 2, lettera e), alle spese di sostegno amministrativo e ai contributi agli organismi dell’Unione di cui agli articoli 70 e 71.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La decisione di finanziamento costituisce al tempo stesso il programma di lavoro annuale o pluriennale ed è adottata, se del caso, il più presto possibile dopo l’adozione del progetto di bilancio e comunque, in linea di principio, non oltre il 31 marzo dell’anno di attuazione. Se il pertinente atto di base prevede modalità specifiche per l’adozione di una decisione di finanziamento o di un programma di lavoro, o di entrambi, tali modalità sono applicate alla parte della decisione di finanziamento che costituisce il programma di lavoro, in conformità delle prescrizioni dell’atto di base. La parte della decisione che costituisce il programma di lavoro è pubblicata sul sito web dell’istituzione dell’Unione interessata immediatamente dopo la sua adozione e prima della sua attuazione. La decisione di finanziamento riporta l’importo totale coperto e contiene una descrizione delle azioni da finanziare. In particolare, essa indica:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’atto di base e la linea di bilancio;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli obiettivi da perseguire e i risultati attesi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i metodi di esecuzione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">eventuali informazioni supplementari sul programma di lavoro richieste dall’atto di base.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">In aggiunta agli elementi di cui al paragrafo 2, la decisione di finanziamento stabilisce:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nel caso delle sovvenzioni: la tipologia dei richiedenti destinatari dell’invito a presentare proposte o dell’attribuzione diretta e la dotazione di bilancio globale riservata alle sovvenzioni;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nel caso degli appalti: la dotazione di bilancio globale riservata agli appalti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nel caso dei contributi ai fondi fiduciari dell’Unione di cui all’articolo 234: gli stanziamenti riservati al fondo fiduciario per l’esercizio e gli importi previsti per l’intera sua durata provenienti dal bilancio, nonché da altri donatori;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nel caso dei premi: la tipologia dei partecipanti cui è destinato il concorso, la dotazione di bilancio globale riservata al concorso e un riferimento specifico ai premi aventi un valore unitario pari o superiore a 1 000 000  EUR;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nel caso degli strumenti finanziari: l’importo stanziato per lo strumento finanziario;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nel caso della gestione indiretta: la persona o l’entità che esegue i fondi dell’Unione a norma dell’articolo 62, paragrafo 1, primo comma, lettera c), o i criteri da utilizzare per la selezione della persona o dell’entità;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nel caso dei contributi ai meccanismi o alle piattaforme di finanziamento misto: l’importo stanziato per il meccanismo o la piattaforma di finanziamento misto e l’elenco delle entità che vi partecipano;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nel caso delle garanzie di bilancio: l’importo della copertura annuale e, se del caso, l’importo della garanzia di bilancio da svincolare.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">L’ordinatore delegato può aggiungere qualsiasi altra informazione che ritiene opportuna nella rispettiva decisione di finanziamento che costituisce il programma di lavoro o in qualsiasi altro documento pubblicato sul sito web dell’istituzione dell’Unione.</div>\n</div>"], [null, "<p class=\"norm\">La decisione di finanziamento pluriennale è coerente con la programmazione finanziaria di cui all’articolo 41, paragrafo 2, e precisa che l’attuazione della decisione è subordinata alla disponibilità degli stanziamenti di bilancio per i rispettivi esercizi dopo l’adozione del bilancio o in base a quanto previsto dal regime dei dodicesimi provvisori.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Fatte salve eventuali disposizioni specifiche dell’atto di base, per ogni modifica sostanziale di una decisione di finanziamento già adottata è seguita la medesima procedura prevista per la decisione iniziale.</div>\n</div>"]]}, "111": {"label": "Articolo 111", "heading": "Operazioni di spesa", "anchor": "art_111", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Tutte le spese sono oggetto di un impegno, di una convalida, dell’emissione di un ordine di pagamento e di un pagamento.</div>\n</div>"], [null, "<p class=\"norm\">Al termine dei periodi di cui all’articolo 114, il saldo non eseguito degli impegni di bilancio è disimpegnato.</p>"], [null, "<p class=\"norm\">Nell’esecuzione di operazioni, l’ordinatore responsabile verifica la conformità della spesa rispetto ai trattati, al bilancio, al presente regolamento e agli altri atti adottati a norma dei trattati, nonché al principio della sana gestione finanziaria.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Gli impegni di bilancio e gli impegni giuridici sono assunti dallo stesso ordinatore, salvo in casi debitamente giustificati. In particolare, nell’ambito degli aiuti erogati per situazioni di crisi e delle operazioni di aiuto umanitario, gli impegni giuridici possono essere assunti dai capi delle delegazioni dell’Unione o, in loro assenza, dai rispettivi vice, su istruzione dell’ordinatore responsabile della Commissione, il quale conserva comunque la piena responsabilità dell’operazione sottostante. Il personale impiegato dalla Commissione nell’ambito degli aiuti erogati per situazioni di crisi e delle operazioni di aiuto umanitario può firmare gli impegni giuridici collegati a pagamenti a valere su casse di anticipi di importi non superiori a 2 500  EUR.</div>\n</div>"], [null, "<p class=\"norm\">L’ordinatore responsabile assume un impegno di bilancio prima di contrarre un impegno giuridico nei confronti di terzi o di trasferire fondi a un fondo fiduciario dell’Unione di cui all’articolo 234.</p>"], [null, "<p class=\"norm inline-element\">Il secondo comma del presente paragrafo non si applica:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">agli impegni giuridici contratti a seguito di una dichiarazione di situazione di crisi nell’ambito di un piano di continuità operativa, in conformità delle procedure adottate dalla Commissione o da qualsiasi altra istituzione dell’Unione a titolo della sua autonomia amministrativa;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">in caso di operazioni di aiuto umanitario, di operazioni di protezione civile e di aiuti erogati per situazioni di crisi, se l’efficacia dell’intervento dell’Unione richiede l’assunzione immediata di un impegno giuridico nei confronti di terzi e se prima non è possibile procedere a un impegno di bilancio specifico.</p>\n</div>\n</div>"], [null, "<p class=\"norm\">Nei casi di cui al terzo comma, lettera b), all’impegno di bilancio si procede senza ritardi dopo aver assunto un impegno giuridico nei confronti di terzi.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">L’ordinatore responsabile convalida una spesa accettando che una voce di spesa sia imputata al bilancio, previa verifica dei documenti giustificativi che attestano i diritti del creditore secondo le condizioni fissate dall’impegno giuridico, quando questo esiste. A tale scopo, l’ordinatore responsabile:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">verifica l’esistenza dei diritti del creditore;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">determina o verifica l’esistenza e l’importo del credito attraverso la menzione «conforme ai fatti»;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">verifica le condizioni di esigibilità del credito.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Fatto salvo il primo comma, la convalida delle spese si applica anche alle relazioni intermedie o finali non associate a richieste di pagamento, nel qual caso l’impatto sul sistema contabile si limita alla contabilità generale.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La decisione di convalida ha luogo tramite firma elettronica con caratteristiche di sicurezza a norma dell’articolo 146 da parte dell’ordinatore o di un membro del personale tecnicamente competente debitamente autorizzato mediante decisione formale dell’ordinatore oppure, eccezionalmente, nel caso di documenti su supporto cartaceo, tramite il timbro che riproduce la firma.</div>\n</div>"], [null, "<p class=\"norm inline-element\">Con la menzione «conforme ai fatti», l’ordinatore responsabile o un membro del personale tecnicamente competente, debitamente autorizzato dall’ordinatore responsabile, certifica:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nel caso dei prefinanziamenti: che risultano soddisfatte le condizioni fissate dall’impegno giuridico per il versamento del prefinanziamento;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nel caso dei pagamenti intermedi e a saldo relativi agli appalti: che i servizi contrattuali sono stati regolarmente prestati, che le forniture contrattuali sono state regolarmente consegnate o che i lavori contrattuali sono stati regolarmente eseguiti;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nel caso dei pagamenti intermedi e a saldo relativi alle sovvenzioni: che l’azione o il programma di lavoro svolto dal beneficiario è conforme sotto tutti gli aspetti alla convenzione di sovvenzione, nonché, se del caso, che i costi dichiarati dal beneficiario sono ammissibili.</p>\n</div>\n</div>"], [null, "<p class=\"norm\">Nel caso di cui al secondo comma, lettera c), le stime dei costi non sono ritenute conformi ai criteri di ammissibilità di cui all’articolo 186, paragrafo 3. Lo stesso principio si applica anche alle relazioni intermedie o finali non associate a richieste di pagamento.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Per autorizzare la spesa, l’ordinatore responsabile emette, previa verifica della disponibilità degli stanziamenti, un ordine di pagamento per dare istruzione al contabile di pagare l’importo della spesa precedentemente convalidata.</div>\n</div>"], [null, "<p class=\"norm\">Nei casi in cui siano effettuati pagamenti periodici riguardanti prestazioni di servizi, compresi i servizi di locazione, o consegne di beni, l’ordinatore può, fatta salva l’analisi dei rischi del medesimo, ordinare l’applicazione di un sistema di addebito diretto da una cassa di anticipi. L’applicazione di tale sistema può altresì essere ordinata su espressa autorizzazione del contabile, conformemente all’articolo 86, paragrafo 3.</p>"]]}, "112": {"label": "Articolo 112", "heading": "Tipi di impegni di bilancio", "anchor": "art_112", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Gli impegni di bilancio rientrano in una delle seguenti categorie:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">impegno di bilancio specifico: quando il destinatario e l’importo della spesa sono determinati;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">impegno di bilancio globale: quando almeno uno degli elementi necessari a definire l’impegno come specifico rimane indeterminato;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">impegno di bilancio accantonato: quando è destinato a coprire le spese di gestione corrente del FEAGA di cui all’articolo 11, paragrafo 2, e le spese correnti di natura amministrativa il cui importo o i cui beneficiari finali non sono determinati in modo definitivo.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">In deroga al primo comma, lettera c), le spese correnti di natura amministrativa relative alle delegazioni dell’Unione e rappresentanze dell’Unione possono essere coperte da impegni di bilancio accantonati anche quando l’importo e il beneficiario finale sono determinati.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Gli impegni di bilancio per azioni la cui realizzazione si estende su più esercizi possono essere ripartiti su più esercizi in frazioni annue solo quando ciò è previsto dall’atto di base o se si tratta di spese amministrative.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">L’impegno di bilancio globale è effettuato sulla base di una decisione di finanziamento.</div>\n</div>"], [null, "<p class=\"norm\">L’impegno di bilancio globale interviene al più tardi prima della decisione relativa ai destinatari e agli importi e, qualora l’esecuzione degli stanziamenti interessati implichi l’adozione di un programma di lavoro, non prima dell’adozione di quest’ultimo.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Un impegno di bilancio globale è eseguito o con la conclusione di una convenzione di finanziamento che prevede a sua volta l’assunzione ulteriore di uno o più impegni giuridici, o con l’assunzione di uno o più impegni giuridici.</div>\n</div>"], [null, "<p class=\"norm\">Le convenzioni di finanziamento nell’ambito dell’assistenza finanziaria diretta ai paesi terzi, compreso il sostegno di bilancio, che costituiscono impegni giuridici, possono dare luogo a pagamenti senza la conclusione di altri impegni giuridici.</p>"], [null, "<p class=\"norm\">Il paragrafo 3, secondo comma, non si applica qualora l’impegno di bilancio globale sia eseguito mediante la conclusione di una convenzione di finanziamento.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Ciascun impegno giuridico specifico assunto a seguito di un impegno di bilancio globale è registrato dall’ordinatore responsabile, prima della firma, nella contabilità di bilancio centrale, mediante imputazione dell’impegno di bilancio globale.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Gli impegni di bilancio accantonati sono eseguiti con l’assunzione di uno o più impegni giuridici da cui sorge il diritto a pagamenti ulteriori. Tuttavia, per quanto riguarda le spese per la gestione del personale, le spese per i membri o ex membri di un’istituzione dell’Unione o le spese sostenute dalle istituzioni dell’Unione per le attività di comunicazione relative all’attualità dell’Unione o nei casi di cui al punto 14.5 dell’allegato I, essi possono essere eseguiti direttamente con i pagamenti senza l’assunzione di precedenti impegni giuridici.</div>\n</div>"]]}, "113": {"label": "Articolo 113", "heading": "Impegni relativi a stanziamenti del FEAGA", "anchor": "art_113", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Per ogni esercizio gli stanziamenti del FEAGA includono gli stanziamenti non dissociati per le spese correlate alle misure di cui all’articolo 4, paragrafo 1, del regolamento (UE) n. 1306/2013. Le spese correlate alle misure di cui all’articolo 4, paragrafo 2, e all’articolo 6 di tale regolamento, tranne che per le misure finanziate a titolo dell’assistenza tecnica non operativa e i contributi a favore di agenzie esecutive, sono coperte con stanziamenti dissociati.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le decisioni della Commissione che stabiliscono l’importo dei rimborsi delle spese correlate al FEAGA sostenute dagli Stati membri costituiscono impegni di bilancio accantonati globali, che non superano il totale degli stanziamenti iscritti nel bilancio per il FEAGA.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Gli impegni di bilancio accantonati globali per il FEAGA, effettuati a titolo di un esercizio e che non hanno dato luogo, entro il 1<span class=\"superscript\">o</span> febbraio dell’esercizio successivo, a impegni di bilancio dettagliati, sono disimpegnati con riferimento all’esercizio in questione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Le spese effettuate dai servizi e dagli organismi di cui alla normativa sul FEAGA formano oggetto, entro due mesi dalla ricezione degli stati trasmessi dagli Stati membri, di un impegno per capitolo, articolo e voce. Si può procedere a tale impegno dopo la scadenza del suddetto termine di due mesi qualora sia necessaria una procedura di storno di stanziamenti relativi alle pertinenti linee di bilancio. Salvo il caso in cui il pagamento da parte degli Stati membri non sia ancora avvenuto oppure vi siano dubbi quanto all’ammissibilità, l’imputazione in pagamento avviene entro lo stesso termine di due mesi.</div>\n</div>"], [null, "<p class=\"norm\">Gli impegni di cui al primo comma del presente paragrafo sono detratti dall’impegno di bilancio accantonato globale di cui al paragrafo 1.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">I paragrafi 2 e 3 si applicano con riserva dell’esame e dell’accettazione dei conti.</div>\n</div>"]]}, "114": {"label": "Articolo 114", "heading": "Termini relativi agli impegni", "anchor": "art_114", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Fatti salvi gli articoli 111, paragrafo 2, e 264, paragrafo 3, gli impegni giuridici inerenti a impegni di bilancio specifici o accantonati sono assunti entro il 31 dicembre dell’anno n, dove l’anno n è l’anno in cui è stato assunto l’impegno di bilancio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Gli impegni di bilancio globali coprono il costo totale dei relativi impegni giuridici assunti fino al 31 dicembre dell’anno n+1.</div>\n</div>"], [null, "<p class=\"norm\">Quando l’impegno di bilancio globale comporta l’assegnazione di un premio di cui al titolo IX, l’impegno giuridico di cui all’articolo 207, paragrafo 4, è assunto entro il 31 dicembre dell’anno n+3.</p>"], [null, "<p class=\"norm\">Per quanto riguarda le azioni esterne, ove l’impegno di bilancio globale comporti la conclusione di una convenzione di finanziamento con un paese terzo, quest’ultima è conclusa entro il 31 dicembre dell’anno n+1. In tal caso l’impegno di bilancio globale copre i costi totali degli impegni giuridici che attuano la convenzione di finanziamento conclusa entro un periodo di tre anni a decorrere dalla data di conclusione della medesima.</p>"], [null, "<p class=\"norm inline-element\">Tuttavia, l’impegno di bilancio globale copre i costi totali degli impegni giuridici assunti fino al termine del periodo di attuazione della convenzione di finanziamento nei casi seguenti:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">azioni finanziate da una pluralità di donatori;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">operazioni di finanziamento misto;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">impegni giuridici relativi all’audit e alla valutazione;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le seguenti circostanze eccezionali:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">modifiche apportate a impegni giuridici già assunti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">impegni giuridici che devono essere assunti dopo la risoluzione anticipata di un impegno giuridico esistente;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">variazioni dell’entità incaricata dell’esecuzione.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Il terzo e quarto comma del paragrafo 2 non si applicano ai seguenti programmi pluriennali attuati mediante impegni frazionati:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">strumento di assistenza preadesione istituito dal regolamento (UE) n. 231/2014 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">10</span>\n);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">strumento europeo di vicinato istituito dal regolamento (UE) n. 232/2014 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">11</span>\n).</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Nei casi di cui al primo comma gli stanziamenti sono automaticamente disimpegnati dalla Commissione in conformità della normativa settoriale.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Gli impegni di bilancio specifici e accantonati per azioni la cui realizzazione si estende su più esercizi comportano, tranne quando si tratta di spese per il personale, un termine finale di esecuzione fissato conformemente alle condizioni previste dagli impegni giuridici cui si riferiscono e tenendo conto del principio della sana gestione finanziaria.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Le frazioni degli impegni di bilancio non eseguite tramite pagamento nei sei mesi successivi al termine finale di esecuzione sono oggetto di disimpegno.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">L’importo di un impegno di bilancio per il quale non è stato effettuato alcun pagamento ai sensi dell’articolo 115 entro i due anni successivi all’assunzione dell’impegno giuridico è oggetto di disimpegno, salvo qualora tale importo sia relativo a un caso oggetto di contenzioso in sede giudiziaria o arbitrale, qualora l’impegno giuridico consista in una convenzione di finanziamento con un paese terzo o la normativa settoriale preveda disposizioni specifiche.</div>\n</div>"]]}, "115": {"label": "Articolo 115", "heading": "Tipi di pagamenti", "anchor": "art_115", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il pagamento delle spese è eseguito dal contabile nei limiti dei fondi disponibili.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Il pagamento si basa sulla prova della conformità dell’azione corrispondente al contratto, all’accordo o all’atto di base e consiste in uno o più delle seguenti operazioni:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il pagamento della totalità degli importi dovuti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il pagamento degli importi dovuti secondo una delle modalità seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un prefinanziamento che fornisce un fondo di tesoreria, che può essere frazionato in più versamenti secondo il principio della sana gestione finanziaria; tale importo di prefinanziamento è pagato in base al contratto, all’accordo o all’atto di base, oppure in base ai documenti giustificativi che consentono di verificare il rispetto delle disposizioni del contratto o dell’accordo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">uno o più pagamenti intermedi in contropartita dell’esecuzione parziale dell’azione o del contratto o dell’accordo che possono liquidare in tutto o in parte il prefinanziamento, fatto salvo l’atto di base;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un pagamento a saldo degli importi dovuti ove l’azione o il contratto o l’accordo siano stati integralmente eseguiti;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il versamento di un accantonamento nel fondo comune di copertura ai sensi dell’articolo 212.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Il pagamento a saldo liquida tutte le spese precedenti. Per il recupero degli importi non utilizzati è emesso un ordine di riscossione.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Nella preparazione dei conti di bilancio i diversi tipi di pagamento di cui al paragrafo 2 sono distinti al momento dell’esecuzione di ogni pagamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Le norme contabili di cui all’articolo 80 comprendono le norme in materia di liquidazione contabile dei prefinanziamenti e di riconoscimento dell’ammissibilità dei costi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">I prefinanziamenti sono liquidati periodicamente dall’ordinatore responsabile in base alla natura economica del progetto e al più tardi al termine dello stesso. La liquidazione è effettuata sulla base delle informazioni sui costi sostenuti o della conferma che le condizioni per il pagamento risultano soddisfatte a norma dell’articolo 125, sulla base della convalida dell’ordinatore in conformità dell’articolo 111, paragrafo 3.</div>\n</div>"], [null, "<p class=\"norm\">Per le convenzioni di sovvenzione, i contratti o gli accordi di contributo di valore superiore a 5 000 000  EUR, l’ordinatore acquisisce alla fine di ciascun esercizio almeno le informazioni necessarie a calcolare una stima ragionevole dei costi. Tali informazioni non sono utilizzate per liquidare i prefinanziamenti, ma possono essere utilizzate dall’ordinatore e dal contabile per rispettare l’articolo 82, paragrafo 2.</p>"], [null, "<p class=\"norm\">Ai fini del secondo comma, negli impegni giuridici assunti sono inserite opportune disposizioni.</p>"]]}, "116": {"label": "Articolo 116", "heading": "Termini relativi ai pagamenti", "anchor": "art_116", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">I pagamenti sono effettuati entro:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">90 giorni di calendario per gli accordi di contributo, i contratti e le convenzioni di sovvenzione riguardanti servizi o azioni di carattere tecnico la cui valutazione è particolarmente complessa e il cui pagamento dipende dall’approvazione di una relazione o di un certificato;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">60 giorni di calendario per tutti gli altri accordi di contributo, contratti e convenzioni di sovvenzione il cui pagamento dipende dall’approvazione di una relazione o di un certificato;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">30 giorni di calendario per tutti gli altri accordi di contributo, contratti e convenzioni di sovvenzione.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il termine per effettuare il pagamento si intende comprensivo delle operazioni di convalida, di ordinazione e di pagamento delle spese.</div>\n</div>"], [null, "<p class=\"norm\">Esso decorre dalla data di ricezione della richiesta di pagamento.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La richiesta di pagamento è registrata tempestivamente dall’ufficio autorizzato dell’ordinatore responsabile e si considera ricevuta alla data di registrazione.</div>\n</div>"], [null, "<p class=\"norm\">Si considera data di pagamento la data di addebito sul conto dell’istituzione dell’Unione.</p>"], [null, "<p class=\"norm inline-element\">La richiesta di pagamento riporta i seguenti elementi essenziali:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli estremi del creditore;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’importo;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la valuta;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la data.</p>\n</div>\n</div>"], [null, "<p class=\"norm\">La mancanza di anche uno solo degli elementi essenziali comporta il rigetto della richiesta di pagamento.</p>"], [null, "<p class=\"norm\">Il creditore è informato per iscritto di un rigetto e delle sue motivazioni, tempestivamente e comunque entro 30 giorni di calendario dalla data di ricezione della richiesta di pagamento.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">L’ordinatore responsabile può sospendere il termine di pagamento nei seguenti casi:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’importo del pagamento richiesto non è dovuto, oppure</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">non sono stati presentati i documenti giustificativi adeguati.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Se l’ordinatore responsabile viene a conoscenza di informazioni che lo inducono a dubitare dell’ammissibilità delle spese di una richiesta di pagamento, può sospendere il termine per il pagamento al fine di verificare, anche attraverso verifiche sul posto, il carattere ammissibile delle spese. Il rimanente periodo utile per il pagamento riprende a decorrere dalla data di ricezione delle informazioni richieste o dei documenti rivisti o dalla data di esecuzione delle ulteriori verifiche necessarie, ivi comprese le verifiche sul posto.</p>"], [null, "<p class=\"norm\">Ai creditori interessati sono comunicati per iscritto i motivi della sospensione.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Tranne nel caso degli Stati membri, della BEI e del FEI, alla scadenza dei termini stabiliti al paragrafo 1, il creditore ha diritto agli interessi, alle seguenti condizioni:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i tassi d’interesse sono quelli indicati all’articolo 99, paragrafo 2;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli interessi sono pagati per il periodo decorrente dal giorno di calendario successivo alla scadenza del termine di pagamento stabilito al paragrafo 1 fino alla data in cui il pagamento è effettuato.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Tuttavia, qualora gli interessi calcolati in conformità del primo comma siano pari o inferiori a 200 EUR, sono versati al creditore soltanto previa richiesta presentata entro due mesi dalla data di ricezione del pagamento tardivo.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Ogni istituzione dell’Unione presenta al Parlamento europeo e al Consiglio una relazione riguardante il rispetto e la sospensione dei termini stabiliti ai paragrafi da 1 a 4 del presente articolo. La relazione della Commissione è allegata alla sintesi delle relazioni annuali di attività di cui all’articolo 74, paragrafo 9.</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "117": {"label": "Articolo 117", "heading": "Designazione del revisore interno", "anchor": "art_117", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ciascuna istituzione dell’Unione crea una funzione di audit interno che è esercitata nel rispetto delle pertinenti norme internazionali. Il revisore interno, designato dall’istituzione dell’Unione interessata, risponde alla stessa della verifica del corretto funzionamento dei sistemi e delle procedure di esecuzione del bilancio. Il revisore interno non è né l’ordinatore né il contabile.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Ai fini dell’audit interno del SEAE, i capi delle delegazioni dell’Unione che agiscono in qualità di ordinatori sottodelegati conformemente all’articolo 60, paragrafo 2, sono soggetti ai poteri di verifica del revisore interno della Commissione relativamente alla gestione finanziaria a loro sottodelegata.</div>\n</div>"], [null, "<p class=\"norm\">Il revisore interno della Commissione svolge anche il ruolo di revisore interno del SEAE relativamente all’esecuzione della sezione del bilancio riguardante il SEAE.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Ciascuna istituzione dell’Unione designa il proprio revisore interno secondo modalità adeguate alle sue specificità e alle sue esigenze. Ciascuna istituzione dell’Unione informa il Parlamento europeo e il Consiglio della designazione del proprio revisore interno.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Ciascuna istituzione dell’Unione definisce secondo la propria specificità e le proprie esigenze la sfera delle funzioni del proprio revisore interno e stabilisce in dettaglio gli obiettivi e le procedure dell’esercizio della funzione di audit interno, nel rispetto delle norme internazionali in materia di audit interno.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Ciascuna istituzione dell’Unione può designare come revisore interno, in base alle sue competenze particolari, un funzionario o altro agente soggetto allo statuto del personale reclutato fra i cittadini degli Stati membri.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Quando due o più istituzioni dell’Unione designano il medesimo revisore interno, esse adottano le disposizioni necessarie affinché la sua responsabilità possa essere chiamata in causa secondo il disposto dell’articolo 121.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Quando il revisore interno cessa le proprie funzioni, ciascuna istituzione dell’Unione ne informa il Parlamento europeo e il Consiglio.</div>\n</div>"]]}, "118": {"label": "Articolo 118", "heading": "Poteri e funzioni del revisore interno", "anchor": "art_118", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il revisore interno consiglia la propria istituzione dell’Unione riguardo al controllo dei rischi, esprimendo pareri indipendenti sulla qualità dei sistemi di gestione e di controllo e formulando raccomandazioni mirate a migliorare le condizioni di attuazione delle operazioni e a promuovere la sana gestione finanziaria.</div>\n</div>"], [null, "<p class=\"norm inline-element\">Il revisore interno è incaricato, in particolare, di quanto segue:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">verificare l’adeguatezza e l’efficacia dei sistemi di gestione interna, nonché delle prestazioni dei servizi nella realizzazione delle politiche, dei programmi e delle azioni in relazione ai rischi a essi associati;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">valutare l’efficienza e l’efficacia dei sistemi di controllo e di audit interni relativi a ciascuna operazione di esecuzione del bilancio.</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il revisore interno esercita le proprie funzioni in relazione a tutte le attività e a tutti i servizi dell’istituzione dell’Unione interessata. Può accedere integralmente e senza limiti a qualsiasi informazione necessaria per l’esercizio delle sue funzioni, all’occorrenza anche in loco, sia negli Stati membri sia nei paesi terzi.</div>\n</div>"], [null, "<p class=\"norm\">Il revisore interno prende conoscenza della relazione annuale degli ordinatori e degli altri elementi d’informazione individuati.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il revisore interno presenta all’istituzione dell’Unione interessata una relazione con le sue constatazioni e raccomandazioni. L’istituzione dell’Unione interessata provvede a dar seguito alle raccomandazioni risultanti dagli audit.</div>\n</div>"], [null, "<p class=\"norm\">Ciascuna istituzione dell’Unione esamina se le raccomandazioni formulate nelle relazioni del proprio revisore interno possano essere oggetto di uno scambio con le altre istituzioni dell’Unione circa le migliori prassi.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Il revisore interno presenta all’istituzione dell’Unione interessata una relazione annuale di audit interno che indica il numero e il tipo di audit interni effettuati, le principali raccomandazioni formulate e il seguito dato a queste ultime.</div>\n</div>"], [null, "<p class=\"norm\">Tale relazione annuale di audit interno segnala gli eventuali problemi sistemici rilevati dal comitato istituito a norma dell’articolo 143, qualora questo sia chiamato a pronunciare il parere di cui all’articolo 93.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Nell’elaborare la relazione il revisore interno volge particolare attenzione all’osservanza integrale dei principi della sana gestione finanziaria e performance e accerta che siano stati presi i provvedimenti adeguati per migliorarne e potenziarne costantemente l’applicazione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Ogni anno la Commissione trasmette su richiesta, nel contesto della procedura di discarico e a norma dell’articolo 319 TFUE, la sua relazione annuale di audit interno nel debito rispetto dei requisiti in materia di riservatezza.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Ciascuna istituzione dell’Unione comunica i recapiti del proprio revisore interno a qualunque persona fisica o giuridica associata alle operazioni di spesa affinché queste possano contattare in forma riservata il revisore interno.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">Come previsto all’articolo 247, ogni anno ciascuna istituzione dell’Unione redige una relazione che contiene un riepilogo del numero e tipo di audit interni effettuati, una sintesi delle raccomandazioni formulate e del seguito dato a queste ultime e la trasmette al Parlamento europeo e al Consiglio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">9.  </span>\n<div class=\"norm inline-element\">Le relazioni e le constatazioni del revisore interno, così come la relazione dell’istituzione dell’Unione interessata, sono accessibili al pubblico solo dopo la convalida da parte del revisore interno delle misure adottate per la loro attuazione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">10.  </span>\n<div class=\"norm inline-element\">Ciascuna istituzione dell’Unione mette a disposizione del proprio revisore interno le risorse necessarie al corretto espletamento della funzione di audit interno e una carta delle funzioni che descrive in dettaglio compiti, diritti e obblighi del proprio revisore interno.</div>\n</div>"]]}, "119": {"label": "Articolo 119", "heading": "Programma di lavoro del revisore interno", "anchor": "art_119", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il revisore interno adotta il programma di lavoro e lo sottopone all’istituzione dell’Unione interessata.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Ciascuna istituzione dell’Unione può chiedere al proprio revisore interno di effettuare audit non figuranti nel programma di lavoro di cui al paragrafo 1.</div>\n</div>"]]}, "120": {"label": "Articolo 120", "heading": "Indipendenza del revisore interno", "anchor": "art_120", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il revisore interno gode di totale indipendenza nello svolgimento degli audit. Regole particolari relative al revisore interno sono previste dall’istituzione dell’Unione interessata in modo da garantire che lo stesso eserciti le sue funzioni in totale indipendenza e in modo da definire la sua responsabilità.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il revisore interno non riceve istruzioni né si vede opporre alcun limite relativamente all’esercizio delle funzioni che, in virtù della sua designazione, gli sono assegnate a norma del presente regolamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Se il revisore interno è un membro del personale, egli esercita le proprie funzioni esclusive di audit in piena indipendenza e assume la propria responsabilità secondo le condizioni previste dallo statuto.</div>\n</div>"]]}, "121": {"label": "Articolo 121", "heading": "Responsabilità del revisore interno", "anchor": "art_121", "frags": [[null, "<p class=\"norm\">La responsabilità del proprio revisore interno in quanto membro del personale può essere chiamata in causa soltanto da ciascuna istituzione dell’Unione, in conformità del presente articolo.</p>"], [null, "<p class=\"norm\">Ciascuna istituzione dell’Unione adotta una decisione motivata recante apertura di un’indagine. La decisione è comunicata all’interessato. L’istituzione dell’Unione interessata può incaricare dell’indagine, sotto la propria responsabilità diretta, uno o più funzionari di grado uguale o superiore al membro del personale interessato. Nel corso dell’indagine è sentito l’interessato.</p>"], [null, "<p class=\"norm\">La relazione d’indagine è comunicata all’interessato, che è successivamente sentito dall’istituzione dell’Unione interessata sulla relazione medesima.</p>"], [null, "<p class=\"norm\">In base alla relazione e all’audizione, l’istituzione dell’Unione interessata adotta una decisione motivata di conclusione della procedura oppure una decisione motivata in conformità degli articoli 22 e 86 e dell’allegato IX dello statuto. Le decisioni che prevedono l’applicazione di misure disciplinari o l’irrogazione di sanzioni pecuniarie sono comunicate all’interessato e trasmesse, per informazione, alle altre istituzioni dell’Unione e alla Corte dei conti.</p>"], [null, "<p class=\"norm\">Contro dette decisioni l’interessato può presentare ricorso dinanzi alla Corte di giustizia dell’Unione europea, secondo le disposizioni dello statuto.</p>"]]}, "122": {"label": "Articolo 122", "heading": "Azione dinanzi alla Corte di giustizia dell’Unione europea", "anchor": "art_122", "frags": [[null, "<p class=\"norm\">Fatti salvi i mezzi di ricorso previsti dallo statuto, il revisore interno può avviare direttamente un’azione dinanzi alla Corte di giustizia dell’Unione europea contro qualsiasi atto relativo all’esercizio della sua funzione di revisore interno. Questi propone tale ricorso entro tre mesi dal giorno di calendario in cui viene a conoscenza dell’atto in questione.</p>"], [null, "<p class=\"norm\">Il ricorso è istruito e giudicato a norma dell’articolo 91, paragrafo 5, dello statuto.</p>"]]}, "123": {"label": "Articolo 123", "heading": "Comitati di controllo dell’audit interno", "anchor": "art_123", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ciascuna istituzione dell’Unione istituisce un comitato di controllo dell’audit interno incaricato di assicurare l’indipendenza del revisore interno, di monitorare la qualità delle attività di audit interno e di garantire che i suoi servizi tengano debitamente conto delle raccomandazioni in materia di audit interno ed esterno e diano loro seguito.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La composizione del comitato di controllo dell’audit interno è decisa da ciascuna istituzione dell’Unione tenendo conto della sua autonomia organizzativa e dell’importanza della consulenza di esperti indipendenti.</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "124": {"label": "Articolo 124", "heading": "Ambito di applicazione", "anchor": "art_124", "frags": [[null, "<p class=\"norm\">A eccezione dell’articolo 138, i riferimenti agli impegni giuridici contenuti nel presente titolo sono intesi come riferimenti agli impegni giuridici, ai contratti quadro e agli accordi quadro relativi ai partenariati finanziari.</p>"]]}, "125": {"label": "Articolo 125", "heading": "Forme di contributo dell’Unione", "anchor": "art_125", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">I contributi dell’Unione in regime di gestione diretta, indiretta e concorrente promuovono il conseguimento di un obiettivo strategico dell’Unione e dei risultati specificati e possono assumere una delle seguenti forme:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">finanziamenti non collegati ai costi delle operazioni in questione in base:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’adempimento delle condizioni previste dalla normativa settoriale o da decisioni della Commissione; oppure</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">al conseguimento dei risultati misurato in riferimento agli obiettivi intermedi precedentemente fissati o mediante indicatori di performance;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">rimborso dei costi ammissibili effettivamente sostenuti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">costi unitari, che coprono tutte o determinate categorie specifiche di costi ammissibili che sono chiaramente individuate in anticipo con riferimento a un importo per unità;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">somme forfettarie, che coprono in modo generale tutte o determinate categorie specifiche di costi ammissibili che sono chiaramente individuate in anticipo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">finanziamenti a tasso fisso, che coprono categorie specifiche di costi ammissibili che sono chiaramente individuate in anticipo, applicando una percentuale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una combinazione delle forme di cui alle lettere da a) a e).</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">I contributi dell’Unione che assumono le forme di cui al primo comma, lettera a), del presente paragrafo sono stabiliti, in regime di gestione diretta e indiretta, in conformità dell’articolo 181, della normativa settoriale o di una decisione della Commissione e, in regime di gestione concorrente, in conformità della normativa settoriale. I contributi dell’Unione che assumono le forme di cui al primo comma, lettere c), d) ed e), del presente paragrafo sono stabiliti, in regime di gestione diretta e indiretta, in conformità dell’articolo 181 o della normativa settoriale e, in regime di gestione concorrente, in conformità della normativa settoriale.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Nel determinare la forma appropriata del contributo si tiene conto quanto più possibile degli interessi e dei metodi contabili dei potenziali destinatari.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">L’ordinatore responsabile riferisce sui finanziamenti non collegati ai costi ai sensi del paragrafo 1, primo comma, lettere a) e f), del presente articolo nella relazione annuale di attività di cui all’articolo 74, paragrafo 9.</div>\n</div>"]]}, "126": {"label": "Articolo 126", "heading": "Riconoscimento reciproco delle valutazioni", "anchor": "art_126", "frags": [[null, "<p class=\"norm\">La Commissione può fare affidamento, parzialmente o integralmente, sulle valutazioni effettuate dai propri servizi o da altre entità, compresi i donatori, nella misura in cui tali valutazioni siano state effettuate rispettando condizioni equivalenti a quelle stabilite nel presente regolamento per il metodo applicabile di esecuzione. A tal fine, la Commissione promuove il riconoscimento dei principi riconosciuti a livello internazionale o delle migliori prassi internazionali.</p>"]]}, "127": {"label": "Articolo 127", "heading": "Riconoscimento reciproco degli audit", "anchor": "art_127", "frags": [[null, "<p class=\"norm\">Fatte salve le possibilità esistenti di effettuare ulteriori audit, qualora un revisore indipendente abbia realizzato sui rendiconti finanziari e sulle relazioni che illustrano l’utilizzo di un contributo dell’Unione un audit fondato sui principi di audit riconosciuti a livello internazionale, che fornisce una ragionevole garanzia di affidabilità, tale audit costituisce la base della garanzia globale di affidabilità, come ulteriormente specificato, ove opportuno, nella normativa settoriale, purché siano sufficientemente comprovate l’indipendenza e la competenza del revisore. A tal fine, la relazione del revisore indipendente e la relativa documentazione di audit sono messe a disposizione su richiesta del Parlamento europeo, della Commissione, della Corte dei conti e delle autorità di audit degli Stati membri.</p>"]]}, "128": {"label": "Articolo 128", "heading": "Utilizzo di informazioni già a disposizione", "anchor": "art_128", "frags": [[null, "<p class=\"norm\">Al fine di evitare di chiedere alle persone e alle entità che ricevono fondi dell’Unione le stesse informazioni più di una volta, le informazioni già a disposizione delle istituzioni dell’Unione, delle autorità di gestione o di altri organismi ed entità che eseguono il bilancio sono utilizzate nella misura del possibile.</p>"]]}, "129": {"label": "Articolo 129", "heading": "Cooperazione finalizzata a tutelare gli interessi finanziari dell’Unione", "anchor": "art_129", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ogni persona o entità che riceve fondi dell’Unione coopera pienamente alla tutela degli interessi finanziari dell’Unione e concede, come condizione per ricevere tali fondi, i diritti necessari e l’accesso di cui hanno bisogno l’ordinatore responsabile, l’EPPO rispetto a quegli Stati membri che partecipano a una cooperazione rafforzata ai sensi del regolamento (UE) 2017/1939, l’OLAF, la Corte dei conti e, se del caso, le competenti autorità nazionali, per esercitare integralmente le rispettive competenze. Nel caso dell’OLAF, tali diritti comprendono il diritto di effettuare indagini, anche attraverso controlli e verifiche sul posto, in conformità del regolamento (UE, Euratom) n. 883/2013 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">12</span>\n).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Ogni persona o entità che riceve fondi dell’Unione in regime di gestione diretta e indiretta accetta per iscritto di concedere i diritti necessari di cui al paragrafo 1 e garantisce che i terzi coinvolti nell’esecuzione dei fondi dell’Unione concedano diritti equivalenti.</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "130": {"label": "Articolo 130", "heading": "Partenariati finanziari quadro", "anchor": "art_130", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La Commissione può concludere accordi quadro relativi ai partenariati finanziari per la cooperazione a lungo termine con le persone e le entità che eseguono i fondi dell’Unione ai sensi dell’articolo 62, paragrafo 1, primo comma, lettera c), o con i beneficiari. Fatto salvo il paragrafo 4, lettera c), del presente articolo, gli accordi quadro relativi ai partenariati finanziari sono soggetti a riesame almeno una volta nel corso di ogni quadro finanziario pluriennale. Nell’ambito di tali accordi possono essere firmati accordi di contributo e convenzioni di sovvenzione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Lo scopo di un accordo quadro relativo al partenariato finanziario è agevolare il conseguimento degli obiettivi strategici dell’Unione stabilizzando le condizioni contrattuali della cooperazione. L’accordo quadro relativo al partenariato finanziario precisa le forme della cooperazione finanziaria e comprende l’obbligo di stabilire, negli accordi specifici sottoscritti conformemente all’accordo quadro relativo al partenariato finanziario, le modalità per il monitoraggio del conseguimento di obiettivi specifici. Tali accordi, inoltre, sulla base dei risultati di una valutazione ex ante, indicano se la Commissione può fare affidamento sui sistemi e sulle procedure, comprese le procedure di audit, utilizzati dalle persone o dalle entità che eseguono i fondi dell’Unione ai sensi dell’articolo 62, paragrafo 1, primo comma, lettera c), o dai beneficiari.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Al fine di ottimizzare i costi e i benefici degli audit e facilitare il coordinamento, possono essere conclusi accordi di audit o di verifica con le persone e le entità che eseguono i fondi dell’Unione ai sensi dell’articolo 62, paragrafo 1, primo comma, lettera c), o con i beneficiari. Tali accordi fanno salvi gli articoli 127 e 129.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Nel caso di partenariati finanziari quadro attuati attraverso sovvenzioni specifiche:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’accordo quadro relativo al partenariato finanziario, oltre a quanto previsto al paragrafo 2, specifica:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la natura delle azioni o dei programmi di lavoro previsti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la procedura di attribuzione delle sovvenzioni specifiche, nel rispetto dei principi e delle norme procedurali del titolo VIII;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’insieme dell’accordo quadro relativo al partenariato finanziario e della specifica convenzione di sovvenzione è conforme ai requisiti di cui all’articolo 201;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la durata del quadro relativo al partenariato finanziario non supera i quattro anni se non in casi debitamente giustificati, che sono chiaramente indicati nella relazione annuale di attività di cui all’articolo 74, paragrafo 9;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il partenariato finanziario quadro è attuato nel rispetto dei principi di trasparenza e di parità di trattamento dei richiedenti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il partenariato finanziario quadro è equiparato a una sovvenzione per quanto riguarda la programmazione, la pubblicazione ex ante e l’attribuzione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">alle sovvenzioni specifiche basate sul quadro relativo al partenariato finanziario si applicano le procedure di pubblicazione ex post di cui all’articolo 38.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Un accordo quadro relativo al partenariato finanziario attuato attraverso sovvenzioni specifiche può stabilire di fare affidamento sui sistemi e sulle procedure del beneficiario, conformemente al paragrafo 2 del presente articolo, se tali sistemi e procedure sono stati valutati conformemente all’articolo 154, paragrafi 2, 3 e 4. In tal caso, l’articolo 196, paragrafo 1, lettera d), non si applica. Qualora le procedure utilizzate dal beneficiario per erogare finanziamenti a terzi di cui all’articolo 154, paragrafo 4, primo comma, lettera d), abbiano ricevuto una valutazione positiva da parte della Commissione, gli articoli 204 e 205 non si applicano.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Nel caso di un accordo quadro relativo al partenariato finanziario attuato attraverso sovvenzioni specifiche, la verifica della capacità finanziaria e operativa di cui all’articolo 198 è effettuata prima della firma dell’accordo quadro relativo al partenariato finanziario. La Commissione può fare affidamento su una verifica equivalente della capacità operativa e finanziaria svolta da altri donatori.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Nel caso di partenariati finanziari quadro attuati attraverso accordi di contributo, l’insieme dell’accordo quadro relativo al partenariato finanziario e dell’accordo di contributo è conforme all’articolo 129 e all’articolo 155, paragrafo 6.</div>\n</div>"]]}, "131": {"label": "Articolo 131", "heading": "Sospensione, risoluzione e riduzione", "anchor": "art_131", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Qualora una procedura di aggiudicazione o di attribuzione risulti inficiata da irregolarità o frodi, l’ordinatore responsabile la sospende e può adottare ogni misura necessaria, incluso l’annullamento della procedura stessa. L’ordinatore responsabile informa immediatamente l’OLAF in merito a sospetti casi di frode.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Qualora, dopo l’aggiudicazione o l’attribuzione, la procedura risulti essere stata inficiata da irregolarità o frodi, l’ordinatore responsabile può:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">rifiutarsi di assumere l’impegno giuridico o annullare l’attribuzione di un premio;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sospendere i pagamenti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sospendere l’esecuzione dell’impegno giuridico;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se del caso, risolvere l’impegno giuridico integralmente o soltanto per quanto riguarda uno o più destinatari.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">L’ordinatore responsabile può sospendere i pagamenti o l’esecuzione dell’impegno giuridico qualora:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’esecuzione dell’impegno giuridico risulti essere stata inficiata da irregolarità, frodi o violazioni degli obblighi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sia necessario verificare se le presunte irregolarità, frodi o violazioni degli obblighi abbiano effettivamente avuto luogo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le irregolarità, le frodi o le violazioni degli obblighi rimettano in discussione l’affidabilità o l’efficacia dei sistemi di controllo interno di una persona o entità che esegue i fondi dell’Unione ai sensi dell’articolo 62, paragrafo 1, primo comma, lettera c), o la legittimità e la regolarità delle operazioni sottostanti.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Qualora le presunte irregolarità, frodi o violazioni degli obblighi di cui al primo comma, lettera b), non vengano confermati, l’esecuzione o i pagamenti riprendono non appena possibile.</p>"], [null, "<p class=\"norm\">Nei casi di cui al primo comma, lettere a) e c), l’ordinatore responsabile può risolvere l’impegno giuridico integralmente o soltanto per quanto riguarda uno o più destinatari.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Oltre alle misure di cui ai paragrafi 2 o 3, l’ordinatore responsabile può ridurre la sovvenzione, il premio, il contributo previsto dall’accordo di contributo o il prezzo dovuto nell’ambito di un contratto proporzionalmente alla gravità delle irregolarità, delle frodi o delle violazioni degli obblighi, compreso il caso in cui le attività in questione non siano state eseguite o siano state eseguite in modo carente, parziale o tardivo.</div>\n</div>"], [null, "<p class=\"norm\">Nel caso di finanziamenti di cui all’articolo 125, paragrafo 1, primo comma, lettera a), l’ordinatore responsabile può ridurre proporzionalmente il contributo qualora i risultati siano stati conseguiti in modo carente, parziale o tardivo o qualora le condizioni non siano state soddisfatte.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Il paragrafo 2, lettere b), c) e d), e il paragrafo 3 non si applicano ai richiedenti nell’ambito di un concorso a premi.</div>\n</div>"]]}, "132": {"label": "Articolo 132", "heading": "Conservazione dei dati", "anchor": "art_132", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">I destinatari conservano la documentazione e i documenti giustificativi, compresi i dati statistici e gli altri dati relativi al finanziamento, nonché i documenti e i dati in formato elettronico, per i cinque anni successivi al pagamento a saldo o, in mancanza di tale pagamento, per i cinque anni successivi alla transazione. Tale periodo è di tre anni se il finanziamento è di importo pari o inferiore a 60 000  EUR.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">I documenti e i dati relativi ad audit, ricorsi, contenziosi, azioni legali riguardanti impegni giuridici o relativi alle indagini dell’OLAF sono conservati fino alla conclusione di tali audit, ricorsi, contenziosi, azioni legali o indagini. Per documenti e dati relativi alle indagini dell’OLAF, l’obbligo di conservazione si applica una volta che tali indagini sono state comunicate al destinatario.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">I documenti e i dati sono conservati sotto forma di originali o di copie autenticate, o su supporti per i dati comunemente accettati, comprese le versioni elettroniche di documenti originali o i documenti esistenti esclusivamente in versione elettronica. Ove esistano versioni elettroniche, non sono richiesti gli originali qualora tali documenti soddisfino i pertinenti requisiti di legge per poter essere considerati equivalenti agli originali e affidabili ai fini dell’audit.</div>\n</div>"]]}, "133": {"label": "Articolo 133", "heading": "Procedura in contraddittorio e mezzi di ricorso", "anchor": "art_133", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Prima dell’adozione di qualsiasi provvedimento che leda i diritti di un partecipante o di un destinatario, l’ordinatore responsabile verifica che il partecipante o il destinatario abbia avuto la possibilità di presentare osservazioni.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Qualora un provvedimento dell’ordinatore responsabile leda i diritti di un partecipante o di un destinatario, l’atto con cui è stato adottato riporta l’indicazione dei mezzi amministrativi e/o di ricorso giudiziario disponibili per l’impugnazione.</div>\n</div>"]]}, "134": {"label": "Articolo 134", "heading": "Abbuoni dei tassi d’interesse e sussidi per le commissioni di garanzia", "anchor": "art_134", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli abbuoni dei tassi d’interesse e i sussidi per le commissioni di garanzia sono concessi conformemente al titolo X, qualora essi siano combinati in un’unica misura con gli strumenti finanziari.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Qualora non siano combinati in un’unica misura con gli strumenti finanziari, gli abbuoni dei tassi d’interessi e i sussidi per le commissioni di garanzia possono essere concessi conformemente al titolo VI o VIII.</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "135": {"label": "Articolo 135", "heading": "Tutela degli interessi finanziari dell’Unione attraverso l’individuazione dei rischi, l’esclusione e l’irrogazione di sanzioni pecuniarie", "anchor": "art_135", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Al fine di tutelare gli interessi finanziari dell’Unione, la Commissione istituisce e gestisce un sistema di individuazione precoce e di esclusione.</div>\n</div>"], [null, "<p class=\"norm inline-element\">Tale sistema mira a facilitare:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’individuazione precoce delle persone o entità di cui al paragrafo 2 che rappresentano un rischio per gli interessi finanziari dell’Unione;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’esclusione delle persone o entità di cui al paragrafo 2 che si trovano in una delle situazioni che danno luogo a esclusione di cui all’articolo 136, paragrafo 1;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’irrogazione di una sanzione pecuniaria nei confronti di un destinatario a norma dell’articolo 138.</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Il sistema di individuazione precoce e di esclusione si applica:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">ai partecipanti e ai destinatari;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">alle entità sulla cui capacità il candidato o l’offerente intende fare affidamento o ai subappaltatori di un contraente;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">a qualsiasi persona o entità che riceve fondi dell’Unione in caso di esecuzione del bilancio a norma dell’articolo 62, paragrafo 1, primo comma, lettera c), e dell’articolo 154, paragrafo 4, sulla base delle informazioni comunicate conformemente all’articolo 155, paragrafo 6;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">a qualsiasi persona o entità che riceve fondi dell’Unione a titolo degli strumenti finanziari attuati in via eccezionale conformemente all’articolo 62, paragrafo 1, primo comma, lettera a);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">ai partecipanti o ai destinatari su cui le entità che eseguono il bilancio conformemente all’articolo 63 hanno fornito informazioni, trasmesse dagli Stati membri in conformità della normativa settoriale, conformemente all’articolo 142, paragrafo 2, lettera d);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">agli sponsor di cui all’articolo 26.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La decisione di registrare le informazioni relative a un’individuazione precoce dei rischi di cui al paragrafo 1, secondo comma, lettera a), del presente articolo, di escludere persone o entità di cui al paragrafo 2 e/o di irrogare una sanzione pecuniaria nei confronti di un destinatario è adottata dall’ordinatore responsabile. Le informazioni relative a tali decisioni sono registrate nella banca dati di cui all’articolo 142, paragrafo 1. Se tali decisioni sono adottate a norma dell’articolo 136, paragrafo 4, le informazioni registrate nella banca dati comprendono anche le informazioni relative alle persone di cui al detto paragrafo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La decisione di escludere persone o entità di cui al paragrafo 2 del presente articolo o di irrogare sanzioni pecuniarie nei confronti di un destinatario si basa su una sentenza definitiva o, nelle situazioni che danno luogo a esclusione di cui all’articolo 136, paragrafo 1, su una decisione amministrativa definitiva, oppure su una qualificazione giuridica preliminare da parte del comitato di cui all’articolo 143, nelle situazioni di cui all’articolo 136, paragrafo 2, al fine di garantire una valutazione centralizzata di dette situazioni. Nei casi di cui all’articolo 141, paragrafo 1, l’ordinatore responsabile dispone il rigetto di un partecipante nell’ambito di una determinata procedura di aggiudicazione o di attribuzione.</div>\n</div>"], [null, "<p class=\"norm\">Fatto salvo l’articolo 136, paragrafo 5, l’ordinatore responsabile può adottare una decisione di esclusione di un partecipante o destinatario e/o di irrogazione di una sanzione pecuniaria nei confronti di un destinatario e una decisione di pubblicare le relative informazioni, sulla base di una qualificazione giuridica preliminare di cui all’articolo 136, paragrafo 2, solo dopo aver ottenuto una raccomandazione dal comitato di cui all’articolo 143.</p>"]]}, "136": {"label": "Articolo 136", "heading": "Criteri di esclusione e decisione di esclusione", "anchor": "art_136", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">L’ordinatore responsabile esclude una persona o un’entità di cui all’articolo 135, paragrafo 2, dalla partecipazione alle procedure di aggiudicazione o di attribuzione disciplinate dal presente regolamento o dalla possibilità di essere selezionata per l’esecuzione dei fondi dell’Unione ove tale persona o entità si trovi in una o più delle seguenti situazioni che danno luogo a esclusione:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la persona o l’entità è in stato di fallimento, è oggetto di una procedura di insolvenza o di liquidazione, è in stato di amministrazione controllata, ha stipulato un concordato preventivo con i creditori, ha cessato le sue attività o si trova in qualsiasi altra situazione analoga derivante da una procedura simile ai sensi del diritto dell’Unione o nazionale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">è stato accertato da una sentenza definitiva o decisione amministrativa definitiva che la persona o l’entità non ha ottemperato agli obblighi relativi al pagamento di imposte e tasse o agli obblighi relativi al pagamento dei contributi previdenziali e assistenziali secondo il diritto applicabile;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">è stato accertato da una sentenza definitiva o decisione amministrativa definitiva che la persona o l’entità si è resa colpevole di gravi illeciti professionali per aver violato le leggi o i regolamenti applicabili o i principi deontologici della professione da essa esercitata o per aver tenuto qualsiasi condotta illecita che incida sulla sua credibilità professionale, qualora dette condotte denotino un intento doloso o una negligenza grave, compreso in particolare nelle ipotesi seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per aver reso in modo fraudolento o negligente false informazioni ai fini della verifica dell’assenza di motivi di esclusione o del rispetto dei criteri di ammissibilità o di selezione o nell’esecuzione dell’impegno giuridico;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per aver concluso accordi con altre persone o entità allo scopo di provocare distorsioni della concorrenza;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per aver violato i diritti di proprietà intellettuale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iv) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per aver tentato di influenzare l’iter decisionale dell’ordinatore responsabile nel corso della procedura di aggiudicazione o di attribuzione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>v) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per aver tentato di ottenere informazioni riservate che potessero conferirle vantaggi indebiti nell’ambito della procedura di aggiudicazione o di attribuzione;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">è stato accertato da una sentenza definitiva che la persona o l’entità è colpevole di:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">frode, ai sensi dell’articolo 3 della direttiva (UE) 2017/1371 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">13</span>\n) e dell’articolo 1 della convenzione relativa alla tutela degli interessi finanziari delle Comunità europee, stabilita dall’atto del Consiglio del 26 luglio 1995 (\n<span class=\"superscript\">14</span>\n);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">corruzione, quale definita all’articolo 4, paragrafo 2, della direttiva (UE) 2017/1371 o corruzione attiva ai sensi dell’articolo 3 della convenzione relativa alla lotta contro la corruzione nella quale sono coinvolti funzionari delle Comunità europee o degli Stati membri dell’Unione europea, stabilita dall’atto del Consiglio del 26 maggio 1997 (\n<span class=\"superscript\">15</span>\n), o condotte, quali definite all’articolo 2, paragrafo 1, della decisione quadro 2003/568/GAI del Consiglio (\n<span class=\"superscript\">16</span>\n), o corruzione, quale definita in altre legislazioni vigenti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">comportamenti connessi a un’organizzazione criminale, di cui all’articolo 2 della decisione quadro 2008/841/GAI del Consiglio (\n<span class=\"superscript\">17</span>\n);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iv) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">riciclaggio o finanziamento del terrorismo ai sensi dell’articolo 1, paragrafi 3, 4 e 5, della direttiva (UE) 2015/849 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">18</span>\n);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>v) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">reati terroristici o reati connessi ad attività terroristiche, quali definiti rispettivamente all’articolo 1 e all’articolo 3 della decisione quadro 2002/475/GAI del Consiglio (\n<span class=\"superscript\">19</span>\n), ovvero istigazione, concorso o tentativo di commettere tali reati, quali definiti all’articolo 4 di detta decisione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>vi) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">lavoro minorile e altri reati relativi alla tratta di esseri umani di cui all’articolo 2 della direttiva 2011/36/UE del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">20</span>\n);</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la persona o l’entità ha mostrato significative carenze nell’adempiere ai principali obblighi ai fini dell’esecuzione di un impegno giuridico finanziato dal bilancio, che:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">hanno causato la risoluzione anticipata di un impegno giuridico;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">hanno comportato l’applicazione della clausola penale o di altre penali contrattuali; o</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sono state evidenziate da un ordinatore, dall’OLAF o dalla Corte dei conti in seguito a verifiche, audit o indagini;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">è stato accertato da una sentenza definitiva o decisione amministrativa definitiva che la persona o l’entità ha commesso un’irregolarità ai sensi dell’articolo 1, paragrafo 2, del regolamento (CE, Euratom) n. 2988/95 del Consiglio (\n<span class=\"superscript\">21</span>\n);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">è stato accertato da una sentenza definitiva o decisione amministrativa definitiva che la persona o l’entità ha creato un’entità in una giurisdizione diversa con l’intento di eludere obblighi fiscali, sociali o altri obblighi giuridici nella giurisdizione in cui ha la sede sociale, l’amministrazione centrale o la sede di attività principale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">è stato accertato da una sentenza definitiva o decisione amministrativa definitiva che è stata creata un’entità con l’intento di cui alla lettera g).</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">In mancanza di una sentenza definitiva o, se del caso, di una decisione amministrativa definitiva nei casi di cui al paragrafo 1, lettere c), d), f), g) e h), del presente articolo, o nel caso di cui al paragrafo 1, lettera e), del presente articolo, l’ordinatore responsabile esclude la persona o l’entità di cui all’articolo 135, paragrafo 2, in base a una qualificazione giuridica preliminare delle condotte di cui a dette lettere, tenuto conto dei fatti accertati o di altre risultanze figuranti nella raccomandazione del comitato di cui all’articolo 143.</div>\n</div>"], [null, "<p class=\"norm\">La qualificazione preliminare di cui al primo comma del presente paragrafo fa salva la valutazione della condotta della persona o entità in questione, di cui all’articolo 135, paragrafo 2, da parte delle autorità competenti degli Stati membri a norma del diritto nazionale. In seguito alla comunicazione di una sentenza definitiva o decisione amministrativa definitiva, l’ordinatore responsabile rivede senza indugio la sua decisione di escludere la persona o l’entità di cui all’articolo 135, paragrafo 2, e/o di irrogare una sanzione pecuniaria nei confronti di un destinatario. Nei casi in cui la durata dell’esclusione non sia stabilita dalla sentenza definitiva o decisione amministrativa definitiva, spetta all’ordinatore responsabile stabilirla in base ai fatti accertati e alle risultanze e tenuto conto della raccomandazione del comitato di cui all’articolo 143.</p>"], [null, "<p class=\"norm\">Qualora detta sentenza definitiva o decisione amministrativa definitiva non consideri la persona o l’entità di cui all’articolo 135, paragrafo 2, colpevole della condotta oggetto di qualificazione giuridica preliminare in base alla quale tale persona o entità è stata esclusa, l’ordinatore responsabile pone fine senza indugio a tale esclusione e/o rimborsa, se opportuno, le eventuali sanzioni pecuniarie irrogate.</p>"], [null, "<p class=\"norm inline-element\">I fatti e le risultanze di cui al primo comma includono, in particolare:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">fatti accertati nel contesto di audit o indagini svolti dall’EPPO rispetto a quegli Stati membri che partecipano a una cooperazione rafforzata ai sensi del regolamento (UE) 2017/1939, dalla Corte dei conti, dall’OLAF o dal revisore interno, o di altre verifiche, audit o controlli effettuati sotto la responsabilità dell’ordinatore;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">decisioni amministrative non definitive che possono includere misure disciplinari adottate dall’organo di vigilanza competente responsabile della verifica dell’applicazione dei principi di deontologia professionale;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">fatti contenuti in decisioni di persone ed entità che eseguono i fondi dell’Unione a norma dell’articolo 62, paragrafo 1, primo comma, lettera c);</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">informazioni trasmesse in conformità dell’articolo 142, paragrafo 2, lettera d), da entità che eseguono i fondi dell’Unione a norma dell’articolo 62, paragrafo 1, primo comma, lettera b);</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">decisioni della Commissione concernenti la violazione del diritto dell’Unione in materia di concorrenza o decisioni di un’autorità nazionale competente concernenti la violazione del diritto dell’Unione o nazionale in materia di concorrenza.</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Le decisioni dell’ordinatore responsabile adottate conformemente agli articoli da 135 a 142 o, se del caso, le raccomandazioni del comitato di cui all’articolo 143 sono adottate conformemente al principio di proporzionalità e tenendo conto, in particolare:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">della gravità della situazione, ivi compresa la sua incidenza sugli interessi finanziari e sull’immagine dell’Unione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">del tempo trascorso dal verificarsi della condotta in questione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">della durata della condotta e della sua ricorrenza;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">del fatto che la condotta sia stata o meno intenzionale o del relativo grado di negligenza;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nei casi di cui al paragrafo 1, lettera b), dell’eventuale entità limitata dell’importo interessato;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">di eventuali altre circostanze attenuanti, quali:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il livello di collaborazione della persona o dell’entità in questione, di cui all’articolo 135, paragrafo 2, con la pertinente autorità competente e il contributo di tale persona o entità all’indagine riconosciuto dall’ordinatore responsabile, o</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la comunicazione della situazione di esclusione per mezzo di una dichiarazione di cui all’articolo 137, paragrafo 1.</p>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">L’ordinatore responsabile esclude la persona o l’entità di cui all’articolo 135, paragrafo 2, qualora:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una persona fisica o giuridica che è membro dell’organo di amministrazione, di direzione o di vigilanza della persona o entità di cui all’articolo 135, paragrafo 2, o che ha poteri di rappresentanza, di decisione o di controllo nei confronti di tale persona o entità, si trovi in una o più delle situazioni di cui al paragrafo 1, lettere da c) a h), del presente articolo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una persona fisica o giuridica che si assume la responsabilità illimitata dei debiti della persona o dell’entità di cui all’articolo 135, paragrafo 2, si trovi in una o più delle situazioni di cui al paragrafo 1, lettera a) o b), del presente articolo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una persona fisica che è essenziale per l’aggiudicazione o l’attribuzione ovvero per l’esecuzione dell’impegno giuridico si trovi in una o più delle situazioni di cui al paragrafo 1, lettere da c) a h).</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Nei casi di cui al paragrafo 2 del presente articolo, l’ordinatore responsabile può escludere a titolo provvisorio una persona o un’entità di cui all’articolo 135, paragrafo 2, senza previa raccomandazione dell’istanza di cui all’articolo 143, qualora la sua partecipazione a una procedura di aggiudicazione o di attribuzione ovvero la sua selezione ai fini dell’esecuzione dei fondi dell’Unione costituisca una grave e imminente minaccia per gli interessi finanziari dell’Unione. In tali casi, l’ordinatore responsabile sottopone immediatamente la questione al comitato di cui all’articolo 143 e adotta la decisione definitiva entro 14 giorni dal ricevimento della raccomandazione del comitato.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">L’ordinatore competente, tenuto conto, se del caso, della raccomandazione del comitato di cui all’articolo 143, non esclude una persona o un’entità di cui all’articolo 135, paragrafo 2, dalla partecipazione a una procedura di aggiudicazione o di attribuzione o dalla possibilità di essere selezionata per eseguire i fondi dell’Unione ove:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la persona o l’entità abbia adottato le misure correttive indicate al paragrafo 7 del presente articolo in misura sufficiente a dimostrare la sua affidabilità. La presente lettera non si applica nel caso di cui al paragrafo 1, lettera d), del presente articolo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sia indispensabile per garantire la continuità del servizio per un periodo di tempo limitato e in attesa dell’adozione delle misure correttive di cui al paragrafo 7 del presente articolo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una tale esclusione sia sproporzionata in base ai criteri di cui al paragrafo 3 del presente articolo.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Inoltre, il paragrafo 1, lettera a), del presente articolo non si applica in caso di acquisto di forniture, a condizioni particolarmente vantaggiose, da un fornitore che sta definitivamente liquidando l’attività commerciale oppure dal liquidatore di un fallimento, un concordato preventivo o una procedura analoga ai sensi del diritto dell’Unione europea o nazionale.</p>"], [null, "<p class=\"norm\">Nei casi di non esclusione di cui al primo e secondo comma del presente paragrafo, l’ordinatore responsabile specifica i motivi in base ai quali non ha escluso la persona o l’entità di cui all’articolo 135, paragrafo 2, e ne informa il comitato di cui all’articolo 143.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Le misure correttive di cui al paragrafo 6, primo comma, lettera a), possono includere, in particolare:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">misure volte a individuare l’origine delle situazioni che determinano l’esclusione e provvedimenti concreti di carattere tecnico, organizzativo e relativi al personale nel pertinente settore di attività della persona o entità di cui all’articolo 135, paragrafo 2, che siano idonei a correggere la condotta e a impedire che essa si verifichi nuovamente;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la prova che la persona o entità di cui all’articolo 135, paragrafo 2, abbia adottato misure per compensare o risarcire il danno o il pregiudizio arrecato agli interessi finanziari dell’Unione dai fatti sottostanti che danno origine alla situazione di esclusione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la prova che la persona o entità di cui all’articolo 135, paragrafo 2, abbia effettuato o garantito il pagamento delle ammende irrogate dall’autorità competente o delle imposte e tasse o dei contributi previdenziali e assistenziali di cui al paragrafo 1, lettera b), del presente articolo.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">L’ordinatore responsabile, tenuto conto, se del caso, della raccomandazione riveduta dell’istanza di cui all’articolo 143, rivede senza indugio la sua decisione di escludere una persona o entità di cui all’articolo 135, paragrafo 2, di propria iniziativa o su richiesta di tale persona o entità, qualora questa abbia adottato misure correttive sufficienti a dimostrare la sua affidabilità o abbia fornito nuovi elementi comprovanti che non sussiste più la situazione di esclusione di cui al paragrafo 1 del presente articolo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">9.  </span>\n<div class=\"norm inline-element\">Nel caso di cui all’articolo 135, paragrafo 2, lettera b), l’ordinatore responsabile esige che il candidato o l’offerente sostituisca l’entità o il subappaltatore, sulla cui capacità intende fare affidamento, che si trovi in una situazione di esclusione di cui al paragrafo 1 del presente articolo.</div>\n</div>"]]}, "137": {"label": "Articolo 137", "heading": "Dichiarazione e prova dell’assenza di una situazione di esclusione", "anchor": "art_137", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">I partecipanti dichiarano se si trovano in una delle situazioni di cui agli articoli 136, paragrafo 1, e 141, paragrafo 1, e, se del caso, se hanno adottato le misure correttive di cui all’articolo 136, paragrafo 6, primo comma, lettera a).</div>\n</div>"], [null, "<p class=\"norm inline-element\">I partecipanti dichiarano inoltre se le seguenti persone o entità si trovano in una delle situazioni di esclusione di cui all’articolo 136, paragrafo 1, lettere da c) a h):</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">persone fisiche o giuridiche che sono membri dell’organo di amministrazione, di direzione o di vigilanza del partecipante o che hanno poteri di rappresentanza, di decisione o di controllo nei confronti di tale partecipante;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">titolari effettivi, di cui all’articolo 3, punto 6), della direttiva (UE) 2015/849, del partecipante.</p>\n</div>\n</div>"], [null, "<p class=\"norm\">Il partecipante o il destinatario informa senza indugio l’ordinatore responsabile di qualsiasi cambiamento intervenuto nelle situazioni dichiarate.</p>"], [null, "<p class=\"norm\">Ove opportuno, il candidato od offerente fornisce le stesse dichiarazioni di cui al primo e secondo comma firmate da un subappaltatore o da qualsiasi altra entità sulla cui capacità intende fare affidamento, secondo il caso.</p>"], [null, "<p class=\"norm\">L’ordinatore responsabile non richiede le dichiarazioni di cui al primo e secondo comma se tali dichiarazioni sono già state presentate in occasione di un’altra procedura di aggiudicazione o di attribuzione, purché la situazione non sia cambiata e non sia trascorso più di un anno dalla data di emissione delle dichiarazioni.</p>"], [null, "<p class=\"norm\">L’ordinatore responsabile può rinunciare alle prescrizioni di cui al primo e secondo comma per i contratti di valore molto modesto, non superiore all’importo di cui al punto 14.4 dell’allegato I.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Se l’ordinatore responsabile lo richiede e qualora ciò sia necessario per assicurare il corretto svolgimento della procedura, il partecipante, il subappaltatore o l’entità sulla cui capacità il candidato od offerente intende fare affidamento forniscono:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">adeguata prova che non si trovano in una delle situazioni di esclusione di cui all’articolo 136, paragrafo 1;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">informazioni sulle persone fisiche o giuridiche che sono membri dell’organo di amministrazione, di direzione o di vigilanza del partecipante o che hanno poteri di rappresentanza, di decisione o di controllo nei confronti di tale partecipante, comprese le persone e le entità che sono parte dell’assetto proprietario e di controllo e i titolari effettivi, e adeguata prova che nessuna di tali persone si trova in una delle situazioni di esclusione di cui all’articolo 136, paragrafo 1, lettere da c) a f);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">adeguata prova che le persone fisiche o giuridiche che si assumono la responsabilità illimitata dei debiti di tale partecipante non si trovano in una delle situazioni di esclusione di cui all’articolo 136, paragrafo 1, lettera a) o b).</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Se del caso e in conformità del diritto nazionale, come prova appropriata del fatto che un partecipante o un’entità di cui al paragrafo 2 non si trova in una delle situazioni di esclusione di cui all’articolo 136, paragrafo 1, lettere a), c), d), f), g) e h), l’ordinatore responsabile può accettare un estratto recente del casellario giudiziale o, in sua mancanza, un documento equivalente rilasciato di recente da un’autorità giudiziaria o amministrativa dello Stato in cui il partecipante o l’entità sono stabiliti, da cui risulti che tali prescrizioni sono soddisfatte.</div>\n</div>"], [null, "<p class=\"norm\">Come prova appropriata del fatto che un partecipante o un’entità di cui al paragrafo 2 non si trova in una delle situazioni di esclusione di cui all’articolo 136, paragrafo 1, lettere a) e b), l’ordinatore responsabile può accettare un certificato rilasciato di recente dalla competente autorità dello Stato in cui il partecipante o l’entità sono stabiliti. Se il paese in cui è stabilito non rilascia questi tipi di certificato, il partecipante può presentare una dichiarazione giurata resa dinanzi a un’autorità giudiziaria o a un notaio o, in mancanza di questa, una dichiarazione solenne pronunciata dinanzi a un’autorità amministrativa o a un organismo professionale qualificato del paese in cui è stabilito.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">L’ordinatore responsabile esenta un partecipante o un’entità di cui al paragrafo 2 dall’obbligo di presentare le prove documentali di cui ai paragrafi 2 e 3:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se può accedere a tali prove gratuitamente in una banca dati nazionale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se tali prove gli sono già state presentate ai fini di un’altra procedura, purché la documentazione presentata sia ancora valida e non sia trascorso più di un anno dalla data di emissione dei documenti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se riconosce che sussiste l’impossibilità materiale di fornire tali prove.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">I paragrafi da 1 a 4 del presente articolo non si applicano alle persone e alle entità che eseguono i fondi dell’Unione ai sensi dell’articolo 62, paragrafo 1, primo comma, lettera c), né agli organismi dell’Unione di cui agli articoli 70 e 71.</div>\n</div>"], [null, "<p class=\"norm\">Per quanto riguarda gli strumenti finanziari, e in mancanza di norme e procedure del tutto equivalenti a quelle di cui all’articolo 154, paragrafo 4, primo comma, lettera d), i destinatari finali e gli intermediari forniscono alla persona o all’entità che esegue i fondi dell’Unione a norma dell’articolo 62, paragrafo 1, primo comma, lettera c), un’autocertificazione firmata che conferma che non si trovano in una delle situazioni di cui all’articolo 136, paragrafo 1, lettere da a) a d), g) e h), o all’articolo 141, paragrafo 1, primo comma, lettere b) e c), né in una situazione ritenuta a queste equivalente in seguito alla valutazione svolta conformemente all’articolo 154, paragrafo 4.</p>"], [null, "<p class=\"norm\">Nei casi in cui gli strumenti finanziari sono eccezionalmente attuati in conformità dell’articolo 62, paragrafo 1, primo comma, lettera a), i destinatari finali forniscono agli intermediari finanziari un’autocertificazione firmata che conferma che non si trovano in una delle situazioni di cui all’articolo 136, paragrafo 1, lettere da a) a d), g) e h), o all’articolo 141, paragrafo 1, primo comma, lettere b) e c).</p>"]]}, "138": {"label": "Articolo 138", "heading": "Sanzioni pecuniarie", "anchor": "art_138", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Per garantire un effetto deterrente, l’ordinatore responsabile può, tenendo conto se del caso della raccomandazione del comitato di cui all’articolo 143, irrogare una sanzione pecuniaria nei confronti di un destinatario con cui è stato assunto un impegno giuridico e che si trovi in una situazione di esclusione di cui all’articolo 136, paragrafo 1, lettera c), d), e) o f).</div>\n</div>"], [null, "<p class=\"norm\">Per quanto riguarda le situazioni di esclusione di cui all’articolo 136, paragrafo 1, lettere da c) a f), la sanzione pecuniaria può essere irrogata in alternativa a una decisione di escludere un destinatario, qualora tale esclusione sia sproporzionata in base ai criteri di cui all’articolo 136, paragrafo 3.</p>"], [null, "<p class=\"norm\">Per quanto riguarda le situazioni di esclusione di cui all’articolo 136, paragrafo 1, lettere c), d) ed e), la sanzione pecuniaria può essere irrogata in aggiunta a un’esclusione se ciò è necessario per tutelare gli interessi finanziari dell’Unione, a causa della condotta sistematica e ricorrente assunta dal destinatario nell’intento di ottenere indebitamente fondi dell’Unione.</p>"], [null, "<p class=\"norm\">Fatti salvi il primo, secondo e terzo comma del presente paragrafo, non è irrogata una sanzione pecuniaria nei confronti di un destinatario che abbia comunicato, conformemente all’articolo 137, di trovarsi in una situazione di esclusione.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L’importo della sanzione pecuniaria non supera il 10 % del valore complessivo dell’impegno giuridico. Nel caso di una convenzione di sovvenzione stipulata con più beneficiari, la sanzione pecuniaria non supera il 10 % dell’importo della sovvenzione cui il beneficiario interessato ha diritto conformemente alla convenzione di sovvenzione.</div>\n</div>"]]}, "139": {"label": "Articolo 139", "heading": "Durata dell’esclusione e termine di prescrizione", "anchor": "art_139", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La durata dell’esclusione non è superiore a nessuno dei seguenti periodi:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’eventuale periodo stabilito dalla sentenza definitiva o dalla decisione amministrativa definitiva di uno Stato membro;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">in mancanza di una sentenza definitiva o di una decisione amministrativa definitiva:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">cinque anni, nei casi di cui all’articolo 136, paragrafo 1, lettera d);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">tre anni, nei casi di cui all’articolo 136, paragrafo 1, lettere c), e da e) a h).</p>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Una persona o entità di cui all’articolo 135, paragrafo 2, è esclusa fintantoché si trovi in una delle situazioni di esclusione di cui all’articolo 136, paragrafo 1, lettere a) e b).</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Il termine di prescrizione per l’esclusione di una persona o entità di cui all’articolo 135, paragrafo 2 e/o per l’irrogazione di sanzioni pecuniarie nei suoi confronti è di cinque anni a decorrere da una delle date seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la data della condotta che ha determinato l’esclusione o, in caso di atti continui o ripetuti, la data alla quale la condotta è cessata, nei casi di cui all’articolo 136, paragrafo 1, lettere da b) a e), g) e h);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la data della sentenza definitiva di un organo giurisdizionale nazionale o della decisione amministrativa definitiva nei casi di cui all’articolo 136, paragrafo 1, lettere b), c), d), g) e h).</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Il termine di prescrizione è interrotto da un atto di un’autorità nazionale, della Commissione, dell’OLAF, dell’EPPO rispetto a quegli Stati membri che partecipano a una cooperazione rafforzata a norma del regolamento (UE) 2017/1939, del comitato di cui all’articolo 143 del presente regolamento o di qualsiasi entità che partecipa all’esecuzione del bilancio, se tale atto è comunicato alla persona o entità di cui all’articolo 135, paragrafo 2, del presente regolamento e riguarda indagini o procedimenti giudiziari. Un nuovo termine di prescrizione comincia a decorrere dal giorno successivo all’interruzione.</p>"], [null, "<p class=\"norm\">Ai fini dell’articolo 136, paragrafo 1, lettera f), del presente regolamento si applica il termine di prescrizione per l’esclusione di una persona o entità di cui all’articolo 135, paragrafo 2, del presente regolamento e/o per l’irrogazione di sanzioni pecuniarie nei confronti di un destinatario di cui all’articolo 3 del regolamento (CE, Euratom) n. 2988/95.</p>"], [null, "<p class=\"norm\">Qualora la condotta della persona o entità di cui all’articolo 135, paragrafo 2, del presente regolamento di cui trattasi rientri in più di uno dei motivi elencati all’articolo 136, paragrafo 1, del presente regolamento, si applica il termine di prescrizione previsto per il motivo più grave.</p>"]]}, "140": {"label": "Articolo 140", "heading": "Pubblicazione dell’esclusione e delle sanzioni pecuniarie", "anchor": "art_140", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Per rafforzare, se necessario, l’effetto deterrente dell’esclusione e/o della sanzione pecuniaria, la Commissione pubblica sul proprio sito web, fatta salva la decisione dell’ordinatore responsabile, le seguenti informazioni relative all’esclusione e, se del caso, alla sanzione pecuniaria nei casi di cui all’articolo 136, paragrafo 1, lettere da c) a h):</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il nome della persona o dell’entità di cui all’articolo 135, paragrafo 2, di cui trattasi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la situazione di esclusione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la durata dell’esclusione e/o l’importo della sanzione pecuniaria.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Qualora la decisione sull’esclusione e/o sulla sanzione pecuniaria sia stata adottata in base alla qualificazione preliminare di cui all’articolo 136, paragrafo 2, la pubblicazione indica che non vi è sentenza definitiva o, se del caso, decisione amministrativa definitiva. In tali casi, le informazioni relative a eventuali ricorsi, al loro stato e al loro esito, così come qualsiasi decisione riveduta dell’ordinatore responsabile, sono pubblicate senza indugio. Qualora sia stata irrogata una sanzione pecuniaria, la pubblicazione indica altresì se la sanzione è stata pagata.</p>"], [null, "<p class=\"norm\">La decisione di pubblicare le informazioni è adottata dall’ordinatore responsabile a seguito della pertinente sentenza definitiva o, se del caso, della decisione amministrativa definitiva o a seguito della raccomandazione del comitato di cui all’articolo 143, secondo il caso. Tale decisione diviene efficace tre mesi dopo la sua comunicazione alla persona o all’entità di cui all’articolo 135, paragrafo 2, di cui trattasi.</p>"], [null, "<p class=\"norm\">Le informazioni pubblicate sono rimosse non appena termina l’esclusione. In caso di sanzione pecuniaria, la pubblicazione è rimossa sei mesi dopo il pagamento di tale sanzione.</p>"], [null, "<p class=\"norm\">In ordine ai dati personali, l’ordinatore responsabile informa conformemente al regolamento (CE) n. 45/2001 la persona o l’entità di cui all’articolo 135, paragrafo 2, del presente regolamento di cui trattasi in merito ai diritti ad essa conferiti dalle norme applicabili sulla protezione dei dati personali e alle procedure di cui dispone per esercitarli.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">In nessuno dei seguenti casi possono essere pubblicate le informazioni di cui al paragrafo 1 del presente articolo:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">qualora occorra garantire la riservatezza di un’indagine o di un procedimento giudiziario nazionale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">qualora la pubblicazione arrechi un danno sproporzionato alla persona o all’entità di cui all’articolo 135, paragrafo 2, di cui trattasi o sia altrimenti sproporzionata, in base ai criteri di proporzionalità di cui all’articolo 136, paragrafo 3, e con riguardo all’importo della sanzione pecuniaria;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">qualora siano interessate persone fisiche, a meno che la pubblicazione dei dati personali sia giustificata da circostanze eccezionali, fra l’altro, dalla gravità della condotta o dalla sua incidenza sugli interessi finanziari dell’Unione. In tali casi, la decisione di pubblicare le informazioni tiene debitamente conto del diritto alla vita privata e degli altri diritti previsti dal regolamento (CE) n. 45/2001.</p>\n</div>\n</div>\n</div>\n</div>"]]}, "141": {"label": "Articolo 141", "heading": "Rigetto nell’ambito di una procedura di aggiudicazione o di attribuzione", "anchor": "art_141", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Nell’ambito di una procedura di aggiudicazione o di attribuzione, l’ordinatore responsabile respinge un partecipante che:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">si trovi in una delle situazioni di esclusione di cui all’articolo 136;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">abbia reso false dichiarazioni nel fornire le informazioni richieste ai fini della partecipazione alla procedura o non abbia fornito tali informazioni;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">abbia precedentemente partecipato alla preparazione dei documenti utilizzati nella procedura di aggiudicazione o di attribuzione, se ciò comporta una violazione del principio di parità di trattamento, inclusa una distorsione della concorrenza non altrimenti risolvibile.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">L’ordinatore responsabile comunica agli altri partecipanti alla procedura di aggiudicazione o di attribuzione le informazioni pertinenti scambiate nell’ambito del coinvolgimento del partecipante nella preparazione della procedura di aggiudicazione o di attribuzione di cui al primo comma, lettera c), od ottenute a seguito di tale coinvolgimento. Prima di tale rigetto, al partecipante è offerta la possibilità di dimostrare che il suo coinvolgimento nella preparazione della procedura di aggiudicazione o di attribuzione non viola il principio della parità di trattamento.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L’articolo 133, paragrafo 1, si applica a meno che il rigetto sia stato motivato, conformemente al paragrafo 1, primo comma, lettera a), del presente articolo, da una decisione di esclusione adottata nei confronti del partecipante in seguito all’esame delle sue osservazioni.</div>\n</div>"]]}, "142": {"label": "Articolo 142", "heading": "Sistema di individuazione precoce e di esclusione", "anchor": "art_142", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le informazioni scambiate nell’ambito del sistema di individuazione precoce e di esclusione di cui all’articolo 135 sono centralizzate in una banca dati creata dalla Commissione («banca dati») e sono gestite nel rispetto del diritto alla vita privata e degli altri diritti previsti dal regolamento (CE) n. 45/2001.</div>\n</div>"], [null, "<p class=\"norm\">Le informazioni relative ai casi di individuazione precoce, di esclusione e/o di sanzione pecuniaria sono registrate nella banca dati dall’ordinatore responsabile previa comunicazione alla persona o entità di cui all’articolo 135, paragrafo 2, di cui trattasi. Tale comunicazione può essere differita in circostanze eccezionali, qualora motivi preminenti e legittimi impongano di garantire la riservatezza di un’indagine o di procedimenti giudiziari nazionali, fino a che tali motivi preminenti e legittimi a tutela della riservatezza non vengano meno.</p>"], [null, "<p class=\"norm\">In conformità del regolamento (CE) n. 45/2001, la Commissione su richiesta informa la persona o entità soggetta al sistema di individuazione precoce e di esclusione, di cui all’articolo 135, paragrafo 2, in merito ai dati conservati nella banca dati relativi a tale persona o entità.</p>"], [null, "<p class=\"norm\">Le informazioni contenute nella banca dati sono aggiornate, se del caso, in seguito a rettifica, cancellazione o modifica dei dati. Tali informazioni sono pubblicate soltanto a norma dell’articolo 140.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Il sistema di individuazione precoce e di esclusione si basa sui fatti e sulle risultanze di cui all’articolo 136, paragrafo 2, quarto comma, nonché sulla trasmissione di informazioni alla Commissione, da parte in particolare:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dell’EPPO rispetto a quegli Stati membri che partecipano a una cooperazione rafforzata a norma del regolamento (UE) 2017/1939 o dell’OLAF, conformemente al regolamento (UE, Euratom) n. 883/2013, ove un’indagine portata a termine o in corso dimostri che potrebbe essere opportuno adottare misure o azioni precauzionali per tutelare gli interessi finanziari dell’Unione, nel debito rispetto dei diritti procedurali e fondamentali e della protezione degli informatori;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">di un ordinatore della Commissione, di un ufficio europeo istituito dalla Commissione o di un’agenzia esecutiva;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">di un’istituzione dell’Unione, di un ufficio europeo, di un’agenzia diversi da quelli di cui alla lettera b) del presente paragrafo, o di un organismo o di una persona incaricata dell’attuazione delle azioni PESC;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">delle entità che eseguono il bilancio conformemente all’articolo 63, nei casi individuati di frodi e/o irregolarità e relativo seguito, ove la trasmissione di informazioni sia richiesta dalla normativa settoriale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">delle persone o entità che eseguono i fondi dell’Unione ai sensi dell’articolo 62, paragrafo 1, primo comma, lettera c), nei casi individuati di frodi e/o irregolarità e relativo seguito.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">A eccezione dei casi in cui le informazioni devono essere comunicate in conformità della normativa settoriale, le informazioni da comunicare a norma del paragrafo 2 del presente articolo comprendono:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli estremi dell’entità o della persona di cui trattasi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una sintesi dei rischi individuati o dei fatti in questione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">ogni informazione che possa essere d’ausilio all’ordinatore nell’esecuzione della verifica di cui al paragrafo 4 del presente articolo o nell’adozione di una decisione di esclusione di cui all’articolo 136, paragrafo 1 o 2, o di una decisione di irrogazione di una sanzione pecuniaria di cui all’articolo 138;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se del caso, informazioni su eventuali misure particolari necessarie a garantire la riservatezza delle informazioni trasmesse, comprese misure per la salvaguardia degli elementi di prova a tutela dell’indagine o dei procedimenti giudiziari nazionali.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La Commissione trasmette senza indugio le informazioni di cui al paragrafo 3 ai propri ordinatori e a quelli delle sue agenzie esecutive, a tutte le altre istituzioni dell’Unione, organismi dell’Unione, uffici europei e agenzie tramite la banca dati di cui al paragrafo 1, al fine di consentire loro di eseguire le necessarie verifiche in relazione alle procedure di aggiudicazione o di attribuzione in corso e agli impegni giuridici in vigore.</div>\n</div>"], [null, "<p class=\"norm\">Nell’eseguire tali verifiche l’ordinatore responsabile esercita i suoi poteri di cui all’articolo 74, nel rispetto dei termini e delle condizioni della procedura di aggiudicazione o di attribuzione e degli impegni giuridici.</p>"], [null, "<p class=\"norm\">Il periodo di conservazione delle informazioni relative ai casi di individuazione precoce trasmesse a norma del paragrafo 3 del presente articolo non è superiore a un anno. Se, durante tale periodo, l’ordinatore responsabile richiede al comitato di formulare una raccomandazione in un caso di esclusione o di sanzioni pecuniarie, il periodo di conservazione può essere prorogato fino a quando l’ordinatore responsabile non ha adottato una decisione.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">A tutte le persone ed entità coinvolte nell’esecuzione del bilancio conformemente all’articolo 62 la Commissione garantisce l’accesso alle informazioni relative alle decisioni di esclusione a norma dell’articolo 136 per consentire loro di verificare se il sistema segnali un’esclusione, al fine di prendere tali informazioni in considerazione, come opportuno e sotto la propria responsabilità, per l’aggiudicazione di contratti nell’esecuzione del bilancio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Nell’ambito della relazione annuale della Commissione al Parlamento europeo e al Consiglio a norma dell’articolo 325, paragrafo 5, TFUE, la Commissione fornisce informazioni aggregate sulle decisioni adottate dagli ordinatori ai sensi degli articoli da 135 a 142 del presente regolamento. Tale relazione fornisce inoltre ulteriori informazioni in merito alle decisioni adottate dagli ordinatori ai sensi dell’articolo 136, paragrafo 6, primo comma, lettera b), del presente regolamento e dell’articolo 140, paragrafo 2, del presente regolamento, e alle decisioni degli ordinatori di discostarsi dalla raccomandazione del comitato ai sensi dell’articolo 143, paragrafo 6, terzo comma, del presente regolamento.</div>\n</div>"], [null, "<p class=\"norm\">Le informazioni di cui al primo comma del presente paragrafo sono fornite nel debito rispetto dei requisiti in materia di riservatezza e, in particolare, non consentono l’identificazione della persona o dell’entità interessata, ai sensi dell’articolo 135, paragrafo 2, di cui trattasi.</p>"]]}, "143": {"label": "Articolo 143", "heading": "Istanza", "anchor": "art_143", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Un comitato si riunisce su richiesta di un ordinatore dell’istituzione dell’Unione, dell’organismo dell’Unione, dell’ufficio europeo o dell’organismo o della persona incaricati di attuare azioni specifiche nel settore della PESC, a norma del titolo V del TUE.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Il comitato si compone di:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un presidente permanente di alto livello e indipendente nominato dalla Commissione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">due rappresentanti permanenti della Commissione in quanto proprietaria del sistema di individuazione precoce e di esclusione, che esprimono una posizione congiunta; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un rappresentante dell’ordinatore richiedente.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">La composizione del comitato è tale da garantire le competenze giuridiche e tecniche appropriate. Il comitato è assistito da un segretariato permanente, fornito dalla Commissione, il quale garantisce la gestione corrente del comitato.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il presidente del comitato è scelto tra gli ex membri della Corte di giustizia dell’Unione europea, della Corte dei conti o gli ex funzionari che hanno ricoperto almeno la qualifica di direttore generale in un’istituzione dell’Unione diversa dalla Commissione. È selezionato in funzione delle sue qualità personali e professionali, deve possedere una vasta esperienza in materia giuridica e finanziaria e dare prova di competenza, indipendenza e integrità. Il suo mandato ha durata quinquennale e non è rinnovabile. Il presidente è nominato con la qualifica di consigliere speciale ai sensi dell’articolo 5 del regime applicabile agli altri agenti dell’Unione europea. Il presidente presiede tutte le sessioni del comitato ed esercita le sue funzioni in piena indipendenza. Non deve sussistere conflitto d’interessi tra le sue funzioni di presidente e altri eventuali incarichi ufficiali.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La Commissione adotta il regolamento interno del comitato.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Il comitato garantisce il diritto della persona o dell’entità di cui all’articolo 135, paragrafo 2, di cui trattasi di presentare osservazioni sui fatti o sulle risultanze di cui all’articolo 136, paragrafo 2, e sulla qualificazione giuridica preliminare prima di adottare le sue raccomandazioni. Il diritto di presentare osservazioni può essere differito in circostanze eccezionali, qualora motivi preminenti e legittimi impongano di garantire la riservatezza di un’indagine o di procedimenti giudiziari nazionali, fino quando tali motivi legittimi non vengano meno.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La raccomandazione del comitato di escludere e/o irrogare una sanzione pecuniaria contiene, se del caso, i seguenti elementi:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i fatti o le risultanze di cui all’articolo 136, paragrafo 2, e la loro qualificazione giuridica preliminare;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una valutazione della necessità di irrogare una sanzione pecuniaria e il relativo importo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una valutazione della necessità di escludere la persona o l’entità di cui all’articolo 135, paragrafo 2, e, in tal caso, la durata proposta di tale esclusione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una valutazione della necessità di pubblicare le informazioni relative alla persona o all’entità di cui all’articolo 135, paragrafo 2, oggetto dell’esclusione e/o della sanzione pecuniaria;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una valutazione delle eventuali misure correttive adottate dalla persona o dall’entità di cui all’articolo 135, paragrafo 2.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Qualora preveda di adottare una decisione più severa di quella che è stata raccomandata dal comitato, l’ordinatore responsabile provvede affinché siffatta decisione sia adottata nel debito rispetto del diritto di essere ascoltati e delle norme sulla protezione dei dati personali.</p>"], [null, "<p class=\"norm\">Qualora decida di discostarsi dalla raccomandazione del comitato, l’ordinatore responsabile motiva la sua decisione al comitato.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Il comitato rivede la propria raccomandazione durante il periodo di esclusione su richiesta dell’ordinatore responsabile nei casi di cui all’articolo 136, paragrafo 8, o in seguito alla comunicazione di una sentenza definitiva o decisione amministrativa definitiva in cui sono stabiliti i motivi dell’esclusione nei casi in cui tale sentenza o decisione non fissi la durata dell’esclusione di cui all’articolo 136, paragrafo 2, secondo comma.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">Il comitato notifica senza indugio all’ordinatore richiedente la propria raccomandazione riveduta e, a seguito della comunicazione, l’ordinatore rivede la propria decisione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">9.  </span>\n<div class=\"norm inline-element\">La Corte di giustizia dell’Unione europea ha competenza giurisdizionale anche di merito per rivedere una decisione con la quale l’ordinatore esclude una persona o un’entità di cui all’articolo 135, paragrafo 2, e/o irroga una sanzione pecuniaria a un destinatario, anche annullando l’esclusione o riducendone o aumentandone la durata e/o annullando, riducendo o aumentando la sanzione pecuniaria irrogata. L’articolo 22, paragrafo 1, del regolamento (CE) n. 58/2003 non si applica qualora la decisione dell’ordinatore di esclusione o di irrogazione di una sanzione pecuniaria sia adottata sulla base di una raccomandazione del comitato.</div>\n</div>"]]}, "144": {"label": "Articolo 144", "heading": "Funzionamento della banca dati per il sistema di individuazione precoce e di esclusione", "anchor": "art_144", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le informazioni richieste alle entità di cui all’articolo 142, paragrafo 2, lettera d), sono trasmesse esclusivamente attraverso il sistema informativo automatizzato istituito dalla Commissione attualmente in uso per la segnalazione di irregolarità e frodi («sistema di gestione delle irregolarità»), in conformità della normativa settoriale.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L’utilizzo dei dati ricevuti attraverso il sistema di gestione delle irregolarità tiene conto dello stato della procedura nazionale esistente al momento della presentazione delle informazioni. Tale utilizzo è preceduto da una consultazione dello Stato membro che ha presentato i dati pertinenti attraverso il sistema di gestione delle irregolarità.</div>\n</div>"]]}, "145": {"label": "Articolo 145", "heading": "Eccezioni applicabili al Centro comune di ricerca", "anchor": "art_145", "frags": [[null, "<p class=\"norm\">Gli articoli da 135 a 144 non si applicano al JRC.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "146": {"label": "Articolo 146", "heading": "Gestione elettronica delle operazioni", "anchor": "art_146", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Qualora le entrate e le spese o gli scambi di documenti siano gestiti mediante sistemi informatici, le firme possono essere apposte mediante una procedura informatizzata o elettronica che garantisca l’autenticazione del firmatario. Tali sistemi informatici comprendono una descrizione completa e aggiornata del sistema, che definisce il contenuto di tutti i campi di dati, precisa il modo in cui ogni singola operazione è trattata e illustra dettagliatamente il modo in cui il sistema informatico garantisce l’esistenza di una pista di controllo completa per ogni operazione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Previo accordo delle istituzioni dell’Unione e degli Stati membri interessati, la trasmissione di documenti tra loro può essere effettuata per via elettronica.</div>\n</div>"]]}, "147": {"label": "Articolo 147", "heading": "Amministrazione elettronica («e-Government»)", "anchor": "art_147", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le istituzioni dell’Unione, le agenzie esecutive e gli organismi dell’Unione di cui agli articoli 70 e 71 istituiscono e applicano norme uniformi per lo scambio elettronico di informazioni con i partecipanti. In particolare, elaborano e applicano quanto più possibile soluzioni per la presentazione, l’archiviazione e il trattamento dei dati presentati nelle procedure di aggiudicazione o di attribuzione e a tal fine realizzano un unico «spazio di interscambio dei dati elettronici» per i partecipanti. La Commissione riferisce periodicamente al Parlamento europeo e al Consiglio sui progressi compiuti al riguardo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">In regime di gestione concorrente tutti gli scambi ufficiali di informazioni tra gli Stati membri e la Commissione sono effettuati secondo le modalità indicate nella normativa settoriale. Tale normativa garantisce l’interoperabilità dei dati raccolti o ricevuti e trasmessi nell’ambito della gestione del bilancio.</div>\n</div>"]]}, "148": {"label": "Articolo 148", "heading": "Sistemi di scambio elettronico", "anchor": "art_148", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Tutte le comunicazioni con i destinatari, compresa l’assunzione di impegni giuridici e ogni loro modifica, possono avvenire tramite sistemi di scambio elettronici.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">I sistemi di scambio elettronico soddisfano le seguenti condizioni:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’accesso al sistema e ai documenti trasmessi tramite il sistema è riservato esclusivamente alle persone autorizzate;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">soltanto le persone autorizzate possono firmare per via elettronica o trasmettere un documento tramite il sistema;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le persone autorizzate sono identificate nel sistema mediante procedure prestabilite;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’ora e la data dell’operazione elettronica sono stabilite con precisione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">è garantita l’integrità dei documenti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">è garantita la disponibilità dei documenti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se del caso, è garantita la riservatezza dei documenti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">è assicurata la protezione dei dati personali a norma del regolamento (CE) n. 45/2001.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Ai dati inviati o ricevuti tramite siffatto sistema si applica la presunzione legale dell’integrità dei dati stessi e dell’esattezza della data e dell’ora di invio o ricezione dei medesimi indicata dal sistema.</div>\n</div>"], [null, "<p class=\"norm\">Un documento inviato o notificato tramite siffatto sistema è considerato equivalente a un documento cartaceo, è ammissibile come prova in un procedimento giudiziario, è considerato originale e a esso si applica la presunzione legale di autenticità e integrità, purché esso non contenga elementi dinamici in grado di modificarlo automaticamente.</p>"], [null, "<p class=\"norm\">La firma elettronica di cui al paragrafo 2, lettera b), ha un’efficacia giuridica equivalente alla firma autografa.</p>"]]}, "149": {"label": "Articolo 149", "heading": "Presentazione del fascicolo di partecipazione", "anchor": "art_149", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le modalità di presentazione del fascicolo di partecipazione sono stabilite dall’ordinatore responsabile, che può scegliere una modalità di presentazione esclusiva.</div>\n</div>"], [null, "<p class=\"norm inline-element\">I mezzi di comunicazione prescelti sono tali da garantire una reale concorrenza e il rispetto delle seguenti condizioni:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">che ogni offerta o domanda contenga tutte le informazioni necessarie per la sua valutazione;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">che sia garantita l’integrità dei dati;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">che sia garantita la riservatezza del fascicolo di partecipazione;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">che sia garantita la protezione dei dati personali a norma del regolamento (CE) n. 45/2001.</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La Commissione garantisce con mezzi appropriati e conformemente all’articolo 147, paragrafo 1, che i partecipanti possano presentare il fascicolo di partecipazione e qualsiasi documento giustificativo in formato elettronico. Qualsiasi sistema di comunicazione elettronica usato a sostegno di comunicazioni e scambi di informazioni ha carattere non discriminatorio, è comunemente disponibile, è compatibile con i prodotti della tecnologia dell’informazione e della comunicazione generalmente in uso e non limita l’accesso dei partecipanti alla procedura di aggiudicazione o di attribuzione.</div>\n</div>"], [null, "<p class=\"norm\">La Commissione riferisce periodicamente al Parlamento europeo e al Consiglio sui progressi compiuti nell’applicazione del presente paragrafo.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">I dispositivi di ricezione elettronica del fascicolo di partecipazione garantiscono, mediante mezzi tecnici e opportune procedure, che:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il partecipante possa essere autenticato con certezza;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’ora e la data esatte della ricezione del fascicolo di partecipazione possano essere stabilite con precisione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">soltanto le persone autorizzate abbiano accesso ai dati trasmessi e possano fissare o modificare le date di apertura del fascicolo di partecipazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nelle diverse fasi della procedura di aggiudicazione o di attribuzione soltanto le persone autorizzate abbiano accesso alla totalità dei dati trasmessi e possano consentirne l’accesso secondo quanto previsto dalla procedura;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sia ragionevolmente garantito che qualsiasi tentativo di violare una qualsiasi delle condizioni di cui alle lettere da a) a d) possa essere rilevato.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Il primo comma non si applica ai contratti di valore inferiore alle soglie di cui all’articolo 175, paragrafo 1.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Quando l’ordinatore responsabile autorizza la presentazione per via elettronica del fascicolo di partecipazione, i documenti elettronici inviati tramite tali sistemi sono considerati essere gli originali.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Quando la presentazione avviene per lettera, i partecipanti possono scegliere di presentare il fascicolo di partecipazione:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per via postale oppure tramite corriere, nei quali casi fa fede il timbro postale o la data della ricevuta di deposito;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">mediante consegna presso gli uffici dell’ordinatore responsabile direttamente da parte del partecipante o tramite un suo mandatario, nel qual caso la prova è costituita dalla ricevuta di consegna.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Presentando il fascicolo di partecipazione, i partecipanti accettano di ricevere la comunicazione dell’esito della procedura per via elettronica.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">I paragrafi da 1 a 6 del presente articolo non si applicano alla selezione delle persone o entità che eseguono i fondi dell’Unione ai sensi dell’articolo 62, paragrafo 1, primo comma, lettera c).</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "150": {"label": "Articolo 150", "heading": "Comitato di valutazione", "anchor": "art_150", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il fascicolo di partecipazione è valutato da un comitato di valutazione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il comitato di valutazione è nominato dall’ordinatore responsabile.</div>\n</div>"], [null, "<p class=\"norm\">Il comitato di valutazione è composto da almeno tre persone.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">I membri del comitato di valutazione incaricato di valutare le domande di sovvenzione o le offerte rappresentano almeno due entità organizzative delle istituzioni o degli organismi dell’Unione di cui agli articoli 68, 70 e 71, senza rapporto gerarchico tra loro; almeno uno di essi non deve dipendere dall’ordinatore responsabile. Qualora le rappresentanze e le unità locali al di fuori dell’Unione, come le delegazioni, gli uffici o le succursali dell’Unione presso i paesi terzi, e gli organismi dell’Unione di cui agli articoli 68, 70 e 71 non abbiano entità distinte, non si applica l’obbligo dell’assenza di rapporto gerarchico tra le entità organizzative.</div>\n</div>"], [null, "<p class=\"norm\">Esperti esterni possono assistere il comitato di valutazione conformemente a una decisione dell’ordinatore responsabile.</p>"], [null, "<p class=\"norm\">I membri del comitato di valutazione possono essere esperti esterni se tale possibilità è prevista dall’atto di base.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">I membri del comitato di valutazione incaricato di valutare le domande nell’ambito di un concorso a premi possono essere persone di cui al paragrafo 3, primo comma, o esperti esterni.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">I membri del comitato di valutazione e gli esperti esterni rispettano l’articolo 61.</div>\n</div>"]]}, "151": {"label": "Articolo 151", "heading": "Chiarimento e correzione del fascicolo di partecipazione", "anchor": "art_151", "frags": [[null, "<p class=\"norm\">L’ordinatore responsabile può correggere gli evidenti errori materiali presenti nel fascicolo di partecipazione dopo che il partecipante ha confermato la correzione proposta.</p>"], [null, "<p class=\"norm\">Qualora il partecipante ometta di presentare prove o dichiarazioni, il comitato di valutazione o, se del caso, l’ordinatore responsabile chiede, salvo in casi debitamente motivati, al partecipante di fornire le informazioni mancanti o di chiarire i documenti giustificativi.</p>"], [null, "<p class=\"norm\">Tali informazioni, chiarimenti o conferme non modificano in modo sostanziale il fascicolo di partecipazione.</p>"]]}, "152": {"label": "Articolo 152", "heading": "Garanzie", "anchor": "art_152", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Con l’eccezione di contratti e sovvenzioni il cui valore non ecceda 60 000  EUR, l’ordinatore responsabile può, se lo ritiene proporzionato e previa analisi dei rischi da parte dello stesso, esigere la costituzione di una garanzia da parte:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dei contraenti o dei beneficiari, al fine di limitare i rischi finanziari collegati al versamento dei prefinanziamenti («garanzia sul prefinanziamento»);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dei contraenti, al fine di garantire il rispetto degli obblighi contrattuali sostanziali nel caso di lavori, forniture o servizi complessi («garanzia di esecuzione»);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dei contraenti, al fine di garantire la regolare esecuzione del contratto durante il periodo di responsabilità contrattuale («ritenuta di garanzia»).</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Il JRC è esonerato dalla costituzione di garanzie.</p>"], [null, "<p class=\"norm\">In alternativa alla richiesta di una garanzia sul prefinanziamento, nel caso delle sovvenzioni l’ordinatore responsabile può decidere di frazionare il pagamento in più versamenti.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L’ordinatore responsabile decide se la garanzia debba essere costituita in euro o nella valuta del contratto o della convenzione di sovvenzione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La garanzia è costituita da una banca o da un’istituzione finanziaria autorizzata approvata dall’ordinatore responsabile.</div>\n</div>"], [null, "<p class=\"norm inline-element\">Su richiesta del contraente o del beneficiario e previa accettazione da parte dell’ordinatore responsabile:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la garanzia di cui al paragrafo 1, primo comma, lettere a), b) e c), può essere sostituita da una fideiussione in solido del contraente o del beneficiario e di un terzo;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la garanzia di cui al paragrafo 1, primo comma, lettera a), può essere sostituita da una garanzia solidale, irrevocabile e incondizionata dei beneficiari che sono parti della medesima convenzione di sovvenzione.</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La garanzia rende la banca o l’istituzione finanziaria o il terzo garanti in solido irrevocabilmente o garanti a prima richiesta delle obbligazioni del contraente o del beneficiario.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Qualora, nel corso dell’esecuzione del contratto o della convenzione di sovvenzione, l’ordinatore responsabile venga a conoscenza del fatto che un garante non è o non è più autorizzato a rilasciare garanzie conformemente al diritto nazionale applicabile, esige che il contraente o il beneficiario sostituisca la garanzia costituita da tale garante.</div>\n</div>"]]}, "153": {"label": "Articolo 153", "heading": "Garanzia sul prefinanziamento", "anchor": "art_153", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Una garanzia sul prefinanziamento copre un importo non superiore all’ammontare del prefinanziamento e deve estendersi per un periodo sufficiente a consentirne l’escussione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La garanzia sul prefinanziamento è svincolata man mano che il prefinanziamento è detratto dai pagamenti intermedi o dai pagamenti a saldo versati al contraente o al beneficiario conformemente alle clausole contrattuali o alle condizioni della convenzione di sovvenzione.</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "154": {"label": "Articolo 154", "heading": "Gestione indiretta", "anchor": "art_154", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La selezione delle persone e delle entità cui affidare l’esecuzione dei fondi dell’Unione o delle garanzie di bilancio a norma dell’articolo 62, paragrafo 1, primo comma, lettera c), è trasparente, giustificata dalla natura dell’azione e non dà luogo a conflitti d’interessi. Per le entità di cui all’articolo 62, paragrafo 1, primo comma, lettera c), punti ii), v), vi) e vii), nell’ambito della selezione si tiene debitamente conto anche della loro capacità finanziaria e operativa.</div>\n</div>"], [null, "<p class=\"norm\">Qualora la persona o l’entità sia indicata in un atto di base, la scheda finanziaria di cui all’articolo 35 comprende una giustificazione della scelta di quella particolare persona o entità.</p>"], [null, "<p class=\"norm\">In caso di esecuzione da parte di una rete, che comporta la designazione di almeno un organismo o entità per Stato membro o paese interessato, tale designazione è effettuata dallo Stato membro o dal paese interessato conformemente all’atto di base. In tutti gli altri casi, la Commissione designa tali organismi o entità di concerto con gli Stati membri o i paesi interessati.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le persone e le entità cui è affidata l’esecuzione dei fondi dell’Unione o delle garanzie di bilancio a norma dell’articolo 62, paragrafo 1, primo comma, lettera c), rispettano i principi di sana gestione finanziaria, trasparenza, non discriminazione e visibilità dell’azione dell’Unione. Qualora la Commissione istituisca accordi quadro relativi a partenariati finanziari conformemente all’articolo 130, tali principi sono ribaditi in detti accordi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Preliminarmente alla firma di accordi di contributo, di convenzioni di finanziamento o di accordi di garanzia, la Commissione garantisce un grado di tutela degli interessi finanziari dell’Unione equivalente a quello previsto quando la Commissione esegue il bilancio a norma dell’articolo 62, paragrafo 1, primo comma, lettera a). A tal fine, la Commissione procede a una valutazione dei sistemi, delle norme e delle procedure utilizzati dalle persone o dalle entità che eseguono i fondi dell’Unione, qualora intenda fare affidamento su tali sistemi, norme e procedure per l’attuazione dell’azione, o adotta misure di vigilanza appropriate conformemente al paragrafo 5 del presente articolo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Conformemente al principio di proporzionalità e tenendo in debita considerazione la natura dell’azione e i rischi finanziari connessi, la Commissione verifica che le persone e le entità che eseguono i fondi dell’Unione a norma dell’articolo 62, paragrafo 1, primo comma, lettera c):</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">istituiscano e garantiscano il funzionamento di un sistema di controllo interno efficace ed efficiente fondato sulle migliori prassi internazionali e che consenta in particolare di prevenire, individuare e rettificare le irregolarità e le frodi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">utilizzino una contabilità che fornisca tempestivamente dati precisi, completi e attendibili;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">siano sottoposte a un audit esterno indipendente, svolto, conformemente alle pertinenti norme riconosciute a livello internazionale, da un servizio di audit funzionalmente indipendente dalle persone o delle entità di cui trattasi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">applichino norme e procedure adeguate di erogazione di finanziamenti a terzi, comprendenti procedure di revisione trasparenti, non discriminatorie, efficienti ed efficaci, norme per il recupero dei fondi indebitamente erogati e norme di esclusione dal beneficio dei finanziamenti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">pubblichino opportune informazioni sui destinatari equivalenti a quelle previste all’articolo 38;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">garantiscano una tutela dei dati personali equivalente a quella di cui all’articolo 5.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Inoltre, di concerto con le persone o le entità interessate, la Commissione può valutare altre norme e procedure, quali quelle inerenti le spese per la gestione delle prassi contabili delle persone o entità. In base ai risultati di tale valutazione, la Commissione può decidere di fare affidamento su tali norme e procedure.</p>"], [null, "<p class=\"norm\">Le persone o le entità che sono state sottoposte a valutazione conformemente al primo e secondo comma informano senza indugio la Commissione in merito a eventuali modifiche sostanziali apportate ai loro sistemi, norme o procedure che possono incidere sull’attendibilità della valutazione della Commissione.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Qualora le persone o entità interessate rispettino soltanto parzialmente i requisiti di cui al paragrafo 4, la Commissione adotta opportune misure di vigilanza per tutelare gli interessi finanziari dell’Unione. Tali misure sono specificate nei pertinenti accordi. Le informazioni su tali eventuali misure sono messe a disposizione del Parlamento europeo e del Consiglio, se questi le richiedono.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La Commissione può decidere di non richiedere una valutazione ex ante di cui ai paragrafi 3 e 4:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per gli organismi dell’Unione di cui agli articoli 70 e 71 e per gli organismi o le persone di cui all’articolo 62, paragrafo 1, primo comma, lettera c), punto viii), che hanno adottato regole finanziarie previo accordo della Commissione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per i paesi terzi o gli organismi da essi designati, nella misura in cui la Commissione mantiene responsabilità a livello di gestione finanziaria che garantiscono una sufficiente tutela degli interessi finanziari dell’Unione, oppure</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per le procedure richieste specificatamente dalla Commissione, comprese le proprie e quelle specificate in atti di base.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Qualora i sistemi, le norme e le procedure delle persone o delle entità di cui all’articolo 62, paragrafo 1, primo comma, lettera c), vengano valutati come appropriati, i contributi dell’Unione a tali persone o entità possono essere eseguiti conformemente al presente titolo. Qualora tali persone o entità partecipino a un invito a presentare proposte, esse si attengono alle norme dell’invito stesso contenute nel titolo VIII. In tal caso, l’ordinatore può decidere di firmare un accordo di contributo o una convenzione di finanziamento invece di una convenzione di sovvenzione.</div>\n</div>"]]}, "155": {"label": "Articolo 155", "heading": "Esecuzione dei fondi dell’Unione e delle garanzie di bilancio", "anchor": "art_155", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Le persone e le entità che eseguono fondi dell’Unione o garanzie di bilancio trasmettono alla Commissione la documentazione seguente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una relazione sull’esecuzione dei fondi dell’Unione o delle garanzie di bilancio, anche riguardo all’adempimento delle condizioni o al conseguimento dei risultati di cui all’articolo 125, paragrafo 1, primo comma, lettera a);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">qualora il contributo sia destinato al rimborso delle spese sostenute, i rispettivi conti relativi a tali spese;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una dichiarazione di gestione relativa alle informazioni di cui alla lettera a) e, se opportuno, alla lettera b), attestante che:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le informazioni sono presentate correttamente e sono complete ed esatte;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i fondi dell’Unione sono stati utilizzati per le finalità previste, definite negli accordi di contributo, nelle convenzioni di finanziamento o negli accordi di garanzia o eventualmente nella pertinente normativa settoriale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i sistemi di controllo predisposti offrono le necessarie garanzie quanto alla legittimità e regolarità delle operazioni sottostanti;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un riepilogo delle relazioni finali di audit e dei controlli effettuati, comprese un’analisi della natura e della portata degli errori e delle carenze individuati nei sistemi e le azioni correttive avviate o programmate.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Se ha luogo il riconoscimento reciproco degli audit di cui all’articolo 127, il riepilogo di cui primo comma, lettera d), del presente paragrafo contiene tutta la documentazione sull’audit oggetto di riconoscimento.</p>"], [null, "<p class=\"norm\">Per azioni che si concludono prima della fine dell’esercizio interessato, la relazione finale può sostituire la dichiarazione di gestione di cui al primo comma, lettera c), purché sia presentata anteriormente al 15 febbraio dell’esercizio successivo.</p>"], [null, "<p class=\"norm\">La documentazione di cui al primo comma è corredata del parere di un organismo di audit indipendente elaborato conformemente alle norme riconosciute a livello internazionale in materia di audit. Detto parere accerta se i sistemi di controllo istituiti funzionano correttamente e sono efficaci in termini di costi e se le operazioni sottostanti sono legittime e regolari. Il parere riferisce altresì se l’l’audit mette in dubbio le asserzioni contenute nella dichiarazione di gestione di cui al primo comma, lettera c). In mancanza di tale parere, l’ordinatore può cercare di ottenere un livello di certezza equivalente tramite altri mezzi indipendenti.</p>"], [null, "<p class=\"norm\">La documentazione di cui al primo comma è trasmessa alla Commissione entro il 15 febbraio dell’esercizio successivo. Il parere di cui al terzo comma è trasmesso alla Commissione entro il 15 marzo di tale esercizio.</p>"], [null, "<p class=\"norm\">Gli obblighi stabiliti nel presente paragrafo lasciano impregiudicati gli accordi conclusi con la BEI, il FEI, le organizzazioni degli Stati membri, le organizzazioni internazionali e i paesi terzi. Per quanto riguarda la dichiarazione di gestione, tali accordi prevedono almeno l’obbligo per tali entità di trasmettere ogni anno alla Commissione l’attestazione che, nell’esercizio interessato, i fondi dell’Unione sono stati utilizzati e contabilizzati in conformità dell’articolo 154, paragrafi 3 e 4, e degli obblighi previsti da tali accordi. Se l’azione attuata non supera i 18 mesi, tale attestazione può essere integrata nella relazione finale.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Nell’eseguire fondi dell’Unione le persone e le entità sono tenute a:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">rispettare il diritto dell’Unione applicabile e le norme concordate a livello internazionale e dell’Unione e, pertanto, non sostenere azioni che contribuiscano al riciclaggio, al finanziamento del terrorismo, all’elusione, alla frode o all’evasione fiscali;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nell’attuare gli strumenti finanziari e le garanzie di bilancio in conformità del titolo X, non partecipare a operazioni nuove o rinnovate con entità costituite o stabilite in giurisdizioni segnalate nell’ambito della pertinente politica dell’Unione in materia di giurisdizioni non cooperative, o che sono individuate quali paesi terzi ad alto rischio conformemente all’articolo 9, paragrafo 2, della direttiva (UE) 2015/849, o che non rispettano effettivamente le norme fiscali concordate a livello internazionale o dell’Unione in materia di trasparenza e scambio di informazioni.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Le entità possono derogare al primo comma, lettera b), soltanto se l’azione è attuata fisicamente in una di tali giurisdizioni e non vi sono indicazioni che l’operazione in questione rientri in una delle categorie di cui al primo comma, lettera a).</p>"], [null, "<p class=\"norm\">Nel concludere accordi con intermediari finanziari, le entità che attuano gli strumenti finanziari e le garanzie di bilancio in conformità del titolo X recepiscono i requisiti di cui al presente paragrafo nei pertinenti accordi e chiedono agli intermediari finanziari di rendere conto della loro osservanza.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Nell’attuare gli strumenti finanziari e le garanzie di bilancio in conformità del titolo X, le persone e le entità applicano i principi e le norme stabiliti dal diritto dell’Unione in materia di prevenzione dell’uso del sistema finanziario a scopo di riciclaggio e di finanziamento del terrorismo, in particolare, il regolamento (UE) 2015/847 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">22</span>\n) e la direttiva (UE) 2015/849. Esse subordinano la concessione di finanziamenti a norma del presente regolamento alla divulgazione di informazioni sulla titolarità effettiva in conformità della direttiva (UE) 2015/849 e pubblicano informazioni per paese ai sensi dell’articolo 89, paragrafo 1, della direttiva 2013/36/UE del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">23</span>\n).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La Commissione verifica che i fondi dell’Unione o le garanzie di bilancio siano stati utilizzati conformemente alle condizioni stabilite nei pertinenti accordi. Qualora i costi sostenuti dalla persona o dall’entità siano rimborsati sulla base di un’opzione semplificata in materia di costi conformemente all’articolo 125, paragrafo 1, primo comma, lettere c), d) ed e), si applicano, <span class=\"italics\">mutatis mutandis</span>, l’articolo 181, paragrafi da 1 a 5, e gli articoli da 182 a 185. Qualora i fondi dell’Unione o le garanzie di bilancio siano stati utilizzati in violazione degli obblighi previsti dai pertinenti accordi, si applica l’articolo 131.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Per le azioni finanziate da una pluralità di donatori, qualora il contributo dell’Unione sia destinato al rimborso delle spese, la procedura di cui al paragrafo 4 consiste nella verifica dell’utilizzo, da parte delle persone o delle entità, di un importo corrispondente a quello versato dalla Commissione per l’azione interessata, conformemente alle condizioni stabilite nella pertinente convenzione di sovvenzione o di finanziamento o nel pertinente accordo di contributo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Gli accordi di contributo, le convenzioni di finanziamento e gli accordi di garanzia definiscono chiaramente le responsabilità e gli obblighi della persona o dell’entità che esegue i fondi dell’Unione, compresi gli obblighi di cui all’articolo 129 e le condizioni relative al versamento del contributo. Se del caso, tali accordi definiscono altresì la remunerazione concordata tra le parti, che è commisurata alle condizioni in base alle quali sono attuate le azioni, tenendo debitamente conto delle situazioni di crisi e di fragilità, e si basa eventualmente sulla performance. Tali accordi contengono inoltre le norme in materia di rendicontazione alla Commissione sull’esecuzione dei compiti assegnati, sui risultati attesi, comprensivi degli indicatori per misurare la performance, e sull’obbligo per le persone o le entità che eseguono i fondi dell’Unione di informare senza indugio la Commissione su eventuali casi individuati di frode e di irregolarità e sulle azioni che si intendono adottare.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Tutti gli accordi di contributo, le convenzioni di finanziamento e gli accordi di garanzia sono messi a disposizione del Parlamento europeo e del Consiglio su loro richiesta.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">Il presente articolo non si applica al contributo dell’Unione agli organismi dell’Unione oggetto di una procedura di discarico distinta, a norma degli articoli 70 e 71, eccezion fatta per eventuali accordi di contributo ad hoc.</div>\n</div>"]]}, "156": {"label": "Articolo 156", "heading": "Gestione indiretta con le organizzazioni internazionali", "anchor": "art_156", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Conformemente all’articolo 62, paragrafo 1, primo comma, lettera c), punto ii), la Commissione può eseguire il bilancio indirettamente con organizzazioni internazionali del settore pubblico istituite mediante accordi internazionali («organizzazioni internazionali») e con agenzie specializzate istituite da tali organizzazioni. Tali accordi sono trasmessi alla Commissione nell’ambito della valutazione svolta da quest’ultima a norma dell’articolo 154, paragrafo 3.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Sono assimilate alle organizzazioni internazionali le seguenti organizzazioni:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il Comitato internazionale della Croce rossa;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la Federazione internazionale delle Società nazionali della Croce Rossa e della Mezzaluna Rossa.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La Commissione può adottare una decisione debitamente motivata che assimila un’organizzazione senza scopo di lucro a un’organizzazione internazionale, purché questa soddisfi le seguenti condizioni:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sia dotata di personalità giuridica e di organi di governo autonomi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sia stata costituita per svolgere compiti specifici di interesse internazionale generale;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">almeno sei Stati membri aderiscano all’organizzazione senza scopo di lucro;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sia dotata di adeguate garanzie finanziarie;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">operi sulla base di una struttura permanente e conformemente a sistemi, norme e procedure che possono essere valutati in conformità dell’articolo 154, paragrafo 3.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Quando le organizzazioni internazionali eseguono fondi in regime di gestione indiretta, si applicano gli accordi di verifica con esse conclusi.</div>\n</div>"]]}, "157": {"label": "Articolo 157", "heading": "Gestione indiretta con le organizzazioni degli Stati membri", "anchor": "art_157", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Conformemente all’articolo 62, paragrafo 1, primo comma, lettera c), punti v) e vi), la Commissione può eseguire il bilancio indirettamente con organizzazioni degli Stati membri.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Quando esegue il bilancio indirettamente con le organizzazioni degli Stati membri, la Commissione fa affidamento sui sistemi, sulle norme e sulle procedure di tali organizzazioni, valutate conformemente all’articolo 154, paragrafi 3 e 4.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Gli accordi quadro relativi a partenariati finanziari conclusi con organizzazioni degli Stati membri in conformità dell’articolo 130 precisano ulteriormente la portata e le modalità del riconoscimento reciproco dei sistemi, delle norme e delle procedure delle organizzazioni degli Stati membri e possono includere disposizioni specifiche in materia di riconoscimento reciproco delle valutazioni e degli audit di cui agli articoli 126 e 127.</div>\n</div>"]]}, "158": {"label": "Articolo 158", "heading": "Gestione indiretta con i paesi terzi", "anchor": "art_158", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La Commissione può eseguire il bilancio indirettamente con un paese terzo o gli organismi da questo designati di cui all’articolo 62, paragrafo 1, primo comma, lettera c), punto i), mediante la conclusione di una convenzione di finanziamento che descrive l’intervento dell’Unione nel paese terzo e stabilisce il metodo di attuazione di ciascuna parte dell’azione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Per la parte dell’azione attuata indirettamente con il paese terzo o gli organismi da esso designati, la convenzione di finanziamento, oltre agli elementi di cui all’articolo 155, paragrafo 5, definisce chiaramente i ruoli e le responsabilità del paese terzo e della Commissione nell’esecuzione dei fondi. La convenzione di finanziamento stabilisce inoltre le norme e le procedure che devono essere applicate dal paese terzo nell’esecuzione dei fondi dell’Unione.</div>\n</div>"]]}, "159": {"label": "Articolo 159", "heading": "Operazioni di finanziamento misto", "anchor": "art_159", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le operazioni di finanziamento misto sono gestite dalla Commissione oppure da persone o entità che eseguono fondi dell’Unione conformemente all’articolo 62, paragrafo 1, primo comma, lettera c).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Quando gli strumenti finanziari e le garanzie di bilancio sono attuati nell’ambito di un meccanismo o di una piattaforma di finanziamento misto, si applica il titolo X.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Per quanto riguarda gli strumenti finanziari e le garanzie di bilancio eseguite nell’ambito di meccanismi o piattaforme di finanziamento misto, si considera soddisfatto l’articolo 209, paragrafo 2, primo comma, lettera h), se è effettuata una valutazione ex ante prima della costituzione del meccanismo o della piattaforma di finanziamento misto pertinenti.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">A livello di meccanismo o di piattaforma di finanziamento misto sono redatte relazioni annuali a norma dell’articolo 249, che tengono conto di tutti gli strumenti finanziari e delle garanzie di bilancio raggruppati nel meccanismo o nella piattaforma e indicano chiaramente i diversi tipi di sostegno finanziario nell’ambito degli stessi.</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "160": {"label": "Articolo 160", "heading": "Principi applicabili agli appalti e ambito di applicazione", "anchor": "art_160", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Tutti i contratti finanziati interamente o parzialmente dal bilancio rispettano i principi di trasparenza, proporzionalità, parità di trattamento e non discriminazione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Tutti i contratti sono messi a gara assicurando la più ampia concorrenza, salvo nel caso di ricorso alla procedura di cui all’articolo 164, paragrafo 1, lettera d).</div>\n</div>"], [null, "<p class=\"norm\">Il valore stimato di un contratto non è stabilito con l’intenzione di eludere le norme applicabili e nessun contratto è frazionato a tal fine.</p>"], [null, "<p class=\"norm\">L’amministrazione aggiudicatrice divide un contratto in lotti ogniqualvolta sia opportuno, tenendo debitamente conto di un’ampia concorrenza.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Le amministrazioni aggiudicatrici non ricorrono a contratti quadro in modo improprio o in modo tale che abbiano per scopo o per effetto di impedire, limitare o falsare la concorrenza.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Il JRC può ricevere finanziamenti imputati a stanziamenti diversi da quelli per la ricerca e lo sviluppo tecnologico nell’ambito della sua partecipazione a procedure di appalto finanziate, in tutto o in parte, dal bilancio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Le norme in materia di appalti di cui al presente regolamento non si applicano alle attività del JRC per conto terzi, con l’eccezione dei principi di trasparenza e di parità di trattamento.</div>\n</div>"]]}, "161": {"label": "Articolo 161", "heading": "Allegato sugli appalti e delega di potere", "anchor": "art_161", "frags": [[null, "<p class=\"norm\">Le disposizioni dettagliate concernenti gli appalti figurano nell’allegato I del presente regolamento. Per assicurare che, quando aggiudicano appalti per proprio conto, le istituzioni dell’Unione applichino norme identiche a quelle imposte alle amministrazioni aggiudicatrici disciplinate dalle direttive 2014/23/UE e 2014/24/UE, alla Commissione è conferito il potere di adottare atti delegati conformemente all’articolo 269 del presente regolamento per modificare l’allegato I del presente regolamento, al fine di allineare tale allegato alle modifiche apportate a dette direttive e di introdurre i relativi adeguamenti tecnici.</p>"]]}, "162": {"label": "Articolo 162", "heading": "Contratti misti e vocabolario comune per gli appalti pubblici", "anchor": "art_162", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Un contratto misto avente per oggetto due o più tipi di appalti (lavori, forniture o servizi) o concessioni (lavori o servizi), o avente per oggetto sia appalti che concessioni, è aggiudicato in conformità delle disposizioni applicabili al tipo di appalto che caratterizza l’oggetto principale del contratto in questione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Nel caso di appalti misti che constano di forniture e servizi, l’oggetto principale è determinato raffrontando i valori rispettivi delle forniture e dei servizi.</div>\n</div>"], [null, "<p class=\"norm\">Un contratto riguardante un solo tipo di appalto (lavori, forniture o servizi) e concessioni (lavori o servizi) è aggiudicato in conformità delle disposizioni applicabili all’appalto pubblico in questione.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il presente titolo non si applica ai contratti di assistenza tecnica conclusi con la BEI o il FEI.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Ogni riferimento alle nomenclature nel contesto degli appalti è effettuato sulla base del Vocabolario comune per gli appalti pubblici (CPV) di cui al regolamento (CE) n. 2195/2002 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">24</span>\n).</div>\n</div>"]]}, "163": {"label": "Articolo 163", "heading": "Misure di pubblicità", "anchor": "art_163", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Per le procedure di valore pari o superiore alle soglie di cui all’articolo 175, paragrafo 1, o all’articolo 178, l’amministrazione aggiudicatrice pubblica nella <span class=\"italics\">Gazzetta ufficiale dell’Unione europea</span>:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un bando di gara per avviare la procedura, tranne nel caso della procedura di cui all’articolo 164, paragrafo 1, lettera d);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un avviso di aggiudicazione che riporta i risultati della procedura.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le procedure di valore inferiore alle soglie di cui all’articolo 175, paragrafo 1, o all’articolo 178 sono oggetto di un’adeguata pubblicità.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La pubblicazione di talune informazioni relative all’aggiudicazione di un contratto può essere omessa qualora la divulgazione ostacoli l’applicazione della legge, o sia contraria all’interesse pubblico, pregiudichi i legittimi interessi commerciali degli operatori economici oppure possa recare pregiudizio alla concorrenza leale tra di loro.</div>\n</div>"]]}, "164": {"label": "Articolo 164", "heading": "Procedure di appalto", "anchor": "art_164", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Le procedure di aggiudicazione di contratti di concessione o di appalti pubblici, compresi i contratti quadro, assumono una delle seguenti forme:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">procedura aperta;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">procedura ristretta, anche tramite un sistema dinamico di acquisizione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">concorso di progettazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">procedura negoziata, anche senza previa pubblicazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dialogo competitivo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">procedura competitiva con negoziazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">partenariato per l’innovazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">procedure che comportano un invito a manifestare interesse.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Nelle procedure aperte qualsiasi operatore economico interessato può presentare un’offerta.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Nelle procedure ristrette, nei dialoghi competitivi, nelle procedure competitive con negoziazione e nei partenariati per l’innovazione qualsiasi operatore economico può presentare una domanda di partecipazione fornendo le informazioni richieste dall’amministrazione aggiudicatrice. L’amministrazione aggiudicatrice invita a presentare un’offerta tutti i candidati che soddisfano i criteri di selezione e che non rientrano in alcuna delle situazioni di cui agli articoli 136, paragrafo 1, e 141, paragrafo 1.</div>\n</div>"], [null, "<p class=\"norm\">Fatto salvo il primo comma, l’amministrazione aggiudicatrice può limitare il numero di candidati da invitare a partecipare alla procedura sulla base di criteri di selezione oggettivi e non discriminatori indicati nel bando di gara o nell’invito a manifestare interesse. Il numero di candidati invitati deve essere sufficiente ad assicurare un’effettiva concorrenza.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">In tutte le procedure che comportano una negoziazione, l’amministrazione aggiudicatrice negozia con gli offerenti le offerte iniziali e le eventuali offerte successive o parti di esse, tranne le offerte finali, per migliorarne il contenuto. I requisiti minimi e i criteri precisati nei documenti di gara non sono soggetti a negoziazione.</div>\n</div>"], [null, "<p class=\"norm\">Un’amministrazione aggiudicatrice può aggiudicare un contratto sulla base dell’offerta iniziale senza negoziazione qualora abbia indicato, nei documenti di gara, che si riserva la possibilità di farlo.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">L’amministrazione aggiudicatrice può ricorrere:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">alla procedura aperta o ristretta per qualunque acquisto;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">a procedure che comportano un invito a manifestare interesse per contratti di valore inferiore alla soglia di cui all’articolo 175, paragrafo 1, per preselezionare candidati da invitare a presentare offerte in risposta a futuri inviti ristretti a presentare offerte o per stilare un elenco di potenziali offerenti da invitare a presentare domande di partecipazione od offerte;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">a un concorso di progettazione per acquisire un piano o un progetto selezionato da una commissione giudicatrice in base a una gara;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">al partenariato per l’innovazione per sviluppare prodotti, servizi o lavori innovativi e acquistare successivamente le forniture, i servizi o i lavori che ne risultano;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">alla procedura competitiva con negoziazione o al dialogo competitivo per contratti di concessione, per gli appalti di servizi di cui all’allegato XIV della direttiva 2014/24/UE, nei casi in cui sono state presentate solo offerte irregolari o inaccettabili in risposta a una procedura aperta o ristretta dopo il completamento della procedura iniziale e per i casi in cui ciò sia giustificato da circostanze specifiche legate, tra l’altro, alla natura o alla complessità dell’oggetto del contratto o al tipo specifico di contratto, come ulteriormente precisato nell’allegato I del presente regolamento;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">alle procedure negoziate per contratti di valore inferiore alle soglie di cui all’articolo 175, paragrafo 1, o alla procedura negoziata senza previa pubblicazione, per tipi specifici di acquisti che esulano dall’ambito di applicazione della direttiva 2014/24/UE oppure in circostanze eccezionali chiaramente definite nell’allegato I del presente regolamento.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Un sistema dinamico di acquisizione è aperto per tutta la sua durata a ogni operatore economico che soddisfa i criteri di selezione.</div>\n</div>"], [null, "<p class=\"norm\">L’amministrazione aggiudicatrice segue le norme relative alla procedura ristretta per gli appalti tramite un sistema dinamico di acquisizione.</p>"]]}, "165": {"label": "Articolo 165", "heading": "Appalto interistituzionale e appalto congiunto", "anchor": "art_165", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Nei casi in cui un contratto o un contratto quadro riveste interesse per due o più istituzioni dell’Unione, agenzie esecutive od organismi dell’Unione di cui agli articoli 70 e 71 e ogniqualvolta vi sia la possibilità di migliorare l’efficienza, le amministrazioni aggiudicatrici interessate hanno la facoltà di eseguire la procedura e la gestione del successivo contratto o contratto quadro su base interistituzionale sotto la guida di una delle amministrazioni aggiudicatrici.</div>\n</div>"], [null, "<p class=\"norm\">Possono partecipare alle procedure interistituzionali anche gli organismi e le persone incaricati di attuare azioni specifiche della PESC di cui al titolo V del TUE, nonché l’Ufficio del segretario del Consiglio superiore delle scuole europee.</p>"], [null, "<p class=\"norm\">Le condizioni stabilite da un contratto quadro si applicano solo tra le amministrazioni aggiudicatrici individuate a tale fine nei documenti di gara e gli operatori economici parti del contratto quadro.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Nei casi in cui un contratto o un contratto quadro è necessario per l’attuazione di un’azione comune fra un’istituzione dell’Unione e una o più amministrazioni aggiudicatrici degli Stati membri, la procedura di appalto può essere condotta congiuntamente dall’istituzione dell’Unione e dalle amministrazioni aggiudicatrici.</div>\n</div>"], [null, "<p class=\"norm\">Con gli Stati dell’EFTA e con i paesi candidati all’adesione all’Unione si può procedere a un appalto congiunto se tale possibilità è stata specificamente prevista in un trattato bilaterale o multilaterale.</p>"], [null, "<p class=\"norm\">All’appalto congiunto si applicano le disposizioni procedurali delle istituzioni dell’Unione.</p>"], [null, "<p class=\"norm\">Quando l’amministrazione aggiudicatrice di uno Stato membro detiene o gestisce una quota del valore stimato totale del contratto pari o superiore al 50 %, oppure in altri casi debitamente motivati, l’istituzione dell’Unione può decidere che all’appalto congiunto si applichino le norme procedurali dell’amministrazione aggiudicatrice dello Stato membro, purché tali norme possano essere considerate equivalenti a quelle dell’istituzione dell’Unione.</p>"], [null, "<p class=\"norm\">L’istituzione dell’Unione e l’amministrazione aggiudicatrice di uno Stato membro, di uno Stato dell’EFTA o di un paese candidato all’adesione all’Unione coinvolti congiuntamente nell’appalto si accordano, in particolare, sulle modalità pratiche della valutazione delle richieste di partecipazione o delle offerte, sull’aggiudicazione del contratto, sul diritto applicabile al contratto e sul giudice competente in caso di controversie.</p>"]]}, "166": {"label": "Articolo 166", "heading": "Preparazione di una procedura di appalto", "anchor": "art_166", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Prima dell’avvio di una procedura di appalto, l’amministrazione aggiudicatrice può svolgere una consultazione preliminare di mercato ai fini della preparazione della procedura.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Nei documenti di gara l’amministrazione aggiudicatrice individua l’oggetto dell’appalto fornendo una descrizione delle sue esigenze e illustrando le caratteristiche richieste dei lavori, delle forniture o dei servizi da acquistare e specifica i criteri di esclusione, selezione e aggiudicazione applicabili. L’amministrazione aggiudicatrice indica altresì quali elementi definiscono i requisiti minimi che tutte le offerte devono soddisfare. I requisiti minimi comprendono il rispetto degli obblighi applicabili in materia di diritto ambientale, sociale e del lavoro stabiliti dal diritto dell’Unione, dal diritto nazionale, da contratti collettivi o dalle convenzioni internazionali in materia sociale e ambientale applicabili elencate nell’allegato X della direttiva 2014/24/UE.</div>\n</div>"]]}, "167": {"label": "Articolo 167", "heading": "Aggiudicazione dei contratti", "anchor": "art_167", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">I contratti sono aggiudicati sulla base dei criteri di aggiudicazione, purché l’amministrazione aggiudicatrice abbia verificato che:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’offerta è conforme ai requisiti minimi precisati nei documenti di gara;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il candidato od offerente non si trova in situazione di esclusione ai sensi dell’articolo 136 o di rigetto ai sensi dell’articolo 141;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il candidato od offerente soddisfa i criteri di selezione indicati nei documenti di gara e non è soggetto a conflitti d’interesse che possano influire negativamente sull’esecuzione del contratto.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L’amministrazione aggiudicatrice applica i criteri di selezione per valutare la capacità del candidato od offerente. I criteri di selezione riguardano unicamente la capacità giuridica e normativa per esercitare l’attività professionale, la capacità economica e finanziaria e la capacità tecnica e professionale. Il JRC è considerato conforme ai criteri di capacità finanziaria.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">L’amministrazione aggiudicatrice applica i criteri di aggiudicazione per valutare l’offerta.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">L’amministrazione aggiudicatrice procede all’aggiudicazione dei contratti sulla base dell’offerta economicamente più vantaggiosa, applicando uno dei tre metodi di aggiudicazione, vale a dire prezzo più basso, costo più basso o miglior rapporto qualità/prezzo.</div>\n</div>"], [null, "<p class=\"norm\">Per il metodo del costo più basso, l’amministrazione aggiudicatrice segue un approccio basato sul rapporto costi-benefici, compreso il calcolo del costo del ciclo di vita.</p>"], [null, "<p class=\"norm\">Per il miglior rapporto qualità/prezzo, l’amministrazione aggiudicatrice tiene conto del prezzo o costo e di altri criteri di qualità connessi all’oggetto del contratto.</p>"]]}, "168": {"label": "Articolo 168", "heading": "Presentazione, comunicazione elettronica e valutazione", "anchor": "art_168", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L’amministrazione aggiudicatrice stabilisce i termini per la ricezione delle offerte e delle domande di partecipazione in conformità del punto 24 dell’allegato I e tenendo conto della complessità dell’acquisto, in modo che gli operatori economici dispongano di un congruo periodo di tempo per preparare l’offerta.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Se ritenuto opportuno e proporzionato, l’amministrazione aggiudicatrice può esigere dagli offerenti la costituzione una garanzia affinché le offerte presentate non siano ritirate prima della firma del contratto. La garanzia richiesta è pari all’1 - 2 % del valore stimato totale del contratto.</div>\n</div>"], [null, "<p class=\"norm inline-element\">L’amministrazione aggiudicatrice svincola le garanzie:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">rispetto agli offerenti o alle offerte respinti di cui al punto 30.2, lettera b) o c), dell’allegato I, previa informazione sull’esito della procedura;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">rispetto agli offerenti classificati di cui al punto 30.2, lettera e), dell’allegato I, previa firma del contratto.</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">L’amministrazione aggiudicatrice apre tutte le domande di partecipazione e le offerte. Tuttavia respinge:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le domande di partecipazione e le offerte che non rispettano il termine per la ricezione, senza aprirle;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le offerte già aperte quando sono pervenute, senza esaminarne il contenuto.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">L’amministrazione aggiudicatrice valuta tutte le domande di partecipazione od offerte non respinte nella fase di apertura di cui al paragrafo 3 sulla base dei criteri indicati nei documenti di gara, al fine di aggiudicare il contratto oppure di procedere a un’asta elettronica.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">L’ordinatore può rinunciare alla nomina del comitato di valutazione a norma dell’articolo 150, paragrafo 2, nei seguenti casi:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se il valore del contratto è inferiore alle soglie di cui all’articolo 175, paragrafo 1;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">in funzione di un’analisi dei rischi nei casi di cui al punto 11.1, secondo comma, lettere c) ed e), lettera f), punti i) e iii), e lettera h), dell’allegato I;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">in funzione di un’analisi dei rischi alla riapertura del confronto competitivo nell’ambito di un contratto quadro;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per le procedure nell’ambito delle azioni esterne di valore pari o inferiore a 20 000  EUR.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Le domande di partecipazione e le offerte che non rispettano tutte le prescrizioni minime figuranti nei documenti di gara sono respinte.</div>\n</div>"]]}, "169": {"label": "Articolo 169", "heading": "Contatti durante la procedura di appalto", "anchor": "art_169", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Prima della scadenza del termine per la ricezione delle domande di partecipazione o delle offerte l’amministrazione aggiudicatrice può comunicare informazioni supplementari circa i documenti di gara se si accorge di un errore o di un’omissione nella redazione o su richiesta dei candidati od offerenti. Le informazioni fornite sono comunicate a tutti i candidati od offerenti.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Dopo la scadenza del termine per la ricezione delle domande di partecipazione o delle offerte, tutti i casi in cui sono stati conclusi contatti e i casi debitamente motivati in cui non sono stati stipulati contatti, di cui all’articolo 151, sono registrati nel fascicolo di gara.</div>\n</div>"]]}, "170": {"label": "Articolo 170", "heading": "Decisione di aggiudicazione e informazione ai candidati od offerenti", "anchor": "art_170", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L’ordinatore responsabile designa l’aggiudicatario del contratto, nel rispetto dei criteri di selezione e di aggiudicazione indicati nei documenti di gara.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L’amministrazione aggiudicatrice comunica a ogni candidato od offerente la cui domanda di partecipazione od offerta è stata respinta i motivi del rigetto, nonché la durata dei periodi di status quo di cui agli articoli 175, paragrafo 2, e 178, paragrafo 1.</div>\n</div>"], [null, "<p class=\"norm\">Per l’aggiudicazione di contratti specifici nell’ambito di un contratto quadro con riapertura del confronto competitivo, l’amministrazione aggiudicatrice informa gli offerenti dell’esito della valutazione.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">L’amministrazione aggiudicatrice comunica a ogni offerente che non si trova in una situazione di esclusione di cui all’articolo 136, paragrafo 1, che non è respinto ai sensi dell’articolo 141, la cui offerta è conforme ai documenti di gara e che ne fa domanda per iscritto, le informazioni seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il nome dell’aggiudicatario, o degli aggiudicatari nel caso di un contratto quadro, e, a eccezione del caso di un contratto specifico nell’ambito di un contratto quadro con riapertura del confronto competitivo, le caratteristiche e i vantaggi relativi dell’offerta prescelta, il prezzo pagato o il valore del contratto, a seconda del caso;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’andamento delle negoziazioni e del dialogo con gli offerenti.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Tuttavia, l’amministrazione aggiudicatrice può decidere di non divulgare talune informazioni qualora la loro diffusione ostacoli l’applicazione della legge, sia contraria all’interesse pubblico ovvero pregiudichi i legittimi interessi commerciali degli operatori economici o possa distorcere la concorrenza leale tra di loro.</p>"]]}, "171": {"label": "Articolo 171", "heading": "Annullamento della procedura di appalto", "anchor": "art_171", "frags": [[null, "<p class=\"norm\">Fino al momento della firma del contratto l’amministrazione aggiudicatrice può annullare la procedura di appalto senza che i candidati o gli offerenti abbiano diritto ad alcun risarcimento.</p>"], [null, "<p class=\"norm\">La decisione è motivata ed è resa nota ai candidati o offerenti con la massima tempestività.</p>"]]}, "172": {"label": "Articolo 172", "heading": "Esecuzione e modifiche del contratto", "anchor": "art_172", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L’esecuzione del contratto non ha inizio prima che lo stesso sia stato firmato.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L’amministrazione aggiudicatrice può modificare un contratto o un contratto quadro senza organizzare una procedura di appalto soltanto nei casi di cui al paragrafo 3 e purché la modifica non muti l’oggetto del contratto o del contratto quadro.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Un contratto, un contratto quadro o un contratto specifico nell’ambito di un contratto quadro può essere modificato senza una nuova procedura di appalto nei seguenti casi:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se si sono resi necessari lavori, forniture o servizi supplementari da parte del contraente originario che non erano inclusi nell’appalto iniziale, ove siano soddisfatte le seguenti condizioni:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un cambiamento del contraente risulta impraticabile per motivi tecnici legati ai requisiti di intercambiabilità o interoperabilità tra apparecchiature, servizi o impianti esistenti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un cambiamento del contraente comporterebbe per l’amministrazione aggiudicatrice una sostanziale duplicazione dei costi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’eventuale aumento di prezzo, ivi compreso il valore complessivo netto delle successive modifiche, non eccede il 50 % del valore del contratto iniziale;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se sono soddisfatte tutte le seguenti condizioni:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la necessità di modifica è determinata da circostanze che un’amministrazione aggiudicatrice diligente non poteva prevedere;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’eventuale aumento di prezzo non eccede il 50 % del valore del contratto iniziale;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se il valore della modifica è inferiore alle soglie seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le soglie di cui all’articolo 175, paragrafo 1, e al punto 38 dell’allegato I nell’ambito delle azioni esterne, applicabili al momento della modifica; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il 10 % del valore del contratto iniziale per gli appalti pubblici di servizi e forniture e per i contratti di concessione di lavori o servizi e il 15 % del valore del contratto iniziale per i contratti pubblici di lavori;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se sono soddisfatte entrambe le condizioni seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i requisiti minimi della procedura di appalto iniziale non sono modificati;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">qualsiasi modifica successiva del valore è conforme alle condizioni di cui alla lettera c) del presente comma, a meno che tale modifica di valore non risulti dalla rigorosa applicazione dei documenti di gara o delle disposizioni contrattuali.</p>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Il valore del contratto iniziale non tiene conto delle revisioni del prezzo.</p>"], [null, "<p class=\"norm\">Il valore complessivo netto di più modifiche successive ai sensi del primo comma, lettera c), non supera alcuna soglia ivi stabilita.</p>"], [null, "<p class=\"norm\">L’amministrazione aggiudicatrice applica le misure di pubblicità ex post di cui all’articolo 163.</p>"]]}, "173": {"label": "Articolo 173", "heading": "Garanzie di esecuzione e ritenute di garanzia", "anchor": "art_173", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Una garanzia di esecuzione ammonta al massimo al 10 % del valore totale dell’appalto.</div>\n</div>"], [null, "<p class=\"norm\">Essa è integralmente svincolata dopo il collaudo definitivo dei lavori, delle forniture o dei servizi complessi, entro un periodo conforme ai termini di cui all’articolo 116, paragrafo 1, che deve essere specificato nel contratto. La garanzia può essere svincolata parzialmente o integralmente dopo il collaudo provvisorio dei lavori, delle forniture o dei servizi complessi.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Una ritenuta di garanzia corrispondente al massimo al 10 % del valore totale dell’appalto può essere costituita mediante trattenute sui pagamenti intermedi man mano che questi sono effettuati oppure mediante trattenuta sul pagamento finale.</div>\n</div>"], [null, "<p class=\"norm\">L’amministrazione aggiudicatrice stabilisce l’importo della ritenuta di garanzia, che è proporzionato ai rischi individuati in relazione all’esecuzione del contratto, tenuto conto dell’oggetto e delle condizioni commerciali usualmente applicate nel settore in questione.</p>"], [null, "<p class=\"norm\">Non può farsi ricorso a una ritenuta di garanzia in un contratto nell’ambito del quale è stata richiesta una garanzia di esecuzione che non è stata svincolata.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il contraente può presentare richiesta, subordinata all’approvazione dell’amministrazione aggiudicatrice, di sostituire la ritenuta di garanzia con un altro tipo di garanzia di cui all’articolo 152.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">L’amministrazione aggiudicatrice svincola la ritenuta di garanzia dopo la scadenza del periodo di responsabilità contrattuale, entro un periodo conforme ai termini di cui all’articolo 116, paragrafo 1, e che deve essere specificato nel contratto.</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "174": {"label": "Articolo 174", "heading": "L’amministrazione aggiudicatrice", "anchor": "art_174", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le istituzioni dell’Unione, le agenzie esecutive e gli organismi dell’Unione di cui agli articoli 70 e 71 sono considerati amministrazioni aggiudicatrici per i contratti che aggiudicano per proprio conto, salvo quando acquistano da una centrale di committenza. I servizi delle istituzioni dell’Unione non sono considerati amministrazioni aggiudicatrici quando concludono tra loro accordi sul livello dei servizi.</div>\n</div>"], [null, "<p class=\"norm\">Le istituzioni dell’Unione considerate amministrazioni aggiudicatrici conformemente al primo comma delegano, in conformità dell’articolo 60, i poteri necessari per esercitare la funzione di amministrazione aggiudicatrice.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Ciascun ordinatore delegato o sottodelegato nell’ambito di ciascuna istituzione dell’Unione valuta se siano raggiunte le soglie di cui all’articolo 175, paragrafo 1.</div>\n</div>"]]}, "175": {"label": "Articolo 175", "heading": "Soglie applicabili e periodo di status quo", "anchor": "art_175", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ai fini dell’aggiudicazione di appalti pubblici e contratti di concessione, l’amministrazione aggiudicatrice rispetta le soglie stabilite all’articolo 4, lettere a) e b), della direttiva 2014/24/UE all’atto della selezione di una procedura di cui all’articolo 164, paragrafo 1, del presente regolamento. Tali soglie determinano le misure di pubblicità di cui all’articolo 163, paragrafi 1 e 2, del presente regolamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Fatte salve le eccezioni e condizioni specificate nell’allegato I del presente regolamento, nel caso di contratti il cui valore superi le soglie di cui al paragrafo 1 l’amministrazione aggiudicatrice non firma il contratto o il contratto quadro con l’aggiudicatario prima che sia trascorso un periodo di status quo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il periodo di status quo ha una durata di 10 giorni se si usano mezzi di comunicazione elettronici, di 15 giorni se si usano altri mezzi.</div>\n</div>"]]}, "176": {"label": "Articolo 176", "heading": "Norme in materia di accesso agli appalti", "anchor": "art_176", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La partecipazione alle procedure di appalto è aperta a parità di condizioni a tutte le persone fisiche e giuridiche che rientrano nell’ambito di applicazione dei trattati e a tutte le persone fisiche e giuridiche stabilite in un paese terzo che abbia concluso un accordo particolare con l’Unione nel settore degli appalti, secondo il disposto di tale accordo. La partecipazione è inoltre aperta alle organizzazioni internazionali.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Ai fini dell’articolo 160, paragrafo 4, il JRC è considerato una persona giuridica stabilita in uno Stato membro.</div>\n</div>"]]}, "177": {"label": "Articolo 177", "heading": "Norme dell’Organizzazione mondiale del commercio in materia di appalti", "anchor": "art_177", "frags": [[null, "<p class=\"norm\">Qualora sia applicabile l’accordo plurilaterale sugli appalti pubblici concluso nell’ambito dell’Organizzazione mondiale del commercio, la procedura di appalto è aperta anche agli operatori economici stabiliti negli Stati che hanno ratificato tale accordo, alle condizioni da esso previste.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "178": {"label": "Articolo 178", "heading": "Aggiudicazione degli appalti per l’azione esterna", "anchor": "art_178", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Agli appalti di cui al presente capo si applicano le disposizioni generali di cui al presente titolo, capo 1, fatte salve le disposizioni specifiche sulle modalità di aggiudicazione degli appalti esterni previste nel capo 3 dell’allegato I. Agli appalti di cui al presente capo non si applicano gli articoli da 174 a 177.</div>\n</div>"], [null, "<p class=\"norm\">Fatte salve le eccezioni e condizioni specificate nell’allegato I, l’amministrazione aggiudicatrice non firma il contratto o il contratto quadro con l’aggiudicatario prima che sia trascorso un periodo di status quo. Il periodo di status quo ha una durata di 10 giorni se si usano mezzi di comunicazione elettronici, di 15 giorni se si usano altri mezzi.</p>"], [null, "<p class=\"norm inline-element\">L’articolo 163, l’articolo 164, paragrafo 1, lettere a) e b), e il secondo comma del presente paragrafo si applicano solo a partire da:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">300 000  EUR per gli appalti di servizi e di forniture;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">5 000 000  EUR per gli appalti di lavori.</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Il presente capo si applica:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">agli appalti non aggiudicati dalla Commissione per proprio conto;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">agli appalti aggiudicati da persone o entità che eseguono fondi dell’Unione a norma dell’articolo 62, paragrafo 1, primo comma, lettera c), nei casi previsti dagli accordi di contributo o dalle convenzioni di finanziamento di cui all’articolo 154.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Le procedure di appalto sono stabilite nelle convenzioni di finanziamento di cui all’articolo 158.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Il presente capo non si applica ad azioni previste da atti di base settoriali specifici relativi agli aiuti in situazioni di crisi umanitaria, alle operazioni di protezione civile e alle azioni di aiuto umanitario.</div>\n</div>"]]}, "179": {"label": "Articolo 179", "heading": "Norme in materia di accesso agli appalti nell’ambito delle azioni esterne", "anchor": "art_179", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La partecipazione alle procedure di appalto è aperta a parità di condizioni a tutti i soggetti che rientrano nell’ambito di applicazione dei trattati e a tutte le altre persone fisiche e giuridiche in conformità delle disposizioni specifiche previste negli atti di base che disciplinano il settore della cooperazione interessato. La partecipazione è inoltre aperta alle organizzazioni internazionali.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">In circostanze eccezionali debitamente giustificate dall’ordinatore responsabile, possono essere ammessi a partecipare alle gare anche cittadini di paesi terzi diversi da quelli di cui al paragrafo 1 del presente articolo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">In caso di applicazione di un accordo relativo all’apertura del mercato degli appalti di beni o servizi cui partecipa l’Unione, le procedure di appalto per contratti finanziati tramite il bilancio sono aperte anche alle persone fisiche e giuridiche stabilite in paesi terzi diversi da quelli di cui ai paragrafi 1 e 2, alle condizioni definite in tale accordo.</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "180": {"label": "Articolo 180", "heading": "Ambito di applicazione e forma delle sovvenzioni", "anchor": "art_180", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il presente titolo si applica alle sovvenzioni attribuite in regime di gestione diretta.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Le sovvenzioni possono essere attribuite per finanziare:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un’azione destinata a promuovere la realizzazione di un obiettivo di una politica dell’Unione («sovvenzioni di un’azione»);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il funzionamento di un organismo avente un obiettivo che si iscrive nell’ambito di una politica dell’Unione e la sostiene («sovvenzioni di funzionamento»).</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Le sovvenzioni di funzionamento assumono la forma di un contributo finanziario al programma di lavoro dell’organismo di cui al primo comma, lettera b).</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Le sovvenzioni possono assumere una delle forme di cui all’articolo 125, paragrafo 1.</div>\n</div>"], [null, "<p class=\"norm inline-element\">Quando la sovvenzione assume la forma di un finanziamento non collegato ai costi a norma dell’articolo 125, paragrafo 1, primo comma, lettera a):</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">non si applicano le disposizioni in materia di ammissibilità e verifica dei costi di cui al presente titolo, in particolare, agli articoli 182, 184 e 185, all’articolo 186, paragrafi 2, 3 e 4, all’articolo 190, agli articoli 191, paragrafo 3, e 203, paragrafo 4;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per quanto riguarda l’articolo 181, si applicano solo la procedura e le prescrizioni di cui ai paragrafi 2 e 3 di tale articolo, al paragrafo 4, primo comma, lettere a) e d), e secondo comma, e al paragrafo 5 di detto articolo.</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Ogni istituzione dell’Unione può aggiudicare appalti pubblici o attribuire sovvenzioni per attività di comunicazione. Le sovvenzioni possono essere attribuite se, a causa della natura delle attività, non è opportuno ricorrere ad appalti.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Il JRC può ricevere finanziamenti imputati a stanziamenti diversi da quelli per la ricerca e lo sviluppo tecnologico nell’ambito della sua partecipazione a procedure di attribuzione delle sovvenzioni finanziate, in tutto o in parte, dal bilancio. In tali casi non si applicano l’articolo 198, paragrafo 4, per quanto riguarda la capacità finanziaria, e l’articolo 196, paragrafo 1, lettere da a) a d).</div>\n</div>"]]}, "181": {"label": "Articolo 181", "heading": "Somme forfettarie, costi unitari e finanziamenti a tasso fisso", "anchor": "art_181", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Quando la sovvenzione assume la forma di somme forfettarie, costi unitari o finanziamenti a tasso fisso di cui all’articolo 125, paragrafo 1, primo comma, lettere c), d) o e), si applica il presente titolo, a eccezione delle disposizioni o parti di disposizioni relative alla verifica dell’ammissibilità dei costi effettivamente sostenuti.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Laddove possibile e opportuno, le somme forfettarie, i costi unitari o i tassi fissi sono determinati in modo tale da consentirne il pagamento al conseguimento di realizzazioni e/o risultati concreti.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Salvo disposizioni diverse dell’atto di base, il ricorso a somme forfettarie, costi unitari o finanziamenti a tasso fisso è autorizzato mediante decisione dell’ordinatore responsabile, che agisce in conformità delle norme interne dell’istituzione dell’Unione interessata.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Nella decisione di autorizzazione figurano almeno:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una giustificazione concernente l’adeguatezza di tali forme di finanziamento in considerazione della natura delle azioni o dei programmi di lavoro sovvenzionati, nonché dei rischi di irregolarità e frode e dei costi del controllo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’individuazione dei costi o delle categorie di costi coperti dalle somme forfettarie, dai costi unitari o dai finanziamenti a tasso fisso che sono considerati ammissibili a norma dell’articolo 186, paragrafo 3, lettere c), e) ed f), e dell’articolo 186, paragrafo 4, a esclusione dei costi non ammissibili in conformità delle norme applicabili dell’Unione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la descrizione dei metodi per determinare le somme forfettarie, i costi unitari o i finanziamenti a tasso fisso. Tali metodi si basano su uno dei seguenti elementi:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dati statistici, analoghi mezzi obiettivi o valutazioni di esperti fornite da esperti disponibili internamente o ingaggiati conformemente alle norme applicabili; oppure</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un approccio beneficiario per beneficiario, facendo riferimento a dati storici certificati o verificabili del beneficiario o alle sue consuete prassi contabili;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">ove possibile, le condizioni essenziali che attivano il pagamento, compreso, se del caso, il conseguimento delle realizzazioni e/o dei risultati;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">ove le somme forfettarie, i costi unitari e i tassi fissi non siano fondati sulle realizzazioni e/o sui risultati, la giustificazione del motivo per cui non è possibile od opportuno un approccio fondato sulle realizzazioni e/o sui risultati.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm inline-element\">I metodi di cui al primo comma, lettera c), garantiscono:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il rispetto del principio della sana gestione finanziaria, segnatamente l’adeguatezza dei relativi importi rispetto alle realizzazioni e/o ai risultati richiesti tenuto conto dei ricavi prevedibili generati dalle azioni o dai programmi di lavoro;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la ragionevole osservanza dei principi di cofinanziamento e divieto del doppio finanziamento.</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">La decisione di autorizzazione si applica per la durata del programma o dei programmi, salvo altrimenti disposto da tale decisione.</div>\n</div>"], [null, "<p class=\"norm inline-element\">La decisione di autorizzazione può disciplinare il ricorso a somme forfettarie, costi unitari o tassi fissi applicabili a più di un programma di finanziamento specifico ove la natura delle attività o delle spese permetta un approccio comune. In tali casi la decisione di autorizzazione può essere adottata:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dagli ordinatori responsabili, ove tutte le attività in questione rientrino nella loro sfera di competenza;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dalla Commissione, ove opportuno alla luce della natura delle attività o delle spese oppure del numero di ordinatori interessati.</p>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">L’ordinatore responsabile può autorizzare o imporre il finanziamento dei costi indiretti del beneficiario mediante applicazione di tassi fissi sino al massimale del 7 % del totale dei costi diretti ammissibili per l’azione. Con decisione motivata della Commissione può essere autorizzato un tasso fisso più elevato. L’ordinatore responsabile riferisce nella relazione annuale di attività di cui all’articolo 74, paragrafo 9, sulle decisioni adottate, sul tasso fisso autorizzato e sulle ragioni che hanno portato a tale decisione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">I proprietari di PMI e altre persone fisiche che non ricevono uno stipendio possono dichiarare costi ammissibili a livello di personale per il lavoro svolto personalmente nell’ambito di un’azione o di un programma di lavoro, sulla base dei costi unitari autorizzati conformemente ai paragrafi da 1 a 6.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">I beneficiari possono dichiarare costi a livello di personale per l’attività svolta da volontari nell’ambito di un’azione o di un programma di lavoro, sulla base dei costi unitari autorizzati conformemente ai paragrafi da 1 a 6.</div>\n</div>"]]}, "182": {"label": "Articolo 182", "heading": "Somme forfettarie uniche", "anchor": "art_182", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Una somma forfettaria di cui all’articolo 125, paragrafo 1, primo comma, lettera d), può coprire la totalità dei costi ammissibili di un’azione o di un programma di lavoro («somma forfettaria unica»).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">In conformità dell’articolo 181, paragrafo 4, le somme forfettarie uniche possono essere determinate sulla base del bilancio di previsione dell’azione o del programma di lavoro. Tale bilancio di previsione rispetta i principi di economia, efficienza ed efficacia. L’osservanza di tali principi è verificata ex ante al momento della valutazione della domanda di sovvenzione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Quando autorizza somme forfettarie uniche, l’ordinatore responsabile si attiene alle disposizioni dell’articolo 181.</div>\n</div>"]]}, "183": {"label": "Articolo 183", "heading": "Verifiche e controlli sui beneficiari in relazione a somme forfettarie, costi unitari e tassi fissi", "anchor": "art_183", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L’ordinatore responsabile verifica, al più tardi prima del pagamento a saldo, il rispetto delle condizioni che attivano il pagamento delle somme forfettarie, dei costi unitari o dei tassi fissi, compreso, ove richiesto, il conseguimento delle realizzazioni e/o dei risultati. Inoltre, il rispetto di tali condizioni può essere oggetto di controlli ex post.</div>\n</div>"], [null, "<p class=\"norm\">Gli importi delle somme forfettarie, dei costi unitari o dei finanziamenti a tasso fisso determinati ex ante applicando il metodo autorizzato dall’ordinatore responsabile o dalla Commissione conformemente all’articolo 181 non sono rimessi in discussione da controlli ex post. È fatto salvo il diritto dell’ordinatore responsabile di verificare che siano soddisfatte le condizioni che attivano il pagamento di cui al primo comma del presente paragrafo, e di ridurre la sovvenzione conformemente all’articolo 131, paragrafo 4, qualora dette condizioni non siano rispettate o in caso di irregolarità, frode o violazione di altri obblighi. Ove le somme forfettarie, i costi unitari o i tassi fissi siano stabiliti in base alle consuete prassi contabili del beneficiario si applica l’articolo 185, paragrafo 2.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La frequenza e la portata delle verifiche e dei controlli possono dipendere, tra l’altro, dalla natura dell’azione o dal beneficiario, comprese passate irregolarità o frodi a esso riconducibili.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Le condizioni che attivano il pagamento delle somme forfettarie, dei costi unitari o dei tassi fissi non richiedono la rendicontazione dei costi effettivamente sostenuti dal beneficiario.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">L’erogazione della sovvenzione sulla base di somme forfettarie, costi unitari o finanziamenti a tasso fisso non pregiudica il diritto di accesso ai registri dei beneficiari ai fini degli articoli 129 e 184.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Ai fini delle verifiche e dei controlli di cui al paragrafo 1 del presente articolo, si applica l’articolo 186, paragrafo 3, lettere a) e b).</div>\n</div>"]]}, "184": {"label": "Articolo 184", "heading": "Valutazione periodica delle somme forfettarie, dei costi unitari o dei tassi fissi", "anchor": "art_184", "frags": [[null, "<p class=\"norm\">Il metodo di determinazione delle somme forfettarie, dei costi unitari o dei tassi fissi, i dati sottostanti e i conseguenti importi, come anche l’adeguatezza di detti importi rispetto alle realizzazioni e/o ai risultati conseguiti, sono valutati periodicamente e, se del caso, adeguati conformemente all’articolo 181. La frequenza e la portata delle valutazioni dipendono dall’evoluzione e dalla natura dei costi, tenuto conto, in particolare, delle modifiche sostanziali dei prezzi di mercato e di altre circostanze pertinenti.</p>"]]}, "185": {"label": "Articolo 185", "heading": "Consuete prassi contabili del beneficiario", "anchor": "art_185", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Quando è autorizzato il ricorso alle consuete prassi contabili del beneficiario, l’ordinatore responsabile può valutare la conformità di tali prassi alle condizioni di cui all’articolo 181, paragrafo 4. Tale valutazione può essere effettuata ex ante o mediante una strategia appropriata di controlli ex post.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Se la conformità delle consuete prassi contabili del beneficiario alle condizioni di cui all’articolo 181, paragrafo 4, è stata stabilita ex ante, gli importi delle somme forfettarie, dei costi unitari o dei finanziamenti a tasso fisso determinati dall’applicazione di tali prassi non sono rimessi in discussione da controlli ex post. Ciò non pregiudica la facoltà dell’ordinatore responsabile di ridurre la sovvenzione conformemente all’articolo 131, paragrafo 4.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">L’ordinatore responsabile può ritenere le consuete prassi contabili del beneficiario conformi alle condizioni di cui all’articolo 181, paragrafo 4, se esse sono accettate dalle autorità nazionali nell’ambito di regimi di finanziamento analoghi.</div>\n</div>"]]}, "186": {"label": "Articolo 186", "heading": "Costi ammissibili", "anchor": "art_186", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Le sovvenzioni non superano un massimale globale espresso in termini di valore assoluto («importo massimo della sovvenzione»), fissato sulla base:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dell’importo globale dei finanziamenti non collegati ai costi, nel caso di cui all’articolo 125, paragrafo 1, primo comma, lettera a);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dei costi ammissibili stimati, ove possibile, nel caso di cui all’articolo 125, paragrafo 1, primo comma, lettera b);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">dell’importo globale dei costi ammissibili stimati chiaramente definiti in anticipo sotto forma di somme forfettarie, costi unitari o finanziamenti a tasso fisso di cui all’articolo 125, paragrafo 1, primo comma, lettere c), d) ed e).</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Fatto salvo l’atto di base, le sovvenzioni possono inoltre essere espresse in percentuale dei costi ammissibili stimati quando la sovvenzione assume la forma di cui al primo comma, lettera b), o in percentuale delle somme forfettarie, dei costi unitari o dei finanziamenti a tasso fisso di cui al primo comma, lettera c).</p>"], [null, "<p class=\"norm\">Quando la sovvenzione assume la forma di cui al primo comma, lettera b), del presente paragrafo e ove, a causa delle specificità di un’azione, la sovvenzione possa essere espressa solo in termini di valore assoluto, la verifica dei costi ammissibili è effettuata conformemente all’articolo 155, paragrafo 4, e, se del caso, all’articolo 155, paragrafo 5.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Fatto salvo il tasso massimo di cofinanziamento specificato nell’atto di base:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la sovvenzione non supera i costi ammissibili;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">quando la sovvenzione assume la forma di cui al paragrafo 1, primo comma, lettera b), e ove i costi ammissibili stimati comprendano i costi relativi all’attività dei volontari di cui all’articolo 181, paragrafo 8, la sovvenzione non supera i costi ammissibili stimati diversi da quelli relativi all’attività dei volontari.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">I costi ammissibili effettivamente sostenuti dal beneficiario, di cui all’articolo 125, paragrafo 1, primo comma, lettera b), soddisfano tutti i seguenti criteri:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sono sostenuti nel corso della durata dell’azione o del programma di lavoro, a eccezione dei costi inerenti alle relazioni finali e ai certificati di audit;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sono indicati nel bilancio stimato totale dell’azione o del programma di lavoro;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sono necessari per attuare l’azione o il programma di lavoro oggetto della sovvenzione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sono identificabili e verificabili, in particolare sono iscritti nei documenti contabili del beneficiario e sono determinati secondo i principi contabili vigenti nel paese in cui è stabilito il beneficiario e secondo le consuete prassi contabili del beneficiario stesso;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">soddisfano le disposizioni della legislazione tributaria e sociale applicabili;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sono ragionevoli, giustificati e conformi al principio della sana gestione finanziaria, in particolare sotto il profilo dell’economia e dell’efficienza.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Gli inviti a presentare proposte precisano le categorie di costi considerati ammissibili al finanziamento dell’Unione.</div>\n</div>"], [null, "<p class=\"norm inline-element\">Salvo diversamente disposto dall’atto di base e in aggiunta al paragrafo 3 del presente articolo, le seguenti categorie di costi sono ammissibili se l’ordinatore responsabile li ha dichiarati tali in base all’invito a presentare proposte:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i costi relativi a una garanzia di prefinanziamento costituita dal beneficiario, ove detta garanzia sia richiesta dall’ordinatore responsabile ai sensi dell’articolo 152, paragrafo 1;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i costi inerenti ai certificati relativi ai rendiconti finanziari e alle relazioni sulla verifica operativa, ove tali certificati o relazioni siano richiesti dall’ordinatore responsabile;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’IVA, quando non è recuperabile ai sensi della normativa nazionale sull’IVA applicabile ed è versata da un beneficiario diverso da un soggetto non considerato passivo ai sensi dell’articolo 13, paragrafo 1, primo comma, della direttiva 2006/112/CE del Consiglio (\n<span class=\"superscript\">25</span>\n).</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i costi di ammortamento, purché effettivamente sostenuti dal beneficiario;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i costi relativi alle retribuzioni del personale delle amministrazioni nazionali, nella misura in cui essi siano correlati ai costi delle attività che la pubblica autorità interessata non svolgerebbe se il progetto in questione non fosse realizzato.</p>\n</div>\n</div>"], [null, "<p class=\"norm inline-element\">Ai fini del secondo comma, lettera c):</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’IVA è considerata non recuperabile se, a norma del diritto nazionale, è imputabile a una delle seguenti attività:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">attività esenti senza diritto a detrazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">attività che non rientrano nell’ambito di applicazione dell’IVA;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">attività di cui al punto i) o ii) in relazione alle quali l’IVA non è detraibile, bensì rimborsata tramite regimi specifici di rimborso o fondi di compensazione che non figurano nella direttiva 2006/112/CE, anche qualora tale regime o fondo sia istituito dalla normativa nazionale sull’IVA;</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’IVA relativa alle attività di cui all’articolo 13, paragrafo 2, della direttiva 2006/112/CE è considerata assolta da un beneficiario diverso da un soggetto non considerato passivo ai sensi dell’articolo 13, paragrafo 1, primo comma, della medesima direttiva, a prescindere dal fatto che lo Stato membro interessato consideri o meno tali attività come attività della pubblica amministrazione svolte da enti di diritto pubblico;</p>\n</div>\n</div>"]]}, "187": {"label": "Articolo 187", "heading": "Entità affiliate e beneficiario unico", "anchor": "art_187", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Ai fini del presente titolo, le seguenti entità sono considerate entità affiliate al beneficiario:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">entità che costituiscono il beneficiario unico in conformità del paragrafo 2;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">entità che soddisfano i criteri di ammissibilità, che non si trovano in una delle situazioni di cui agli articoli 136, paragrafo 1, e 141, paragrafo 1, e che hanno un legame con il beneficiario, in particolare un rapporto giuridico o di capitale, che non è limitato all’azione né instaurato al solo scopo della sua attuazione.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Il titolo V, capo 2, sezione 2, si applica altresì alle entità affiliate.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Se più entità soddisfano i criteri per ottenere una sovvenzione e insieme costituiscono una sola entità, tale entità può essere considerata beneficiario unico, anche quando è specificatamente istituita allo scopo di attuare l’azione da finanziare con la sovvenzione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Salvo diversamente disposto nell’invito a presentare proposte, le entità affiliate a un beneficiario possono partecipare all’attuazione di un’azione, purché siano soddisfatte entrambe le condizioni seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le entità in questione sono individuate nella convenzione di sovvenzione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le entità in questione si attengono alle norme applicabili al beneficiario ai sensi della convenzione di sovvenzione per quanto concerne:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’ammissibilità dei costi o le condizioni che attivano il pagamento;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i diritti della Commissione, dell’OLAF e della Corte dei conti di effettuare verifiche e audit.</p>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">I costi sostenuti da tali entità possono essere accettati come costi ammissibili effettivamente sostenuti e possono essere coperti da somme forfettarie, costi unitari e finanziamenti a tasso fisso.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "188": {"label": "Articolo 188", "heading": "Principi generali applicabili alle sovvenzioni", "anchor": "art_188", "frags": [[null, "<p class=\"norm\">Le sovvenzioni rispettano i seguenti principi:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">parità di trattamento;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">trasparenza;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">cofinanziamento;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">divieto di cumulo e di doppio finanziamento;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">non retroattività;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">divieto del fine di lucro.</p>\n</div>\n</div>"]]}, "189": {"label": "Articolo 189", "heading": "Trasparenza", "anchor": "art_189", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le sovvenzioni sono attribuite a seguito della pubblicazione di inviti a presentare proposte, tranne nei casi di cui all’articolo 195.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Tutte le sovvenzioni attribuite nel corso di un esercizio sono oggetto di pubblicazione conformemente all’articolo 38, paragrafi da 1 a 4.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Dopo la pubblicazione di cui ai paragrafi 1 e 2, la Commissione trasmette al Parlamento europeo e al Consiglio, su loro richiesta, una relazione riguardante:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il numero di richiedenti dell’esercizio precedente;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il numero e la percentuale delle domande accolte nell’ambito di ciascun invito a presentare proposte;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la durata media della procedura dalla data di chiusura dell’invito a presentare proposte fino all’attribuzione della sovvenzione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il numero e l’importo delle sovvenzioni per le quali non ha avuto luogo la pubblicazione ex post nell’esercizio precedente conformemente all’articolo 38, paragrafo 4;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le sovvenzioni attribuite a istituzioni finanziarie, fra cui la BEI e il FEI, in conformità dell’articolo 195, primo comma, lettera g).</p>\n</div>\n</div>\n</div>\n</div>"]]}, "190": {"label": "Articolo 190", "heading": "Cofinanziamento", "anchor": "art_190", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le sovvenzioni sono soggette al regime del cofinanziamento. Pertanto, le risorse necessarie alla realizzazione dell’azione o del programma di lavoro non provengono interamente dalla sovvenzione.</div>\n</div>"], [null, "<p class=\"norm\">Il cofinanziamento può essere erogato sotto forma di risorse proprie del beneficiario, di redditi generati dall’azione o dal programma di lavoro ovvero di contributi finanziari o in natura da parte di terzi.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">I contributi in natura da parte di terzi sotto forma di attività di volontariato, valutati conformemente all’articolo 181, paragrafo 8, sono presentati come costi ammissibili nel bilancio di previsione. Essi sono presentati separatamente rispetto agli altri costi ammissibili. Le attività di volontariato possono comprendere fino al 50 % del cofinanziamento. Ai fini del calcolo di tale percentuale, i contributi in natura e altri cofinanziamenti sono basati sulle stime fornite dal richiedente.</div>\n</div>"], [null, "<p class=\"norm\">Gli altri contributi in natura da parte di terzi sono presentati separatamente rispetto ai contributi ai costi ammissibili nel bilancio di previsione. Il loro valore approssimativo è indicato nel bilancio di previsione e non è suscettibile di successive modifiche.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">In deroga al paragrafo 1, un’azione esterna può essere finanziata integralmente dalla sovvenzione quando ciò sia indispensabile per la sua realizzazione. In tal caso, la decisione di attribuzione ne riporta la motivazione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Il presente articolo non si applica agli abbuoni dei tassi d’interesse e ai sussidi per le commissioni di garanzia.</div>\n</div>"]]}, "191": {"label": "Articolo 191", "heading": "Principio del divieto di cumulo e divieto del doppio finanziamento", "anchor": "art_191", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Per una stessa azione può essere attribuita una sola sovvenzione a carico del bilancio a favore di uno stesso beneficiario, a meno che non autorizzino altrimenti i pertinenti atti di base.</div>\n</div>"], [null, "<p class=\"norm\">Un beneficiario può ricevere una sola sovvenzione di funzionamento a carico del bilancio per esercizio.</p>"], [null, "<p class=\"norm\">Un’azione può essere oggetto di un finanziamento congiunto su linee di bilancio distinte di competenza di diversi ordinatori.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il richiedente informa immediatamente gli ordinatori di eventuali richieste multiple e sovvenzioni multiple relative alla stessa azione o allo stesso programma di lavoro.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">In nessun caso il bilancio finanzia due volte i medesimi costi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">I paragrafi 1 e 2 non si applicano ai tipi di aiuti seguenti e, se del caso, la Commissione può decidere di non verificare se il medesimo costo sia stato finanziato due volte:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">aiuti corrisposti a persone fisiche a fini di studio, ricerca, formazione o istruzione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">aiuti diretti corrisposti a persone fisiche estremamente bisognose, come i disoccupati e i rifugiati.</p>\n</div>\n</div>\n</div>\n</div>"]]}, "192": {"label": "Articolo 192", "heading": "Principio del divieto del fine di lucro", "anchor": "art_192", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le sovvenzioni non hanno per scopo o per effetto un profitto nell’ambito dell’azione o del programma di lavoro del beneficiario («principio del divieto del fine di lucro»).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Ai fini del presente paragrafo, si definisce profitto un surplus delle entrate, calcolato al momento del pagamento a saldo, rispetto ai costi ammissibili dell’azione o del programma di lavoro, in cui le entrate sono limitate alla sovvenzione dell’Unione e ai ricavi generati da tale azione o programma di lavoro.</div>\n</div>"], [null, "<p class=\"norm\">Nel caso di una sovvenzione di funzionamento, gli importi destinati alla costituzione di riserve non sono presi in considerazione per la verifica del rispetto del principio del divieto del fine di lucro.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Il paragrafo 1 non si applica:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">alle azioni il cui obiettivo è rafforzare la capacità finanziaria di un beneficiario o alle azioni che producono reddito al fine di garantire la loro continuità dopo il periodo di finanziamento a carico dell’Unione previsto dalla convenzione di sovvenzione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">agli aiuti corrisposti a persone fisiche a fini di studio, ricerca, formazione o istruzione o ad altri aiuti diretti corrisposti a persone fisiche estremamente bisognose, come i disoccupati e i rifugiati;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">alle azioni attuate da organizzazioni senza scopo di lucro;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">alle sovvenzioni che assumono la forma di cui all’articolo 125, paragrafo 1, primo comma, lettera a);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">alle sovvenzioni di valore modesto.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Qualora si ottenga un profitto, la Commissione ha il diritto di recuperarne la percentuale corrispondente al contributo dell’Unione ai costi ammissibili effettivamente sostenuti dal beneficiario nel realizzare l’azione o il programma di lavoro.</div>\n</div>"]]}, "193": {"label": "Articolo 193", "heading": "Principio di non retroattività", "anchor": "art_193", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Salvo diversamente disposto dal presente articolo, le sovvenzioni non sono attribuite retroattivamente.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Può essere attribuita una sovvenzione per un’azione già avviata solo se il richiedente può provare la necessità di avviare l’azione prima della firma della convenzione di sovvenzione.</div>\n</div>"], [null, "<p class=\"norm inline-element\">In tali casi i costi sostenuti prima della data di presentazione della domanda di sovvenzione non sono ammissibili, tranne:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">in casi eccezionali debitamente giustificati previsti nell’atto di base, oppure</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">in caso di estrema urgenza, per le misure di cui all’articolo 195, primo comma, lettera a) o b), in relazione a cui un intervento rapido dell’Unione sarebbe di grande importanza.</p>\n</div>\n</div>"], [null, "<p class=\"norm inline-element\">Nel caso di cui al secondo comma, lettera b), i costi sostenuti da un beneficiario prima della data di presentazione della domanda sono ammissibili al finanziamento dell’Unione alle seguenti condizioni:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i motivi della deroga sono debitamente giustificati dall’ordinatore responsabile;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la convenzione di sovvenzione fissa esplicitamente la data d’ammissibilità a una data anteriore a quella di presentazione della domanda.</p>\n</div>\n</div>"], [null, "<p class=\"norm\">L’ordinatore delegato riferisce su ciascuno dei casi di cui al presente paragrafo nell’ambito del titolo «Deroghe al principio di non retroattività a norma dell’articolo 193 del regolamento finanziario» della relazione annuale di attività di cui all’articolo 74, paragrafo 9.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">È esclusa la sovvenzione retroattiva per azioni già concluse.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Nel caso di sovvenzioni di funzionamento, la convenzione di sovvenzione è firmata entro quattro mesi dall’inizio dell’esercizio del beneficiario. I costi sostenuti prima della data di presentazione della domanda di sovvenzione o prima dell’inizio dell’esercizio del beneficiario non sono ammissibili al finanziamento. Il primo versamento al beneficiario è effettuato entro 30 giorni di calendario dalla firma della convenzione di sovvenzione.</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "194": {"label": "Articolo 194", "heading": "Contenuto e pubblicazione degli inviti a presentare proposte", "anchor": "art_194", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Gli inviti a presentare proposte precisano quanto segue:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli obiettivi perseguiti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i criteri di ammissibilità, di esclusione, di selezione e di attribuzione e i relativi documenti giustificativi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le modalità del finanziamento dell’Unione, che specificano tutti i tipi di contributi di quest’ultima, in particolare le forme di sovvenzione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le modalità e il termine ultimo di presentazione delle proposte;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la data prevista entro la quale tutti i richiedenti sono informati in merito ai risultati della valutazione della loro domanda e la data indicativa per la firma delle convenzioni di sovvenzione.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Le date di cui al paragrafo 1, lettera e), sono fissate sulla base dei periodi seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per informare tutti i richiedenti dei risultati della valutazione della loro domanda, un massimo di sei mesi dal termine ultimo di presentazione delle proposte complete;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per firmare con i richiedenti le convenzioni di sovvenzione, un massimo di tre mesi dalla data in cui i richiedenti sono stati informati della loro idoneità.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Tali termini possono essere rettificati per tener conto del tempo necessario a rispettare le procedure specifiche eventualmente previste dall’atto di base in conformità del regolamento (UE) n. 182/2011 e può essere superato in casi eccezionali, debitamente giustificati, in particolare per azioni complesse, laddove vi sia un elevato numero di proposte o ritardi imputabili ai richiedenti.</p>"], [null, "<p class=\"norm\">L’ordinatore delegato riferisce nella sua relazione annuale di attività sui tempi medi per l’informazione dei richiedenti e la firma delle convenzioni di sovvenzione. Qualora vengano superati i termini di cui al primo comma, l’ordinatore delegato fornisce le motivazioni e, ove non risultino debitamente giustificate ai sensi del secondo comma, propone azioni correttive.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Gli inviti a presentare proposte sono pubblicati sul sito web delle istituzioni dell’Unione e con ogni altro mezzo adeguato, ivi inclusa la <span class=\"italics\">Gazzetta ufficiale dell’Unione europea</span>, qualora sia necessario garantire ulteriore pubblicità nei confronti dei potenziali beneficiari. Gli inviti a presentare proposte possono essere pubblicati previa adozione della decisione di finanziamento di cui all’articolo 110, anche nel corso dell’anno precedente l’esecuzione del bilancio. Ogni modifica del contenuto degli inviti a presentare proposte è pubblicata secondo le stesse modalità.</div>\n</div>"]]}, "195": {"label": "Articolo 195", "heading": "Deroghe all’invito a presentare proposte", "anchor": "art_195", "frags": [[null, "<p class=\"norm\">Possono essere attribuite sovvenzioni senza invito a presentare proposte soltanto nei seguenti casi:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nell’ambito dell’aiuto umanitario, degli interventi di sostegno di emergenza, degli interventi di protezione civile o degli aiuti erogati per la gestione di una situazione di crisi;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">in altri casi d’urgenza eccezionali e debitamente giustificati;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">a favore di organismi che si trovano di diritto o di fatto in situazione di monopolio o a favore di organismi designati dagli Stati membri, sotto la loro responsabilità, qualora tali Stati membri si trovino di diritto o di fatto in situazione di monopolio;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">a favore di organismi indicati in un atto di base, ai sensi dell’articolo 58, come beneficiari o a favore di organismi designati dagli Stati membri, sotto la loro responsabilità, qualora tali Stati membri siano indicati come beneficiari in un atto di base;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nel settore della ricerca e dello sviluppo tecnologico, a favore di organismi indicati nel programma di lavoro di cui all’articolo 110, quando l’atto di base prevede esplicitamente tale possibilità, e a condizione che il progetto non rientri nell’ambito di un invito a presentare proposte;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per attività aventi speciali caratteristiche che esigono un particolare tipo di organismo, per la sua competenza tecnica, l’alto grado di specializzazione o i poteri amministrativi, purché tali attività non rientrino nell’ambito di un invito a presentare proposte;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">a favore della BEI o del FEI per le azioni di assistenza tecnica. In tali casi non si applica l’articolo 196, paragrafo 1, lettere da a) a d).</p>\n</div>\n</div>"], [null, "<p class=\"norm\">Ove il particolare tipo di organismo di cui al primo comma, lettera f), sia uno Stato membro, la sovvenzione può altresì essere attribuita senza invito a presentare proposte all’organismo designato dallo Stato membro, sotto la sua responsabilità, ai fini dell’attuazione dell’azione;</p>"], [null, "<p class=\"norm\">I casi di cui al primo comma, lettere c) ed f), sono debitamente giustificati nella decisione di attribuzione.</p>"]]}, "196": {"label": "Articolo 196", "heading": "Contenuto delle domande di sovvenzione", "anchor": "art_196", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La domanda di sovvenzione contiene:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">informazioni sullo status giuridico del richiedente;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un’autocertificazione del richiedente in conformità dell’articolo 137, paragrafo 1, e sul rispetto dei criteri di ammissibilità e di selezione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le informazioni necessarie per dimostrare la capacità finanziaria e operativa del richiedente di realizzare l’azione o il programma di lavoro oggetto della sua proposta, nonché, se deciso dall’ordinatore responsabile sulla base di una valutazione dei rischi, i documenti giustificativi a conferma di tali informazioni, quali il conto profitti e perdite e il bilancio patrimoniale riguardanti, al massimo, gli ultimi tre esercizi chiusi.</p>\n<p class=\"list\">Tali informazioni e documenti giustificativi non sono richiesti ai richiedenti cui, a norma dell’articolo 198, paragrafo 5 o 6, non si applica la verifica della capacità finanziaria od operativa. Inoltre, i documenti giustificativi non sono richiesti per le sovvenzioni di valore modesto;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">quando la domanda riguarda la sovvenzione di un’azione per un importo superiore a 750 000  EUR oppure una sovvenzione di funzionamento d’importo superiore a 100 000  EUR, una relazione di audit effettuata da un revisore esterno riconosciuto, se esiste - e in ogni caso, se una revisione legale è prescritta dal diritto dell’Unione o dal diritto nazionale - la quale certifichi i conti riguardanti, al massimo, gli ultimi tre esercizi per i quali essi sono disponibili. In tutti gli altri casi il richiedente presenta un’autocertificazione, firmata dal suo rappresentante legale, della validità dei suoi conti riguardanti, al massimo, gli ultimi tre esercizi per i quali i conti sono disponibili.</p>\n<p class=\"list\">Il primo comma si applica soltanto alla prima domanda presentata dallo stesso beneficiario presso un ordinatore responsabile nel corso di uno stesso esercizio.</p>\n<p class=\"list\">In caso di convenzioni tra la Commissione e più beneficiari, le soglie di cui al primo comma si applicano a ciascun beneficiario.</p>\n<p class=\"list\">Nel caso dei partenariati di cui all’articolo 130, paragrafo 4, la relazione di audit di cui al primo comma della presente lettera, relativa agli ultimi due esercizi per i quali sono disponibili i conti, dev’essere presentata prima della firma dell’accordo quadro relativo al partenariato finanziario.</p>\n<p class=\"list\">In funzione di una valutazione dei rischi, l’ordinatore responsabile può rinunciare a imporre l’obbligo di cui al primo comma agli istituti d’istruzione e di formazione e, nel caso di convenzioni con più beneficiari, ai beneficiari che hanno accettato la responsabilità in solido o ai quali non sono attribuite responsabilità finanziarie.</p>\n<p class=\"list\">Il primo comma non si applica alle persone e alle entità ammissibili in regime di gestione indiretta che soddisfino le condizioni specificate all’articolo 62, paragrafo 1, primo comma, lettera c), e all’articolo 154;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una descrizione dell’azione o del programma di lavoro e un bilancio di previsione che:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sia in pareggio tra entrate e spese; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">indichi i costi ammissibili stimati dell’azione o del programma di lavoro.</p>\n<p class=\"list\">I punti i) e ii) non si applicano alle azioni finanziate da una pluralità di donatori.</p>\n<p class=\"list\">In deroga al punto i), in casi debitamente motivati il bilancio di previsione può includere accantonamenti per imprevisti o per eventuali variazioni dei tassi di cambio;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’indicazione delle fonti e degli importi dei finanziamenti dell’Unione ricevuti o chiesti in relazione alla stessa azione o parte dell’azione ovvero per il funzionamento del richiedente nel corso dello stesso esercizio, nonché ogni altro finanziamento ricevuto o chiesto per la stessa azione.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La domanda può essere suddivisa in più parti che possono essere presentate in fasi diverse conformemente all’articolo 200, paragrafo 2.</div>\n</div>"]]}, "197": {"label": "Articolo 197", "heading": "Criteri di ammissibilità", "anchor": "art_197", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">I criteri di ammissibilità stabiliscono le condizioni di partecipazione agli inviti a presentare proposte.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Sono ammessi a partecipare a un invito a presentare proposte i seguenti richiedenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">persone giuridiche;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">persone fisiche, se lo esigono la natura o le caratteristiche dell’azione o l’obiettivo perseguito dal richiedente;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">entità non aventi personalità giuridica a norma del rispettivo diritto nazionale, purché i loro rappresentanti abbiano la capacità di assumere impegni giuridici in nome delle entità e che queste ultime offrano garanzie per la tutela degli interessi finanziari dell’Unione equivalenti a quelle offerte dalle persone giuridiche. In particolare, il richiedente possiede capacità finanziarie e operative equivalenti a quelle di una persona giuridica. I rappresentanti del richiedente dimostrano che tali condizioni sono soddisfatte.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">L’invito a presentare proposte può stabilire criteri di ammissibilità supplementari, che sono determinati tenendo in debito conto gli obiettivi dell’azione e rispettano i principi di trasparenza e di non discriminazione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Ai fini dell’articolo 180, paragrafo 5, e del presente articolo, il JRC è considerato una persona giuridica stabilita in uno Stato membro.</div>\n</div>"]]}, "198": {"label": "Articolo 198", "heading": "Criteri di selezione", "anchor": "art_198", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">I criteri di selezione permettono di valutare la capacità del richiedente di realizzare l’azione o il programma di lavoro oggetto della sua proposta.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il richiedente deve disporre di fonti di finanziamento stabili e sufficienti per mantenere la sua attività durante il periodo sovvenzionato e partecipare al suo finanziamento («capacità finanziaria»).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il richiedente deve disporre delle competenze e qualificazioni professionali richieste per portare a termine l’azione o il programma di lavoro oggetto della sua proposta, salvo disposizioni speciali dell’atto di base («capacità operativa»).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La verifica della capacità finanziaria e operativa si basa, in particolare, sull’analisi di ogni informazione o documento giustificativo di cui all’articolo 196.</div>\n</div>"], [null, "<p class=\"norm\">L’ordinatore responsabile chiede al richiedente di fornire un’adeguata documentazione qualora nell’invito a presentare proposte non siano stati richiesti documenti giustificativi ed egli abbia motivi ragionevoli per mettere in dubbio la capacità finanziaria od operativa del richiedente.</p>"], [null, "<p class=\"norm\">Nel caso di partenariati la verifica è effettuata conformemente all’articolo 130, paragrafo 6.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La verifica della capacità finanziaria non concerne:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le persone fisiche beneficiarie di aiuti per l’istruzione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le persone fisiche più bisognose, come disoccupati e rifugiati, e che ricevono aiuti diretti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli organismi pubblici, incluse le organizzazioni degli Stati membri;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le organizzazioni internazionali;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le persone o entità che chiedono abbuoni dei tassi d’interessi e sussidi per le commissioni di garanzia, ove tali sconti e sussidi mirino a rafforzare la capacità finanziaria di un beneficiario o a produrre un reddito.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">In funzione di una valutazione dei rischi, l’ordinatore responsabile può rinunciare a imporre l’obbligo di verificare la capacità operativa di organismi pubblici, organizzazioni degli Stati membri od organizzazioni internazionali.</div>\n</div>"]]}, "199": {"label": "Articolo 199", "heading": "Criteri di attribuzione", "anchor": "art_199", "frags": [[null, "<p class=\"norm\">I criteri di attribuzione permettono di:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">valutare la qualità delle proposte presentate a fronte degli obiettivi e delle priorità fissati e dei risultati attesi;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">attribuire le sovvenzioni alle azioni o ai programmi di lavoro che rendono massima l’efficacia globale del finanziamento dell’Unione;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">valutare le domande di sovvenzione.</p>\n</div>\n</div>"]]}, "200": {"label": "Articolo 200", "heading": "Procedura di valutazione", "anchor": "art_200", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le proposte sono valutate sulla base dei criteri di selezione e di attribuzione preventivamente annunciati, al fine di individuare quelle che possono beneficiare di un finanziamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">All’occorrenza, l’ordinatore responsabile divide la procedura in più fasi. Le norme procedurali sono indicate nell’invito a presentare proposte.</div>\n</div>"], [null, "<p class=\"norm\">I richiedenti la cui proposta è respinta in una delle fasi sono informati a norma del paragrafo 7.</p>"], [null, "<p class=\"norm\">Nel corso di una medesima procedura non sono richiesti più di una volta gli stessi documenti e informazioni.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il comitato di valutazione di cui all’articolo 150 o, eventualmente, l’ordinatore responsabile può chiedere al richiedente, conformemente all’articolo 151, di fornire informazioni supplementari o chiarimenti riguardo ai documenti giustificativi presentati. L’ordinatore mette opportunamente agli atti i contatti avuti con i richiedenti nel corso della procedura.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Alla fine dei lavori, i membri del comitato di valutazione firmano un verbale che riprende tutte le proposte esaminate, con la valutazione della loro qualità e l’indicazione di quelle che possono beneficiare di un finanziamento.</div>\n</div>"], [null, "<p class=\"norm\">Se necessario, il verbale determina una classifica delle proposte esaminate e fornisce raccomandazioni circa l’importo massimo da attribuire ed eventuali modifiche non sostanziali della domanda di sovvenzione.</p>"], [null, "<p class=\"norm\">Il verbale è conservato a futura memoria.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">L’ordinatore responsabile può invitare il richiedente a modificare la proposta alla luce delle raccomandazioni del comitato di valutazione. L’ordinatore responsabile mette opportunamente agli atti i contatti avuti con i richiedenti nel corso della procedura.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Sulla base della valutazione, l’ordinatore responsabile prende una decisione che esplicita almeno quanto segue:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’oggetto e l’importo globale della decisione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i nomi dei richiedenti prescelti, il titolo delle azioni, gli importi accettati e le motivazioni della scelta, anche quando si discosta dal parere del comitato di valutazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i nominativi dei richiedenti respinti e i motivi del rigetto.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">L’ordinatore responsabile informa per iscritto i richiedenti della decisione relativa alla loro domanda. In caso di mancata attribuzione della sovvenzione, l’istituzione dell’Unione interessata comunica i motivi del rigetto. I richiedenti respinti sono informati del risultato della valutazione della propria domanda quanto prima e, in ogni caso, entro 15 giorni di calendario dalla comunicazione ai richiedenti prescelti.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Per le sovvenzioni attribuite a norma dell’articolo 195 l’ordinatore responsabile può:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">decidere di non applicare i paragrafi 2 e 4 del presente articolo e l’articolo 150;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">riunire il contenuto della relazione di valutazione e della decisione di attribuzione in un unico documento e firmarlo.</p>\n</div>\n</div>\n</div>\n</div>"]]}, "201": {"label": "Articolo 201", "heading": "Convenzione di sovvenzione", "anchor": "art_201", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le sovvenzioni formano oggetto di una convenzione scritta.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La convenzione di sovvenzione comprende almeno quanto segue:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’oggetto;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il beneficiario;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la durata, e precisamente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la data di entrata in vigore;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la data di inizio e la durata dell’azione o dell’esercizio cui la sovvenzione si riferisce;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la descrizione dell’azione o, per una sovvenzione di funzionamento, del programma di lavoro, insieme alla descrizione dei risultati attesi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’importo massimo del finanziamento dell’Unione espresso in euro, il bilancio di previsione dell’azione o del programma di lavoro e la forma della sovvenzione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le norme in materia di presentazione di relazioni e pagamenti e le norme in materia di appalti di cui all’articolo 205;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’accettazione da parte del beneficiario degli obblighi di cui all’articolo 129;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le disposizioni in materia di visibilità dell’intervento finanziario dell’Unione, tranne in casi debitamente motivati in cui la pubblicità non sia possibile ovvero opportuna;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la precisazione che il diritto applicabile è il diritto dell’Unione, integrato, se necessario, dal diritto nazionale indicato nella convenzione di sovvenzione. Le convenzioni di sovvenzione concluse con organizzazioni internazionali possono prevedere deroghe;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>j) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il giudice o il tribunale arbitrale competente per le controversie.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Gli obblighi pecuniari di entità o persone diverse dagli Stati membri derivanti dall’esecuzione di una convenzione di sovvenzione hanno carattere esecutivo in conformità dell’articolo 100, paragrafo 2.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Le modifiche delle convenzioni di sovvenzione non hanno per scopo o per effetto l’introduzione di variazioni che possano rimettere in discussione la decisione di attribuzione della sovvenzione o violare il principio della parità di trattamento dei richiedenti.</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "202": {"label": "Articolo 202", "heading": "Importo della sovvenzione ed estensione delle risultanze degli audit", "anchor": "art_202", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L’importo della sovvenzione diventa definitivo soltanto dopo l’approvazione da parte dell’ordinatore responsabile delle relazioni finali e, se del caso, dei conti, fatti salvi ulteriori audit, verifiche e indagini da parte dell’istituzione dell’Unione interessata, dell’OLAF o della Corte dei conti. L’articolo 131, paragrafo 4, si applica anche dopo che l’importo della sovvenzione è diventato definitivo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Qualora dai controlli o dagli audit emergano irregolarità, frodi o violazioni degli obblighi sistemiche o ricorrenti imputabili al beneficiario, che incidono in modo rilevante su una serie di sovvenzioni attribuite a tale beneficiario a condizioni analoghe, l’ordinatore responsabile può sospendere l’esecuzione della convenzione di sovvenzione o dei pagamenti di tutte le sovvenzioni interessate ovvero, se del caso, porre fine alle convenzioni di sovvenzione interessate con detto beneficiario, con riguardo alla gravità delle risultanze.</div>\n</div>"], [null, "<p class=\"norm\">L’ordinatore responsabile può, inoltre, ridurre le sovvenzioni, rigettare i costi non ammissibili e recuperare gli importi indebitamente versati a titolo di tutte le sovvenzioni interessate da irregolarità, frodi o violazioni degli obblighi sistemiche o ricorrenti, di cui al primo comma, che possono essere oggetto di audit, verifiche e indagini in conformità delle convenzioni di sovvenzione interessate.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">L’ordinatore responsabile stabilisce gli importi che devono essere ridotti o recuperati, ove possibile e realizzabile, sulla base dei costi indebitamente dichiarati ammissibili per ogni sovvenzione in questione, previa accettazione delle relazioni e dei rendiconti finanziari riveduti presentati dal beneficiario.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Qualora non sia possibile o realizzabile quantificare con precisione l’importo dei costi non ammissibili per ogni sovvenzione in questione, gli importi da ridurre o recuperare possono essere determinati estrapolando il tasso di riduzione o di recupero applicato alle sovvenzioni per le quali le irregolarità, frodi o violazioni degli obblighi sistemiche o ricorrenti sono state dimostrate, ovvero, laddove i costi non ammissibili non possano servire come base per la determinazione degli importi da ridurre o recuperare, applicando un tasso fisso, sulla base del principio di proporzionalità. Al beneficiario è accordata la possibilità di proporre un metodo o un tasso alternativo debitamente motivato prima che la riduzione o il recupero abbiano luogo.</div>\n</div>"]]}, "203": {"label": "Articolo 203", "heading": "Documenti giustificativi delle richieste di pagamento", "anchor": "art_203", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L’ordinatore responsabile specifica quali documenti giustificativi devono corredare le richieste di pagamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Per ogni sovvenzione, il prefinanziamento può essere frazionato in più versamenti in conformità del principio della sana gestione finanziaria. La richiesta di un nuovo versamento di prefinanziamento è corredata della dichiarazione del beneficiario sull’utilizzo del prefinanziamento precedente. Il versamento è effettuato integralmente se è stato utilizzato almeno il 70 % dell’importo totale del prefinanziamento precedente. Altrimenti, il versamento è ridotto in misura equivalente agli importi non ancora utilizzati, fino al raggiungimento di tale soglia.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il beneficiario autocertifica che le informazioni figuranti nelle richieste di pagamento sono complete, affidabili e veritiere, fatto salvo l’obbligo di fornire i documenti giustificativi. Inoltre, egli certifica che i costi sostenuti sono ammissibili in conformità della convenzione di sovvenzione e che le richieste di pagamento sono corroborate da documenti giustificativi adeguati e verificabili.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">L’ordinatore responsabile può esigere, come giustificativo dei pagamenti intermedi o del pagamento a saldo di qualsiasi importo, un certificato relativo ai rendiconti finanziari dell’azione o del programma di lavoro e ai relativi conti. Tale certificato è richiesto in base a una valutazione dei rischi, tenendo conto, in particolare, dell’importo della sovvenzione, dell’importo del pagamento, della natura del beneficiario e della natura delle attività sovvenzionate.</div>\n</div>"], [null, "<p class=\"norm\">Il certificato è rilasciato da un revisore esterno riconosciuto o, nel caso di organismi pubblici, da un pubblico ufficiale competente e indipendente.</p>"], [null, "<p class=\"norm\">Nel certificato si attesta, secondo la metodologia approvata dall’ordinatore responsabile e sulla base di procedure concordate conformi ai principi internazionali, che i costi dichiarati dal beneficiario nei rendiconti finanziari sui quali si basa la richiesta di pagamento rispondono a verità, sono accuratamente registrati e sono ammissibili in conformità della convenzione di sovvenzione. In casi specifici e debitamente motivati, l’ordinatore responsabile può richiedere il certificato sotto forma di parere o in un altro formato conformemente ai principi internazionali.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">In funzione di una valutazione dei rischi, l’ordinatore responsabile può richiedere, a sostegno di qualsiasi pagamento, una relazione sulla verifica operativa, redatta da un terzo indipendente riconosciuto dall’ordinatore responsabile. La relazione sulla verifica operativa attesta che quest’ultima è stata svolta secondo una metodologia approvata dall’ordinatore responsabile e precisa se l’azione o il programma di lavoro siano stati effettivamente attuati conformemente alle condizioni stabilite nella convenzione di sovvenzione.</div>\n</div>"]]}, "204": {"label": "Articolo 204", "heading": "Sostegno finanziario a terzi", "anchor": "art_204", "frags": [[null, "<p class=\"norm\">Quando l’attuazione di un’azione o di un programma di lavoro richiede un sostegno finanziario a terzi, il beneficiario può fornirlo se le condizioni per tale fornitura sono definite nella convenzione di sovvenzione conclusa tra il beneficiario e la Commissione, senza alcun margine discrezionale da parte del beneficiario.</p>"], [null, "<p class=\"norm\">Il margine discrezionale non è considerato sussistere se la convenzione di sovvenzione specifica quanto segue:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’importo massimo del sostegno finanziario che può essere versato a terzi, che non è superiore a 60 000  EUR, e i criteri da applicare per determinare l’importo esatto;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i diversi tipi di attività che possono beneficiare di tale sostegno finanziario, sulla base di un elenco tassativo;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la definizione delle persone o delle categorie di persone che possono beneficiare di tale sostegno finanziario e i criteri per accordarlo.</p>\n</div>\n</div>"], [null, "<p class=\"norm\">La soglia di cui al secondo comma, lettera a), può essere superata qualora sia altrimenti impossibile o eccessivamente difficile conseguire gli obiettivi delle azioni.</p>"]]}, "205": {"label": "Articolo 205", "heading": "Appalti di esecuzione", "anchor": "art_205", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Fatte salve la direttiva 2014/24/UE e la direttiva 2014/25/UE del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">26</span>\n), quando l’attuazione dell’azione o del programma di lavoro richiede l’aggiudicazione di appalti pubblici, il beneficiario, evitando ogni conflitto d’interessi, può aggiudicare l’appalto pubblico conformemente alle sue consuete prassi in materia di acquisti, purché l’appalto pubblico sia aggiudicato all’offerta economicamente più vantaggiosa o, se del caso, all’offerta che presenta il prezzo più basso.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Quando l’attuazione dell’azione o del programma di lavoro richiede l’aggiudicazione di un appalto pubblico di valore superiore a 60 000  EUR, in casi debitamente giustificati l’ordinatore responsabile può prescrivere al beneficiario di osservare determinate norme specifiche ulteriori a quelle di cui al paragrafo 1.</div>\n</div>"], [null, "<p class=\"norm\">Dette norme specifiche sono basate sulle norme contenute nel presente regolamento, sono proporzionate al valore degli appalti pubblici di cui trattasi, all’entità relativa del contributo dell’Unione rispetto al costo totale dell’azione e ai rischi e sono incluse nella convenzione di sovvenzione.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "206": {"label": "Articolo 206", "heading": "Disposizioni generali", "anchor": "art_206", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">I premi sono attribuiti conformemente ai principi della trasparenza e della parità di trattamento e promuovono la realizzazione degli obiettivi strategici dell’Unione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">I premi non sono attribuiti direttamente, senza un concorso.</div>\n</div>"], [null, "<p class=\"norm\">Possono essere pubblicati concorsi a premi con un valore unitario pari o superiore a 1 000 000  EUR solo se essi sono menzionati nella decisione di finanziamento di cui all’articolo 110 e previa trasmissione al Parlamento europeo e al Consiglio di informazioni in merito ai premi stessi.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">L’ammontare del premio non è correlato ai costi sostenuti dal vincitore.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Qualora l’attuazione di un’azione o di un programma di lavoro richieda l’attribuzione di premi a terzi da parte del beneficiario, quest’ultimo può attribuire detti premi purché i criteri di ammissibilità e attribuzione, l’ammontare dei premi e le modalità di pagamento siano definiti nella convenzione di sovvenzione conclusa tra il beneficiario e la Commissione, senza alcun margine discrezionale.</div>\n</div>"]]}, "207": {"label": "Articolo 207", "heading": "Regole di concorso, attribuzione e pubblicazione", "anchor": "art_207", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Le regole di concorso:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">specificano i criteri di ammissibilità;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">specificano le modalità e il termine ultimo di iscrizione dei richiedenti, se necessari, e di presentazione delle domande;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">specificano i criteri di esclusione di cui all’articolo 136 e i motivi di rigetto di cui all’articolo 141;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">prevedono la responsabilità esclusiva del richiedente nel caso di un’azione legale inerente alle attività svolte nell’ambito del concorso;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">prevedono l’accettazione da parte dei vincitori degli obblighi di cui all’articolo 129 e degli obblighi in materia di pubblicità specificati dalle regole del concorso;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">stabiliscono i criteri di attribuzione, in modo da consentire di valutare la qualità delle domande rispetto agli obiettivi perseguiti e ai risultati attesi, nonché di stabilire obiettivamente se le domande abbiano avuto esito positivo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">specificano l’ammontare del premio o dei premi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">specificano le modalità di versamento dei premi ai vincitori dopo l’attribuzione.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Ai fini del primo comma, lettera a), i beneficiari sono ammissibili se non altrimenti disposto dalle regole del concorso.</p>"], [null, "<p class=\"norm\">L’articolo 194, paragrafo 3, si applica <span class=\"italics\">mutatis mutandis</span> alla pubblicazione dei concorsi.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le regole di concorso possono fissare le condizioni di annullamento del concorso, in particolare nel caso in cui gli obiettivi di quest’ultimo non possano essere conseguiti.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">I premi sono attribuiti dall’ordinatore responsabile a seguito della valutazione svolta dal comitato di valutazione di cui all’articolo 150.</div>\n</div>"], [null, "<p class=\"norm\">L’articolo 200, paragrafi 4 e 6, si applica <span class=\"italics\">mutatis mutandis</span> alla decisione di attribuzione.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">I richiedenti sono informati del risultato della valutazione della propria domanda quanto prima, e in ogni caso entro 15 giorni di calendario dalla decisione di attribuzione presa dall’ordinatore.</div>\n</div>"], [null, "<p class=\"norm\">La decisione di attribuzione del premio è comunicata al vincitore e costituisce l’impegno giuridico.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Tutti i premi attribuiti nel corso di un esercizio sono oggetto di pubblicazione conformemente all’articolo 38, paragrafi da 1 a 4.</div>\n</div>"], [null, "<p class=\"norm inline-element\">Dopo la pubblicazione la Commissione trasmette al Parlamento europeo e al Consiglio, su loro richiesta, una relazione riguardante:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il numero di richiedenti dell’anno precedente;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il numero di richiedenti e la percentuale di domande accolte per ogni concorso;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’elenco degli esperti che hanno fatto parte dei comitati di valutazione dell’anno precedente, con indicazione della procedura con cui sono stati selezionati.</p>\n</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "208": {"label": "Articolo 208", "heading": "Ambito di applicazione e attuazione", "anchor": "art_208", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L’Unione può costituire strumenti finanziari o fornire garanzie di bilancio ovvero assistenza finanziaria a carico del bilancio mediante un atto di base che ne definisca l’ambito di applicazione e il periodo di attuazione, ove sia dimostrato che essi rappresentano il modo più appropriato di realizzare gli obiettivi strategici dell’Unione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Gli Stati membri possono contribuire agli strumenti finanziari, alle garanzie di bilancio o all’assistenza finanziaria dell’Unione. Se l’atto di base lo autorizza, possono contribuire anche terzi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Quando gli strumenti finanziari sono attuati in regime di gestione concorrente con gli Stati membri, si applica la normativa settoriale.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Quando gli strumenti finanziari o le garanzie di bilancio sono attuati in regime di gestione indiretta, la Commissione conclude accordi con le entità a norma dell’articolo 62, paragrafo 1, primo comma, lettera c), punti ii), iii), v) e vi). Quando i sistemi, le norme e le procedure di tali entità sono stati valutati a norma dell’articolo 154, paragrafo 4, queste possono fare pieno affidamento su tali sistemi, norme e procedure. Nell’attuare strumenti finanziari e garanzie di bilancio in regime di gestione indiretta, dette entità possono concludere accordi con intermediari finanziari selezionati conformemente a procedure equivalenti a quelle applicate dalla Commissione. Dette entità recepiscono in tali accordi i requisiti stabiliti all’articolo 155, paragrafo 2.</div>\n</div>"], [null, "<p class=\"norm\">La Commissione continua a essere responsabile di assicurare che il quadro di attuazione degli strumenti finanziari sia conforme al principio della sana gestione finanziaria e consenta il conseguimento di obiettivi strategici definiti e temporalmente definiti, misurabili in termini di realizzazioni e/o risultati. La Commissione è responsabile dell’attuazione degli strumenti finanziari, fatta salva la responsabilità civile e contrattuale delle entità delegate, conformemente al diritto applicabile e all’articolo 129.</p>"], [null, "<p class=\"norm\">Quando agli strumenti finanziari o alle garanzie di bilancio contribuiscono paesi terzi ai sensi del paragrafo 2, l’atto di base può prevedere la designazione di entità attuative o controparti ammissibili dei paesi interessati.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">La Corte dei conti ha pieno accesso alle informazioni relative agli strumenti finanziari, alle garanzie di bilancio e all’assistenza finanziaria, anche mediante verifiche sul posto.</div>\n</div>"], [null, "<p class=\"norm\">La Corte dei conti è il revisore esterno responsabile dei progetti e programmi sostenuti da uno strumento finanziario, da una garanzia di bilancio o dall’assistenza finanziaria.</p>"]]}, "209": {"label": "Articolo 209", "heading": "Principi e condizioni applicabili agli strumenti finanziari e alle garanzie di bilancio", "anchor": "art_209", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli strumenti finanziari e le garanzie di bilancio sono utilizzati in conformità dei principi di sana gestione finanziaria, trasparenza, proporzionalità, non discriminazione, parità di trattamento e sussidiarietà, nonché dei loro obiettivi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Gli strumenti finanziari e le garanzie di bilancio:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">ovviano alle carenze del mercato oppure a situazioni di investimento non ottimali e forniscono un sostegno proporzionato soltanto ai destinatari finali ritenuti, secondo principi riconosciuti a livello internazionale, economicamente sostenibili nel momento in cui l’Unione concede il sostegno finanziario;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">conseguono addizionalità evitando la sostituzione del potenziale sostegno e degli investimenti provenienti da altre fonti pubbliche o di private;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">non falsano la concorrenza sul mercato interno e sono coerenti con le norme sugli aiuti di Stato;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">conseguono un effetto leva e moltiplicatore, con una forbice di valori basata su una valutazione ex ante per il corrispondente strumento finanziario o la corrispondente garanzia di bilancio, mobilitando un investimento globale che supera l’entità del contributo o della garanzia dell’Unione, compresa, ove opportuno, la massimizzazione degli investimenti privati;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sono attuati in maniera tale da assicurare la presenza di un interesse comune delle entità attuative o delle controparti che partecipano all’attuazione a conseguire gli obiettivi strategici definiti nel pertinente atto di base, con disposizioni relative, per esempio, a requisiti di investimento congiunto, obblighi di condivisione dei rischi o incentivi finanziari, prevenendo nel contempo un conflitto d’interessi con altre attività delle entità o controparti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">forniscono una remunerazione dell’Unione coerente con la condivisione del rischio tra gli attori finanziari partecipanti e gli obiettivi strategici dello strumento finanziario o della garanzia di bilancio;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">prevedono che, qualora debba essere corrisposta una remunerazione alle entità attuative o alle controparti che partecipano all’attuazione, essa sia legata alle performance e comprenda:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le spese amministrative destinate a remunerare l’entità o la controparte per il lavoro svolto nell’attuazione di uno strumento finanziario o di una garanzia di bilancio, che si basano, per quanto possibile, sugli interventi effettuati o sugli esborsi sostenuti; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se del caso, incentivi legati alle politiche per promuovere la realizzazione degli obiettivi strategici o la performance finanziaria dello strumento finanziario o della garanzia di bilancio.</p>\n</div>\n</div>\n<p class=\"list\">In casi debitamente giustificati possono essere rimborsate le spese straordinarie;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">si fondano su valutazioni ex ante, singolarmente o come parte di un programma, conformemente all’articolo 34, e spiegano la scelta del tipo di operazione finanziaria tenendo conto degli obiettivi strategici perseguiti e dei rischi finanziari e risparmi connessi per il bilancio.</p>\n<p class=\"list\">Le valutazioni di cui al primo comma, lettera h), sono riesaminate e aggiornate per tenere conto degli effetti di cambiamenti socioeconomici rilevanti sulla motivazione dello strumento finanziario o della garanzia di bilancio.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Fatta salva la normativa settoriale per la gestione concorrente, le entrate, compresi i dividendi, le plusvalenze, le commissioni di garanzia e gli interessi sui prestiti e sugli importi dei conti fiduciari rimborsati alla Commissione o sui conti fiduciari aperti per strumenti finanziari o garanzie di bilancio e imputabili al sostegno a titolo del bilancio nell’ambito di uno strumento finanziario o di una garanzia di bilancio sono iscritti nel bilancio previa detrazione dei costi e delle commissioni di gestione.</div>\n</div>"], [null, "<p class=\"norm\">I rimborsi annuali, compresi i rimborsi di capitale, le garanzie rilasciate e i rimborsi del capitale dei prestiti, effettuati sui conti della Commissione o su conti fiduciari aperti per strumenti finanziari o garanzie di bilancio e imputabili al sostegno a titolo del bilancio nell’ambito di uno strumento finanziario o di una garanzia di bilancio costituiscono entrate con destinazione specifica interne conformemente all’articolo 21, paragrafo 3, lettera f), e sono utilizzati per lo stesso strumento finanziario o la stessa garanzia di bilancio, fatto salvo l’articolo 215, paragrafo 5, per un periodo non superiore al periodo di impegno di bilancio più due anni, se non diversamente specificato in un atto di base.</p>"], [null, "<p class=\"norm\">Nel proporre l’importo delle future dotazioni per strumenti finanziari o garanzie di bilancio la Commissione tiene conto di tali entrate con destinazione specifica interne.</p>"], [null, "<p class=\"norm\">Fatto salvo il secondo comma, l’importo ancora da liquidare delle entrate con destinazione specifica autorizzate da un atto di base di cui è prevista l’abrogazione o la scadenza può altresì essere assegnato a un altro strumento finanziario che persegue obiettivi analoghi, se ciò è previsto nell’atto di base istitutivo di tale strumento finanziario.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">L’ordinatore responsabile dello strumento finanziario, della garanzia di bilancio o dell’assistenza finanziaria elabora un rendiconto finanziario per il periodo dal 1<span class=\"superscript\">o</span> gennaio al 31 dicembre in conformità dell’articolo 243 e nel rispetto delle norme contabili di cui all’articolo 80 e dei principi contabili internazionali del settore pubblico (IPSAS).</div>\n</div>"], [null, "<p class=\"norm\">Per gli strumenti finanziari e le garanzie di bilancio attuati in regime di gestione indiretta l’ordinatore responsabile verifica che i rendiconti finanziari non sottoposti ad audit relativi al periodo dal 1<span class=\"superscript\">o</span> gennaio al 31 dicembre ed elaborati nel rispetto delle norme contabili di cui all’articolo 80 e degli IPSAS, nonché tutte le informazioni necessarie per produrre i rendiconti finanziari in conformità dell’articolo 82, paragrafo 2, siano presentati dalle entità a norma dell’articolo 62, paragrafo 1, lettera c), punti ii), iii,) v) e vi), entro il 15 febbraio dell’anno successivo e che i rendiconti finanziari sottoposti ad audit siano presentati da dette entità entro il 15 maggio dell’anno successivo.</p>"]]}, "210": {"label": "Articolo 210", "heading": "Passività finanziaria dell’Unione", "anchor": "art_210", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La passività finanziaria e i pagamenti netti aggregati a titolo del bilancio non superano mai:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per gli strumenti finanziari: l’importo dell’impegno di bilancio a essi corrispondente;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per le garanzie di bilancio: l’importo della garanzia di bilancio autorizzato dall’atto di base;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per l’assistenza finanziaria: l’importo massimo dei prestiti che la Commissione è abilitata ad assumere per finanziare l’assistenza finanziaria autorizzata dall’atto di base e i corrispondenti interessi.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le garanzie di bilancio e l’assistenza finanziaria possono generare per l’Unione una passività potenziale che supera soltanto gli attivi finanziari previsti a copertura della passività finanziaria dell’Unione, ove previsto dall’atto di base che istituisce una garanzia di bilancio o un’assistenza finanziaria e alle condizioni ivi stabilite.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Ai fini della valutazione annuale di cui all’articolo 41, paragrafo 5, lettera j), le passività potenziali derivanti dalle garanzie di bilancio o dall’assistenza finanziaria a carico del bilancio sono ritenute sostenibili se la loro evoluzione pluriennale prevista è compatibile con i limiti fissati dal regolamento che stabilisce il quadro finanziario pluriennale previsto all’articolo 312, paragrafo 2, TFUE e il massimale relativo agli stanziamenti annuali di pagamento di cui all’articolo 3, paragrafo 1, della decisione 2014/335/UE, Euratom.</div>\n</div>"]]}, "211": {"label": "Articolo 211", "heading": "Copertura delle passività finanziarie", "anchor": "art_211", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Per le garanzie di bilancio e l’assistenza finanziaria ai paesi terzi un atto di base fissa un tasso di copertura in percentuale dell’importo della passività finanziaria autorizzata. Tale importo esclude i contributi di cui all’articolo 208, paragrafo 2.</div>\n</div>"], [null, "<p class=\"norm\">L’atto di base stabilisce che il tasso di copertura sia rivisto con cadenza almeno triennale.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il tasso di copertura è fissato sulla scorta di una valutazione qualitativa e quantitativa dei rischi finanziari derivanti da una garanzia di bilancio o dall’assistenza finanziaria a un paese terzo, che la Commissione effettua conformemente al principio di prudenza, ossia senza sovrastimare attività e profitti né sottostimare passività e perdite.</div>\n</div>"], [null, "<p class=\"norm\">Salvo diversamente specificato nell’atto di base che istituisce la garanzia di bilancio o l’assistenza finanziaria a un paese terzo, il tasso di copertura si basa sulla copertura globale necessaria in anticipo per coprire le perdite nette attese, oltre a un’adeguata riserva di sicurezza. Fatti salvi i poteri del Parlamento europeo e del Consiglio, la copertura globale è costituita per il periodo di tempo previsto nella pertinente scheda finanziaria di cui all’articolo 35.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Per uno strumento finanziario è prevista, se del caso, la copertura per rispondere a pagamenti futuri relativi a un impegno di bilancio dello strumento finanziario in questione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Confluiscono nella copertura le seguenti risorse:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i contributi provenienti dal bilancio, nel pieno rispetto del regolamento che stabilisce il quadro finanziario pluriennale e previo esame delle possibilità di riassegnazioni;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli utili sugli investimenti di risorse detenute nel fondo comune di copertura;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli importi recuperati dai debitori inadempienti secondo la procedura di recupero stabilita nell’accordo di garanzia o di prestito;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le entrate e ogni altro pagamento ricevuto dall’Unione in conformità dell’accordo di garanzia o di prestito;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se del caso, i contributi in denaro contante degli Stati membri e di terzi ai sensi dell’articolo 208, paragrafo 2.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Per il calcolo della copertura risultante dal tasso di copertura di cui al paragrafo 1 si tiene conto solamente delle risorse di cui al primo comma, lettere da a) a d), del presente paragrafo.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La copertura è utilizzata per i seguenti pagamenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">attivazione della garanzia di bilancio;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">obbligazioni di pagamento relative a un impegno di bilancio per uno strumento finanziario;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">obbligazioni finanziarie derivanti dall’assunzione di prestiti ai sensi dell’articolo 220, paragrafo 1;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se del caso, altre spese connesse all’attuazione degli strumenti finanziari, delle garanzie di bilancio e dell’assistenza finanziaria ai paesi terzi.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Allorché il finanziamento fornito tramite la garanzia di bilancio supera l’importo della copertura risultante dal tasso di copertura di cui al paragrafo 1 del presente articolo, le risorse di cui al paragrafo 4, primo comma, lettere b), c) e d), del presente articolo connesse a tale garanzia sono utilizzate nei limiti del periodo ammissibile previsto nell’atto di base, ma non oltre la fase di costituzione della copertura, fatto salvo l’articolo 213, paragrafo 4, per ripristinare la garanzia di bilancio all’ammontare iniziale.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La Commissione informa immediatamente il Parlamento europeo e il Consiglio e può proporre idonee misure di ricostituzione o un aumento del tasso di copertura nei seguenti casi:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se, in conseguenza dell’attivazione della garanzia di bilancio, i relativi accantonamenti scendono al di sotto del 50 % del tasso di copertura di cui al paragrafo 1, e ancora al di sotto del 30 % di detto tasso di copertura, oppure se una valutazione dei rischi effettuata dalla Commissione fa ritenere che essi possano scendere al di sotto di una di tali percentuali nell’arco di un anno;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se un paese che beneficia dell’assistenza finanziaria dell’Unione non è in grado di pagare alla scadenza.</p>\n</div>\n</div>\n</div>\n</div>"]]}, "212": {"label": "Articolo 212", "heading": "Fondo comune di copertura", "anchor": "art_212", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli accantonamenti a copertura delle passività finanziarie derivanti dagli strumenti finanziari, dalle garanzie di bilancio o dall’assistenza finanziaria sono depositati in un fondo comune di copertura.</div>\n</div>"], [null, "<p class=\"norm\">Entro il 30 giugno 2019, la Commissione presenta al Parlamento europeo e al Consiglio una valutazione esterna indipendente dei vantaggi e degli svantaggi di affidare la gestione finanziaria delle attività del fondo comune di copertura alla Commissione, alla BEI o a una combinazione di entrambe, tenendo conto dei pertinenti criteri tecnici e istituzionali utilizzati nel confronto tra i servizi di gestione patrimoniale, tra cui le infrastrutture tecniche, di un confronto dei costi dei servizi forniti, della struttura istituzionale, della comunicazione di informazioni, della performance, della rendicontabilità e delle competenze della Commissione e della BEI, nonché degli altri mandati di gestione patrimoniale per il bilancio. La valutazione è corredata, se del caso, di una proposta legislativa.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">I profitti o le perdite globali derivanti dall’investimento delle risorse detenute nel fondo comune di copertura sono ripartiti proporzionalmente tra i rispettivi strumenti finanziari, garanzie di bilancio o assistenza finanziaria.</div>\n</div>"], [null, "<p class=\"norm\">Il gestore finanziario delle risorse del fondo comune di copertura tiene un importo minimo di risorse del fondo in denaro contante o equivalenti di liquidità in conformità delle norme prudenziali e delle previsioni di pagamento fornite dagli ordinatori degli strumenti finanziari, delle garanzie di bilancio o dell’assistenza finanziaria.</p>"], [null, "<p class=\"norm\">Il gestore finanziario delle risorse del fondo comune di copertura può sottoscrivere contratti di vendita con patto di opzione, garantiti dalle risorse del fondo comune di copertura, per effettuare versamenti dal fondo se tale procedura può essere ragionevolmente considerata più vantaggiosa per il bilancio rispetto alla cessione di risorse nell’arco temporale della richiesta di pagamento. La durata o il periodo di rinnovo dei contratti di vendita con patto di opzione collegati a un pagamento sono limitati alla durata minima necessaria per minimizzare la perdita per il bilancio.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">A norma dell’articolo 77, paragrafo 1, primo comma, lettera d), e dell’articolo 86, paragrafi 1 e 2, il contabile stabilisce le procedure applicabili alle operazioni in entrate e in spese e, d’accordo con il gestore finanziario delle risorse del fondo comune di copertura, alle attività e passività connesse al fondo comune di copertura.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Nei casi eccezionali in cui ha effettuato uno storno di cui all’articolo 30, paragrafo 1, primo comma, lettera g), la Commissione ne informa immediatamente il Parlamento europeo e il Consiglio e propone urgentemente le misure necessarie per ripristinare la voce di bilancio della garanzia da cui è stato effettuato lo storno, nel pieno rispetto dei massimali di cui al regolamento che stabilisce il quadro finanziario pluriennale.</div>\n</div>"]]}, "213": {"label": "Articolo 213", "heading": "Tasso di copertura effettivo", "anchor": "art_213", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La copertura delle garanzie di bilancio e dell’assistenza finanziaria ai paesi terzi nel fondo comune di copertura è basata su un tasso di copertura effettivo. Tale tasso fornisce un livello di tutela rispetto alle passività finanziarie dell’Unione equivalente a quello che sarebbe fornito dai rispettivi tassi di copertura se le risorse fossero depositate e gestite separatamente.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Il tasso di copertura effettivo applicabile è una percentuale di ciascun tasso di copertura iniziale determinato in conformità dell’articolo 211, paragrafo 2, secondo comma. Si applica soltanto all’importo delle risorse del fondo comune di copertura previste per il pagamento dell’attivazione delle garanzie nell’arco di un anno. Fornisce il rapporto, sotto forma di percentuale, tra l’importo di denaro contante ed equivalenti di liquidità nel fondo comune di copertura richiesto per onorare l’attivazione di garanzie e l’importo totale di denaro contante ed equivalenti di liquidità che sarebbe necessario in ciascun fondo di garanzia per onorare l’attivazione della garanzia se le risorse fossero depositate e gestite separatamente, dove entrambi gli importi rappresentano un rischio di liquidità equivalente. Tale rapporto non scende al di sotto del 95 %. Il calcolo del tasso di copertura effettivo tiene conto dei seguenti elementi:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la previsione dei flussi in entrata e in uscita nel fondo comune di copertura, tenendo conto della fase iniziale di costituzione della copertura totale in conformità dell’articolo 211, paragrafo 2, secondo comma;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la correlazione del rischio tra le garanzie di bilancio e l’assistenza finanziaria a paesi terzi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le condizioni di mercato.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Entro il 1<span class=\"superscript\">o</span> luglio 2020 la Commissione adotta atti delegati conformemente all’articolo 269 al fine di integrare il presente regolamento con le condizioni dettagliate per il calcolo del tasso di copertura effettivo, ivi compresa una metodologia per tale calcolo.</p>"], [null, "<p class=\"norm\">Alla Commissione è conferito il potere di adottare atti delegati conformemente all’articolo 269 al fine di modificare il rapporto minimo di cui al primo comma del presente paragrafo alla luce dell’esperienza acquisita in relazione al funzionamento del fondo comune di copertura, mantenendo un approccio prudente in linea con il principio di sana gestione finanziaria. Il rapporto minimo non è fissato a un livello inferiore all’85 %.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il tasso di copertura effettivo è calcolato ogni anno dal gestore finanziario delle risorse del fondo comune di copertura e costituisce il riferimento per il calcolo, da parte della Commissione, dei contributi provenienti dal bilancio ai sensi dell’articolo 211, paragrafo 4, lettera a), e, successivamente, del paragrafo 4, lettera b), del presente articolo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">In seguito al calcolo del tasso di copertura annuo effettivo in conformità dei paragrafi 1 e 2 del presente articolo, nell’ambito della procedura di bilancio sono effettuate e presentate nel documento di lavoro di cui all’articolo 41, paragrafo 5, lettera h), le seguenti operazioni:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">ogni eccedenza degli accantonamenti relativi a una garanzia di bilancio o all’assistenza finanziaria a un paese terzo è restituita al bilancio;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">ogni ricostituzione del fondo avviene in frazioni annue nell’arco di un periodo massimo di tre anni, fatto salvo l’articolo 211, paragrafo 6.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Previa consultazione del contabile, la Commissione stabilisce gli orientamenti applicabili alla gestione delle risorse nel fondo comune di copertura in conformità di adeguate norme prudenziali ed escludendo le operazioni su derivati a fini speculativi. Tali orientamenti sono acclusi all’accordo con il gestore finanziario delle risorse del fondo comune di copertura.</div>\n</div>"], [null, "<p class=\"norm\">L’adeguatezza degli orientamenti è sottoposta a una valutazione indipendente ogni tre anni e comunicata al Parlamento europeo e al Consiglio.</p>"]]}, "214": {"label": "Articolo 214", "heading": "Relazione annuale", "anchor": "art_214", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">In aggiunta all’obbligo di relazione di cui all’articolo 250, la Commissione riferisce con cadenza annuale al Parlamento europeo e al Consiglio in merito al fondo comune di copertura.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il gestore finanziario delle risorse del fondo comune di copertura riferisce con cadenza annuale al Parlamento europeo e al Consiglio in merito al fondo comune di copertura.</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "215": {"label": "Articolo 215", "heading": "Norme e attuazione", "anchor": "art_215", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">In deroga all’articolo 208, paragrafo 1, gli strumenti finanziari possono essere costituiti, in casi debitamente giustificati, senza essere autorizzati per mezzo di un atto di base, a condizione che siano inclusi nel progetto di bilancio in conformità dell’articolo 41, paragrafo 4, primo comma, lettera e).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Quando gli strumenti finanziari o le garanzie di bilancio sono combinati con un sostegno accessorio del bilancio, comprese le sovvenzioni, in un unico accordo, il presente titolo si applica all’intera misura. Le relazioni sono presentate in conformità dell’articolo 250 e indicano chiaramente quali parti della misura sono strumenti finanziari o garanzie di bilancio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La Commissione garantisce una gestione armonizzata e semplificata degli strumenti finanziari, in particolare nel settore della contabilità, della rendicontazione, del monitoraggio e della gestione del rischio finanziario.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Quando l’Unione partecipa a uno strumento finanziario con una quota di minoranza, la Commissione garantisce l’osservanza del presente titolo, in conformità del principio di proporzionalità, sulla base dell’entità e della portata della partecipazione dell’Unione allo strumento. Tuttavia, nonostante l’entità e la portata della partecipazione dell’Unione allo strumento, la Commissione garantisce il rispetto degli articoli 129 e 155, dell’articolo 209, paragrafi 2 e 4, dell’articolo 250 e, nella misura in cui riguarda situazioni di esclusione di cui all’articolo 136, paragrafo 1, lettera d), del titolo V, capo 2, sezione 2.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Qualora ritengano che uno strumento finanziario non abbia raggiunto i suoi obiettivi in modo efficace, il Parlamento europeo o il Consiglio possono chiedere alla Commissione di presentare una proposta di atto di base rivisto al fine di chiudere lo strumento. Nel caso della chiusura dello strumento finanziario i nuovi importi rimborsati allo strumento a norma dell’articolo 209, paragrafo 3, sono considerati entrate generali e reimmessi nel bilancio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">L’obiettivo degli strumenti finanziari o di un raggruppamento di strumenti finanziari a livello di meccanismo e, se del caso, la loro forma giuridica specifica e il luogo di registrazione sono pubblicati sul sito web della Commissione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Le entità investite dell’attuazione degli strumenti finanziari possono aprire conti fiduciari a norma dell’articolo 85, paragrafo 3, per conto dell’Unione. Tali entità trasmettono i relativi estratti conto al servizio competente della Commissione. I pagamenti su conti fiduciari sono effettuati dalla Commissione sulla base di richieste di pagamento debitamente motivate da previsioni di spesa, tenendo conto dei saldi disponibili sui conti fiduciari e della necessità di evitare saldi eccessivi su tali conti.</div>\n</div>"]]}, "216": {"label": "Articolo 216", "heading": "Strumenti finanziari attuati direttamente dalla Commissione", "anchor": "art_216", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Gli strumenti finanziari possono essere attuati direttamente a norma dell’articolo 62, paragrafo 1, primo comma, lettera a), con le seguenti modalità:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un veicolo di investimento dedicato al quale la Commissione partecipa insieme ad altri investitori pubblici o privati al fine di incrementare l’effetto leva del contributo dell’Unione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">prestiti, garanzie, partecipazioni e altri strumenti di condivisione dei rischi diversi dagli investimenti in veicoli di investimento dedicati, forniti direttamente ai destinatari finali o tramite intermediari finanziari.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">I veicoli di investimento dedicati di cui al paragrafo 1, lettera a), sono istituiti conformemente alla legislazione di uno Stato membro. Nell’ambito delle azioni esterne, essi possono anche essere istituiti conformemente alla legislazione di un paese terzo. I gestori di tali veicoli sono tenuti, per legge o per contratto, ad agire con la diligenza di un gestore professionale e in buona fede.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">I gestori di veicoli di investimento dedicati di cui al paragrafo 1, lettera a), e gli intermediari finanziari o i destinatari finali di strumenti finanziari sono selezionati tenendo conto della natura dello strumento finanziario che deve essere attuato, dell’esperienza e della capacità finanziaria e operativa delle entità interessate, nonché della sostenibilità economica dei progetti dei destinatari finali. La selezione è trasparente, giustificata da ragioni oggettive e non dà luogo a conflitti d’interessi.</div>\n</div>"]]}, "217": {"label": "Articolo 217", "heading": "Trattamento dei contributi provenienti da fondi eseguiti in regime di gestione concorrente", "anchor": "art_217", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">È tenuta una contabilità separata per i contributi agli strumenti finanziari costituiti a norma della presente sezione provenienti da fondi eseguiti in regime di gestione concorrente.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">I contributi provenienti dai fondi eseguiti in regime di gestione concorrente sono iscritti in una contabilità separata e utilizzati conformemente agli obiettivi dei rispettivi fondi per azioni e destinatari finali compatibili con il programma o i programmi da cui provengono i contributi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Ai contributi dei fondi eseguiti in regime di gestione concorrente agli strumenti finanziari costituiti a norma della presente sezione si applica la normativa settoriale. Fermo quanto disposto dal precedente periodo, le autorità di gestione possono basarsi su una valutazione ex ante preesistente, svolta a norma dell’articolo 209, paragrafo 2, primo e secondo comma, lettera h), per decidere di contribuire a uno strumento finanziario esistente.</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "218": {"label": "Articolo 218", "heading": "Norme in materia di garanzie di bilancio", "anchor": "art_218", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">L’atto di base definisce:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’importo della garanzia di bilancio che non può mai essere superato, fatto salvo l’articolo 208, paragrafo 2;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le tipologie di operazioni coperte dalla garanzia di bilancio.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">I contributi degli Stati membri alle garanzie di bilancio ai sensi dell’articolo 208, paragrafo 2, possono essere forniti sotto forma di garanzie o in contanti.</div>\n</div>"], [null, "<p class=\"norm\">I contributi di terzi alle garanzie di bilancio ai sensi dell’articolo 208, paragrafo 2, possono essere forniti in contanti.</p>"], [null, "<p class=\"norm\">La garanzia di bilancio è accresciuta dai contributi di cui al primo e secondo comma. I pagamenti relativi all’attivazione delle garanzie sono effettuati, ove necessario, dagli Stati membri o da terzi contributori su base <span class=\"italics\">pari passu</span>. La Commissione firma con i contributori un accordo contenente, in particolare, le disposizioni relative alle condizioni di pagamento.</p>"]]}, "219": {"label": "Articolo 219", "heading": "Attuazione delle garanzie di bilancio", "anchor": "art_219", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le garanzie di bilancio sono irrevocabili, incondizionate e su richiesta per le tipologie di operazioni coperte.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le garanzie di bilancio sono attuate a norma dell’articolo 62, paragrafo 1, primo comma, lettera c), o, in casi eccezionali, a norma dell’articolo 62, paragrafo 1, primo comma, lettera a).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La garanzia di bilancio copre soltanto le operazioni di finanziamento e investimento che soddisfano le condizioni stabilite all’articolo 209, paragrafo 2, primo comma, lettere da a) a d).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Le controparti contribuiscono con risorse proprie alle operazioni coperte dalla garanzia di bilancio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">La Commissione sottoscrive con la controparte un accordo di garanzia. La concessione della garanzia di bilancio è subordinata all’entrata in vigore dell’accordo di garanzia.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Le controparti comunicano con cadenza annuale alla Commissione:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una valutazione del rischio e le informazioni relative alla classificazione delle operazioni coperte dalla garanzia di bilancio, nonché gli inadempimenti attesi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">informazioni sull’obbligazione finanziaria in essere dell’Unione derivante dalla garanzia di bilancio, ripartita per singola operazione e misurata conformemente alle norme contabili dell’Unione di cui all’articolo 80 o agli IPSAS;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il totale dei profitti o delle perdite derivanti dalle operazioni coperte dalla garanzia di bilancio.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "220": {"label": "Articolo 220", "heading": "Norme e attuazione", "anchor": "art_220", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L’assistenza finanziaria dell’Unione a Stati membri o paesi terzi è fornita a condizioni predefinite e assume la forma di un prestito o di una linea di credito o di un altro strumento ritenuto idoneo a garantire l’efficacia del sostegno. A tal fine, il pertinente atto di base conferisce alla Commissione il potere di reperire le risorse necessarie assumendo prestiti per conto dell’Unione sui mercati dei capitali o presso istituzioni finanziarie.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1 —————</p>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">L’assistenza finanziaria è erogata in euro, tranne in casi debitamente giustificati.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">L’assistenza finanziaria è attuata direttamente dalla Commissione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La Commissione sottoscrive con il paese beneficiario un accordo contenente disposizioni che:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">assicurano che il paese beneficiario verifichi a cadenza regolare che i finanziamenti erogati siano stati utilizzati correttamente in conformità delle condizioni predefinite, adotti misure atte a prevenire irregolarità e frodi e, se necessario, intraprenda azioni legali per il recupero dei fondi concessi a titolo di assistenza finanziaria che siano stati oggetto di appropriazione indebita;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">assicurano la tutela degli interessi finanziari dell’Unione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">autorizzano espressamente la Commissione, l’OLAF e la Corte dei conti a esercitare i loro diritti conformemente all’articolo 129;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">assicurano che l’Unione abbia diritto al rimborso anticipato del prestito qualora si riscontri che, in relazione alla gestione dell’assistenza finanziaria, il paese beneficiario è stato coinvolto in atti di frode o di corruzione o in altre attività illegali che ledono gli interessi finanziari dell’Unione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">assicurano che tutti i costi sostenuti dall’Unione in relazione all’assistenza finanziaria siano a carico del paese beneficiario.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Ove possibile, la Commissione eroga il prestito a rate, purché siano rispettate le condizioni cui è subordinata l’assistenza finanziaria. Qualora tali condizioni non siano soddisfatte, la Commissione sospende o cancella temporaneamente l’erogazione dell’assistenza finanziaria.</div>\n</div>"], [null, "<p class=\"modref\">\n▼M1 —————</p>"], [null, "<p class=\"modref\">\n▼M1\n</p>"]]}, "220a": {"label": "Articolo 220 bis", "heading": "Strategia di finanziamento diversificata", "anchor": "art_220a", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La Commissione attua una strategia di finanziamento diversificata che comprende l'assunzione di prestiti autorizzata a norma dell'articolo 5, paragrafo 1, della decisione (UE, Euratom) 2020/2053 del Consiglio (\n<span class=\"superscript\">27</span>\n) e, tranne in casi debitamente giustificati, operazioni di assunzione di prestiti e di gestione del debito per finanziare i programmi di assistenza finanziaria. La strategia di finanziamento diversificata è attuata mediante tutte le operazioni necessarie al fine di assicurare una presenza regolare sui mercati dei capitali, si basa sulla messa in comune degli strumenti di finanziamento e si avvale di una riserva di liquidità comune.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La Commissione stabilisce le disposizioni necessarie per l'attuazione della strategia di finanziamento diversificata. La Commissione, a cadenza periodica e in modo articolato, informa il Parlamento europeo e il Consiglio su tutti gli aspetti della sua strategia di assunzione di prestiti e di gestione del debito.</div>\n</div>"], [null, "<p class=\"modref\">\n▼B\n</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "221": {"label": "Articolo 221", "heading": "Disposizioni generali", "anchor": "art_221", "frags": [[null, "<p class=\"norm\">Possono essere concessi contributi finanziari diretti a carico del bilancio ai partiti politici europei, quali definiti nell’articolo 2, punto 3), del regolamento (UE, Euratom) n. 1141/2014 («partiti politici europei»), affinché possano contribuire a formare una coscienza politica europea e a esprimere la volontà politica dei cittadini dell’Unione, in conformità di detto regolamento.</p>"]]}, "222": {"label": "Articolo 222", "heading": "Principi", "anchor": "art_222", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">I contributi sono utilizzati per il rimborso solo della percentuale di cui all’articolo 17, paragrafo 4, del regolamento (UE, Euratom) n. 1141/2014 dei costi di funzionamento dei partiti politici europei direttamente connessi agli obiettivi di tali partiti, come specificato all’articolo 17, paragrafo 5, e all’articolo 21 di tale regolamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">I contributi possono essere utilizzati per rimborsare spese connesse a contratti conclusi da partiti politici europei, a condizione che all’atto dell’aggiudicazione di tali contratti non vi fossero conflitti d’interessi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">I contributi non sono utilizzati per concedere, direttamente o indirettamente, vantaggi personali, in denaro o in natura, ad alcun membro o dipendente di un partito politico europeo. I contributi non sono utilizzati per finanziare, direttamente o indirettamente, attività di terzi, in particolare partiti politici nazionali o fondazioni politiche a livello europeo o nazionale, sotto forma di sovvenzioni, donazioni, prestiti o altri accordi simili. Ai fini del presente paragrafo non sono considerate terzi le entità associate ai partiti politici europei, ove tali entità facciano parte dell’organizzazione amministrativa dei partiti politici europei medesimi, come previsto nello statuto di questi ultimi. I contributi non sono utilizzati per gli scopi esclusi dall’articolo 22 del regolamento (UE, Euratom) n. 1141/2014.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">I contributi sono subordinati al rispetto dei principi di trasparenza e di parità di trattamento, conformemente ai criteri di cui al regolamento (UE, Euratom) n. 1141/2014.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">I contributi sono concessi dal Parlamento europeo su base annuale e sono pubblicati a norma dell’articolo 38, paragrafi da 1 a 4, del presente regolamento e dell’articolo 32, paragrafo 1, del regolamento (UE, Euratom) n. 1141/2014.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">I partiti politici europei che ricevono un contributo non ricevono, direttamente o indirettamente, altri fondi provenienti dal bilancio. In particolare, sono vietate le donazioni attinte dai bilanci di gruppi politici rappresentati al Parlamento europeo. In nessun caso il bilancio finanzia due volte la medesima spesa.</div>\n</div>"], [null, "<p class=\"norm\">I contributi non pregiudicano la facoltà dei partiti politici europei di costituire riserve con importi derivanti da risorse proprie in conformità del regolamento (UE, Euratom) n. 1141/2014.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Se, alla fine di un esercizio per il quale ha ricevuto una sovvenzione di funzionamento, una fondazione politica europea, quale definita all’articolo 2, punto 4), del regolamento (UE, Euratom) n. 1141/2014, realizza un’eccedenza di entrate rispetto alle spese, può riportare all’esercizio successivo la parte di tale eccedenza corrispondente al massimo al 25 % delle entrate totali di quell’esercizio, a condizione che tale parte sia usata entro il primo trimestre di detto esercizio successivo.</div>\n</div>"]]}, "223": {"label": "Articolo 223", "heading": "Aspetti di bilancio", "anchor": "art_223", "frags": [[null, "<p class=\"norm\">I contributi e gli stanziamenti destinati a organismi o esperti esterni indipendenti di audit di cui all’articolo 23 del regolamento (UE, Euratom) n. 1141/2014 sono versati dalla sezione del bilancio relativa al Parlamento europeo.</p>"]]}, "224": {"label": "Articolo 224", "heading": "Bando per la presentazione delle domande di contributi", "anchor": "art_224", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">I contributi sono concessi in esito a bando per la presentazione delle domande di contributi pubblicato ogni anno almeno sul sito web del Parlamento europeo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">A un partito politico europeo può essere concesso un solo contributo all’anno.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Un partito politico europeo può ricevere un contributo solo se ne fa richiesta nel rispetto dei termini e delle condizioni stabiliti nel bando per la presentazione delle domande di contributi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Il bando per la presentazione delle domande di contributi stabilisce a quali condizioni un richiedente può ricevere un contributo in conformità del regolamento (UE, Euratom) n. 1141/2014, nonché i criteri di esclusione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Il bando per la presentazione delle domande di contributi determina almeno la natura delle spese che possono essere rimborsate mediante il contributo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Il bando per la presentazione delle domande di contributi richiede un bilancio di previsione.</div>\n</div>"]]}, "225": {"label": "Articolo 225", "heading": "Procedura di attribuzione", "anchor": "art_225", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le domande di contributi sono presentate per iscritto entro il termine stabilito e, se del caso, in formato elettronico protetto.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">I contributi non sono concessi ai richiedenti che, al momento della procedura di attribuzione, si trovano in una o più delle situazioni di cui all’articolo 136, paragrafo 1, e all’articolo 141, paragrafo 1, né a quelli che sono registrati come esclusi nella banca dati di cui all’articolo 142.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">I richiedenti sono tenuti ad attestare che non si trovano in una delle situazioni di cui al paragrafo 2.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">L’ordinatore responsabile può essere assistito da un comitato ai fini della valutazione delle domande di contributo. L’ordinatore responsabile precisa le regole in materia di composizione, nomina e funzionamento di detto comitato e le regole volte a prevenire i conflitti d’interessi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Le domande che soddisfano i criteri di ammissibilità e di esclusione sono selezionate in base ai criteri di cui all’articolo 19 del regolamento (UE, Euratom) n. 1141/2014.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La decisione dell’ordinatore responsabile in merito alle domande precisa almeno:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’oggetto e l’importo globale dei contributi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il nome dei richiedenti selezionati e gli importi accettati per ognuno di essi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i nominativi dei richiedenti respinti e i motivi del rigetto.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">L’ordinatore responsabile informa per iscritto i richiedenti della decisione assunta in relazione alle rispettive domande. Se la domanda di contributo è respinta o gli importi richiesti non sono concessi in tutto o in parte, l’ordinatore responsabile comunica i motivi del rigetto o della mancata attribuzione degli importi richiesti, con riferimento, in particolare, ai criteri di ammissibilità e di attribuzione di cui al paragrafo 5 del presente articolo e all’articolo 224, paragrafo 4. Se la domanda è respinta, l’ordinatore responsabile informa il richiedente dei mezzi amministrativi e/o di ricorso giurisdizionale a sua disposizione previsti all’articolo 133, paragrafo 2.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">I contributi formano oggetto di un accordo scritto.</div>\n</div>"]]}, "226": {"label": "Articolo 226", "heading": "Forma dei contributi", "anchor": "art_226", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">I contributi possono assumere una delle seguenti forme:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">rimborso di una percentuale delle spese rimborsabili effettivamente sostenute;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">rimborso sulla base di costi unitari;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">somme forfettarie;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">finanziamenti a tasso fisso;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una combinazione delle forme di cui alle lettere da a) a d).</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Possono essere rimborsate solo le spese che soddisfano i criteri stabiliti nel bando per la presentazione delle domande di contributi e che non sono state sostenute prima della data di presentazione della domanda.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">L’accordo di cui all’articolo 225, paragrafo 8, contiene disposizioni che consentono di verificare l’osservanza delle condizioni per l’attribuzione di somme forfettarie, finanziamenti a tasso fisso o costi unitari.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">I contributi sono versati nella loro totalità, sotto forma di un unico prefinanziamento, a meno che l’ordinatore responsabile decida altrimenti in casi debitamente giustificati.</div>\n</div>"]]}, "227": {"label": "Articolo 227", "heading": "Garanzie", "anchor": "art_227", "frags": [[null, "<p class=\"norm\">L’ordinatore responsabile può, se lo ritiene opportuno e proporzionato, caso per caso e previa analisi dei rischi, esigere che un partito politico europeo costituisca una garanzia anticipata per limitare i rischi finanziari connessi al pagamento del prefinanziamento solo quando, alla luce dell’analisi dei rischi, tale partito risulti esposto al rischio imminente di trovarsi in una delle situazioni di esclusione di cui all’articolo 136, paragrafo 1, lettere a) e d), del presente regolamento o quando una decisione dell’Autorità per i partiti politici europei e le fondazioni politiche europee, istituita a norma dell’articolo 6 del regolamento (UE, Euratom) n. 1141/2014 («Autorità»), è stata comunicata al Parlamento europeo e al Consiglio in conformità dell’articolo 10, paragrafo 4, di tale regolamento.</p>"], [null, "<p class=\"norm\">L’articolo 153 si applica <span class=\"italics\">mutatis mutandis</span> alle garanzie che possono essere richieste nei casi di cui al primo comma del presente articolo per i pagamenti di prefinanziamento a favore dei partiti politici europei.</p>"]]}, "228": {"label": "Articolo 228", "heading": "Uso dei contributi", "anchor": "art_228", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">I contributi sono spesi in conformità dell’articolo 222.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Qualsiasi parte del contributo non utilizzata entro l’esercizio cui si riferisce tale contributo (anno n) è utilizzata per le spese rimborsabili sostenute entro il 31 dicembre dell’anno n+1. La parte rimanente del contributo non spesa entro tale data è recuperata conformemente al titolo IV, capo 6.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">I partiti politici europei rispettano il tasso massimo di cofinanziamento stabilito all’articolo 17, paragrafo 4, del regolamento (UE, Euratom) n. 1141/2014. Gli importi che residuano dai contributi del precedente esercizio non sono utilizzati per finanziare la parte delle spese a cui i partiti politici europei devono provvedere tramite risorse proprie. I contributi di terzi a eventi congiunti non sono considerati parte delle risorse proprie di un partito politico europeo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">I partiti politici europei utilizzano la parte del contributo che non è stata usata entro l’esercizio cui si riferisce tale contributo prima di utilizzare i contributi concessi dopo tale esercizio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">L’interesse maturato sui pagamenti di prefinanziamento è considerato parte del contributo.</div>\n</div>"]]}, "229": {"label": "Articolo 229", "heading": "Relazione sull’uso dei contributi", "anchor": "art_229", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">A norma dell’articolo 23 del regolamento (UE, Euratom) n. 1141/2014, un partito politico europeo presenta all’ordinatore responsabile, per approvazione, la relazione annuale sull’utilizzo del contributo e il bilancio annuale.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L’ordinatore responsabile redige la relazione annuale di attività di cui all’articolo 74, paragrafo 9, sulla base della relazione annuale e del bilancio annuale di cui al paragrafo 1 del presente articolo. Per redigere la relazione possono essere utilizzati altri documenti giustificativi.</div>\n</div>"]]}, "230": {"label": "Articolo 230", "heading": "Importo del contributo", "anchor": "art_230", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L’importo del contributo diventa definitivo soltanto dopo l’approvazione della relazione annuale e del bilancio annuale di cui all’articolo 229, paragrafo 1, da parte dell’ordinatore responsabile. L’approvazione della relazione annuale e del bilancio annuale non pregiudica verifiche successive da parte dell’Autorità.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L’importo non speso del prefinanziamento diventa definitivo soltanto dopo che è stato utilizzato dal partito politico europeo per pagare spese rimborsabili che soddisfano i criteri definiti nel bando per la presentazione di domande di contributi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Quando il partito politico europeo non si conforma agli obblighi che gli incombono in relazione all’uso dei contributi, questi sono sospesi, ridotti o revocati dopo aver dato al partito politico europeo la possibilità di presentare osservazioni.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Prima di effettuare un pagamento l’ordinatore responsabile verifica che il partito politico europeo continui a essere iscritto nel registro di cui all’articolo 7 del regolamento (UE, Euratom) n. 1141/2014 e non sia stato oggetto di una delle sanzioni previste all’articolo 27 di tale regolamento tra la data della domanda e la fine dell’esercizio cui si riferisce il contributo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Quando il partito politico europeo non è più iscritto nel registro di cui all’articolo 7 del regolamento (UE, Euratom) n. 1141/2014 o è stato oggetto di una delle sanzioni previste all’articolo 27 di tale regolamento, l’ordinatore responsabile può sospendere, ridurre o revocare il contributo e recuperare gli importi indebitamente versati conformemente all’accordo di cui all’articolo 225, paragrafo 8, del presente regolamento, in proporzione alla gravità degli errori, delle irregolarità, delle frodi o di altra violazione degli obblighi relativi all’uso del contributo, dopo aver dato al partito politico europeo la possibilità di presentare osservazioni.</div>\n</div>"]]}, "231": {"label": "Articolo 231", "heading": "Controlli e sanzioni", "anchor": "art_231", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L’accordo di cui all’articolo 225, paragrafo 8, prevede espressamente che il Parlamento europeo eserciti i suoi poteri di controllo dei documenti e dei locali e che l’OLAF e la Corte dei conti esercitino i rispettivi poteri e competenze, di cui all’articolo 129, su tutti i partiti politici europei che hanno ricevuto fondi dell’Unione, nonché sui loro contraenti e subappaltatori.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">L’ordinatore responsabile può irrogare sanzioni amministrative e finanziarie effettive, proporzionate e dissuasive in conformità degli articoli 136 e 137 del presente regolamento e dell’articolo 27 del regolamento (UE, Euratom) n. 1141/2014.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Le sanzioni di cui al paragrafo 2 possono altresì essere irrogate ai partiti politici europei che, al momento della presentazione della domanda di contributo o dopo aver ricevuto il contributo, abbiano reso false dichiarazioni fornendo le informazioni richieste dall’ordinatore responsabile oppure non abbiano fornito tali informazioni.</div>\n</div>"]]}, "232": {"label": "Articolo 232", "heading": "Tenuta dei registri", "anchor": "art_232", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">I partiti politici europei tengono tutti i registri e i documenti giustificativi relativi al contributo per cinque anni a decorrere dall’ultimo pagamento relativo al contributo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La documentazione inerente agli audit, ai ricorsi, ai contenziosi e alla definizione delle richieste derivanti dall’utilizzo del contributo o alle indagini dell’OLAF, se comunicata al destinatario, è conservata fintanto che tali audit, ricorsi, contenzioni, definizioni delle richieste o indagini siano stati conclusi.</div>\n</div>"]]}, "233": {"label": "Articolo 233", "heading": "Selezione degli organismi o degli esperti esterni di audit", "anchor": "art_233", "frags": [[null, "<p class=\"norm\">Gli organismi o gli esperti esterni indipendenti di audit di cui all’articolo 23 del regolamento (UE, Euratom) n. 1141/2014 sono selezionati mediante una procedura di appalto. La durata del contratto non può superare i cinque anni. Dopo due contratti consecutivi si ritiene che sussista un conflitto d’interessi che potrebbe influire negativamente sullo svolgimento dell’audit.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "234": {"label": "Articolo 234", "heading": "Fondi fiduciari dell’Unione per azioni esterne", "anchor": "art_234", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Per le azioni di emergenza e di post-emergenza necessarie per reagire a una crisi o per azioni tematiche, la Commissione può istituire fondi fiduciari dell’Unione per azioni esterne («fondi fiduciari dell’Unione») in base a un accordo concluso con altri donatori.</div>\n</div>"], [null, "<p class=\"norm\">I fondi fiduciari dell’Unione sono istituiti unicamente se gli accordi conclusi con altri donatori assicurano contributi da fonti diverse dal bilancio.</p>"], [null, "<p class=\"norm\">La Commissione consulta il Parlamento europeo e il Consiglio in merito alla sua intenzione di istituire un fondo fiduciario dell’Unione destinato ad azioni di emergenza e di post-emergenza.</p>"], [null, "<p class=\"norm\">L’istituzione di un fondo fiduciario dell’Unione destinato ad azioni tematiche è soggetto all’approvazione del Parlamento europeo e del Consiglio.</p>"], [null, "<p class=\"norm\">Ai fini del terzo e quarto comma del presente paragrafo, la Commissione mette a disposizione del Parlamento europeo e del Consiglio i progetti di decisione relativi all’istituzione di un fondo fiduciario dell’Unione. Tali progetti di decisione comprendono la descrizione degli obiettivi del fondo fiduciario dell’Unione, la giustificazione della sua istituzione conformemente al paragrafo 3, l’indicazione della durata e gli accordi preliminari con gli altri donatori. I progetti di decisione contengono altresì un progetto di accordo costitutivo da concludere con gli altri donatori.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La Commissione presenta i progetti di decisione relativi al finanziamento di un fondo fiduciario dell’Unione al comitato competente ove previsto nell’atto di base a norma del quale è erogato il contributo dell’Unione al fondo fiduciario dell’Unione. Il comitato competente non è invitato a pronunciarsi sugli aspetti che sono già stati presentati al Parlamento europeo e al Consiglio per consultazione o approvazione a norma del paragrafo 1, terzo, quarto e quinto comma, rispettivamente.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">I fondi fiduciari dell’Unione sono istituiti e eseguiti soltanto alle condizioni seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">esiste un valore aggiunto dell’intervento dell’Unione: gli obiettivi dei fondi fiduciari dell’Unione, in particolare a motivo della loro portata o dei loro effetti potenziali, possono essere conseguiti meglio a livello di Unione che non a livello nazionale e l’uso degli strumenti di finanziamento esistenti non sarebbe sufficiente a conseguire gli obiettivi strategici dell’Unione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i fondi fiduciari dell’Unione determinano visibilità politica per l’Unione e vantaggi gestionali evidenti, nonché un migliore controllo da parte dell’Unione dei rischi e dei pagamenti dei contributi dell’Unione e degli altri donatori;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i fondi fiduciari dell’Unione non duplicano altri canali esistenti di finanziamento o altri strumenti simili senza fornire alcuna addizionalità;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli obiettivi dei fondi fiduciari dell’Unione sono allineati agli obiettivi dello strumento o della voce di bilancio dell’Unione da cui sono finanziati.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Per ciascun fondo fiduciario dell’Unione è istituito un comitato, presieduto dalla Commissione, che garantisce un’equa rappresentanza dei donatori e decide in merito all’impiego dei fondi. Il comitato comprende un rappresentante di ciascuno Stato membro non contribuente, in qualità di osservatore. Le norme per la composizione del comitato e il suo regolamento interno sono fissati nell’accordo costitutivo del fondo fiduciario dell’Unione. Tali norme comprendono la previsione della necessità di un voto favorevole da parte della Commissione per l’adozione finale della decisione sull’utilizzo dei fondi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">I fondi fiduciari dell’Unione sono istituiti per una durata limitata stabilita dall’accordo costituivo. Tale durata può essere prorogata con decisione della Commissione soggetta alla procedura di cui al paragrafo 1 su richiesta del comitato del fondo fiduciario dell’Unione interessato e previa presentazione da parte della Commissione di una relazione che giustifichi la proroga e confermi, in particolare, il rispetto delle condizioni di cui al paragrafo 3.</div>\n</div>"], [null, "<p class=\"norm\">Il Parlamento europeo e/o il Consiglio possono chiedere alla Commissione, laddove opportuno, di interrompere gli stanziamenti per un fondo fiduciario dell’Unione o di rivedere l’accordo costitutivo al fine di liquidare il fondo medesimo, in particolare sulla base delle informazioni presentate nel documento di lavoro di cui all’articolo 41, paragrafo 6. In tal caso, gli eventuali fondi rimanenti sono restituiti proporzionalmente al bilancio a titolo di entrate generali, nonché agli Stati membri contribuenti e agli altri donatori.</p>"]]}, "235": {"label": "Articolo 235", "heading": "Esecuzione dei fondi fiduciari dell’Unione per azioni esterne", "anchor": "art_235", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">I fondi fiduciari dell’Unione sono eseguiti in conformità dei principi di sana gestione finanziaria, trasparenza, proporzionalità, non discriminazione e parità di trattamento, nonché conformemente agli obiettivi specifici definiti in ciascun accordo costitutivo e nel pieno rispetto dei diritti di verifica e controllo del contributo dell’Unione spettanti al Parlamento europeo e al Consiglio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le azioni finanziate dai fondi fiduciari dell’Unione possono essere attuate direttamente dalla Commissione a norma dell’articolo 62, paragrafo 1, primo comma, lettera a), e indirettamente con le entità che eseguono i fondi dell’Unione a norma dell’articolo 62, paragrafo 1, primo comma, lettera c), punti i), ii), iii), v) e vi).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">I fondi sono impegnati ed erogati dagli agenti finanziari della Commissione ai sensi del titolo IV, capo 4. Il contabile della Commissione funge da contabile dei fondi fiduciari dell’Unione. Egli è incaricato di definire le procedure contabili e il piano contabile comuni a tutti i fondi fiduciari dell’Unione. Il revisore interno della Commissione, l’OLAF e la Corte dei conti esercitano nei confronti dei fondi fiduciari dell’Unione le stesse competenze attribuite loro nei confronti di altre azioni svolte dalla Commissione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">I contributi dell’Unione e degli altri donatori non sono integrati nel bilancio, bensì versati in un apposito conto bancario. Il contabile procede all’apertura e alla chiusura dell’apposito conto bancario del fondo fiduciario dell’Unione. Tutte le operazioni effettuate nel corso dell’anno sull’apposito conto bancario sono debitamente registrate nei conti relativi al fondo fiduciario dell’Unione.</div>\n</div>"], [null, "<p class=\"norm\">I contributi dell’Unione sono trasferiti sull’apposito conto bancario sulla base delle richieste di pagamento debitamente giustificate da previsioni di esborso, tenendo conto del saldo disponibile sul conto e della conseguente necessità di pagamenti aggiuntivi. Le previsioni di esborso sono fornite su base annuale o, se del caso, semestrale.</p>"], [null, "<p class=\"norm\">I contributi versati da altri donatori sono presi in considerazione quando sono incassati sull’apposito conto bancario del fondo fiduciario dell’Unione e per l’importo in euro risultante dalla conversione all’atto dell’accredito sull’apposito conto bancario. Gli interessi maturati sull’apposito conto bancario del fondo fiduciario dell’Unione sono investiti nel fondo stesso, salvo se altrimenti disposto nell’accordo costitutivo di quest’ultimo.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">La Commissione è autorizzata a utilizzare al massimo il 5 % degli importi raccolti nel fondo fiduciario dell’Unione per coprire i propri costi di gestione a decorrere dagli anni in cui i contributi di cui al paragrafo 4 hanno iniziato a essere utilizzati. Fermo quanto disposto dal primo periodo, per evitare la doppia imputazione dei costi, i costi di gestione derivanti dal contributo dell’Unione al fondo fiduciario dell’Unione sono coperti da tale contributo solo nella misura in cui non siano già stati coperti da altre linee di bilancio. Per la durata del fondo fiduciario dell’Unione tali costi di gestione sono assimilati a entrate con destinazione specifica ai sensi dell’articolo 21, paragrafo 2, lettera a), punto ii).</div>\n</div>"], [null, "<p class=\"norm\">Oltre alla redazione della relazione annuale di cui all’articolo 252, due volte l’anno l’ordinatore provvede alla rendicontazione finanziaria delle operazioni effettuate da ogni fondo fiduciario dell’Unione.</p>"], [null, "<p class=\"norm\">La Commissione riferisce inoltre mensilmente sullo stato di esecuzione di ogni fondo fiduciario dell’Unione.</p>"], [null, "<p class=\"norm\">I fondi fiduciari dell’Unione sono sottoposti annualmente a un audit esterno indipendente.</p>"]]}, "236": {"label": "Articolo 236", "heading": "Ricorso al sostegno di bilancio", "anchor": "art_236", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Qualora previsto dai pertinenti atti di base, la Commissione può fornire sostegno di bilancio a un paese terzo se sono soddisfatte le condizioni seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la gestione delle finanze pubbliche del paese terzo risulta sufficientemente trasparente, affidabile ed efficace;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il paese terzo ha posto in essere politiche settoriali o nazionali sufficientemente credibili e pertinenti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il paese terzo ha posto in essere politiche macroeconomiche orientate alla stabilità;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il paese terzo ha previsto un accesso sufficiente e tempestivo a informazioni di bilancio complete e solide.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il pagamento del contributo dell’Unione si basa sul rispetto delle condizioni di cui al paragrafo 1, compreso il miglioramento della gestione delle finanze pubbliche. Inoltre, alcuni pagamenti possono essere altresì subordinati al raggiungimento, misurato da indicatori di performance obiettivi, di target intermedi che esprimono i risultati e i progressi in materia di riforme realizzati nel corso del tempo nei rispettivi settori.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Nei paesi terzi la Commissione sostiene il rispetto dello stato di diritto, lo sviluppo delle capacità di controllo parlamentare, di audit e di lotta alla corruzione, come anche il rafforzamento della trasparenza e dell’accesso del pubblico alle informazioni.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Le corrispondenti convenzioni di finanziamento concluse con il paese terzo prevedono:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’obbligo per il paese terzo di trasmettere alla Commissione informazioni affidabili e tempestive che le consentano di valutare il rispetto delle condizioni di cui al paragrafo 2;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il diritto della Commissione di sospendere la convenzione di finanziamento se il paese terzo viola un obbligo relativo al rispetto dei diritti umani, dei principi democratici e dello stato di diritto e nei casi gravi di corruzione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">opportune disposizioni a norma delle quali il paese terzo deve impegnarsi a rimborsare immediatamente, in tutto o in parte, i finanziamenti erogati per la relativa operazione, qualora sia accertato che il pagamento dei fondi pertinenti dell’Unione è viziato da gravi irregolarità imputabili al paese terzo.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Per procedere al rimborso di cui al primo comma, lettera c), del presente paragrafo può essere applicato l’articolo 101, paragrafo 1, secondo comma.</p>"]]}, "237": {"label": "Articolo 237", "heading": "Esperti esterni retribuiti", "anchor": "art_237", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Per valori inferiori alle soglie di cui all’articolo 175, paragrafo 1, e secondo la procedura di cui al paragrafo 3 del presente articolo, le istituzioni dell’Unione possono selezionare esperti esterni retribuiti, incaricati di assisterle nella valutazione delle domande di sovvenzione, dei progetti e delle offerte, nonché di fornire pareri e consulenza in casi specifici.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Gli esperti esterni retribuiti sono remunerati sulla base di un importo fisso preventivamente comunicato e sono scelti in funzione della loro capacità professionale. La selezione avviene in base a criteri selettivi che rispettano i principi di non discriminazione, parità di trattamento e assenza di conflitto d’interessi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Un invito a manifestare interesse è pubblicato sul sito web dell’istituzione dell’Unione interessata.</div>\n</div>"], [null, "<p class=\"norm\">L’invito a manifestare interesse comprende una descrizione dei compiti, la loro durata e le condizioni di retribuzione fissate.</p>"], [null, "<p class=\"norm\">In esito all’invito a manifestare interesse è redatto un elenco di esperti. Tale elenco rimane valido per un periodo non superiore a cinque anni dalla pubblicazione o per la durata del programma pluriennale attinente ai compiti.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Ogni persona fisica interessata può presentare la sua candidatura in qualsiasi momento nel corso del periodo di validità dell’invito a manifestare interesse, a eccezione degli ultimi tre mesi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Gli esperti retribuiti con gli stanziamenti per la ricerca e lo sviluppo tecnologico sono assunti in conformità delle procedure definite dal Parlamento europeo e dal Consiglio nel momento in cui adottano ciascun programma quadro di ricerca o conformemente alle corrispondenti regole di partecipazione. Ai fini del titolo V, capo 2, sezione 2, tali esperti sono considerati destinatari.</div>\n</div>"]]}, "238": {"label": "Articolo 238", "heading": "Esperti non retribuiti", "anchor": "art_238", "frags": [[null, "<p class=\"norm\">Le istituzioni dell’Unione possono rimborsare le spese di viaggio e di soggiorno sostenute dalle persone da esse invitate o munite di mandato delle istituzioni medesime o, se del caso, versare loro qualsiasi altra indennità.</p>"]]}, "239": {"label": "Articolo 239", "heading": "Quote di adesione e altre sottoscrizioni", "anchor": "art_239", "frags": [[null, "<p class=\"norm\">L’Unione può versare quote a titolo di sottoscrizioni presso gli organismi dei quali è membro od osservatore.</p>"]]}, "240": {"label": "Articolo 240", "heading": "Spese per i membri e il personale delle istituzioni dell’Unione", "anchor": "art_240", "frags": [[null, "<p class=\"norm\">Le istituzioni dell’Unione possono pagare le spese per i membri e il personale delle istituzioni dell’Unione, compresi i contributi alle associazioni dei deputati ed ex deputati del Parlamento europeo, e i contributi alle scuole europee.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "241": {"label": "Articolo 241", "heading": "Struttura contabile", "anchor": "art_241", "frags": [[null, "<p class=\"norm\">I conti annuali dell’Unione sono preparati per ciascun esercizio, che inizia il 1<span class=\"superscript\">o</span> gennaio e termina il 31 dicembre. Tali conti comprendono quanto segue:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli stati finanziari consolidati, che presentano, in conformità delle norme contabili di cui all’articolo 80, il consolidamento delle informazioni finanziarie contenute negli stati finanziari delle istituzioni dell’Unione, degli organismi dell’Unione di cui all’articolo 70 e degli altri organismi che soddisfano i criteri di consolidamento contabile;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le relazioni aggregate sull’esecuzione del bilancio, che presentano le informazioni contenute nelle relazioni sull’esecuzione del bilancio delle istituzioni dell’Unione.</p>\n</div>\n</div>"]]}, "242": {"label": "Articolo 242", "heading": "Documenti giustificativi", "anchor": "art_242", "frags": [[null, "<p class=\"norm\">Ogni scrittura nei conti si basa su adeguati documenti giustificativi in conformità dell’articolo 75.</p>"]]}, "243": {"label": "Articolo 243", "heading": "Stati finanziari", "anchor": "art_243", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Gli stati finanziari sono presentati in milioni di EUR e, in conformità delle norme contabili di cui all’articolo 80, comprendono:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">lo stato patrimoniale, che presenta l’intera situazione patrimoniale e finanziaria al 31 dicembre dell’esercizio precedente;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il conto economico, che presenta il risultato economico dell’esercizio precedente;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la situazione dei flussi di cassa, che mostra gli incassi e gli esborsi dell’esercizio e la situazione finale di tesoreria;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la situazione di variazione dell’attivo netto, che presenta una sintesi dei movimenti che durante l’esercizio hanno interessato le riserve e gli utili accantonati.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Le note degli stati finanziari completano e commentano le informazioni fornite negli stati di cui al paragrafo 1, fornendo le informazioni supplementari prescritte dalle norme contabili di cui all’articolo 80 e dalla prassi contabile riconosciuta a livello internazionale, allorché tali informazioni siano pertinenti per le attività dell’Unione. Le note contengono almeno le seguenti informazioni:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i principi, le norme e i metodi contabili;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le note esplicative, che forniscono informazioni supplementari non contenute nel corpo degli stati finanziari, ma necessarie per una rappresentazione fedele dei conti.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Dopo la chiusura dell’esercizio e fino alla data di trasmissione della contabilità generale, il contabile procede alle correzioni che, senza comportare esborsi o incassi a carico dell’esercizio, sono necessarie per un quadro veritiero e corretto dei conti.</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "244": {"label": "Articolo 244", "heading": "Relazioni sull’esecuzione del bilancio", "anchor": "art_244", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Le relazioni sull’esecuzione del bilancio sono presentate in milioni di EUR e sono raffrontabili anno per anno. Esse comprendono:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le relazioni che presentano in forma aggregata la totalità delle operazioni di bilancio dell’esercizio in entrate e in spese;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il risultato di bilancio, calcolato sulla base dell’equilibrio di bilancio annuale di cui alla decisione 2014/335/UE, Euratom;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le note esplicative, che completano e commentano le informazioni fornite nelle relazioni.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La struttura delle relazioni sull’esecuzione del bilancio è la stessa del bilancio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Le relazioni sull’esecuzione del bilancio contengono:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">informazioni sulle entrate, in particolare le evoluzioni concernenti le previsioni del bilancio in entrate, l’esecuzione del bilancio in entrate e i diritti accertati;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">informazioni che illustrano l’evoluzione della totalità degli stanziamenti di impegno e di pagamento disponibili;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">informazioni che illustrano l’impiego della totalità degli stanziamenti di impegno e di pagamento disponibili;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">informazioni che illustrano gli impegni ancora in essere, riportati dall’esercizio precedente o assunti nel corso dell’esercizio.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Per quanto riguarda le informazioni sulle entrate, alla relazione sull’esecuzione del bilancio è accluso uno stato che illustra, per ciascuno Stato membro, la ripartizione degli importi ancora da recuperare alla fine dell’esercizio corrispondenti a risorse proprie coperte da un ordine di riscossione.</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "245": {"label": "Articolo 245", "heading": "Conti provvisori", "anchor": "art_245", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Entro il 1<span class=\"superscript\">o</span> marzo dell’esercizio successivo i contabili delle istituzioni dell’Unione diverse dalla Commissione e gli organismi di cui all’articolo 241 comunicano i loro conti provvisori al contabile della Commissione e alla Corte dei conti.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Entro il 1<span class=\"superscript\">o</span> marzo dell’esercizio successivo i contabili delle istituzioni dell’Unione diverse dalla Commissione e gli organismi di cui all’articolo 241 comunicano le informazioni contabili necessarie a fini di consolidamento al contabile della Commissione, secondo le modalità e il formato stabiliti da quest’ultimo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Entro il 31<span class=\"superscript\">o</span> marzo dell’esercizio successivo il contabile della Commissione consolida i conti provvisori di cui al paragrafo 2 con quelli della Commissione e trasmette i conti provvisori della Commissione e i conti provvisori consolidati dell’Unione alla Corte dei conti per via elettronica.</div>\n</div>"]]}, "246": {"label": "Articolo 246", "heading": "Approvazione dei conti consolidati definitivi", "anchor": "art_246", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Entro il 1<span class=\"superscript\">o</span> giugno la Corte dei conti formula le sue osservazioni sui conti provvisori delle istituzioni dell’Unione diverse dalla Commissione e di ciascuno degli organismi di cui all’articolo 241 e, entro il 15 giugno, le sue osservazioni sui conti provvisori della Commissione e sui conti provvisori consolidati dell’Unione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Entro il 15 giugno i contabili delle istituzioni dell’Unione diverse dalla Commissione e dagli organismi di cui all’articolo 241 comunicano le informazioni contabili richieste al contabile della Commissione, secondo le modalità e il formato stabiliti da quest’ultimo, al fine di redigere i conti consolidati definitivi.</div>\n</div>"], [null, "<p class=\"norm\">Entro il 1<span class=\"superscript\">o</span> luglio le istituzioni dell’Unione diverse dalla Commissione e ciascuno degli organismi di cui all’articolo 241 comunicano i rispettivi conti definitivi al Parlamento europeo, al Consiglio, alla Corte dei conti e al contabile della Commissione.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">I contabili di ogni istituzione dell’Unione e di ciascuno degli organismi di cui all’articolo 241 trasmettono alla Corte dei conti e in copia al contabile della Commissione, contemporaneamente ai rispettivi conti definitivi, una dichiarazione a essi relativa.</div>\n</div>"], [null, "<p class=\"norm\">I conti definitivi sono corredati di una nota redatta dal contabile, nella quale questi dichiara che essi sono stati elaborati in conformità del presente titolo e dei principi, delle norme e dei metodi contabili applicabili descritti nelle note agli stati finanziari.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Il contabile della Commissione redige i conti consolidati definitivi in base alle informazioni presentategli a norma del paragrafo 2 del presente articolo dalle istituzioni dell’Unione diverse dalla Commissione e dagli organismi di cui all’articolo 241.</div>\n</div>"], [null, "<p class=\"norm\">I conti consolidati definitivi sono corredati di una nota redatta dal contabile della Commissione, nella quale questi dichiara che essi sono stati elaborati in conformità del presente titolo e dei principi, delle norme e dei metodi contabili applicabili descritti nelle note agli stati finanziari.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Entro il 31 luglio, la Commissione trasmette per via elettronica, dopo averli approvati, i conti consolidati definitivi e i propri conti definitivi al Parlamento europeo, al Consiglio e alla Corte dei conti.</div>\n</div>"], [null, "<p class=\"norm\">Entro la stessa data il contabile della Commissione trasmette alla Corte dei conti una dichiarazione relativa ai conti consolidati definitivi.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Entro il 15 novembre i conti consolidati definitivi sono pubblicati nella <span class=\"italics\">Gazzetta ufficiale dell’Unione europea</span>, corredati della dichiarazione d’affidabilità fornita dalla Corte dei conti a norma dell’articolo 287 TFUE e dell’articolo 106 <span class=\"italics\">bis</span> del trattato Euratom.</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "247": {"label": "Articolo 247", "heading": "Relazioni integrate in materia finanziaria e di responsabilità", "anchor": "art_247", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Entro il 31 luglio dell’esercizio successivo la Commissione trasmette al Parlamento europeo e al Consiglio un insieme integrato di relazioni in materia finanziaria e di responsabilità, che comprende:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i conti consolidati definitivi di cui all’articolo 246;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la relazione annuale sulla gestione e il rendimento, che prevede una sintesi chiara e concisa delle realizzazioni in termini di controllo interno e gestione finanziaria di cui alle relazioni annuali di attività di ciascun ordinatore delegato e che comprende informazioni sulle disposizioni essenziali in materia di governance in seno alla Commissione, nonché:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una stima del livello di errore nelle spese dell’Unione sulla base di una metodologia coerente e una stima delle rettifiche future;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">informazioni sulle azioni preventive e correttive concernenti il bilancio, che presentano l’incidenza finanziaria delle misure adottate per tutelare il bilancio dalle spese che violano il diritto applicabile;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">informazioni sull’attuazione della strategia antifrode della Commissione;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una previsione a lungo termine dei futuri flussi in entrata e in uscita nei successivi cinque anni, basata sui quadri finanziari pluriennali applicabili e sulla decisione 2014/335/UE, Euratom;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la relazione annuale sugli audit interni di cui all’articolo 118, paragrafo 4;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la valutazione delle finanze dell’Unione basata sui risultati conseguiti di cui all’articolo 318 TFUE, in cui sono valutati, in particolare, i progressi compiuti verso il conseguimento degli obiettivi strategici in considerazione degli indicatori di performance di cui all’articolo 33 del presente regolamento;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la relazione sul seguito dato al discarico di cui all’articolo 261, paragrafo 3.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La relazione integrata in materia finanziaria e di responsabilità di cui al paragrafo 1 presenta ciascuna relazione separatamente e in maniera chiaramente identificabile. Le singole relazioni sono messe a disposizione del Parlamento europeo, del Consiglio e della Corte dei conti entro il 30 giugno, a esclusione dei conti consolidati definitivi.</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "248": {"label": "Articolo 248", "heading": "Relazione mensile sull’esecuzione del bilancio", "anchor": "art_248", "frags": [[null, "<p class=\"norm\">Il contabile della Commissione, oltre agli stati e alle relazioni annuali di cui agli articoli 243 e 244, trasmette una volta al mese al Parlamento europeo e al Consiglio dati, aggregati almeno a livello di capitolo, e separatamente ripartiti per capitolo, articolo e voce, sull’esecuzione del bilancio, per quanto concerne sia le entrate che le spese relative all’insieme degli stanziamenti disponibili. Tali dati forniscono anche informazioni sull’impiego degli stanziamenti riportati.</p>"], [null, "<p class=\"norm\">I dati sono messi a disposizione entro dieci giorni lavorativi a decorrere dalla fine di ogni mese tramite il sito web della Commissione.</p>"]]}, "249": {"label": "Articolo 249", "heading": "Relazione annuale sulla gestione di bilancio e finanziaria", "anchor": "art_249", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Ogni istituzione dell’Unione e ogni organismo di cui all’articolo 241 prepara una relazione sulla gestione di bilancio e finanziaria dell’esercizio.</div>\n</div>"], [null, "<p class=\"norm\">Essi mettono la relazione a disposizione del Parlamento europeo, del Consiglio e della Corte dei conti entro il 31 marzo dell’esercizio successivo.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La relazione di cui al paragrafo 1 fornisce una sintesi degli storni di stanziamenti fra le varie voci del bilancio.</div>\n</div>"]]}, "250": {"label": "Articolo 250", "heading": "Relazione annuale sugli strumenti finanziari, le garanzie di bilancio e l’assistenza finanziaria", "anchor": "art_250", "frags": [[null, "<p class=\"norm\">La Commissione riferisce ogni anno al Parlamento europeo e al Consiglio in merito agli strumenti finanziari, alle garanzie di bilancio, all’assistenza finanziaria e alle passività potenziali in conformità dell’articolo 41, paragrafi 4 e 5, e dell’articolo 52, paragrafo 1, lettere d) ed e). Tali informazioni sono contemporaneamente messe a disposizione della Corte dei conti.</p>"]]}, "251": {"label": "Articolo 251", "heading": "Relazione sulle questioni contabili", "anchor": "art_251", "frags": [[null, "<p class=\"norm\">Entro il 15 settembre di ogni esercizio il contabile della Commissione trasmette al Parlamento europeo e al Consiglio una relazione contenente informazioni concernenti gli attuali rischi osservati, le tendenze generali constatate, i nuovi problemi contabili incontrati e i progressi compiuti su aspetti contabili, compresi quelli individuati dalla Corte dei conti, nonché le informazioni relative ai recuperi.</p>"]]}, "252": {"label": "Articolo 252", "heading": "Relazione sui fondi fiduciari dell’Unione per azioni esterne", "anchor": "art_252", "frags": [[null, "<p class=\"norm\">Conformemente all’articolo 41, paragrafo 6, la Commissione riferisce ogni anno al Parlamento europeo e al Consiglio sulle attività sostenute dai fondi fiduciari dell’Unione di cui all’articolo 234, sulla loro attuazione e sulla loro performance, nonché sui relativi conti.</p>"], [null, "<p class=\"norm\">Il comitato del fondo fiduciario dell’Unione interessato approva la relazione annuale del fondo fiduciario dell’Unione redatta dall’ordinatore. Approva altresì i conti definitivi preparati dal contabile. Il comitato presenta i conti definitivi al Parlamento europeo e al Consiglio nell’ambito della procedura di discarico per la Commissione.</p>"]]}, "253": {"label": "Articolo 253", "heading": "Pubblicazione di informazioni sui destinatari", "anchor": "art_253", "frags": [[null, "<p class=\"norm\">La Commissione pubblica le informazioni sui destinatari in conformità dell’articolo 38.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "254": {"label": "Articolo 254", "heading": "Audit esterno della Corte dei conti", "anchor": "art_254", "frags": [[null, "<p class=\"norm\">Il Parlamento europeo, il Consiglio e la Commissione informano la Corte dei conti, con la massima tempestività, di tutte le decisioni e di tutte le norme da essi adottate a norma degli articoli 12, 16, 21, 29, 30, 32 e 43.</p>"]]}, "255": {"label": "Articolo 255", "heading": "Norme e procedure di audit", "anchor": "art_255", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">L’esame da parte della Corte dei conti della legittimità e della regolarità di tutte le entrate e spese è effettuato tenendo in considerazione i trattati, il bilancio, il presente regolamento, gli atti delegati adottati a norma del presente regolamento e tutti gli altri atti adottati in esecuzione dei trattati. Tale esame può tenere conto del carattere pluriennale dei programmi e dei relativi sistemi di vigilanza e controllo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Nell’assolvimento delle proprie attribuzioni la Corte dei conti ha facoltà di prendere conoscenza, secondo il disposto dell’articolo 257, di tutti i documenti e di tutte le informazioni concernenti la gestione finanziaria da parte dei servizi o degli organismi per quanto riguarda le operazioni finanziate o cofinanziate dall’Unione. Essa ha il potere di sentire qualsiasi funzionario responsabile di un’operazione di entrata o di spesa e di avvalersi di tutte le procedure di audit adeguate a detti servizi o organismi. L’audit negli Stati membri è effettuato di concerto con le istituzioni nazionali di audit o, se queste non dispongono delle necessarie competenze, con i servizi nazionali competenti. La Corte dei conti e le istituzioni nazionali di audit degli Stati membri cooperano in uno spirito di reciproca fiducia, pur mantenendo la loro indipendenza.</div>\n</div>"], [null, "<p class=\"norm\">Per raccogliere tutte le informazioni necessarie all’assolvimento dei compiti a essa affidati dai trattati o dagli atti adottati in esecuzione dei medesimi, la Corte dei conti, qualora lo richieda, può essere presente alle operazioni di audit effettuate nell’ambito dell’esecuzione del bilancio da parte o per conto di un’istituzione dell’Unione.</p>"], [null, "<p class=\"norm\">Su richiesta della Corte dei conti ogni istituzione dell’Unione autorizza le istituzioni finanziarie che detengono averi dell’Unione a far sì che la Corte stessa possa accertarsi della corrispondenza dei dati esterni con la situazione contabile.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Per l’assolvimento del suo compito, la Corte dei conti notifica alle istituzioni dell’Unione e alle autorità alle quali si applica il presente regolamento i nominativi dei membri del suo personale autorizzati a effettuare audit presso di esse.</div>\n</div>"]]}, "256": {"label": "Articolo 256", "heading": "Verifiche relative a titoli e fondi", "anchor": "art_256", "frags": [[null, "<p class=\"norm\">La Corte dei conti provvede a che tutti i titoli e i fondi depositati o in cassa siano verificati mediante attestazioni sottoscritte dai depositari o mediante verbali di situazioni di cassa e di portafoglio. Essa può procedere a tali verifiche direttamente.</p>"]]}, "257": {"label": "Articolo 257", "heading": "Diritto di accesso della Corte dei conti", "anchor": "art_257", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Le istituzioni dell’Unione, gli organismi che gestiscono entrate o spese a nome dell’Unione, nonché i destinatari, accordano alla Corte dei conti ogni agevolazione e le forniscono tutte le informazioni di cui essa ritenga di aver bisogno per l’assolvimento dei suoi compiti. Su richiesta della Corte dei conti, mettono a sua disposizione tutti i documenti relativi all’aggiudicazione e all’esecuzione degli appalti finanziati dal bilancio e ogni conto relativo a movimenti di denaro o di materiali, ogni documento contabile o giustificativo e i relativi documenti amministrativi, ogni documentazione relativa alle entrate e alle spese, ogni inventario, ogni organigramma che la Corte dei conti ritenga necessario per la revisione, in base a documenti o ad audit sul posto, dei conti annuali e delle relazioni sull’esecuzione del bilancio e, per lo stesso scopo, ogni documento e tutti i dati creati o conservati elettronicamente. Il diritto di accesso della Corte dei conti include l’accesso al sistema informatico utilizzato per la gestione delle entrate o delle spese oggetto del suo audit, se tale accesso è pertinente per quest’ultimo.</div>\n</div>"], [null, "<p class=\"norm\">Gli organismi di audit interni e gli altri servizi delle amministrazioni nazionali interessate accordano alla Corte dei conti ogni agevolazione di cui essa ritenga di aver bisogno per l’assolvimento dei suoi compiti.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">I funzionari le cui operazioni sono soggette alle verifiche della Corte dei conti sono tenuti ad:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">aprire le loro casse, esibire fondi, titoli e materiali di qualsiasi natura, i documenti giustificativi della loro gestione dei fondi di cui sono depositari, nonché libri e registri e qualsiasi altro documento attinente;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">esibire la corrispondenza e qualunque altro documento necessario alla completa esecuzione dell’audit di cui all’articolo 255.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">La comunicazione delle informazioni di cui al primo comma, lettera b), può essere chiesta solo dalla Corte dei conti.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La Corte dei conti è abilitata a sottoporre ad audit i documenti relativi alle entrate e alle spese dell’Unione detenuti dai servizi delle istituzioni dell’Unione e, in particolare, dai servizi responsabili delle decisioni su tali entrate e spese, dagli organismi che gestiscono entrate o spese in nome dell’Unione e dalle persone fisiche o giuridiche beneficiarie di pagamenti provenienti dal bilancio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La verifica della legittimità e regolarità delle entrate e delle spese e il controllo della sana gestione finanziaria si estendono all’impiego, da parte degli organismi esterni alle istituzioni dell’Unione, dei fondi dell’Unione ricevuti a titolo di contributi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">I finanziamenti dell’Unione versati a destinatari esterni alle istituzioni dell’Unione sono subordinati all’accettazione scritta, da parte di tali destinatari o, in mancanza di questa, da parte dei contraenti o dei subappaltatori, di un audit eseguito dalla Corte dei conti sull’uso dei finanziamenti accordati.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">La Commissione, su richiesta della Corte dei conti, fornisce tutte le informazioni sull’assunzione e sull’erogazione di prestiti.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">L’uso di sistemi informatici integrati non ha l’effetto di limitare l’accesso da parte della Corte dei conti a documenti giustificativi. Ogniqualvolta tecnicamente possibile, è accordato alla Corte dei conti l’accesso elettronico dai propri locali ai dati e ai documenti necessari per l’audit, in conformità delle pertinenti norme di sicurezza.</div>\n</div>"]]}, "258": {"label": "Articolo 258", "heading": "Relazione annuale della Corte dei conti", "anchor": "art_258", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Entro il 30 giugno la Corte dei conti trasmette alla Commissione e alle altre istituzioni dell’Unione interessate le osservazioni che ritiene di natura tale da dover figurare nella sua relazione annuale. Tali osservazioni rimangono riservate e sono oggetto di una procedura in contraddittorio. Tutte le istituzioni dell’Unione inviano le proprie risposte alla Corte dei conti entro il 15 ottobre. Le istituzioni dell’Unione diverse dalla Commissione inviano contemporaneamente le proprie risposte alla Commissione.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Nella relazione annuale della Corte dei conti figura una valutazione della sana gestione finanziaria.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La relazione annuale della Corte dei conti contiene una sezione per ciascuna istituzione dell’Unione e per il fondo comune di copertura. La Corte dei conti può aggiungere le eventuali relazioni di sintesi od osservazioni di portata generale che ritiene adeguate.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Entro il 15 novembre, la Corte dei conti invia alle autorità preposte al discarico e alle altre istituzioni dell’Unione la propria relazione annuale corredata delle risposte delle istituzioni dell’Unione e ne cura la pubblicazione nella <span class=\"italics\">Gazzetta ufficiale dell’Unione europea</span>.</div>\n</div>"]]}, "259": {"label": "Articolo 259", "heading": "Relazioni speciali della Corte dei conti", "anchor": "art_259", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La Corte dei conti trasmette all’istituzione dell’Unione o all’organismo interessato le osservazioni che ritiene di natura tale da dover figurare in una relazione speciale. Tali osservazioni rimangono riservate e sono oggetto di una procedura in contraddittorio.</div>\n</div>"], [null, "<p class=\"norm\">In generale, entro sei settimane dalla trasmissione di dette osservazioni, l’istituzione dell’Unione o l’organismo interessato comunica alla Corte dei conti le proprie eventuali risposte a tali osservazioni. Tale termine è sospeso in casi debitamente giustificati, in particolare qualora, durante la procedura in contraddittorio, l’istituzione dell’Unione o l’organismo interessato necessiti di un riscontro da parte degli Stati membri per mettere a punto la sua risposta.</p>"], [null, "<p class=\"norm\">Le risposte dell’istituzione dell’Unione o dell’organismo interessato riguardano direttamente ed esclusivamente le osservazioni della Corte dei conti.</p>"], [null, "<p class=\"norm\">Su richiesta della Corte dei conti o dell’istituzione dell’Unione o dell’organismo interessato, le risposte possono essere esaminate dal Parlamento europeo e dal Consiglio dopo la pubblicazione della relazione.</p>"], [null, "<p class=\"norm\">La Corte dei conti provvede a che le relazioni speciali siano elaborate e adottate entro un congruo periodo di tempo che, in termini generali, non supera i 13 mesi.</p>"], [null, "<p class=\"norm\">Le relazioni speciali corredate delle risposte delle istituzioni dell’Unione o degli organismi interessati sono trasmesse senza indugio al Parlamento europeo e al Consiglio, ognuno dei quali decide, eventualmente d’intesa con la Commissione, quale seguito darvi.</p>"], [null, "<p class=\"norm\">La Corte dei conti adotta tutti i provvedimenti necessari affinché le risposte alle sue osservazioni da parte di ciascuna istituzione dell’Unione od organismo interessato, nonché il calendario per l’elaborazione della relazione speciale, siano pubblicati unitamente a quest’ultima.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">I pareri di cui all’articolo 287, paragrafo 4, secondo comma, TFUE che non riguardano proposte o progetti nell’ambito della procedura di consultazione legislativa possono essere pubblicati dalla Corte dei conti nella <span class=\"italics\">Gazzetta ufficiale dell’Unione europea</span>. La Corte dei conti decide in merito a tale pubblicazione dopo aver consultato l’istituzione dell’Unione che ha chiesto il parere o cui il parere si riferisce. I pareri pubblicati sono corredati di eventuali commenti delle istituzioni dell’Unione interessate.</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "260": {"label": "Articolo 260", "heading": "Calendario della procedura di discarico", "anchor": "art_260", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Entro il 15 maggio dell’anno n +2, il Parlamento europeo, su raccomandazione del Consiglio, che delibera a maggioranza qualificata, dà atto alla Commissione dell’esecuzione del bilancio dell’esercizio n.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Se il termine di cui al paragrafo 1 non può essere rispettato, il Parlamento europeo o il Consiglio informano la Commissione dei relativi motivi.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Qualora il Parlamento europeo rinvii la decisione di discarico, la Commissione si adopera per adottare al più presto misure che consentano e facilitino la rimozione degli ostacoli che si frappongono alla decisione.</div>\n</div>"]]}, "261": {"label": "Articolo 261", "heading": "Procedura di discarico", "anchor": "art_261", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La decisione di discarico riguarda i conti della totalità delle entrate e delle spese dell’Unione, nonché il relativo saldo, e l’attivo e il passivo dell’Unione descritti nel bilancio finanziario.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">In vista del discarico il Parlamento europeo esamina, successivamente al Consiglio, i conti, gli stati finanziari e la relazione di valutazione di cui all’articolo 318 TFUE. Esamina anche la relazione annuale della Corte dei conti, corredata delle risposte delle istituzioni dell’Unione sottoposte ad audit, nonché le sue relazioni speciali pertinenti riguardo all’esercizio interessato e la sua dichiarazione attestante l’affidabilità dei conti, nonché la legittimità e la regolarità delle relative operazioni.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La Commissione presenta al Parlamento europeo, su richiesta dello stesso, tutte le informazioni necessarie al corretto svolgimento della procedura di discarico per l’esercizio in causa, conformemente all’articolo 319 TFUE.</div>\n</div>"]]}, "262": {"label": "Articolo 262", "heading": "Misure di follow-up", "anchor": "art_262", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">In conformità dell’articolo 319 TFUE e dell’articolo 106 <span class=\"italics\">bis</span> del trattato Euratom, le istituzioni dell’Unione e gli organismi dell’Unione di cui agli articoli 70 e 71 del presente regolamento adottano ogni misura adeguata per dar seguito alle osservazioni che accompagnano la decisione di discarico del Parlamento europeo e ai commenti che accompagnano la raccomandazione di discarico adottata dal Consiglio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Su richiesta del Parlamento europeo o del Consiglio, le istituzioni dell’Unione e gli organismi dell’Unione di cui agli articoli 70 e 71 riferiscono in merito alle misure adottate a seguito di tali osservazioni e commenti, in particolare sulle istruzioni impartite ai servizi incaricati dell’esecuzione del bilancio. Gli Stati membri cooperano con la Commissione informandola delle misure da essi adottate per dare seguito alle osservazioni, affinché essa ne tenga conto nella sua relazione. Le relazioni delle istituzioni dell’Unione e degli organismi dell’Unione di cui agli articoli 70 e 71 sono trasmesse anche alla Corte dei conti.</div>\n</div>"]]}, "263": {"label": "Articolo 263", "heading": "Disposizioni specifiche riguardanti il SEAE", "anchor": "art_263", "frags": [[null, "<p class=\"norm\">Al SEAE si applicano le procedure di cui all’articolo 319 TFUE e agli articoli 260, 261 e 262 del presente regolamento. Il SEAE coopera pienamente con le istituzioni dell’Unione coinvolte nella procedura di discarico e fornisce, se del caso, ogni informazione supplementare necessaria, anche partecipando a riunioni degli organismi competenti.</p>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "264": {"label": "Articolo 264", "heading": "Disposizioni generali", "anchor": "art_264", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli stanziamenti amministrativi sono stanziamenti non dissociati.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il presente titolo si applica agli stanziamenti amministrativi di cui all’articolo 47, paragrafo 4, e a quelli delle istituzioni dell’Unione diverse dalla Commissione.</div>\n</div>"], [null, "<p class=\"norm\">Gli impegni di bilancio corrispondenti a stanziamenti amministrativi di natura comune a diversi titoli e gestiti complessivamente possono essere iscritti complessivamente nei conti di bilancio in base alla classificazione sommaria per natura di cui all’articolo 47, paragrafo 4.</p>"], [null, "<p class=\"norm\">Le spese corrispondenti sono iscritte nelle linee di bilancio di ciascun titolo secondo la medesima ripartizione degli stanziamenti.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Le spese amministrative risultanti da contratti conclusi per periodi superiori alla durata dell’esercizio, in conformità delle prassi locali o perché relativi alla fornitura di materiale di dotazione, sono imputate al bilancio per l’esercizio nel corso del quale sono effettuate.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Possono essere versati anticipi al personale e ai membri delle istituzioni dell’Unione conformemente allo statuto e alle disposizioni specifiche concernenti i membri delle istituzioni dell’Unione.</div>\n</div>"]]}, "265": {"label": "Articolo 265", "heading": "Pagamenti anticipati", "anchor": "art_265", "frags": [[null, "<p class=\"norm\">Le spese di cui all’articolo 11, paragrafo 2, lettera a), che in virtù di disposizioni legali o contrattuali sono effettuate in anticipo, possono dar luogo a decorrere dal 1<span class=\"superscript\">o</span> dicembre a pagamenti a valere sugli stanziamenti previsti per l’esercizio successivo. In tal caso non si applica il limite di cui all’articolo 11, paragrafo 2.</p>"]]}, "266": {"label": "Articolo 266", "heading": "Disposizioni specifiche riguardanti i progetti immobiliari", "anchor": "art_266", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Entro il 1<span class=\"superscript\">o</span> giugno di ogni anno ogni istituzione dell’Unione trasmette al Parlamento europeo e al Consiglio un documento di lavoro sulla sua politica immobiliare che include le seguenti informazioni:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per ogni edificio, la spesa e la superficie coperte dagli stanziamenti delle linee di bilancio corrispondenti. La spesa comprende i costi di sistemazione degli edifici, ma non le altre spese;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la prevedibile evoluzione della programmazione globale della superficie e delle ubicazioni per gli anni successivi, con una descrizione dei progetti immobiliari in fase di progettazione già identificati;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le condizioni e i costi definitivi, nonché le informazioni utili per quanto riguarda la realizzazione di nuovi progetti immobiliari già presentati al Parlamento europeo e al Consiglio secondo la procedura di cui ai paragrafi 2 e 3 e non inclusi nei documenti di lavoro dell’anno precedente.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Per qualsiasi progetto immobiliare che possa comportare conseguenze finanziarie significative per il bilancio, l’istituzione dell’Unione interessata informa quanto prima - e in ogni caso prima che abbia luogo qualsiasi indagine del mercato locale, nel caso di appalti immobiliari, o prima della pubblicazione dei bandi di gara, nel caso di lavori di costruzione - il Parlamento europeo e il Consiglio della superficie immobiliare necessaria e del programma provvisorio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Per qualsiasi progetto immobiliare che possa comportare conseguenze finanziarie significative per il bilancio, l’istituzione dell’Unione interessata presenta al Parlamento europeo e al Consiglio il progetto immobiliare, segnatamente una stima dettagliata dei costi e il finanziamento previsto, compreso l’eventuale ricorso alle entrate con destinazione specifica interne di cui all’articolo 21, paragrafo 3, lettera e), nonché un elenco dei progetti di contratto destinati a essere utilizzati, e ne chiede l’approvazione prima della conclusione dei contratti. Su richiesta dell’istituzione dell’Unione interessata, i documenti presentati concernenti il progetto immobiliare sono trattati in via riservata.</div>\n</div>"], [null, "<p class=\"norm\">Salvo nei casi di forza maggiore di cui al paragrafo 4, il Parlamento europeo e il Consiglio si pronunciano sul progetto immobiliare entro quattro settimane dal suo ricevimento da parte delle due istituzioni.</p>"], [null, "<p class=\"norm\">Il progetto immobiliare si considera approvato alla scadenza del termine di quattro settimane, a meno che il Parlamento europeo o il Consiglio non adotti una decisione contraria alla proposta entro tale periodo.</p>"], [null, "<p class=\"norm\">Se durante tale periodo di quattro settimane il Parlamento europeo e/o il Consiglio avanzano obiezioni, esso è prorogato per una volta di due settimane.</p>"], [null, "<p class=\"norm\">Se il Parlamento europeo e/o il Consiglio adottano una decisione contraria al progetto immobiliare, l’istituzione dell’Unione interessata ritira la proposta e può presentarne una nuova.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">In casi di forza maggiore, per i quali sono fornite debite motivazioni, le informazioni di cui al paragrafo 2 possono essere presentate unitamente al progetto immobiliare. Il Parlamento europeo e il Consiglio si pronunciano sul progetto immobiliare entro due settimane dal suo ricevimento da parte delle due istituzioni. Il progetto immobiliare si considera approvato alla scadenza del termine di due settimane, a meno che il Parlamento europeo e/o il Consiglio non adottino una decisione contraria alla proposta entro tale periodo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Sono considerati progetti immobiliari che possono comportare conseguenze finanziarie significative per il bilancio:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’acquisto di terreni;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’acquisto, la vendita, la ristrutturazione, la costruzione di edifici o qualsiasi progetto che abbini tali elementi da realizzarsi durante lo stesso periodo di importo superiore a 3 000 000  EUR;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’acquisto, la ristrutturazione, la costruzione di edifici o qualsiasi progetto che abbini detti elementi da realizzarsi durante lo stesso periodo di importo superiore a 2 000 000  EUR, nel caso in cui detto prezzo rappresenti più del 110 % del prezzo locale di beni immobili analoghi valutato da un esperto indipendente;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la vendita di terreni o edifici nel caso in cui il prezzo rappresenti meno del 90 % del prezzo locale di beni immobili analoghi valutato da un esperto indipendente;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">qualsiasi nuovo appalto immobiliare, inclusi l’usufrutto, i contratti di locazione a lungo termine e il rinnovo di appalti immobiliari esistenti a condizioni meno favorevoli non rientrante nella lettera b) e avente un costo annuale di almeno 750 000  EUR;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la proroga o il rinnovo di appalti immobiliari esistenti, inclusi l’usufrutto e i contratti di locazione a lungo termine, a condizioni identiche o più favorevoli e aventi un costo annuale di almeno 3 000 000  EUR.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Il presente paragrafo si applica anche ai progetti immobiliari di natura interistituzionale nonché alle delegazioni dell’Unione.</p>"], [null, "<p class=\"norm\">Le soglie di cui al primo comma, lettere da b) a f), comprendono i costi di sistemazione dell’edificio. Per i contratti di locazione e di usufrutto, tali soglie tengono conto dei costi di sistemazione dell’edificio, ma non delle altre spese.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Fatto salvo l’articolo 17, un progetto di acquisto immobiliare può essere finanziato mediante un prestito previa approvazione del Parlamento europeo e del Consiglio.</div>\n</div>"], [null, "<p class=\"norm\">I prestiti sono contratti e rimborsati conformemente al principio della sana gestione finanziaria e tenendo in debita considerazione gli interessi finanziari dell’Unione.</p>"], [null, "<p class=\"norm\">Se l’istituzione dell’Unione propone di finanziare l’acquisto mediante un prestito, il piano finanziario che deve essere presentato, unitamente alla richiesta di approvazione preventiva dell’istituzione dell’Unione interessata, precisa in particolare il livello massimo del finanziamento, il periodo di finanziamento, il tipo di finanziamento, le condizioni finanziarie e i risparmi ottenuti rispetto ad altri tipi di condizioni contrattuali.</p>"], [null, "<p class=\"norm\">Il Parlamento europeo e il Consiglio si pronunciano sulla richiesta di approvazione preventiva entro un periodo di quattro settimane dal suo ricevimento da parte delle due istituzioni, prorogabile per una volta di due settimane. L’acquisto finanziato tramite un prestito è da considerarsi respinto se il Parlamento europeo e il Consiglio non lo approvano esplicitamente entro tale termine.</p>"]]}, "267": {"label": "Articolo 267", "heading": "Procedura di informazione tempestiva e procedura di approvazione preventiva", "anchor": "art_267", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">La procedura di informazione tempestiva prevista all’articolo 266, paragrafo 2, e la procedura di approvazione preventiva prevista all’articolo 266, paragrafi 3 e 4, non si applicano all’acquisizione di terreni a titolo gratuito o per un importo simbolico.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">La procedura di informazione tempestiva prevista all’articolo 266, paragrafo 2, e la procedura di approvazione preventiva prevista all’articolo 266, paragrafi 3 e 4, si applicano anche agli edifici residenziali se l’acquisto, la ristrutturazione, la costruzione di edifici o qualsiasi progetto che abbini tali elementi durante lo stesso periodo ecceda l’importo di 2 000 000  EUR e detto prezzo rappresenti più del 110 % dell’indice locale dei prezzi d’acquisto o di locazione di beni immobili analoghi. Il Parlamento europeo e il Consiglio possono chiedere all’istituzione dell’Unione responsabile di trasmettere le informazioni relative agli edifici residenziali.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">In circostanze politiche eccezionali o urgenti le informazioni tempestive di cui all’articolo 266, paragrafo 2, relative ai progetti immobiliari concernenti delegazioni dell’Unione o uffici dell’Unione ubicati in paesi terzi possono essere presentate unitamente al progetto immobiliare a norma dell’articolo 266, paragrafo 3. In tali casi le procedure di informazione tempestiva e di approvazione preventiva sono espletate quanto prima.</div>\n</div>"], [null, "<p class=\"norm\">Per i progetti di edilizia residenziale in paesi terzi, le procedure di informazione tempestiva e di approvazione preventiva si svolgono congiuntamente.</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">La procedura di approvazione preventiva prevista all’articolo 266, paragrafi 3 e 4, non si applica ai contratti preparatori o agli studi necessari per valutare i costi dettagliati e il finanziamento del progetto immobiliare.</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "268": {"label": "Articolo 268", "heading": "Richieste di informazioni da parte del Parlamento europeo e del Consiglio", "anchor": "art_268", "frags": [[null, "<p class=\"norm\">Per le questioni di bilancio di loro rispettiva competenza il Parlamento europeo e il Consiglio possono ottenere qualsiasi informazione o chiarimento pertinente.</p>"]]}, "269": {"label": "Articolo 269", "heading": "Esercizio della delega", "anchor": "art_269", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il potere di adottare gli atti delegati è conferito alla Commissione alle condizioni stabilite nel presente articolo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il potere di adottare atti delegati di cui all’articolo 70, paragrafo 1, all’articolo 71, terzo comma, all’articolo 161 e all’articolo 213, paragrafo 2, secondo e terzo comma, è conferito alla Commissione per un periodo che termina il 31 dicembre 2020. La Commissione elabora una relazione sulla delega di potere entro il 31 dicembre 2018. La delega di potere è tacitamente prorogata per i periodi corrispondenti ai successivi quadri finanziari pluriennali, a meno che il Parlamento europeo o il Consiglio non si oppongano a tale proroga al più tardi tre mesi prima della scadenza di ciascun periodo.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La delega di potere di cui all’articolo 70, paragrafo 1, all’articolo 71, terzo comma, all’articolo 161 e all’articolo 213, paragrafo 2, secondo e terzo comma, può essere revocata in qualsiasi momento dal Parlamento europeo o dal Consiglio. La decisione di revoca pone fine alla delega di potere ivi specificata. Gli effetti della decisione decorrono dal giorno successivo alla pubblicazione della decisione nella <span class=\"italics\">Gazzetta ufficiale dell’Unione europea</span> o da una data successiva ivi specificata. Essa non pregiudica la validità degli atti delegati già in vigore.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Prima dell’adozione dell’atto delegato la Commissione consulta gli esperti designati da ciascuno Stato membro nel rispetto dei principi stabiliti nell’accordo interistituzionale «Legiferare meglio» del 13 aprile 2016.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Non appena adotta un atto delegato, la Commissione ne dà contestualmente notifica al Parlamento europeo e al Consiglio.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">L’atto delegato adottato a norma dell’articolo 70, paragrafo 1, dell’articolo 71, terzo comma, dell’articolo 161 e dell’articolo 213, paragrafo 2, secondo e terzo comma, entra in vigore solo se né il Parlamento europeo né il Consiglio hanno sollevato obiezioni entro il termine di due mesi dalla data in cui esso è stato loro notificato o se, prima della scadenza di tale termine, sia il Parlamento europeo che il Consiglio hanno informato la Commissione che non intendono sollevare obiezioni. Tale termine è prorogato di due mesi su iniziativa del Parlamento europeo o del Consiglio.</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "270": {"label": "Articolo 270", "heading": "Modifiche del regolamento (UE) n. 1296/2013", "anchor": "art_270", "frags": [[null, "<p class=\"norm\">Il regolamento (UE) n. 1296/2013 è così modificato:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>1) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 5, il paragrafo 2 è sostituito dal seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Agli assi di cui all’articolo 3, paragrafo 1, si applicano in media, per l’intero periodo del programma, le seguenti percentuali indicative:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">almeno il 55 % all’asse “Progress”;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">almeno il 18 % all’asse “EURES”;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">almeno il 18 % all’asse “Microfinanza e imprenditoria sociale.” »;</p>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>2) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’articolo 14 è sostituito dal seguente:</p>\n<p class=\"title-article-quoted\">«Articolo 14</p>\n<p class=\"stitle-article-quoted\">Sezioni tematiche e finanziamento</p>\n<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">L’asse “Progress” sostiene le azioni delle sezioni tematiche di cui alle lettere a), b) e c). Per l’intero periodo del programma, la dotazione indicativa della dotazione complessiva per l’asse “Progress” è ripartita tra le diverse sezioni tematiche secondo le seguenti percentuali minime:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">occupazione, in particolare la lotta contro la disoccupazione giovanile: 20 %;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">protezione e inclusione sociali, nonché riduzione e prevenzione della povertà: 45 %;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">condizioni di lavoro: 7 %.</p>\n</div>\n</div>\n</div>\n</div>\n<p class=\"norm\">Ogni importo restante è assegnato a una o più delle sezioni tematiche di cui al primo comma, lettera a), b) o c), o a una combinazione delle stesse.</p>\n<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Una quota rilevante della dotazione complessiva per l’asse “Progress” è destinata alla promozione della sperimentazione sociale come metodo per testare e valutare soluzioni innovative in vista di una loro utilizzazione su più ampia scala.»;</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>3) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’articolo 19 è sostituito dal seguente:</p>\n<p class=\"title-article-quoted\">«Articolo 19</p>\n<p class=\"stitle-article-quoted\">Sezioni tematiche e finanziamento</p>\n<p class=\"norm\">L’asse “EURES” sostiene le azioni delle sezioni tematiche di cui alle lettere a), b) e c). Per l’intero periodo del programma, la dotazione indicativa della dotazione complessiva per l’asse “EURES” è ripartita tra le diverse sezioni tematiche secondo le seguenti percentuali minime:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">trasparenza delle offerte e delle domande di lavoro e delle relative informazioni per chi cerca e per chi offre lavoro: 15 %;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sviluppo di servizi di assunzione e collocamento dei lavoratori mediante l’intermediazione tra l’offerta e la domanda di lavoro a livello di Unione, in particolare i programmi mirati di mobilità: 15 %;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">partenariati transfrontalieri: 18 %.</p>\n</div>\n</div>\n<p class=\"norm\">Ogni importo restante è assegnato a una o più delle sezioni tematiche di cui al primo comma, lettere a), b) o c), o a una combinazione delle stesse.»;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>4) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’articolo 25 è sostituito dal seguente:</p>\n<p class=\"title-article-quoted\">«Articolo 25</p>\n<p class=\"stitle-article-quoted\">Sezioni tematiche e finanziamento</p>\n<p class=\"norm\">L’asse “Microfinanza e imprenditoria sociale” sostiene le azioni delle sezioni tematiche di cui alle lettere a) e b). Per l’intero periodo del programma, la dotazione indicativa della dotazione complessiva per l’asse “Microfinanza e imprenditoria sociale” è ripartita tra le diverse sezioni tematiche secondo le seguenti percentuali minime:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">microfinanziamenti per le categorie vulnerabili e le microimprese: 35 %;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">imprenditoria sociale: 35 %.</p>\n</div>\n</div>\n<p class=\"norm\">Ogni importo restante è assegnato alle sezioni tematiche di cui al primo comma, lettere a) o b), o a una combinazione delle stesse.»;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>5) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 32, il secondo comma è sostituito dal seguente:</p>\n<p class=\"norm\">«I programmi di lavoro si svolgono, se del caso, per un periodo continuo di tre anni e contengono una descrizione delle azioni da finanziare, le procedure di selezione delle azioni che l’Unione deve finanziare, la copertura geografica, i destinatari e un calendario indicativo di attuazione. I programmi di lavoro comprendono altresì un’indicazione dell’importo stanziato per ciascun obiettivo specifico. I programmi di lavoro rafforzano la coerenza del programma indicando i collegamenti fra i tre assi.»;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>6) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli articoli 33 e 34 sono soppressi.</p>\n</div>\n</div>"]]}, "271": {"label": "Articolo 271", "heading": "Modifiche del regolamento (UE) n. 1301/2013", "anchor": "art_271", "frags": [[null, "<p class=\"norm\">Il regolamento (UE) n. 1301/2013 è così modificato:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>1) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’articolo 3, paragrafo 1 è così modificato:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la lettera e) è sostituita dalla seguente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>«e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">investimenti nello sviluppo del potenziale endogeno attraverso investimenti fissi in attrezzature e infrastrutture, tra cui infrastrutture per la cultura e il turismo sostenibile, servizi alle imprese, sostegno a organismi di ricerca e innovazione e investimenti in tecnologie e nella ricerca applicata nelle imprese;»;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">è aggiunto il comma seguente:</p>\n<p class=\"norm\">«Gli investimenti in infrastrutture per la cultura e il turismo sostenibile di cui al primo comma, lettera e), del presente paragrafo sono considerati di ridotte dimensioni e ammissibili a un sostegno qualora il contributo all’operazione a titolo del FESR non superi 10 000 000  EUR. Tale massimale è innalzato a 20 000 000  EUR nel caso delle infrastrutture considerate patrimonio culturale ai sensi dell’articolo 1 della convenzione dell’Unesco sulla protezione del patrimonio culturale e naturale mondiale del 1972.»;</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>2) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 5, punto 9), è aggiunta la lettera seguente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>«e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sostenendo l’accoglienza e l’integrazione socioeconomica di migranti e rifugiati;»;</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>3) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nella tabella dell’allegato I, il testo che inizia con «Infrastrutture sociali» fino alla fine della tabella è sostituito dal seguente:</p>\n<p>\n<br/>\n</p>\n<div class=\"centered\">\n<p>\n<br/>\n</p>\n<table border=\"1\" cellpadding=\"2\" cellspacing=\"0\" width=\"240\">\n<col width=\"16%\"/>\n<col width=\"11%\"/>\n<col width=\"72%\"/>\n<tbody>\n<tr>\n<td colspan=\"3\" valign=\"top\">\n<p class=\"tbl-norm\">«Infrastrutture sociali</p>\n</td>\n</tr>\n<tr>\n<td valign=\"top\">\n<p class=\"tbl-norm\">Assistenza all’infanzia e istruzione</p>\n</td>\n<td valign=\"top\">\n<p class=\"tbl-norm\">persone</p>\n</td>\n<td valign=\"top\">\n<p class=\"tbl-norm\">Capacità dell’infrastruttura per l’assistenza all’infanzia o l’istruzione sostenuta</p>\n</td>\n</tr>\n<tr>\n<td valign=\"top\">\n<p class=\"tbl-norm\">Sanità</p>\n</td>\n<td valign=\"top\">\n<p class=\"tbl-norm\">persone</p>\n</td>\n<td valign=\"top\">\n<p class=\"tbl-norm\">Popolazione coperta dai servizi sanitari migliorati</p>\n</td>\n</tr>\n<tr>\n<td valign=\"top\">\n<p class=\"tbl-norm\">Edilizia abitativa</p>\n</td>\n<td valign=\"top\">\n<p class=\"tbl-norm\">alloggi</p>\n</td>\n<td valign=\"top\">\n<p class=\"tbl-norm\">Abitazioni ripristinate</p>\n</td>\n</tr>\n<tr>\n<td valign=\"top\">\n<p class=\"normal\"> </p>\n<div></div>\n</td>\n<td valign=\"top\">\n<p class=\"tbl-norm\">alloggi</p>\n</td>\n<td valign=\"top\">\n<p class=\"tbl-norm\">Abitazioni ripristinate, di cui per migranti e rifugiati (esclusi i centri di accoglienza)</p>\n</td>\n</tr>\n<tr>\n<td valign=\"top\">\n<p class=\"tbl-norm\">Migranti e rifugiati</p>\n</td>\n<td valign=\"top\">\n<p class=\"tbl-norm\">persone</p>\n</td>\n<td valign=\"top\">\n<p class=\"tbl-norm\">Capacità dell’infrastruttura a sostegno di migranti e rifugiati (esclusi gli alloggi)</p>\n</td>\n</tr>\n<tr>\n<td colspan=\"3\" valign=\"top\">\n<p class=\"tbl-norm\">Indicatori specifici per lo sviluppo urbano</p>\n</td>\n</tr>\n<tr>\n<td valign=\"top\">\n<p class=\"normal\"> </p>\n<div></div>\n</td>\n<td valign=\"top\">\n<p class=\"tbl-norm\">persone</p>\n</td>\n<td valign=\"top\">\n<p class=\"tbl-norm\">Popolazione che vive in aree con strategie di sviluppo urbano integrato</p>\n</td>\n</tr>\n<tr>\n<td valign=\"top\">\n<p class=\"normal\"> </p>\n<div></div>\n</td>\n<td valign=\"top\">\n<p class=\"tbl-norm\">metri quadrati</p>\n</td>\n<td valign=\"top\">\n<p class=\"tbl-norm\">Spazi aperti creati o ripristinati in aree urbane</p>\n</td>\n</tr>\n<tr>\n<td valign=\"top\">\n<p class=\"normal\"> </p>\n<div></div>\n</td>\n<td valign=\"top\">\n<p class=\"tbl-norm\">metri quadrati</p>\n</td>\n<td valign=\"top\">\n<p class=\"tbl-norm\">Edifici pubblici o commerciali costruiti o ristrutturati in aree urbane».</p>\n</td>\n</tr>\n</tbody>\n</table>\n</div>\n</div>\n</div>"]]}, "272": {"label": "Articolo 272", "heading": "Modifiche del regolamento (UE) n. 1303/2013", "anchor": "art_272", "frags": [[null, "<p class=\"norm\">Il regolamento (UE) n. 1303/2013 è così modificato:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>1) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">al considerando 10, la seconda frase è sostituita dalla seguente:</p>\n<p class=\"norm\">«Tali condizioni dovrebbero consentire alla Commissione di assicurarsi che gli Stati membri utilizzino i fondi SIE legittimamente, regolarmente e conformemente al principio di sana gestione finanziaria principio di sana gestione finanziaria di cui al regolamento (UE, Euratom) 2018/1046 del Parlamento europeo Parlamento e del Consiglio (\n<span class=\"superscript\">*1</span>\n) (“regolamento finanziario”).</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>2) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’articolo 2 è così modificato:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il punto 10) è sostituito dal seguente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>«10) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">“beneficiario” significa un organismo pubblico o privato o una persona fisica responsabile dell’avvio, o di entrambi l’avvio e l’attuazione, delle operazioni:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nell’ambito degli aiuti di Stato, l’organismo che riceve l’aiuto, tranne qualora l’aiuto per impresa sia inferiore a 200 000  EUR, nel qual caso lo Stato membro interessato può decidere che il beneficiario sia l’organismo che concede l’aiuto, fatti salvi i regolamenti della Commissione (UE) n. 1407/2013 (\n<span class=\"superscript\">*2</span>\n), (UE) n. 1408/2013 (\n<span class=\"superscript\">*3</span>\n) e (UE) n. 717/2014 (\n<span class=\"superscript\">*4</span>\n) e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nell’ambito degli strumenti finanziari ai sensi del titolo IV della parte II del presente regolamento, l’organismo che attua lo strumento finanziario ovvero, se del caso, il fondo di fondi;</p>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il punto 31) è sostituito dal seguente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>«31) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">“strategia macroregionale”: un quadro integrato concordato dal Consiglio e, se del caso, approvato dal Consiglio europeo, che potrebbe essere sostenuto, tra gli altri, dai fondi SIE per affrontare sfide comuni riguardanti un’area geografica definita, connesse agli Stati membri e ai paesi terzi situati nella stessa area geografica, che beneficiano così di una cooperazione rafforzata che contribuisce al conseguimento della coesione economica, sociale e territoriale;»;</p>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>3) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’articolo 4 è così modificato:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nel paragrafo 7, il riferimento «articolo 59 del regolamento finanziario» è sostituito da «articolo 63 del regolamento finanziario»;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il paragrafo 8 è sostituito dal seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«8.  </span>\n<div class=\"norm inline-element\">La Commissione e gli Stati membri rispettano il principio della sana gestione finanziaria in conformità dell’articolo 33, dell’articolo 36, paragrafo 1, e dell’articolo 61 del regolamento finanziario.»;</div>\n</div>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>4) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 9 è aggiunto il comma seguente:</p>\n<p class=\"norm\">«Le priorità stabilite per ciascuno dei fondi SIE nelle norme specifiche di ciascun fondo riguardano, in particolare, l’uso appropriato di ciascun fondo SIE nei settori della migrazione e dell’asilo. In tale contesto è garantito, ove opportuno, il coordinamento con il Fondo asilo, migrazione e integrazione istituito dal regolamento (UE) n. 516/2014 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">*5</span>\n).</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>5) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 16 è aggiunto il paragrafo seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«4 <span class=\"italics\">bis</span>.  </span>\n<div class=\"norm inline-element\">Se del caso, lo Stato membro trasmette ogni anno, entro il 31 gennaio, un accordo di partenariato modificato in seguito all’approvazione, da parte della Commissione, delle modifiche di uno o più programmi nell’anno civile precedente.</div>\n</div>\n<p class=\"norm\">La Commissione adotta ogni anno, entro il 31 marzo, una decisione recante conferma che le modifiche dell’accordo di partenariato rispecchiano le modifiche di uno o più programmi approvate dalla Commissione nell’anno civile precedente.</p>\n<p class=\"norm\">La decisione può comprendere la modifica di altri elementi dell’accordo di partenariato conformemente alla proposta di cui al paragrafo 4, purché la proposta sia stata presentata alla Commissione entro il 31 dicembre dell’anno civile precedente.»;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>6) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’articolo 30 è così modificato:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">al paragrafo 2, il secondo comma è sostituito dal seguente:</p>\n<p class=\"norm\">«Quando la modifica di un programma si ripercuote sulle informazioni fornite nell’accordo di partenariato, si applica la procedura di cui all’articolo 16, paragrafo 4 <span class=\"italics\">bis</span>.»;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">al paragrafo 3, la terza frase è soppressa;</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>7) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 32, il paragrafo 4 è sostituito dal seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«4.  </span>\n<div class=\"norm inline-element\">Se il comitato di selezione delle strategie di sviluppo locale di tipo partecipativo istituito ai sensi dell’articolo 33, paragrafo 3, ritiene che l’attuazione della strategia di sviluppo locale di tipo partecipativo selezionata richieda il sostegno di più di un fondo, può designare, conformemente alle norme e secondo le procedure nazionali, un fondo capofila per sostenere tutti i costi di preparazione, di gestione e di animazione ai sensi dell’articolo 35, paragrafo 1, lettere a, d) ed e), relativi alla strategia di sviluppo locale di tipo partecipativo.»;</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>8) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’articolo 34, paragrafo 3, è così modificato:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le lettere da a) a d) sono sostituite dalle seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>«a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">rafforzare la capacità dei soggetti locali, compresi i potenziali beneficiari, di elaborare e attuare operazioni, anche stimolandone le capacità di preparare e gestire i loro progetti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">elaborare una procedura di selezione trasparente e non discriminatoria che eviti conflitti d’interessi, garantisca che almeno il 50 % dei voti espressi nelle decisioni di selezione provenga da partner che non sono autorità pubbliche e consenta la selezione mediante procedura scritta;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">elaborare e approvare criteri oggettivi non discriminatori di selezione delle operazioni che garantiscano la coerenza con la strategia di sviluppo locale di tipo partecipativo stabilendo l’ordine di priorità di tali operazioni in funzione del loro contributo al conseguimento degli obiettivi e dei target di tale strategia;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">preparare e pubblicare gli inviti a presentare proposte o una procedura permanente di presentazione di progetti;»;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">è aggiunto il comma seguente:</p>\n<p class=\"norm\">«I gruppi di azione locale che svolgono compiti non contemplati dal primo comma, lettere da a) a g), che rientrano nelle competenze dell’autorità di gestione, dell’autorità di certificazione o dell’organismo pagatore sono designati come organismi intermedi conformemente alle norme specifiche di ciascun fondo.»;</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>9) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 36, il paragrafo 3 è sostituito dal seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«3.  </span>\n<div class=\"norm inline-element\">Lo Stato membro o l’autorità di gestione può delegare a uno o più organismi intermedi, compresi enti locali, organismi di sviluppo regionale od organizzazioni non governative, determinati compiti connessi alla gestione e all’attuazione di un ITI conformemente alle norme specifiche di ciascun fondo.»;</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>10) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’articolo 37 è così modificato:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">al paragrafo 2, la lettera c) è sostituita dalla seguente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>«c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una stima delle risorse pubbliche e private aggiuntive che lo strumento finanziario ha la possibilità di raccogliere, fino al livello del destinatario finale (effetto moltiplicatore previsto), compresa, se del caso, una valutazione della necessità e dell’entità del trattamento differenziato di cui all’articolo 43 <span class=\"italics\">bis</span> inteso ad attrarre risorse complementari da investitori che operano conformemente al principio dell’economia di mercato e/o una descrizione del meccanismo che sarà impiegato per stabilire la necessità e l’entità di tale trattamento differenziato, quale una procedura di valutazione competitiva o adeguatamente indipendente;»;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">al paragrafo 3, il primo comma è sostituito dal seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«3.  </span>\n<div class=\"norm inline-element\">La valutazione ex ante di cui al paragrafo 2 del presente articolo può tener conto delle valutazioni ex ante di cui all’articolo 209, paragrafo 2, primo comma, lettera h), e secondo comma del regolamento finanziario ed essere eseguita in fasi. In ogni caso, è completata prima che l’autorità di gestione decida di erogare contributi del programma a uno strumento finanziario.»;</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il paragrafo 8 è sostituito dal seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«8.  </span>\n<div class=\"norm inline-element\">I destinatari finali di un sostegno fornito mediante uno strumento finanziario dei fondi SIE possono anche ricevere assistenza a titolo di un’altra priorità dei fondi SIE o di un altro programma o da un altro strumento finanziato sostenuto dal bilancio dell’Unione, compreso il Fondo europeo per gli investimenti strategici (FEIS) istituito dal regolamento (UE) 2015/1017 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">*6</span>\n), a seconda del caso, conformemente alle norme dell’Unione applicabili in materia di aiuti di Stato. In tal caso sono mantenute registrazioni separate per ciascuna fonte di assistenza e lo strumento di sostegno finanziario dei fondi SIE è parte di un’operazione in cui le spese ammissibili sono distinte dalle altre fonti di assistenza.</div>\n</div>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>11) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’articolo 38 è così modificato:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">al paragrafo 1 è aggiunta la lettera seguente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>«c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli strumenti finanziari che combinano tale contributo con prodotti finanziari della BEI nell’ambito del FEIS conformemente all’articolo 39 <span class=\"italics\">bis</span>.»;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il paragrafo 4 è così modificato:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">al primo comma, le lettere b) e c) sono sostituite dalle seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>«b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">affidare compiti di esecuzione, tramite l’aggiudicazione diretta di un contratto:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">alla BEI;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">a un’istituzione finanziaria internazionale in cui uno Stato membro detiene una partecipazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">a una banca o a un istituto di proprietà dello Stato costituiti come entità giuridiche che svolgono attività finanziarie su base professionale e soddisfano tutte le condizioni seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">non vi è alcuna partecipazione diretta di capitali privati, a eccezione di forme di partecipazione di capitali privati prescritte dalle disposizioni legislative nazionali, in conformità dei trattati, che non comportano controllo o potere di veto né consentono l’esercizio di un’influenza determinante sulla banca o sull’istituto in questione, e a eccezione di forme di partecipazione di capitali privati che non conferiscono alcuna influenza sulle decisioni riguardanti la gestione corrente dello strumento finanziario sostenuto dai fondi SIE;</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">operano con un mandato pubblico, conferito dall’autorità competente di uno Stato membro a livello nazionale o regionale, che comprende, come parte o totalità dei loro compiti, lo svolgimento di attività di sviluppo economico che contribuiscono agli obiettivi dei fondi SIE;</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">svolgono, come parte o totalità dei loro compiti, attività di sviluppo economico che contribuiscono agli obiettivi dei fondi SIE in regioni, settori o ambiti strategici per i quali l’accesso ai finanziamenti da fonti di mercato non è generalmente disponibile o sufficiente;</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">operano senza l’obiettivo primario di massimizzare i profitti, ma garantiscono la sostenibilità finanziaria a lungo termine delle loro attività;</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">garantiscono che l’aggiudicazione diretta di un contratto di cui alla lettera b) non accordi alcun vantaggio diretto o indiretto ad attività commerciali attraverso misure adeguate conformemente al diritto applicabile;</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">sono soggetti alla vigilanza di un’autorità indipendente conformemente al diritto applicabile;</div>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">affidare compiti di esecuzione a un altro organismo di diritto pubblico o privato, o</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">assumere direttamente compiti di esecuzione, in caso di strumenti finanziari costituiti esclusivamente da prestiti o garanzie. In tal caso l’autorità di gestione è considerata il beneficiario ai sensi dell’articolo 2, punto 10).»;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il secondo comma è sostituito dal seguente:</p>\n<p class=\"norm\">«Nell’attuare lo strumento finanziario, gli organismi di cui al primo comma, lettere da a) a d), del presente paragrafo garantiscono la conformità al diritto applicabile e ai requisiti di cui all’articolo 155, paragrafi 2 e 3, del regolamento finanziario»;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i paragrafi 5 e 6 sono sostituiti dai seguenti:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«5.  </span>\n<div class=\"norm inline-element\">Gli organismi di cui al paragrafo 4, primo comma, lettere a), b) e c), del presente articolo, quando attuano fondi di fondi, possono a loro volta affidare parte dell’attuazione a intermediari finanziari, a condizione che tali organismi si assumano la responsabilità di garantire che gli intermediari finanziari soddisfano i criteri di cui all’articolo 33, paragrafo 1, e all’articolo 209, paragrafo 2, del regolamento finanziario. Gli intermediari finanziari sono selezionati mediante procedure aperte, trasparenti, proporzionate e non discriminatorie, evitando conflitti d’interessi.</div>\n</div>\n<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Gli organismi di cui al paragrafo 4, primo comma, lettere b) e c), ai quali sono stati affidati compiti di esecuzione aprono conti fiduciari a proprio nome e per conto dell’autorità di gestione o configurano lo strumento finanziario come un capitale separato nell’ambito dell’istituzione. Nel caso di un capitale separato, è operata una distinzione contabile tra le risorse del programma investite nello strumento finanziario e le altre risorse disponibili nell’istituzione. Le attività detenute su conti fiduciari e tali capitali separati sono gestiti in conformità del principio della sana gestione finanziaria, applicando opportune norme prudenziali, e dispongono di adeguata liquidità.»;</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">al paragrafo 7, la parte introduttiva del primo comma è sostituita dalla seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«7.  </span>\n<div class=\"norm inline-element\">Qualora uno strumento finanziario sia attuato a norma del paragrafo 4, primo comma, lettere a), b) e c), in funzione di come è strutturata l’attuazione dello strumento finanziario, i termini e le condizioni per i contributi dei programmi agli strumenti finanziari sono definiti in accordi di finanziamento conformemente all’allegato IV ai livelli seguenti:»;</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il paragrafo 8 è sostituito dal seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«8.  </span>\n<div class=\"norm inline-element\">Per gli strumenti finanziari attuati a norma del paragrafo 4, primo comma, lettera d), i termini e le condizioni per i contributi dei programmi agli strumenti finanziari sono definiti in un documento strategico in conformità dell’allegato IV che sarà esaminato dal comitato di sorveglianza.»;</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il paragrafo 10 è sostituito dal seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«10.  </span>\n<div class=\"norm inline-element\">La Commissione adotta atti di esecuzione che stabiliscono condizioni uniformi per quanto riguarda le modalità dettagliate del trasferimento e della gestione dei contributi dei programmi, gestiti dagli organismi di cui al paragrafo 4, primo comma, del presente articolo e all’articolo 39 <span class=\"italics\">bis</span>, paragrafo 5. Tali atti di esecuzione sono adottati secondo la procedura d’esame di cui all’articolo 150, paragrafo 3.»;</div>\n</div>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>12) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’articolo 39 è così modificato:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">al paragrafo 2, primo comma, la frase introduttiva è sostituita dalla seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«2.  </span>\n<div class=\"norm inline-element\">Gli Stati membri possono ricorrere al FESR e al FEASR durante il periodo di ammissibilità di cui all’articolo 65, paragrafo 2, del presente regolamento, per fornire un contributo finanziario agli strumenti finanziari di cui all’articolo 38, paragrafo 1, lettera a), del presente regolamento gestiti indirettamente dalla Commissione con la BEI a norma dell’articolo 62, paragrafo 1, primo comma, lettera c), punto iii), del regolamento finanziario e dell’articolo 208, paragrafo 4, del regolamento finanziario, per quanto riguarda le seguenti attività:»;</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">al paragrafo 4, primo comma:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la lettera a) è sostituita dalla seguente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>«a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">in deroga all’articolo 37, paragrafo 2, si basa su una valutazione ex ante a livello dell’Unione, effettuata dalla BEI e dalla Commissione o, qualora siano disponibili dati più recenti, su una valutazione ex ante a livello dell’Unione, nazionale o regionale.</p>\n<p class=\"list\">Sulla base delle fonti di dati disponibili in materia di finanziamento del debito da parte del settore bancario e sulle PMI, la valutazione ex ante contempla, tra l’altro, un’analisi del fabbisogno di finanziamento delle PMI al livello pertinente, le condizioni e il fabbisogno di finanziamento delle PMI, nonché un’indicazione del deficit di finanziamento delle PMI, un profilo della situazione economica e finanziaria del settore delle PMI al livello pertinente, la massa critica minima dei contributi aggregati, una forbice del volume totale stimato di prestiti generato da tali contributi, nonché il valore aggiunto;»;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la lettera b) è sostituita dalla seguente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>«b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">è fornito da ogni Stato membro partecipante quale elemento di un asse prioritario separato nell’ambito di un programma, nel caso di un contributo del FESR, o di un unico programma nazionale dedicato per contributo finanziario del FESR e del FEASR, a sostegno dell’obiettivo tematico di cui all’articolo 9, primo comma, punto 3);»;</p>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i paragrafi 7 e 8 sono sostituiti dai seguenti:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«7.  </span>\n<div class=\"norm inline-element\">In deroga all’articolo 41, paragrafi 1 e 2, per quanto riguarda i contributi finanziari di cui al paragrafo 2 del presente articolo, le domande di pagamento degli Stati membri alla Commissione sono formulate sulla base del 100 % degli importi che gli Stati membri devono versare alla BEI in conformità del calendario definito nell’accordo di finanziamento di cui al paragrafo 4, primo comma, lettera c), del presente articolo. Tali domande di pagamento sono basate sugli importi richiesti dalla BEI ritenuti necessari per coprire gli impegni nell’ambito di accordi di garanzia od operazioni di cartolarizzazione da concludere nei tre mesi successivi. I pagamenti degli Stati membri alla BEI sono effettuati prontamente e in ogni caso prima che la BEI sottoscriva gli impegni.</div>\n</div>\n<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Alla chiusura del programma, la spesa ammissibile di cui all’articolo 42, paragrafo 1, primo comma, lettere a) e b), equivale all’importo complessivo dei contributi del programma versati allo strumento finanziario, corrispondente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per le attività di cui al paragrafo 2, primo comma, lettera a), del presente articolo, alle risorse di cui all’articolo 42, paragrafo 1, primo comma, lettera b);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per le attività di cui al paragrafo 2, primo comma, lettera b), del presente articolo, all’importo aggregato del nuovo finanziamento del debito risultante dalle operazioni di cartolarizzazione, versato alle, o a beneficio delle, PMI ammissibili entro il periodo di ammissibilità di cui all’articolo 65, paragrafo 2.»;</p>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>13) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">è inserito l’articolo seguente:</p>\n<p class=\"title-article-quoted\">«Articolo 39 <span class=\"norm\">bis</span>\n</p>\n<p class=\"stitle-article-quoted\">Contributo dei fondi SIE agli strumenti finanziari che combinano tale contributo a prodotti finanziari della BEI nell’ambito del Fondo europeo per gli investimenti strategici</p>\n<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Al fine di attrarre investimenti supplementari del settore privato, le autorità di gestione possono ricorrere ai fondi SIE per fornire un contributo agli strumenti finanziari di cui all’articolo 38, paragrafo 1, lettera c), purché ciò contribuisca, tra l’altro, al raggiungimento degli obiettivi dei fondi SIE e alla strategia dell’Unione per una crescita intelligente, sostenibile e inclusiva.</div>\n</div>\n<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il contributo di cui al paragrafo 1 non supera il 25 % del sostegno complessivo fornito ai destinatari finali. Nelle regioni meno sviluppate di cui all’articolo 120, paragrafo 3, primo comma, lettera b), il contributo finanziario può superare il 25 %, ove ciò sia debitamente giustificato dalle valutazioni di cui all’articolo 37, paragrafo 2, o al paragrafo 3 del presente articolo, ma non deve superare il 40 %. Il sostegno complessivo di cui al presente paragrafo comprende l’importo totale dei nuovi prestiti e dei prestiti garantiti, nonché degli investimenti azionari o quasi-azionari forniti ai destinatari finali. Dei prestiti garantiti di cui al presente paragrafo si tiene conto solo nella misura in cui le risorse dei fondi SIE sono impegnate per contratti di garanzia calcolati in base a una prudente valutazione ex ante dei rischi a copertura di un ammontare multiplo di nuovi prestiti.</div>\n</div>\n<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">In deroga all’articolo 37, paragrafo 2, i contributi ai sensi del paragrafo 1 del presente articolo possono basarsi sulla valutazione preparatoria, compresa un’analisi approfondita (<span class=\"italics\">due diligence</span>), eseguita dalla BEI ai fini del suo contributo al prodotto finanziario nell’ambito del FEIS.</div>\n</div>\n<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Le relazioni presentate dalle autorità di gestione a norma dell’articolo 46 del presente regolamento sulle operazioni che comprendono strumenti finanziari ai sensi del presente articolo si basano sulle informazioni conservate dalla BEI per le proprie relazioni a norma dell’articolo 16, paragrafi 1 e 2, del regolamento (UE) 2015/1017, integrate dalle informazioni supplementari richieste a norma dell’articolo 46, paragrafo 2, del presente regolamento. I requisiti di cui al presente paragrafo consentono condizioni uniformi in materia di relazioni conformemente all’articolo 46, paragrafo 3, del presente regolamento.</div>\n</div>\n<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Quando contribuisce agli strumenti finanziari di cui all’articolo 38, paragrafo 1, lettera c), l’autorità di gestione può:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">investire nel capitale di un’entità giuridica nuova o già esistente incaricata della realizzazione di investimenti in destinatari finali coerenti con gli obiettivi dei rispettivi fondi SIE, che svolgerà compiti di esecuzione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">affidare compiti di esecuzione conformemente all’articolo 38, paragrafo 4, primo comma, lettere b) e c).</p>\n</div>\n</div>\n</div>\n</div>\n<p class=\"norm\">L’organismo cui sono stati affidati compiti di esecuzione di cui al presente paragrafo, primo comma, lettera b), apre un conto fiduciario a proprio nome e per conto dell’autorità di gestione o costituisce un capitale separato nell’ambito dell’istituto per il contributo del programma. Nel caso di un capitale separato, è attuata una distinzione contabile tra le risorse del programma investite nello strumento finanziario e le altre risorse disponibili nell’istituto. Le attività detenute su conti fiduciari e tali capitali separati sono gestiti in conformità del principio della sana gestione finanziaria, applicando opportune norme prudenziali, e dispongono di adeguata liquidità.</p>\n<p class=\"norm\">Ai fini del presente articolo, uno strumento finanziario può anche assumere la forma, o far parte, di una piattaforma d’investimento ai sensi dell’articolo 2, punto 4), del regolamento (UE) 2015/1017, purché la piattaforma d’investimento assuma la forma di una società veicolo o di un conto gestito.</p>\n<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Nell’attuare gli strumenti finanziari a norma dell’articolo 38, paragrafo 1, lettera c), del presente regolamento gli organismi di cui al paragrafo 5 del presente articolo garantiscono la conformità al diritto applicabile e ai requisiti di cui all’articolo 155, paragrafi 2 e 3, del regolamento finanziario.</div>\n</div>\n<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">Entro il 3 novembre 2018, la Commissione adotta atti delegati conformemente all’articolo 149 per integrare il presente regolamento stabilendo norme specifiche aggiuntive sul ruolo, le competenze e le responsabilità degli organismi di attuazione degli strumenti finanziari e sui relativi criteri di selezione e prodotti che possono essere offerti mediante strumenti finanziari conformemente all’articolo 38, paragrafo 1, lettera c).</div>\n</div>\n<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">Gli organismi di cui al paragrafo 5 del presente articolo, quando attuano fondi di fondi, possono a loro volta affidare parte dell’attuazione a intermediari finanziari, a condizione che tali organismi si assumano la responsabilità di garantire che gli intermediari finanziari soddisfano i criteri di cui all’articolo 33, paragrafo 1, e all’articolo 209, paragrafo 2, del regolamento finanziario. Gli intermediari finanziari sono selezionati mediante procedure aperte, trasparenti, proporzionate e non discriminatorie, evitando conflitti d’interessi.</div>\n</div>\n<div class=\"norm\">\n<span class=\"no-parag\">9.  </span>\n<div class=\"norm inline-element\">Quando, ai fini dell’attuazione degli strumenti finanziari di cui all’articolo 38, paragrafo 1, lettera c), le autorità di gestione utilizzano le risorse di programmi finanziati dai fondi SIE per contribuire a uno strumento esistente il cui gestore dei fondi è già stato selezionato dalla BEI, da un’istituzione finanziaria internazionale in cui uno Stato membro detiene una partecipazione o da una banca o un istituto di proprietà dello Stato costituiti come entità giuridiche che svolgono attività finanziarie su base professionale e soddisfano le condizioni di cui all’articolo 38, paragrafo 4, primo comma, lettera b), punto iii), tali autorità affidano i compiti di esecuzione al gestore dei fondi tramite aggiudicazione di un contratto diretto.</div>\n</div>\n<div class=\"norm\">\n<span class=\"no-parag\">10.  </span>\n<div class=\"norm inline-element\">In deroga all’articolo 41, paragrafi 1 e 2, per i contributi agli strumenti finanziari a norma del paragrafo 9 del presente articolo le domande di pagamento intermedio sono scaglionate in conformità del calendario di pagamento definito nell’accordo di finanziamento. Il calendario di pagamento di cui alla prima frase del presente paragrafo corrisponde al calendario di pagamento concordato per gli altri investitori nello stesso strumento finanziario.</div>\n</div>\n<div class=\"norm\">\n<span class=\"no-parag\">11.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">I termini e le condizioni per i contributi a norma dell’articolo 38, paragrafo 1, lettera c), sono definiti in accordi di finanziamento conformemente all’allegato IV ai livelli seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">ove applicabile, tra i rappresentanti debitamente autorizzati dell’autorità di gestione e l’organismo che attua il fondo di fondi;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">tra i rappresentanti debitamente autorizzati dell’autorità di gestione o, ove applicabile, tra l’organismo che attua il fondo di fondi e l’organismo che attua lo strumento finanziario.</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"norm\">\n<span class=\"no-parag\">12.  </span>\n<div class=\"norm inline-element\">Per i contributi a norma del paragrafo 1 del presente articolo a piattaforme di investimento che ricevono contributi da strumenti istituiti a livello di Unione, è garantita la coerenza con le norme sugli aiuti di Stato in conformità dell’articolo 209, paragrafo 2, lettera c), del regolamento finanziario.</div>\n</div>\n<div class=\"norm\">\n<span class=\"no-parag\">13.  </span>\n<div class=\"norm inline-element\">Nel caso degli strumenti finanziari di cui all’articolo 38, paragrafo 1, lettera c), che assumono la forma di uno strumento di garanzia, gli Stati membri possono decidere che i fondi SIE concorrano, se del caso, alle diverse componenti dei portafogli di prestiti coperti anche dalla garanzia dell’Unione a titolo del regolamento (UE) 2015/1017.</div>\n</div>\n<div class=\"norm\">\n<span class=\"no-parag\">14.  </span>\n<div class=\"norm inline-element\">Nell’ambito di un programma possono essere stabiliti un asse prioritario separato, per il FESR, l’FSE, il Fondo di coesione e il FEAMP, e un tipo di operazione separato, per il FEASR, con un tasso di cofinanziamento massimo del 100 % per sostenere le operazioni realizzate attraverso gli strumenti finanziari di cui all’articolo 38, paragrafo 1, lettera c).</div>\n</div>\n<div class=\"norm\">\n<span class=\"no-parag\">15.  </span>\n<div class=\"norm inline-element\">In deroga all’articolo 70 e all’articolo 93, paragrafo 1, i contributi di cui al paragrafo 1 del presente articolo possono essere utilizzati per originare nuovi finanziamenti mediante debito e capitale proprio nell’intero territorio dello Stato membro, a prescindere dalle categorie di regioni, salvo se diversamente previsto nell’accordo di finanziamento.</div>\n</div>\n<div class=\"norm\">\n<span class=\"no-parag\">16.  </span>\n<div class=\"norm inline-element\">Entro il 31 dicembre 2019 la Commissione procede a un riesame dell’applicazione del presente articolo e presenta, se del caso, una proposta legislativa al Parlamento europeo e al Consiglio.»;</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>14) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’articolo 40 è così modificato:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i paragrafi 1 e 2 sono sostituiti dai seguenti:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«1.  </span>\n<div class=\"norm inline-element\">Le autorità designate conformemente all’articolo 124 del presente regolamento e all’articolo 65 del regolamento FEASR non effettuano verifiche sul posto a livello della BEI o delle altre istituzioni finanziarie internazionali in cui uno Stato membro detiene una partecipazione per gli strumenti finanziari da loro attuati.</div>\n</div>\n<p class=\"norm\">Tuttavia, le autorità designate effettuano verifiche a norma dell’articolo 125, paragrafo 5, del presente regolamento e controlli conformemente all’articolo 59, paragrafo 1, del regolamento (UE) n. 1306/2013 a livello degli altri organismi che attuano gli strumenti finanziari nella giurisdizione del rispettivo Stato membro.</p>\n<p class=\"norm\">La BEI e le altre istituzioni finanziarie internazionali in cui uno Stato membro detiene una partecipazione forniscono alle autorità designate una relazione di controllo unitamente a ciascuna domanda di pagamento. Forniscono inoltre alla Commissione e alle autorità designate una relazione annuale di audit redatta dai loro revisori esterni. Tali obblighi di relazione non pregiudicano gli obblighi di relazione, anche per quanto riguarda i risultati degli strumenti finanziari, definiti all’articolo 46, paragrafi 1 e 2, del presente regolamento.</p>\n<p class=\"norm\">Alla Commissione è conferito il potere di adottare un atto di esecuzione relativo ai modelli delle relazioni di controllo e delle relazioni annuali di audit di cui al terzo comma del presente paragrafo.</p>\n<p class=\"norm\">Tale atto di esecuzione è adottato secondo la procedura consultiva di cui all’articolo 150, paragrafo 2.</p>\n<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Fatti salvi l’articolo 127 del presente regolamento e l’articolo 9 del regolamento (UE) n. 1306/2013, gli organismi responsabili dell’audit dei programmi non effettuano audit a livello della BEI o delle altre istituzioni finanziarie internazionali in cui uno Stato membro detiene una partecipazione per gli strumenti finanziari da loro attuati.</div>\n</div>\n<p class=\"norm\">Gli organismi responsabili dell’audit dei programmi effettuano audit delle operazioni e dei sistemi di gestione e di controllo a livello degli altri organismi che attuano gli strumenti finanziari nella giurisdizione dei rispettivi Stati membri e a livello dei destinatari finali, purché siano soddisfatte le condizioni di cui al paragrafo 3.</p>\n<p class=\"norm\">La Commissione può effettuare audit a livello degli organismi di cui al paragrafo 1 ove ritenga che ciò sia necessario per ottenere una ragionevole garanzia in considerazione dei rischi individuati.</p>\n<div class=\"norm\">\n<span class=\"no-parag\">2 <span class=\"italics\">bis</span>.  </span>\n<div class=\"norm inline-element\">Per quanto riguarda gli strumenti finanziari di cui all’articolo 38, paragrafo 1, lettera a), e all’articolo 39 che sono stati istituiti mediante accordi di finanziamento firmati prima del 2 agosto 2018, si applicano le norme di cui al presente articolo applicabili al momento della firma dell’accordo di finanziamento, in deroga ai paragrafi 1 e 2 del presente articolo.»;</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il paragrafo 4 è sostituito dal seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«4.  </span>\n<div class=\"norm inline-element\">Entro il 3 novembre 2018, la Commissione adotta atti delegati, conformemente all’articolo 149, che integrano il presente regolamento stabilendo norme specifiche aggiuntive riguardanti la gestione e il controllo degli strumenti finanziari di cui all’articolo 38, paragrafo 1, lettere b) e c), per quanto concerne i tipi di controlli da eseguire da parte delle autorità di gestione e di audit, le modalità di conservazione dei documenti giustificativi e gli elementi da evidenziare nei documenti giustificativi.»;</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">è inserito il paragrafo seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«5 <span class=\"italics\">bis</span>.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">In deroga all’articolo 143, paragrafo 4, del presente regolamento e all’articolo 56, secondo comma, del regolamento (UE) n. 1306/2013, nelle operazioni che comprendono strumenti finanziari, un contributo soppresso in conformità dell’articolo 143, paragrafo 2, del presente regolamento o dell’articolo 56, primo comma, del regolamento (UE) n. 1306/2013 a seguito di un’irregolarità isolata può essere riutilizzato nell’ambito della stessa operazione alle seguenti condizioni:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se l’irregolarità che dà luogo alla soppressione del contributo è individuata a livello del destinatario finale, il contributo soppresso può essere riutilizzato solo per altri destinatari finali nell’ambito dello stesso strumento finanziario;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se l’irregolarità che dà luogo alla soppressione del contributo è individuata a livello dell’intermediario finanziario in un fondo di fondi, il contributo soppresso può essere riutilizzato solo per altri intermediari finanziari.</p>\n</div>\n</div>\n</div>\n</div>\n<p class=\"norm\">Se l’irregolarità che dà luogo alla soppressione del contributo è individuata a livello dell’organismo che attua il fondo di fondi - o a livello dell’organismo che attua gli strumenti finanziari, se lo strumento finanziario è attuato mediante una struttura priva di un fondo di fondi - il contributo soppresso non può essere riutilizzato nell’ambito della stessa operazione.</p>\n<p class=\"norm\">Laddove sia effettuata una rettifica finanziaria per un’irregolarità sistemica, il contributo soppresso non può essere riutilizzato per nessuna operazione interessata da tale irregolarità sistemica.»;</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>15) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’articolo 41 è così modificato:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">al paragrafo 1, primo comma, la parte introduttiva è sostituita dalla seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«1.  </span>\n<div class=\"norm inline-element\">Per quanto riguarda gli strumenti finanziari di cui all’articolo 38, paragrafo 1, lettere a) e c), e per quanto riguarda gli strumenti finanziari di cui all’articolo 38, paragrafo 1, lettera b), attuati in conformità dell’articolo 38, paragrafo 4, primo comma, lettere a), b) e c), sono effettuate domande scaglionate di pagamento intermedio per i contributi del programma erogati allo strumento finanziario durante il periodo di ammissibilità stabilito all’articolo 65, paragrafo 2 (“periodo di ammissibilità”) conformemente alle seguenti condizioni:»;</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il paragrafo 2 è sostituito dal seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«2.  </span>\n<div class=\"norm inline-element\">Per quanto riguarda gli strumenti finanziari di cui all’articolo 38, paragrafo 1, lettera b), attuati in conformità dell’articolo 38, paragrafo 4, primo comma, lettera d), le domande di pagamento intermedio e di pagamento del saldo finale comprendono l’importo complessivo dei pagamenti effettuati dall’autorità di gestione per gli investimenti nei destinatari finali di cui all’articolo 42, paragrafo 1, primo comma, lettere a) e b).»;</div>\n</div>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>16) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’articolo 42 è così modificato:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">al paragrafo 3, il primo comma è sostituito dal seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«3.  </span>\n<div class=\"norm inline-element\">In caso di strumenti azionari mirati alle imprese di cui all’articolo 37, paragrafo 4, per i quali l’accordo di finanziamento di cui all’articolo 38, paragrafo 7, lettera b), è stato firmato prima del 31 dicembre 2018, che al termine del periodo di ammissibilità hanno investito almeno il 55 % delle risorse del programma impegnate nel pertinente accordo di finanziamento, un importo limitato di pagamenti per investimenti nei destinatari finali da effettuarsi per un periodo non superiore a quattro anni dopo la fine del periodo di ammissibilità può essere considerato una spesa ammissibile se versato in un conto di garanzia aperto specificamente a tale scopo, purché nel rispetto delle norme in materia di aiuti di Stato e nell’adempimento di tutte le condizioni in appresso.»;</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">al paragrafo 5, il primo comma è sostituito dal seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«5.  </span>\n<div class=\"norm inline-element\">Ove i costi e le commissioni di gestione di cui al paragrafo 1, primo comma, lettera d), e al paragrafo 2 del presente articolo siano applicati dall’organismo che attua il fondo di fondi o dagli organismi che attuano gli strumenti finanziari a norma dell’articolo 38, paragrafo 1, lettera c), e dell’articolo 38, paragrafo 4, primo comma, lettere a), b) e c), questi non superano i massimali definiti nell’atto delegato di cui al paragrafo 6 del presente articolo. Mentre i costi di gestione comprendono voci di costo dirette o indirette rimborsate dietro prove di spesa, le commissioni di gestione si riferiscono a un prezzo concordato per servizi resi definito attraverso un processo di mercato competitivo, se del caso. I costi e le commissioni di gestione si fondano su una metodologia di calcolo basata sulla performance.»;</div>\n</div>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>17) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">è inserito l’articolo seguente:</p>\n<p class=\"title-article-quoted\">«Articolo 43 <span class=\"norm\">bis</span>\n</p>\n<p class=\"stitle-article-quoted\">Trattamento differenziato degli investitori</p>\n<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il sostegno dei fondi SIE agli strumenti finanziari investito nei destinatari finali e le plusvalenze e gli altri rendimenti, quali interessi, commissioni di garanzia, dividendi, redditi di capitale o altri introiti generati da tali investimenti, che sono imputabili al sostegno fornito dai fondi SIE, possono essere impiegati per il trattamento differenziato di investitori operanti secondo il principio dell’economia di mercato e della BEI, quando utilizza la garanzia dell’Unione a norma del regolamento (UE) 2015/1017. Questo trattamento differenziato è giustificato dalla necessità di attrarre fondi di contropartita privati e di mobilitare finanziamenti pubblici.</div>\n</div>\n<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le valutazioni di cui agli articoli 37, paragrafo 2, e 39 <span class=\"italics\">bis</span>, paragrafo 3, comprendono, se del caso, una valutazione della necessità e dell’entità del trattamento differenziato di cui al paragrafo 1 del presente articolo e/o una descrizione dei meccanismi che saranno utilizzati per stabilire la necessità e l’entità di tale trattamento differenziato.</div>\n</div>\n<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il trattamento differenziato non supera quanto necessario per creare gli incentivi volti ad attrarre fondi di contropartita privati. Esso non compensa in eccesso gli investitori operanti secondo il principio dell’economia di mercato o la BEI, quando utilizza la garanzia dell’Unione a norma del regolamento (UE) 2015/1017. L’allineamento degli interessi è garantito mediante un’adeguata condivisione dei rischi e dei profitti.</div>\n</div>\n<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Il trattamento differenziato degli investitori operanti secondo il principio dell’economia di mercato fa salve le norme dell’Unione sugli aiuti di Stato.»;</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>18) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 44, il paragrafo 1 è sostituito dal seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Fatto salvo l’articolo 43 <span class=\"italics\">bis</span>, le risorse rimborsate agli strumenti finanziari a fronte degli investimenti o dello sblocco delle risorse impegnate per i contratti di garanzia, compresi i rimborsi in conto capitale, le plusvalenze e gli altri rendimenti, quali interessi, commissioni di garanzia, dividendi, redditi di capitale o altri introiti generati dagli investimenti, che sono imputabili al sostegno fornito dai fondi SIE, sono reimpiegate per le seguenti finalità, a concorrenza degli importi necessari e nell’ordine concordato nei pertinenti accordi di finanziamento:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">per ulteriori investimenti attraverso lo stesso strumento finanziario o altri strumenti finanziari, conformemente agli specifici obiettivi definiti nell’ambito di una priorità;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se del caso, per coprire le perdite nell’importo nominale del contributo dei fondi SIE allo strumento finanziario risultanti da un interesse negativo, se tali perdite si verificano nonostante una gestione attiva della tesoreria da parte degli organismi che attuano gli strumenti finanziari;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se del caso, per il rimborso dei costi di gestione sostenuti e per il pagamento delle commissioni di gestione dello strumento finanziario.»;</p>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>19) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 46, paragrafo 2, il primo comma è così modificato:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la lettera c) è sostituita dalla seguente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>«c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’identificazione degli organismi di attuazione degli strumenti finanziari e degli organismi di attuazione dei fondi di fondi, se del caso, di cui all’articolo 38, paragrafo 1, lettere a), b) e c);»;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le lettere g) e h) sono sostituite dalle seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>«g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli interessi e altre plusvalenze generati dal sostegno dei fondi SIE allo strumento finanziario e le risorse del programma rimborsate agli strumenti finanziari a fronte degli investimenti di cui agli articoli 43 e 44 e gli importi utilizzati per il trattamento differenziato di cui all’articolo 43 <span class=\"italics\">bis</span>;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i progressi compiuti nel conseguimento dell’atteso effetto leva degli investimenti effettuati dallo strumento finanziario;»;</p>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>20) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 49, il paragrafo 4 è sostituito dal seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«4.  </span>\n<div class=\"norm inline-element\">Il comitato di sorveglianza può formulare osservazioni all’autorità di gestione in merito all’attuazione e alla valutazione del programma, comprese azioni relative alla riduzione degli oneri amministrativi a carico dei beneficiari. Esso può altresì formulare osservazioni sulla visibilità del sostegno dei fondi SIE e sulle azioni di sensibilizzazione dei risultati di tale sostegno. Esso controlla le azioni intraprese a seguito delle sue osservazioni.»;</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>21) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 51, il paragrafo 1 è sostituito dal seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«1.  </span>\n<div class=\"norm inline-element\">Ogni anno, a partire dal 2016 e fino al 2023 compreso, è organizzata una riunione annuale di riesame tra la Commissione e ciascuno Stato membro, al fine di esaminare la performance di ciascun programma, tenendo conto, se del caso, della relazione di attuazione annuale e delle osservazioni della Commissione. Nel corso di tale riunione sono riesaminate anche le attività di comunicazione e informazione del programma, in particolare i risultati e l’efficacia delle misure adottate per informare il pubblico circa i risultati e il valore aggiunto del sostegno dei fondi SIE.»;</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>22) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 56, il paragrafo 5 è soppresso;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>23) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 57, il paragrafo 3 è sostituito dal seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«3.  </span>\n<div class=\"norm inline-element\">I paragrafi 1 e 2 del presente articolo si applicano anche ai contributi del FESR o del FEASR a favore dei programmi dedicati di cui all’articolo 39, paragrafo 4, primo comma, lettera b).»;</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>24) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 58, il paragrafo 1 è così modificato:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">al secondo comma, il riferimento «articolo 60 del regolamento finanziario» è sostituito da «articolo 154 del regolamento finanziario»;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">al terzo comma, la lettera f) è sostituita dalla seguente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>«f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">azioni di divulgazione delle informazioni, creazione di reti di sostegno, interventi di comunicazione, con particolare riferimento ai risultati e al valore aggiunto del sostegno dei fondi SIE, azioni di sensibilizzazione e azioni destinate a promuovere la cooperazione e lo scambio di esperienze, anche con paesi terzi.»;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il quarto comma è sostituito dal seguente:</p>\n<p class=\"norm\">«La Commissione dedica almeno il 15 % delle risorse di cui al presente articolo all’ottenimento di una maggiore efficienza nella comunicazione al pubblico e di più forti sinergie tra le attività di comunicazione svolte su iniziativa della Commissione medesima, ampliando la base di conoscenze sui risultati ottenuti, in particolare attraverso una raccolta e una diffusione dei dati più efficaci, valutazioni e relazioni, e soprattutto evidenziando il contributo dei fondi SIE nel migliorare le condizioni di vita delle persone, come pure aumentando la visibilità del sostegno dei fondi SIE e sensibilizzando in merito ai risultati e al valore aggiunto di tale sostegno. Le misure di informazione, comunicazione e visibilità relative ai risultati e al valore aggiunto del sostegno dei fondi SIE, con particolare riferimento alle operazioni, sono portate avanti dopo la chiusura dei programmi, se del caso. Tali misure contribuiscono anche alla comunicazione istituzionale delle priorità politiche dell’Unione nella misura in cui sono connesse agli obiettivi generali del presente regolamento;»;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">è aggiunto il comma seguente:</p>\n<p class=\"norm\">«A seconda della loro finalità, le misure di cui al presente articolo possono essere finanziate mediante spese operative o amministrative.»;</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>25) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’articolo 59 è così modificato:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">è inserito il paragrafo seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«1 <span class=\"italics\">bis</span>.  </span>\n<div class=\"norm inline-element\">Ogni fondo SIE può sostenere operazioni di assistenza tecnica ammissibili ai sensi di uno degli altri fondi SIE.»;</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">è aggiunto il paragrafo seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Fatto salvo il paragrafo 2, gli Stati membri possono attuare le azioni di cui al paragrafo 1 tramite l’aggiudicazione diretta di un contratto:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">alla BEI;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">a un’istituzione finanziaria internazionale in cui uno Stato membro detiene una partecipazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">a una banca o a un istituto di proprietà dello Stato di cui all’articolo 38, paragrafo 4, primo comma, lettera b), punto iii).»;</p>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>26) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’articolo 61 è così modificato:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">al paragrafo 1, il primo comma è sostituito dal seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«1.  </span>\n<div class=\"norm inline-element\">Il presente articolo si applica alle operazioni che generano entrate nette dopo il loro completamento. Ai fini del presente articolo, per «entrate nette» si intendono i flussi finanziari in entrata pagati direttamente dagli utenti per beni o servizi forniti dall’operazione, quali le tariffe direttamente a carico degli utenti per l’utilizzo dell’infrastruttura, la vendita o la locazione di terreni o immobili o i pagamenti per i servizi detratti gli eventuali costi operativi e costi di sostituzione di attrezzature con ciclo di vita breve sostenuti durante il periodo corrispondente. I risparmi sui costi operativi generati dall’operazione, con l’eccezione dei risparmi sui costi risultanti dall’attuazione di misure di efficienza energetica, sono trattati come entrate nette a meno che non siano compensati da una pari riduzione delle sovvenzioni per il funzionamento.»;</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">al paragrafo 3, primo comma, è inserita la lettera seguente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>«a <span class=\"italics\">bis</span>) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">applicazione di un tasso forfettario di entrate nette stabilito da uno Stato membro per un settore o sottosettore non contemplato dalla lettera a). Prima che sia applicato il tasso forfettario, l’autorità di audit responsabile verifica che tale tasso sia stato stabilito secondo un metodo giusto, equo e verificabile basato su dati storici o criteri oggettivi;»;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il paragrafo 5 è sostituito dal seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«5.  </span>\n<div class=\"norm inline-element\">In alternativa all’applicazione dei metodi di cui al paragrafo 3 del presente articolo, il tasso massimo di cofinanziamento di cui all’articolo 60, paragrafo 1, può essere ridotto, su richiesta di uno Stato membro, per una priorità o misura nell’ambito della quale tutte le operazioni che ricevono un sostegno potrebbero applicare un tasso forfettario uniforme conformemente al paragrafo 3, primo comma, lettera a), del presente articolo. Tale riduzione non è inferiore all’importo calcolato moltiplicando il tasso massimo di cofinanziamento dell’Unione applicabile in virtù delle norme specifiche di ciascun fondo per il pertinente tasso forfettario di cui a tale lettera a).»;</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">al paragrafo 7, primo comma, la lettera h) è sostituita dalla seguente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>«h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">alle operazioni per le quali gli importi o i tassi del sostegno sono definiti nell’allegato II del regolamento FEASR o nel regolamento FEAMP.»;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il paragrafo 8 è sostituito dal seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«8.  </span>\n<div class=\"norm inline-element\">Inoltre, i paragrafi da 1 a 6 non si applicano alle operazioni per le quali il sostegno nell’ambito di un programma costituisce un aiuto di Stato.»;</div>\n</div>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>27) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’articolo 65 è così modificato:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il terzo comma del paragrafo 8 è così modificato:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la lettera h) è sostituita dalla seguente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>«h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">alle operazioni per le quali gli importi o i tassi del sostegno sono definiti nell’allegato II del regolamento FEASR o nel regolamento FEAMP, a eccezione delle operazioni per le quali il regolamento FEAMP fa riferimento al presente paragrafo; o»;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la lettera i) è sostituita dalla seguente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>«i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">alle operazioni per le quali i costi totali ammissibili non superino 100 000  EUR.»;</p>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il paragrafo 11 è sostituito dal seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«11.  </span>\n<div class=\"norm inline-element\">Un’operazione può ricevere sostegno da uno o più fondi SIE oppure da uno o più programmi e da altri strumenti dell’Unione, purché la spesa dichiarata in una domanda di pagamento per uno dei fondi SIE non sia dichiarata per il sostegno di un altro fondo o strumento dell’Unione, o dello stesso fondo nell’ambito di un altro programma. L’importo della spesa da indicare in una domanda di pagamento di un fondo SIE può essere calcolato per ciascun fondo SIE e per il programma o i programmi interessati su base proporzionale, conformemente al documento che specifica le condizioni per il sostegno.»;</div>\n</div>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>28) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’articolo 67 è così modificato:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il paragrafo 1 è così modificato:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la lettera c) è sostituita dalla seguente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>«c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">somme forfettarie;»;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">è aggiunta la lettera seguente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>«e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">finanziamenti che non sono collegati ai costi delle operazioni pertinenti, ma si basano sul rispetto delle condizioni connesse alla realizzazione di progressi nell’attuazione o nel conseguimento degli obiettivi dei programmi di cui all’atto delegato adottato in conformità del paragrafo 5 <span class=\"italics\">bis</span>.»</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">è aggiungo il comma seguente:</p>\n<p class=\"norm\">«Per la forma di finanziamento di cui al primo comma, lettera e), l’audit mira esclusivamente a verificare che siano state soddisfatte le condizioni per il rimborso.»;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">è inserito il paragrafo seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«<span class=\"italics\">2 bis</span>.  </span>\n<div class=\"norm inline-element\">Nel caso di operazioni o progetti non coperti dalla prima frase del paragrafo 4 e che ricevono sostegno dal FESR e dall’FSE, le sovvenzioni e l’assistenza rimborsabile per le quali il sostegno pubblico non supera 100 000  EUR assumono la forma di tabelle standard di costi unitari, somme forfettarie o tassi forfettari, fatta eccezione per le operazioni che ricevono sostegno nell’ambito di aiuti di Stato che non costituiscono aiuti <span class=\"italics\">de minimis</span>.</div>\n</div>\n<p class=\"norm\">Qualora si ricorra a finanziamenti a tasso forfettario, le categorie di costi a cui è applicato il tasso forfettario possono essere rimborsate conformemente al paragrafo 1, primo comma, lettera a).</p>\n<p class=\"norm\">Per operazioni sostenute dal FEASR, dal FESR o dall’FSE, quando si ricorre al tasso forfettario di cui all’articolo 68 <span class=\"italics\">ter</span>, paragrafo 1, le indennità e le retribuzioni pagate ai partecipanti possono essere rimborsate conformemente al paragrafo 1, primo comma, lettera a), del presente articolo.</p>\n<p class=\"norm\">Il presente paragrafo è soggetto alle disposizioni transitorie di cui all’articolo 152, paragrafo 7.»;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il paragrafo 4 è sostituito dal seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«4.  </span>\n<div class=\"norm inline-element\">Laddove un’operazione o un progetto facente parte di un’operazione sia attuato esclusivamente tramite appalti pubblici di lavori, beni o servizi, si applica solo il paragrafo 1, primo comma, lettere a) ed e). Laddove l’appalto pubblico nell’ambito di un’operazione o di un progetto facente parte di un’operazione sia limitato a determinate categorie di costi, tutte le opzioni di cui al paragrafo 1 sono applicabili all’intera operazione o progetto facente parte di un’operazione.»;</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il paragrafo 5 è così modificato:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la lettera a) è sostituita dalla seguente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>«a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un metodo di calcolo giusto, equo e verificabile, basato:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">su dati statistici, altre informazioni oggettive o valutazioni di esperti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">su dati storici verificati dei singoli beneficiari;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sull’applicazione delle consuete prassi contabili dei singoli beneficiari;»;</p>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">è inserita la lettera seguente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>«a <span class=\"italics\">bis</span>) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un progetto di bilancio redatto caso per caso e approvato ex ante dall’autorità di gestione o, nel caso del FEASR, dall’autorità competente per la selezione delle operazioni, ove il sostegno pubblico non superi 100 000  EUR;»;</p>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">è inserito il paragrafo seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«5 <span class=\"italics\">bis</span>.  </span>\n<div class=\"norm inline-element\">Alla Commissione è conferito il potere di adottare atti delegati conformemente all’articolo 149 per integrare il presente regolamento per quanto concerne la definizione delle tabelle standard di costi unitari o dei finanziamenti a tasso forfettario di cui al paragrafo 1, primo comma, lettere b) e d), del presente articolo, i relativi metodi di cui al paragrafo 5, lettera a), del presente articolo e la forma di sostegno di cui al paragrafo 1, primo comma, lettera e), del presente articolo, precisando le modalità dettagliate relative alle condizioni di finanziamento e alla loro applicazione.»;</div>\n</div>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>29) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’articolo 68 è sostituito dal seguente:</p>\n<p class=\"title-article-quoted\">«Articolo 68</p>\n<p class=\"stitle-article-quoted\">Finanziamento a tasso forfettario dei costi indiretti in materia di sovvenzioni e assistenza rimborsabile</p>\n<p class=\"norm\">Laddove l’esecuzione di un’operazione dia origine a costi indiretti, questi ultimi possono essere calcolati forfettariamente in uno dei seguenti modi:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un tasso forfettario fino al 25 % dei costi diretti ammissibili, a condizione che sia calcolato sulla base di un metodo giusto, equo e verificabile o di un metodo applicato nell’ambito di regimi di sovvenzione finanziati interamente dallo Stato membro per una tipologia analoga di operazione e beneficiario;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un tasso forfettario fino al 15 % dei costi diretti ammissibili per il personale, senza che vi sia un obbligo per lo Stato membro di eseguire un calcolo per determinare il tasso applicabile;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un tasso forfettario applicato ai costi diretti ammissibili basato su metodi esistenti e percentuali corrispondenti applicabili nelle politiche dell’Unione per una tipologia analoga di operazione e beneficiario.</p>\n</div>\n</div>\n<p class=\"norm\">Alla Commissione è conferito il potere di adottare atti delegati conformemente all’articolo 149 per integrare le disposizioni sul tasso forfettario e i relativi metodi di cui al primo comma, lettera c), del presente paragrafo.»;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>30) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sono inseriti gli articoli seguenti:</p>\n<p class=\"title-article-quoted\">«Articolo 68 <span class=\"norm\">bis</span>\n</p>\n<p class=\"stitle-article-quoted\">Costi per il personale in materia di sovvenzioni e assistenza rimborsabile</p>\n<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">I costi diretti per il personale di un’operazione possono essere calcolati in base a un tasso forfettario fino al 20 % dei costi diretti di tale operazione diversi dai costi per il personale. Gli Stati membri non sono tenuti a eseguire un calcolo per determinare il tasso applicabile, purché i costi diretti dell’operazione non comprendano appalti pubblici di lavori di valore superiore alla soglia di cui all’articolo 4, lettera a), della direttiva 2014/24/UE.</div>\n</div>\n<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Ai fini della determinazione dei costi per il personale, una tariffa oraria può essere calcolata dividendo per 1 720  ore i più recenti costi annui lordi per l’impiego documentati, per le persone che lavorano a tempo pieno, o per la quota proporzionale corrispondente di 1 720  ore, per le persone che lavorano a tempo parziale.</div>\n</div>\n<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Quando si applica la tariffa oraria calcolata in conformità del paragrafo 2, il numero complessivo di ore dichiarate per persona per un determinato anno non supera il numero di ore utilizzate per il calcolo di tale tariffa oraria.</div>\n</div>\n<p class=\"norm\">Il primo comma non si applica ai programmi a titolo dell’obiettivo Cooperazione territoriale europea per quanto riguarda i costi per il personale relativi a persone che lavorano con un incarico a tempo parziale nell’ambito dell’operazione.</p>\n<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Qualora non siano disponibili, i costi annui lordi per l’impiego possono essere desunti dai costi lordi per l’impiego documentati disponibili o dal contratto di lavoro, debitamente adeguati in base a un periodo di 12 mesi.</div>\n</div>\n<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">I costi per il personale relativi a persone che lavorano con un incarico a tempo parziale nell’ambito dell’operazione possono essere calcolati come percentuale fissa dei costi lordi per l’impiego, corrispondente a una percentuale fissa delle ore di lavoro impiegate nell’ambito dell’operazione su base mensile, senza l’obbligo di istituire un sistema separato di registrazione dell’orario di lavoro. Il datore di lavoro rilascia ai dipendenti un documento che stabilisce tale percentuale fissa.</div>\n</div>\n<p class=\"title-article-quoted\">Articolo 68 <span class=\"norm\">ter</span>\n</p>\n<p class=\"stitle-article-quoted\">Finanziamento a tasso forfettario dei costi diversi dai costi per il personale</p>\n<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Un tasso forfettario fino al 40 % dei costi diretti ammissibili per il personale può essere utilizzato per coprire i costi ammissibili residui di un’operazione senza che vi sia un obbligo per lo Stato membro di eseguire un calcolo per determinare il tasso applicabile.</div>\n</div>\n<p class=\"norm\">Per le operazioni sostenute dall’FSE, dal FESR o dal FEASR le retribuzioni e le indennità versate ai partecipanti sono considerate costi ammissibili aggiuntivi non inclusi nel tasso forfettario.</p>\n<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Il tasso forfettario di cui al paragrafo 1 non è applicato ai costi per il personale calcolati in base a un tasso forfettario.»;</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>31) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’articolo 70 è sostituito dal seguente:</p>\n<p class=\"title-article-quoted\">«Articolo 70</p>\n<p class=\"stitle-article-quoted\">Ammissibilità delle operazioni a seconda dell’ubicazione</p>\n<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Fatte salve le deroghe di cui al paragrafo 2 e le norme specifiche di ciascun fondo, le operazioni sostenute dai fondi SIE sono ubicate nell’area del programma.</div>\n</div>\n<p class=\"norm\">Le operazioni riguardanti la prestazione di servizi a cittadini o imprese che coprono l’intero territorio di uno Stato membro sono considerate ubicate in tutte le aree del programma all’interno di uno Stato membro. In questi casi le spese sono assegnate proporzionalmente alle aree del programma interessate, secondo criteri oggettivi.</p>\n<p class=\"norm\">Il secondo comma del presente paragrafo non si applica al programma nazionale di cui all’articolo 6, paragrafo 2, del regolamento (UE) n. 1305/2013 o al programma specifico per l’istituzione e la gestione della rete rurale nazionale di cui all’articolo 54, paragrafo 1, di detto regolamento.</p>\n<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">L’autorità di gestione può accettare che un’operazione sia attuata al di fuori dell’area del programma ma sempre all’interno dell’Unione, purché siano soddisfatte tutte le seguenti condizioni:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’operazione è a vantaggio dell’area del programma;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’importo complessivo a titolo del FESR, del fondo di coesione, del FEASR o del FEAMP destinato dal programma a operazioni ubicate fuori dall’area del programma non supera il 15 % del sostegno del FESR, del Fondo di coesione, del FEASR o del FEAMP a livello di priorità al momento dell’adozione del programma;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il comitato di sorveglianza ha dato il suo consenso all’operazione o al tipo di operazioni interessate;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le autorità responsabili per il programma nell’ambito del quale è finanziata l’operazione soddisfano gli obblighi posti a carico di tali autorità per quanto concerne la gestione, il controllo e l’audit o stipulano accordi con autorità nell’area in cui si svolge l’operazione.</p>\n</div>\n</div>\n</div>\n</div>\n<p class=\"norm\">Qualora le operazioni finanziate a titolo dei fondi e del FEAMP siano attuate fuori dall’area del programma in conformità del presente paragrafo e apportino benefici sia all’esterno che all’interno dell’area del programma, tali spese sono assegnate proporzionalmente a tali aree secondo criteri oggettivi.</p>\n<p class=\"norm\">Qualora le operazioni riguardino l’obiettivo tematico di cui all’articolo 9, primo comma, punto 1), e siano attuate all’esterno dello Stato membro ma sempre all’interno dell’Unione, si applicano soltanto le lettere b) e d) del primo comma del presente paragrafo.</p>\n<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Per le operazioni concernenti attività di assistenza tecnica o misure di informazione, comunicazione e visibilità e attività promozionali, e per le operazioni relative all’obiettivo tematico di cui all’articolo 9, primo comma, punto 1), è possibile sostenere spese al di fuori dell’Unione, purché siano necessarie per la buona esecuzione dell’operazione.</div>\n</div>\n<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">I paragrafi 1, 2 e 3 non si applicano ai programmi nell’ambito dell’obiettivo Cooperazione territoriale europea. I paragrafi 2 e 3 non si applicano alle operazioni sostenute dall’FSE.»;</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>32) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 71, il paragrafo 4 è sostituito dal seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«4.  </span>\n<div class=\"norm inline-element\">I paragrafi 1, 2 e 3 del presente articolo non si applicano ai contributi forniti a o da strumenti finanziari, al leasing ai sensi dell’articolo 45, paragrafo 2, lettera b), del regolamento (UE) n. 1305/2013 né a operazioni per le quali si verifichi la cessazione di un’attività produttiva a causa di un fallimento non fraudolento.»;</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>33) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’articolo 75 è così modificato:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">al paragrafo 1, il riferimento «articolo 59, paragrafo 5, del regolamento finanziario» è sostituito da «articolo 63, paragrafi 5, 6 e 7, del regolamento finanziario»;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">è inserito il paragrafo seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«<span class=\"italics\">2 bis</span>.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">La Commissione fornisce alla competente autorità nazionale:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il progetto di relazione di audit risultante da un audit o un controllo sul posto entro tre mesi dalla fine di tale audit o controllo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la relazione di audit definitiva entro tre mesi dal ricevimento di una risposta completa da parte della competente autorità nazionale in merito al progetto di relazione di audit risultante dall’audit o dal controllo sul posto in questione;</p>\n</div>\n</div>\n</div>\n</div>\n<p class=\"norm\">Le relazioni di cui al primo comma, lettere a) e b), sono messe a disposizione entro i termini di cui a dette lettere in almeno una delle lingue ufficiali delle istituzioni dell’Unione.</p>\n<p class=\"norm\">Il termine di cui al primo comma, lettera a), non comprende il periodo che ha inizio il giorno successivo alla data in cui la Commissione invia la sua richiesta di informazioni supplementari allo Stato membro e si estende fin quando lo Stato membro non risponde a tale richiesta.</p>\n<p class=\"norm\">Il presente paragrafo non è applicabile al FEASR.»;</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>34) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 76, secondo comma, il riferimento «articolo 84, paragrafo 2, del regolamento finanziario» è sostituito da «articolo 110, paragrafo 1, del regolamento finanziario»;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>35) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 79, paragrafo 2, il riferimento «articolo 68, paragrafo 3, del regolamento finanziario» è sostituito da «articolo 82, paragrafo 2, del regolamento finanziario»;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>36) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 83, paragrafo 1, primo comma, lettera c), il riferimento «articolo 59, paragrafo 5, del regolamento finanziario» è sostituito da «articolo 63, paragrafi 5, 6 e 7, del regolamento finanziario»;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>37) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 84, il riferimento «articolo 59, paragrafo 6, del regolamento finanziario» è sostituito da «articolo 63, paragrafo 8, del regolamento finanziario»;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>38) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 98, il paragrafo 2 è sostituito dal seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«2.  </span>\n<div class=\"norm inline-element\">Il FESR e l’FSE possono finanziare, in modo complementare ed entro un limite del 10 % del finanziamento dell’Unione per ciascun asse prioritario di un programma operativo, parte di un’operazione i cui costi sono ammissibili al sostegno dell’altro fondo sulla base delle norme applicate a tale fondo, a condizione che tali costi siano necessari per la buona esecuzione dell’operazione e siano direttamente associati a essa.»;</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>39) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’articolo 102 è così modificato:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il paragrafo 6 è sostituito dal seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«6.  </span>\n<div class=\"norm inline-element\">La spesa relativa a un grande progetto può essere inclusa in una domanda di pagamento successivamente alla presentazione per l’approvazione di cui al paragrafo 2. Qualora la Commissione non approvi il grande progetto selezionato dall’autorità di gestione, la dichiarazione di spesa successiva al ritiro della domanda da parte dello Stato membro o all’adozione della decisione della Commissione è rettificata di conseguenza.»;</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">è aggiunto il paragrafo seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«7.  </span>\n<div class=\"norm inline-element\">Qualora un grande progetto sia valutato da esperti indipendenti a norma del paragrafo 1 del presente articolo, la spesa relativa al progetto può essere inclusa in una domanda di pagamento dopo che l’autorità di gestione ha informato la Commissione dell’avvenuta comunicazione agli esperti indipendenti delle informazioni richieste a norma dell’articolo 101.</div>\n</div>\n<p class=\"norm\">Un’analisi indipendente della qualità dev’essere consegnata entro sei mesi dalla comunicazione delle informazioni agli esperti indipendenti.</p>\n<p class=\"norm inline-element\">Le spese corrispondenti sono ritirate e la dichiarazione di spesa è rettificata di conseguenza nei seguenti casi:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se l’analisi indipendente della qualità non è stata trasmessa alla Commissione entro tre mesi dalla scadenza del termine di cui al secondo comma;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se lo Stato membro ritira la comunicazione delle informazioni; o</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">se la valutazione pertinente è negativa.»;</p>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>40) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 104, i paragrafi 2 e 3 sono sostituiti dai seguenti:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«2.  </span>\n<div class=\"norm inline-element\">La spesa pubblica destinata a un piano d’azione comune è pari ad almeno 5 000 000  EUR o al 5 % del sostegno pubblico al programma operativo o a uno dei programmi partecipanti, se inferiore.</div>\n</div>\n<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il paragrafo 2 non si applica alle operazioni sostenute a titolo dell’IOG, al primo piano d’azione comune presentato da uno Stato membro nell’ambito dell’obiettivo Investimenti a favore della crescita e dell’occupazione o al primo piano d’azione comune presentato da un programma nell’ambito dall’obiettivo cooperazione territoriale europea.»;</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>41) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 105, paragrafo 2, la seconda frase è soppressa;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>42) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 106, il primo comma è così modificato:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il punto 1) è sostituito dal seguente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>«1) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una descrizione degli obiettivi del piano d’azione comune e di come esso contribuisce agli obiettivi del programma o alle pertinenti raccomandazioni specifiche per paese, degli indirizzi di massima per le politiche economiche degli Stati membri e dell’Unione ai sensi dell’articolo 121, paragrafo 2, TFUE e delle pertinenti raccomandazioni del Consiglio di cui gli Stati membri devono tener conto nelle politiche per l’occupazione a norma dell’articolo 148, paragrafo 4, TFUE;»;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il punto 2) è soppresso;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il punto 3 è sostituito dal seguente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>«3) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">una descrizione dei progetti o dei tipi di progetti previsti, unitamente, se del caso, ai target intermedi e ai target finali in termini di realizzazioni e risultati legati agli indicatori comuni per asse prioritario;»;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i punti 6), 7) e 8) sono sostituiti dai seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>«6) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la conferma che contribuirà all’approccio volto a promuovere la parità tra uomini e donne, come previsto nel pertinente programma o accordo di partenariato;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>7) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la conferma che contribuirà all’approccio sullo sviluppo sostenibile, come previsto nel pertinente programma o accordo di partenariato;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>8) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le sue disposizioni di esecuzione, comprendenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le informazioni sulla selezione del piano d’azione comune da parte dell’autorità di gestione, conformemente all’articolo 125, paragrafo 3;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le modalità di conduzione del piano d’azione comune, conformemente all’articolo 108;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le modalità di sorveglianza e valutazione del piano d’azione comune, comprese le disposizioni volte a garantire la qualità, la raccolta e la conservazione dei dati sul conseguimento dei target intermedi, delle realizzazioni e dei risultati;»;</p>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il punto 9) è così modificato:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la lettera a) è sostituita dalla seguente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>«a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i costi da sostenere per conseguire i target intermedi e finali in termini di realizzazioni e risultati, nel caso di tabelle standard di costi unitari e somme forfettarie, in base ai metodi di cui all’articolo 67, paragrafo 5, del presente regolamento e all’articolo 14 del regolamento FSE;»;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la lettera b) è soppressa;</p>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>43) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 107, il paragrafo 3 è sostituito dal seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«3.  </span>\n<div class=\"norm inline-element\">La decisione di cui al paragrafo 2 indica il beneficiario e gli obiettivi del piano d’azione comune, i target intermedi, ove pertinente, e i target finali in termini di realizzazioni e risultati, i costi per conseguire tali target intermedi e finali in termini di realizzazioni e risultati e il piano di finanziamento per ciascun programma operativo e asse prioritario, compreso l’importo complessivo ammissibile e l’ammontare della spesa pubblica, il periodo di esecuzione del piano d’azione comune e, se pertinente, la copertura geografica e i gruppi di destinatari del piano d’azione comune.»;</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>44) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 108, paragrafo 1, il primo comma è sostituito dal seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«1.  </span>\n<div class=\"norm inline-element\">Lo Stato membro o l’autorità di gestione istituisce un comitato direttivo del piano d’azione comune, che può essere diverso dal comitato di sorveglianza dei pertinenti programmi operativi. Il comitato direttivo si riunisce almeno due volte l’anno e riferisce all’autorità di gestione. Se del caso, l’autorità di gestione informa il comitato di sorveglianza competente dei risultati del lavoro svolto dal comitato direttivo e dei progressi nell’attuazione del piano d’azione comune in conformità dell’articolo 110, paragrafo 1, lettera e), e dell’articolo 125, paragrafo 2, lettera a).»;</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>45) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 109, la seconda frase è soppressa;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>46) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’articolo 110 è così modificato:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">al paragrafo 1, la lettera c) è sostituita dalla seguente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>«c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’attuazione della strategia di comunicazione, comprese le misure di informazione e comunicazione, e delle misure volte a migliorare la visibilità dei fondi;»;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">al paragrafo 2, la lettera a) è sostituita dalla seguente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>«a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la metodologia e i criteri usati per la selezione delle operazioni, tranne se tali criteri sono approvati da gruppi di azione locale in conformità dell’articolo 34, paragrafo 3, lettera c);»;</p>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>47) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’articolo 114 è così modificato:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il paragrafo 1 è sostituito dal seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«1.  </span>\n<div class=\"norm inline-element\">L’autorità di gestione o lo Stato membro preparano un piano di valutazione per uno o più programmi operativi. Il piano di valutazione è presentato al comitato di sorveglianza al più tardi entro un anno dall’adozione del programma operativo. Nel caso dei programmi dedicati di cui all’articolo 39, paragrafo 4, primo comma, lettera b), adottati prima del 2 agosto 2018, il piano di valutazione è presentato al comitato di sorveglianza entro un anno da tale data.»;</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il paragrafo 4 è soppresso;</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>48) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’intestazione della parte terza, titolo III, capo II, è sostituita dalla seguente:</p>\n<p class=\"norm\">«Informazione, comunicazione e visibilità»;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>49) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’articolo 115 è così modificato:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la rubrica è sostituita dalla seguente:</p>\n<p class=\"stitle-article-quoted\">«Informazione, comunicazione e visibilità»;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">al paragrafo 1, la lettera d) è sostituita dalla seguente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>«d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">pubblicizzare presso i cittadini dell’Unione il ruolo e le realizzazioni della politica di coesione e dei fondi mediante misure volte a migliorare la visibilità dei risultati e dell’impatto degli accordi di partenariato, dei programmi operativi e delle operazioni.»;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il paragrafo 3 è sostituito dal seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«3.  </span>\n<div class=\"norm inline-element\">Le norme dettagliate concernenti l’informazione, la comunicazione e la visibilità destinate al pubblico e le misure di informazione rivolte ai beneficiari potenziali e ai beneficiari sono contenute nell’allegato XII.»;</div>\n</div>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>50) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 116, il paragrafo 3 è sostituito dal seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«3.  </span>\n<div class=\"norm inline-element\">In deroga al paragrafo 2, terzo comma, del presente articolo, l’autorità di gestione informa il comitato o i comitati di sorveglianza responsabili almeno una volta all’anno in merito ai progressi nell’attuazione della strategia di comunicazione di cui all’articolo 110, paragrafo 1, lettera c), e in merito alla sua analisi dei risultati di tale attuazione, nonché circa le attività di informazione e comunicazione e le misure per migliorare la visibilità dei fondi, che sono pianificate per l’anno successivo. Il comitato di sorveglianza esprime un parere in merito alle attività e alle misure pianificate per l’anno successivo, ivi inclusi i modi per aumentare l’efficacia delle attività di comunicazione rivolte al pubblico.»;</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>51) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 117, il paragrafo 4 è sostituito dal seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«4.  </span>\n<div class=\"norm inline-element\">La Commissione istituisce reti a livello dell’Unione che comprendono le persone designate dagli Stati membri, al fine di garantire lo scambio di informazioni sui risultati dell’attuazione delle strategie di comunicazione, lo scambio di esperienze nell’attuazione delle misure di informazione e di comunicazione e lo scambio di buone prassi, nonché al fine di consentire la pianificazione congiunta o il coordinamento delle attività di comunicazione tra gli Stati membri e con la Commissione, ove opportuno. Almeno una volta all’anno le reti discutono e valutano l’efficacia delle misure di informazione e comunicazione e propongono raccomandazioni per migliorare la portata e l’impatto delle attività di comunicazione e per sensibilizzare in merito ai risultati e al valore aggiunto di tali attività.»;</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>52) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’articolo 119 è così modificato:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">al paragrafo 1, il primo comma è sostituito dal seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«1.  </span>\n<div class=\"norm inline-element\">L’ammontare dei fondi destinato all’assistenza tecnica in uno Stato membro è limitato al 4 % dell’importo complessivo dei fondi assegnato ai programmi operativi nell’ambito dell’obiettivo Investimenti a favore della crescita e dell’occupazione.»;</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">al paragrafo 2, la prima frase è soppressa;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il paragrafo 4 è sostituito dal seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«4.  </span>\n<div class=\"norm inline-element\">Nel caso dei fondi strutturali, qualora le dotazioni di cui al paragrafo 1 siano utilizzate a sostegno di operazioni di assistenza tecnica riguardanti nel loro insieme più di una categoria di regioni, le spese relative alle operazioni possono essere eseguite nell’ambito di un asse prioritario che combina diverse categorie di regioni e assegnate su base proporzionale tenendo conto delle rispettive assegnazioni alle diverse categorie di regioni del programma operativo o della dotazione nell’ambito di ciascuna categoria di regioni come percentuale della dotazione complessiva destinata allo Stato membro.»;</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">è inserito il paragrafo seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«5 <span class=\"italics\">bis</span>.  </span>\n<div class=\"norm inline-element\">La valutazione del rispetto delle percentuali è effettuata al momento dell’adozione del programma operativo.»;</div>\n</div>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>53) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 122, paragrafo 2, il quarto comma è sostituito dal seguente:</p>\n<p class=\"norm\">«Quando un importo indebitamente versato a un beneficiario per un’operazione non può essere recuperato per colpa o negligenza di uno Stato membro, spetta a quest’ultimo rimborsare l’importo in questione al bilancio dell’Unione. Gli Stati membri possono decidere di non recuperare un importo versato indebitamente se l’importo che deve essere recuperato presso il beneficiario non supera, al netto degli interessi, 250 EUR di contributo dei fondi a un’operazione in un esercizio contabile.»;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>54) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 123, paragrafo 5, il primo comma è sostituito dal seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«5.  </span>\n<div class=\"norm inline-element\">Nel caso dei fondi e del FEAMP, purché sia rispettato il principio della separazione delle funzioni, l’autorità di gestione, l’autorità di certificazione, se del caso, e l’autorità di audit possono fare parte della stessa autorità pubblica o dello stesso organismo pubblico.»;</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>55) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’articolo 125 è così modificato:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">al paragrafo 3, la lettera c) è sostituita dalla seguente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>«c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">provvede affinché sia fornito al beneficiario un documento contenente le condizioni per il sostegno relative a ciascuna operazione, compresi i requisiti specifici concernenti i prodotti o servizi da fornire nell’ambito dell’operazione, il piano finanziario, il termine per l’esecuzione, come pure i requisiti riguardanti l’informazione, la comunicazione e la visibilità;»;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il paragrafo 4, primo comma, è così modificato:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la lettera a) è sostituita dalla seguente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>«a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">verifica che i prodotti e i servizi cofinanziati siano stati forniti e che l’operazione sia conforme al diritto applicabile, al programma operativo e alle condizioni per il sostegno dell’operazione e:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">qualora i costi debbano essere rimborsati ai sensi dell’articolo 67, paragrafo 1, primo comma, lettera a), che l’importo della spesa dichiarata dai beneficiari in relazione a tali costi sia stato pagato;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nel caso di costi rimborsati a norma dell’articolo 67, paragrafo 1, primo comma, lettere da b) a e), che siano state rispettate le condizioni per il rimborso della spesa al beneficiario;»;</p>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">alla lettera e), il riferimento «articolo 59, paragrafo 5, lettere a) e b), del regolamento finanziario» è sostituito da «articolo 63, paragrafo 5, lettere a) e b), e articolo 63, paragrafi 6 e 7, del regolamento finanziario»;</p>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>56) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 126, lettera b), il riferimento «articolo 59, paragrafo 5, lettera a), del regolamento finanziario» è sostituito da «articolo 63, paragrafo 5, lettera a), e articolo 63, paragrafo 6, del regolamento finanziario»;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>57) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’articolo 127 è così modificato:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">al paragrafo 1, terzo comma, il riferimento «articolo 59, paragrafo 5, secondo comma, del regolamento finanziario» è sostituito da «articolo 63, paragrafo 7, del regolamento finanziario»;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">al paragrafo 5, primo comma, lettera a), il riferimento «articolo 59, paragrafo 5, secondo comma, del regolamento finanziario» è sostituito da «articolo 63, paragrafo 7, del regolamento finanziario»;</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>58) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’articolo 131 è sostituito dal seguente:</p>\n<p class=\"title-article-quoted\">«Articolo 131</p>\n<p class=\"stitle-article-quoted\">Domande di pagamento</p>\n<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Le domande di pagamento comprendono, per ciascuna priorità:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’importo totale delle spese ammissibili sostenute dal beneficiario e pagate nell’attuazione delle operazioni, come contabilizzato nel sistema contabile dell’autorità di certificazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’importo totale della spesa pubblica relativa all’attuazione delle operazioni, come contabilizzato nel sistema contabile dell’autorità di certificazione.</p>\n</div>\n</div>\n</div>\n</div>\n<p class=\"norm\">Per quanto concerne gli importi da includere nelle domande di pagamento in relazione alle forme di sostegno di cui all’articolo 67, paragrafo 1, primo comma, lettera e), le domande di pagamento comprendono gli elementi di cui agli atti delegati adottati in conformità dell’articolo 67, paragrafo 5 <span class=\"italics\">bis</span>, e utilizzano i modelli per le domande di pagamento di cui agli atti di esecuzione adottati in conformità del paragrafo 6 del presente articolo.</p>\n<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Le spese ammissibili contenute in una domanda di pagamento sono giustificate da fatture quietanzate o da documenti contabili di valore probatorio equivalente, salvo per le forme di sostegno di cui all’articolo 67, paragrafo 1, primo comma, lettere da b) a e), del presente regolamento, agli articoli 68, 68 <span class=\"italics\">bis</span> e 68 <span class=\"italics\">ter</span> del presente regolamento, all’articolo 69, paragrafo 1, del presente regolamento e all’articolo 109 del presente regolamento e all’articolo 14 del regolamento FSE. Per tali forme di sostegno, gli importi indicati nella domanda di pagamento sono i costi calcolati sulla base applicabile.</div>\n</div>\n<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Nel caso degli aiuti di Stato, il contributo pubblico corrispondente alle spese contenute in una domanda di pagamento è stato versato ai beneficiari dall’organismo che concede l’aiuto oppure, qualora gli Stati membri abbiano deciso che il beneficiario è l’organismo che concede l’aiuto a norma dell’articolo 2, punto 10, lettera a), è stato versato dal beneficiario all’organismo che riceve l’aiuto.</div>\n</div>\n<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">In deroga al paragrafo 1 del presente articolo, nel caso degli aiuti di Stato, la domanda di pagamento può includere gli anticipi versati al beneficiario dall’organismo che concede l’aiuto oppure, qualora gli Stati membri abbiano deciso che il beneficiario è l’organismo che concede l’aiuto a norma dell’articolo 2, punto 10), lettera a), gli anticipi versati dal beneficiario all’organismo che riceve l’aiuto, alle seguenti condizioni cumulative:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">tali anticipi sono soggetti a una garanzia fornita da una banca o da qualunque altra istituzione finanziaria stabilita in uno Stato membro o sono coperti da uno strumento fornito a garanzia da un ente pubblico o dallo Stato membro;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">tali anticipi non eccedono il 40 % dell’importo totale dell’aiuto da concedere a un beneficiario per una determinata operazione oppure, qualora gli Stati membri abbiano deciso che il beneficiario è l’organismo che concede l’aiuto a norma dell’articolo 2, punto 10, lettera a), il 40 % dell’importo totale dell’aiuto da concedere all’organismo che riceve l’aiuto nell’ambito di una determinata operazione;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">tali anticipi sono coperti dalle spese sostenute dal beneficiario oppure, qualora gli Stati membri abbiano deciso che il beneficiario è l’organismo che concede l’aiuto a norma dell’articolo 2, punto 10), lettera a), dalle spese sostenute dall’organismo che riceve l’aiuto nell’attuazione dell’operazione, e sono giustificati da fatture quietanzate o da documenti contabili di valore probatorio equivalente presentati entro tre anni dall’anno in cui è stato versato l’anticipo oppure entro il 31 dicembre 2023, se anteriore;</p>\n</div>\n</div>\n</div>\n</div>\n<p class=\"norm\">Qualora le condizioni di cui al primo comma, lettera c), non siano soddisfatte, la successiva domanda di pagamento è rettificata di conseguenza.</p>\n<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Ciascuna domanda di pagamento contenente gli anticipi del tipo di cui al paragrafo 4 del presente articolo indica separatamente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’importo complessivo versato come anticipo dal programma operativo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’importo che entro tre anni dal pagamento dell’anticipo in conformità del paragrafo 4, primo comma, lettera c), è stato coperto dalle spese sostenute dal beneficiario oppure, qualora gli Stati membri abbiano deciso che il beneficiario è l’organismo che concede l’aiuto a norma dell’articolo 2, punto 10), lettera a), dall’organismo che riceve l’aiuto; e</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’importo che non è stato coperto dalle spese pagate dal beneficiario oppure, qualora gli Stati membri abbiano deciso che il beneficiario è l’organismo che concede l’aiuto a norma dell’articolo 2, punto 10), lettera a), dall’organismo che riceve l’aiuto e per il quale il periodo di tre anni non è ancora trascorso.</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">Al fine di garantire condizioni uniformi di esecuzione del presente articolo, la Commissione adotta atti di esecuzione che stabiliscono il modello per le domande di pagamento. Tali atti di esecuzione sono adottati secondo la procedura di esame di cui all’articolo 150, paragrafo 3.»;</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>59) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 137, paragrafo 1, il riferimento «articolo 59, paragrafo 5, lettera a), del regolamento finanziario» è sostituito da «articolo 63, paragrafo 5, lettera a), e articolo 63, paragrafo 6, del regolamento finanziario»;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>60) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 138, il riferimento «articolo 59, paragrafo 5, del regolamento finanziario» è sostituito da «articolo 63, paragrafo 5, e articolo 63, paragrafo 7, secondo comma, del regolamento finanziario»;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>61) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 140, paragrafo 3, è aggiunta la frase seguente:</p>\n<p class=\"norm\">«Se i documenti sono conservati su supporti per i dati comunemente accettati in conformità della procedura di cui al paragrafo 5, gli originali non sono necessari.»;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>62) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 145, paragrafo 7, secondo comma, lettera a), il riferimento «articolo 59, paragrafo 5, del regolamento finanziario» è sostituito da «articolo 63, paragrafi 5, 6 e 7, del regolamento finanziario»;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>63) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 147, paragrafo 1, il riferimento «articolo 78 del regolamento finanziario» è sostituito da «articolo 98 del regolamento finanziario»;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>64) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 148, il paragrafo 1 è sostituito dal seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«1.  </span>\n<div class=\"norm inline-element\">Le operazioni per le quali la spesa totale ammissibile non supera 400 000  EUR per il FESR e il Fondo di coesione, 300 000  EUR per l’FSE o 200 000  EUR per il FEAMP non sono soggette a più di un audit da parte dell’autorità di audit o della Commissione prima della presentazione dei bilanci relativi all’esercizio in cui l’operazione è completata. Altre operazioni non sono soggette a più di un audit per esercizio da parte dell’autorità di audit o della Commissione prima della presentazione dei bilanci relativi all’esercizio in cui l’operazione è completata. Le operazioni non sono soggette a un audit da parte della Commissione o dell’autorità di audit in qualsiasi anno, se è già stato svolto un audit durante quello stesso anno da parte della Corte dei conti europea, a condizione che i risultati dei lavori di audit eseguiti dalla Corte dei conti europea per tali operazioni possano essere utilizzati dall’autorità di audit o dalla Commissione al fine di ottemperare ai loro rispettivi compiti.</div>\n</div>\n<p class=\"norm\">In deroga al primo comma, le operazioni per le quali la spesa totale ammissibile è compresa tra 200 000  EUR e 400 000  EUR per il FESR e il Fondo di coesione, tra 150 000  EUR e 300 000  EUR per l’FSE e tra 100 000  EUR e 200 000  EUR per il FEAMP possono essere soggette a più di un audit se l’autorità di audit, sulla base del suo giudizio professionale, ritiene che non è possibile emettere/redigere un parere di audit basandosi sui metodi di campionamento statistico o non statistico di cui all’articolo 127, paragrafo 1, senza effettuare più di un audit della rispettiva operazione.»;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>65) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’articolo 149 è così modificato:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i paragrafi 2 e 3 sono sostituiti dai seguenti:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«2.  </span>\n<div class=\"norm inline-element\">Il potere di adottare gli atti delegati di cui all’articolo 5, paragrafo 3, all’articolo 12, secondo comma, all’articolo 22, paragrafo 7, quarto comma, all’articolo 37, paragrafo 13, all’articolo 38, paragrafo 4, terzo comma, all’articolo 39 <span class=\"italics\">bis</span>, paragrafo 7, all’articolo 40, paragrafo 4, all’articolo 41, paragrafo 3, all’articolo 42, paragrafo 1, secondo comma, all’articolo 42, paragrafo 6, all’articolo 61, paragrafo 3, secondo, terzo, quarto e settimo comma, all’articolo 63, paragrafo 4, all’articolo 64, paragrafo 4, all’articolo 67, paragrafo 5 <span class=\"italics\">bis</span>, all’articolo 68, secondo comma, all’articolo 101, quarto comma, all’articolo 122, paragrafo 2, quinto comma, all’articolo 125, paragrafo 8, primo comma, all’articolo 125, paragrafo 9, all’articolo 127, paragrafi 7 e 8, e all’articolo 144, paragrafo 6, è conferito alla Commissione a decorrere dal 21 dicembre 2013 fino al 31 dicembre 2020.;</div>\n</div>\n<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">La delega di potere di cui all’articolo 5, paragrafo 3, all’articolo 12, secondo comma, all’articolo 22, paragrafo 7, quarto comma, all’articolo 37, paragrafo 13, all’articolo 38, paragrafo 4, terzo comma, all’articolo 39 <span class=\"italics\">bis</span>, paragrafo 7, all’articolo 40, paragrafo 4, all’articolo 41, paragrafo 3, all’articolo 42, paragrafo 1, secondo comma, all’articolo 42, paragrafo 6, all’articolo 61, paragrafo 3, secondo, terzo, quarto e settimo comma, all’articolo 63, paragrafo 4, all’articolo 64, paragrafo 4, all’articolo 67, paragrafo 5 <span class=\"italics\">bis</span>, all’articolo 68, secondo comma, all’articolo 101, quarto comma, all’articolo 122, paragrafo 2, quinto comma, all’articolo 125, paragrafo 8, primo comma, all’articolo 125, paragrafo 9, all’articolo 127, paragrafi 7 e 8, e all’articolo 144, paragrafo 6, può essere revocata in qualsiasi momento dal Parlamento europeo o dal Consiglio. La decisione di revoca pone fine alla delega di potere ivi specificata. Gli effetti della decisione decorrono dal giorno successivo alla pubblicazione della decisione nella <span class=\"italics\">Gazzetta ufficiale dell’Unione europea</span> o da una data successiva ivi specificata. Essa non pregiudica la validità degli atti delegati già in vigore.»;</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">è inserito il comma seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«3 <span class=\"italics\">bis</span>.  </span>\n<div class=\"norm inline-element\">Prima dell’adozione dell’atto delegato la Commissione consulta gli esperti designati da ciascuno Stato membro nel rispetto dei principi stabiliti nell’accordo interistituzionale “Legiferare meglio” del 13 aprile 2016.»;</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il paragrafo 5 è sostituito dal seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«5.  </span>\n<div class=\"norm inline-element\">Un atto delegato adottato conformemente all’articolo 5, paragrafo 3, all’articolo 12, secondo comma, all’articolo 22, paragrafo 7, quarto comma, all’articolo 37, paragrafo 13, all’articolo 38, paragrafo 4, terzo comma, all’articolo 39 <span class=\"italics\">bis</span>, paragrafo 7, all’articolo 40, paragrafo 4, all’articolo 41, paragrafo 3, all’articolo 42, paragrafo 1, secondo comma, all’articolo 42, paragrafo 6, all’articolo 61, paragrafo 3, secondo, terzo, quarto e settimo comma, all’articolo 63, paragrafo 4, all’articolo 64, paragrafo 4, all’articolo 67, paragrafo 5 <span class=\"italics\">bis</span>, all’articolo 68, secondo comma, all’articolo 101, quarto comma, all’articolo 122, paragrafo 2, quinto comma, all’articolo 125, paragrafo 8, primo comma, all’articolo 125, paragrafo 9, all’articolo 127, paragrafi 7 e 8, e all’articolo 144, paragrafo 6, entra in vigore solo se nessuna obiezione è stata espressa dal Parlamento europeo o dal Consiglio entro un termine di due mesi a decorrere dalla notifica dell’atto al Parlamento europeo e al Consiglio stesso o se, prima della scadenza di tale termine, il Parlamento europeo e il Consiglio hanno entrambi informato la Commissione della loro intenzione di non sollevare obiezioni. Tale termine è prorogato di due mesi su iniziativa del Parlamento europeo o del Consiglio.»;</div>\n</div>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>66) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 152 è aggiunto il paragrafo seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«7.  </span>\n<div class=\"norm inline-element\">L’autorità di gestione, o il comitato di sorveglianza per i programmi che rientrano nell’obiettivo Cooperazione territoriale europea, può decidere di non applicare l’articolo 67, paragrafo 2 <span class=\"italics\">bis</span>, per un periodo massimo di 12 mesi a decorrere dal 2 agosto 2018.</div>\n</div>\n<p class=\"norm\">Se l’autorità di gestione, o il comitato di sorveglianza per i programmi che rientrano nell’obiettivo Cooperazione territoriale europea, ritiene che l’articolo 67, paragrafo 2 <span class=\"italics\">bis</span>, comporti un onere amministrativo sproporzionato, può decidere di prorogare il periodo transitorio di cui al primo comma del presente paragrafo per il periodo che considera adeguato. L’autorità, o il comitato, notifica tale decisione alla Commissione prima della scadenza del periodo transitorio iniziale.</p>\n<p class=\"norm\">Il primo e il secondo comma non si applicano alle sovvenzioni e all’assistenza rimborsabile sostenute dall’FSE per le quali il sostegno pubblico non supera 50 000  EUR.»;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>67) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’allegato IV è così modificato:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la sezione 1 è così modificata:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la parte introduttiva è sostituita dalla seguente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>«1. </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">Qualora uno strumento finanziario sia attuato a norma dell’articolo 39 <span class=\"italics\">bis</span> e dell’articolo 38, paragrafo 4, primo comma, lettere a), b) e c), l’accordo di finanziamento comprende i termini e le condizioni per i contributi del programma allo strumento finanziario e comprende almeno gli elementi seguenti:»;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la lettera f) è sostituita dalla seguente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>«f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i requisiti e le procedure per la gestione del contributo scaglionato previsto dal programma conformemente all’articolo 41 e per la previsione dei flussi delle opportunità di investimento, compresi i requisiti per la contabilità fiduciaria/separata a norma dell’articolo 38, paragrafo 6, e dell’articolo 39 <span class=\"italics\">bis</span>, paragrafo 5, secondo comma;»;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>iii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il punto i) è sostituito dal seguente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>«i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le disposizioni relative al riutilizzo delle risorse imputabili al sostegno dei fondi SIE fino alla fine del periodo di ammissibilità conformemente all’articolo 44 e, ove pertinente, le disposizioni sul trattamento differenziato di cui all’articolo 43 <span class=\"italics\">bis</span>;»;</p>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la sezione 2 è così modificata:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la parte introduttiva è sostituita dalla seguente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>«2. </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">I documenti di strategia di cui all’articolo 38, paragrafo 8, per gli strumenti finanziari attuati a norma dell’articolo 38, paragrafo 4, primo comma, lettera d), comprendono almeno gli elementi seguenti:»;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la lettera c) è sostituita dalla seguente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>«c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’uso e il riutilizzo di risorse imputabili al sostegno dei fondi SIE conformemente agli articoli 43, 44 e 45 e, ove pertinente, le disposizioni sul trattamento differenziato di cui all’articolo 43 <span class=\"italics\">bis</span>;»;</p>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>68) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’allegato XII è così modificato:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’intestazione dell’allegato XII è sostituita dalla seguente:</p>\n<p class=\"norm\">\n<span class=\"boldface\">«INFORMAZIONE, COMUNICAZIONE E VISIBILITÀ DEL SOSTEGNO FORNITO DAI FONDI»;</span>\n</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’intestazione della sezione 2 è sostituita dalla seguente:</p>\n<p class=\"list\">MISURE DI INFORMAZIONE E COMUNICAZIONE E MISURE VOLTE A MIGLIORARE LA VISIBILITÀ PER IL PUBBLICO»;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la sottosezione 2.1 è così modificata:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il punto 1 è sostituito dal seguente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>«1. </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">Lo Stato membro e l’autorità di gestione assicurano che le misure di informazione e comunicazione siano realizzate conformemente alla strategia di comunicazione al fine di migliorare la visibilità e l’interazione con i cittadini e che tali misure mirino alla massima copertura mediatica utilizzando diverse forme e metodi di comunicazione al livello appropriato e adattati, se del caso, all’innovazione tecnologica.»;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">al punto 2, le lettere e) ed f) sono sostituite dalle seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>«e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">fornire esempi di operazioni, in particolare di quelle relativamente a cui il valore aggiunto dell’intervento dei fondi è particolarmente visibile, suddivisi per programma operativo, sul sito web unico o sul sito web del programma operativo, accessibile mediante il portale web unico. Gli esempi sono in una lingua ufficiale dell’Unione di ampia diffusione diversa dalla lingua o dalle lingue ufficiali dello Stato membro interessato;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">fornire informazioni aggiornate in merito all’attuazione del programma operativo, compresi le realizzazioni e i risultati principali, sul sito web unico o sul sito web del programma operativo, accessibile mediante il portale web unico.»;</p>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la sottosezione 2.2 è così modificata:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">al punto 1, la parte introduttiva è sostituita dalla seguente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>«1. </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">Tutte le misure di informazione e di comunicazione e le misure volte a migliorare la visibilità dei fondi a cura del beneficiario riconoscono il sostegno dei fondi all’operazione riportando:»;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">è aggiunto il punto seguente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>«6. </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">Le responsabilità specificate nella presente sottosezione si applicano dal momento in cui è fornito al beneficiario il documento che specifica le condizioni per il sostegno all’operazione di cui all’articolo 125, paragrafo 3, lettera c).»;</p>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nella sottosezione 3.1, punto 2, la lettera f) è sostituita dalla seguente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>«f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">la responsabilità dei beneficiari di informare il pubblico circa lo scopo dell’operazione e il sostegno all’operazione da parte dei fondi, conformemente alla sottosezione 2.2, dal momento in cui è fornito al beneficiario il documento che specifica le condizioni per il sostegno all’operazione di cui all’articolo 125, paragrafo 3, lettera c). L’autorità di gestione può chiedere che i potenziali beneficiari propongano, nelle domande, attività di comunicazione indicative volte a migliorare la visibilità dei fondi, che siano proporzionali alla dimensione dell’operazione.»;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">nella sottosezione 4, la lettera i) è sostituita dalla seguente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>«i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">un aggiornamento annuale che riporti le attività di informazione e comunicazione, comprese le misure volte a migliorare la visibilità dei fondi, da svolgere nell’anno successivo, basato, tra l’altro, sugli insegnamenti tratti in merito all’efficacia di tali misure.».</p>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>"]]}, "273": {"label": "Articolo 273", "heading": "Modifiche del regolamento (UE) n. 1304/2013", "anchor": "art_273", "frags": [[null, "<p class=\"norm\">Il regolamento (UE) n. 1304/2013 è così modificato:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>1) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 13, paragrafo 2, è aggiunto il comma seguente:</p>\n<p class=\"norm\">«Qualora le operazioni di cui al primo comma, lettera a), apportino benefici anche all’area del programma in cui sono attuate, le spese sono assegnate proporzionalmente a tali aree del programma secondo criteri oggettivi.»;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>2) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’articolo 14 è così modificato:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">è inserito il paragrafo seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«-1.  </span>\n<div class=\"norm inline-element\">Le disposizioni generali applicabili alle opzioni semplificate in materia di costi a titolo dell’FSE sono fissate negli articoli 67, 68, 68 <span class=\"italics\">bis</span> e 68 <span class=\"italics\">ter</span> del regolamento (UE) n. 1303/2013.»;</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">i paragrafi 2, 3 e 4 sono soppressi;</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>3) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’allegato I, il punto 1) è sostituito dal seguente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>«1) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">Indicatori comuni di output per i partecipanti</p>\n<p class=\"list\">Per “partecipanti” (\n<span class=\"superscript\">28</span>\n) si intendono le persone che beneficiano direttamente di un intervento dell’FSE, che possono essere identificate, alle quali è possibile chiedere di fornire informazioni circa le loro caratteristiche e per le quali sono previste spese specifiche. Le altre persone non sono considerate partecipanti. Tutti i dati sono suddivisi per genere.</p>\n<p class=\"list\">Gli indicatori comuni di output per i partecipanti sono:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">i disoccupati, compresi i disoccupati di lunga durata*,</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">i disoccupati di lunga durata*,</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">le persone inattive*,</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">le persone inattive, che non studiano né seguono corsi di formazione*,</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">i lavoratori, compresi i lavoratori autonomi*,</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">le persone di età inferiore a 25 anni*,</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">le persone di età superiore a 54 anni*,</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">le persone di età superiore a 54 anni che sono disoccupate, inclusi i disoccupati di lunga durata, o inattive, che non studiano né seguono corsi di formazione*,</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">i titolari di un diploma di istruzione primaria (ISCED 1) o secondaria inferiore (ISCED 2)*,</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">i titolari di un diploma di istruzione secondaria superiore (ISCED 3) o post secondaria (ISCED 4)*,</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">i titolari di un diploma di istruzione terziaria (ISCED da 5 a 8)*,</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">i migranti, i partecipanti di origine straniera e le minoranze (comprese le comunità emarginate come i Rom)**,</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">i partecipanti con disabilità**,</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">le altre persone svantaggiate**.</div>\n</div>\n</div>\n<p class=\"list\">Il numero totale dei partecipanti sarà calcolato automaticamente sulla base degli indicatori di output.</p>\n<p class=\"list\">Tali dati sui partecipanti a un’operazione sostenuta dall’FSE sono comunicati nelle relazioni di attuazione annuali di cui all’articolo 50, paragrafi 1 e 2, e all’articolo 111, paragrafo 1, del regolamento (UE) n. 1303/2013.</p>\n<p class=\"list\">I seguenti dati sui partecipanti saranno forniti nelle relazioni di attuazione annuali di cui all’articolo 50 del regolamento (UE) n. 1303/2013:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">i senzatetto o le persone colpite da esclusione abitativa*,</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>— </span>\n</div>\n<div class=\"grid-list-column-2\">\n<div class=\"list\">le persone provenienti da zone rurali* (\n<span class=\"superscript\">29</span>\n)</div>\n</div>\n</div>\n<p class=\"list\">I dati di detti due indicatori saranno raccolti sulla base di un campione rappresentativo di partecipanti all’interno di ogni priorità d’investimento. La validità interna è garantita in modo tale che i dati possano essere generalizzati a livello di priorità di investimento.</p>\n</div>\n</div>\n</div>\n</div>"]]}, "274": {"label": "Articolo 274", "heading": "Modifiche del regolamento (UE) n. 1309/2013", "anchor": "art_274", "frags": [[null, "<p class=\"norm\">Il regolamento (UE) n. 1309/2013 è così modificato:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>1) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">al considerando 24, la prima frase è sostituita dalla seguente:</p>\n<p class=\"norm\">«Gli Stati membri dovrebbero rimanere responsabili dell’attuazione del contributo finanziario, nonché della gestione e del controllo delle azioni sostenute da finanziamenti dell’Unione, conformemente alle pertinenti disposizioni del regolamento (UE, Euratom) 2018/1046 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">*7</span>\n) (“regolamento finanziario”).</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>2) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 4, il paragrafo 2 è sostituito dal seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«2.  </span>\n<div class=\"norm inline-element\">Nei mercati del lavoro di dimensioni ridotte o in circostanze eccezionali debitamente giustificate dallo Stato membro che ha presentato la domanda, in particolare per quanto concerne le domande collettive che coinvolgono le PMI, una domanda di contributo finanziario ai sensi del presente articolo può essere considerata ricevibile anche se i criteri fissati al paragrafo 1, lettera a) o b), non sono completamente soddisfatti, laddove gli esuberi abbiano un grave impatto sull’occupazione e sull’economia locale, regionale o nazionale. Lo Stato membro richiedente precisa quale dei criteri d’intervento stabiliti al paragrafo 1, lettere a) e b), non è interamente soddisfatto. Per quanto concerne le domande collettive che coinvolgono le PMI ubicate in una regione, qualora lo Stato membro richiedente dimostri che le PMI sono il principale o l’unico tipo di impresa in tale regione, la domanda può riguardare, a titolo eccezionale, PMI operanti in settori economici diversi definiti a livello delle divisioni della NACE revisione 2. L’importo cumulato dei contributi in circostanze eccezionali non può eccedere il 15 % dell’importo annuo massimo del FEG.»;</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>3) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 6, il paragrafo 2 è sostituito dal seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«2.  </span>\n<div class=\"norm inline-element\">In deroga all’articolo 2, gli Stati membri richiedenti possono fornire servizi personalizzati cofinanziati dal FEG per un determinato numero di NEET di età inferiore ai 25 anni o, qualora gli Stati membri lo decidano, di età inferiore ai 30 anni, alla data di presentazione della domanda, uguale al numero dei beneficiari interessati, dando la priorità alle persone collocate in esubero o la cui attività sia cessata, a condizione che almeno una parte degli esuberi ai sensi dell’articolo 3 si verifichi in regioni di livello NUTS 2 che registravano tassi di disoccupazione giovanile per la fascia di età 15-24 anni di almeno il 20 % sulla base degli ultimi dati annuali disponibili. Il sostegno può essere fornito ai NEET di età inferiore ai 25 anni o, qualora gli Stati membri lo decidano, di età inferiore ai 30 anni, nelle regioni di livello NUTS 2.»;</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>4) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 11, il paragrafo 3 è sostituito dal seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«3.  </span>\n<div class=\"norm inline-element\">I compiti di cui al paragrafo 1 sono eseguiti conformemente al regolamento finanziario.»;</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>5) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 15, il paragrafo 4 è sostituito dal seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«4.  </span>\n<div class=\"norm inline-element\">Qualora abbia concluso che sono soddisfatte le condizioni per fornire un contributo finanziario a valere sul FEG, la Commissione presenta una proposta di mobilitazione. La decisione di mobilizzare il FEG è adottata congiuntamente dal Parlamento europeo e dal Consiglio entro un mese dalla presentazione della proposta agli stessi. Il Consiglio delibera a maggioranza qualificata e il Parlamento europeo delibera alla maggioranza dei suoi membri e dei tre quinti dei voti espressi.</div>\n</div>\n<p class=\"norm\">Gli storni relativi al FEG sono effettuati conformemente all’articolo 31 del regolamento finanziario, in linea di principio entro un periodo non superiore a sette giorni a decorrere dalla data di adozione della decisione pertinente da parte del Parlamento europeo e del Consiglio.»;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>6) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 16, paragrafo 2, il riferimento «articolo 59 del regolamento finanziario» è sostituito da«articolo 63 del regolamento finanziario»;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>7) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 21, paragrafo 2, il riferimento «articolo 59, paragrafo 3, del regolamento finanziario» è sostituito da«articolo 63, paragrafo 3, del regolamento finanziario» e il riferimento «articolo 59, paragrafo 5, del regolamento finanziario» è sostituito da«articolo 63, paragrafo 5, del regolamento finanziario».</p>\n</div>\n</div>"]]}, "275": {"label": "Articolo 275", "heading": "Modifiche del regolamento (UE) n. 1316/2013", "anchor": "art_275", "frags": [[null, "<p class=\"norm\">Il regolamento (UE) n. 1316/2013 è così modificato:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>1) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">è inserito il capo seguente:</p>\n<p class=\"title-division-1\">«<span class=\"italics\">CAPO V <span class=\"norm\">bis</span>\n</span>\n</p>\n<p class=\"title-division-2\">\n<span class=\"boldface\">\n<span class=\"italics\">Finanziamento misto</span>\n</span>\n</p>\n<p class=\"title-article-quoted\">Articolo 16 <span class=\"norm\">bis</span>\n</p>\n<p class=\"stitle-article-quoted\">Meccanismi di finanziamento misto dell’MCE</p>\n<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Nell’ambito del presente regolamento possono essere istituiti, in conformità dell’articolo 159 del regolamento (UE, Euratom) 2018/1046 del Parlamento europeo e del Consiglio (\n<span class=\"superscript\">*8</span>\n), meccanismi di finanziamento misto dell’MCE per uno o più settori dello stesso MCE. Possono essere ammessi a ricevere assistenza finanziaria mediante operazioni di finanziamento misto tutte le azioni che contribuiscono a progetti di interesse comune.</div>\n</div>\n<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">I meccanismi di finanziamento misto dell’MCE sono attuati in conformità dell’articolo 6, paragrafo 3.</div>\n</div>\n<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il contributo complessivo del bilancio dell’Unione ai meccanismi di finanziamento misto dell’MCE non supera il 10 % della dotazione finanziaria complessiva dell’MCE di cui all’articolo 5, paragrafo 1.</div>\n</div>\n<p class=\"norm\">Oltre la soglia stabilita al primo comma, nel settore dei trasporti il contributo complessivo del bilancio dell’Unione ai meccanismi di finanziamento misto dell’MCE non supera 500 000 000  EUR.</p>\n<p class=\"norm\">Se il 10 % della dotazione finanziaria complessiva per l’esecuzione dell’MCE di cui all’articolo 5, paragrafo 1, non è integralmente impiegato per i meccanismi di finanziamento misto dell’MCE e/o per strumenti finanziari, l’importo restante è reso disponibile e ridistribuito a tale dotazione finanziaria.</p>\n<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">L’importo di 11 305 500 000  EUR trasferito dal fondo di coesione di cui all’articolo 5, paragrafo 1, lettera a), non è usato per impegnare risorse di bilancio in meccanismi di finanziamento misto dell’MCE.</div>\n</div>\n<div class=\"norm\">\n<span class=\"no-parag\">5.  </span>\n<div class=\"norm inline-element\">Il sostegno fornito sotto forma di sovvenzioni e di strumenti finanziari nell’ambito di un meccanismo di finanziamento misto dell’MCE è conforme ai criteri di ammissibilità e alle condizioni per l’assistenza finanziaria di cui all’articolo 7. L’importo dell’assistenza finanziaria da concedere alle operazioni di finanziamento misto sostenute mediante un meccanismo di finanziamento misto dell’MCE è modulato sulla base di un’analisi dei costi-benefici, della disponibilità di risorse di bilancio dell’Unione e della necessità di massimizzare l’effetto leva dei finanziamenti dell’Unione. Nessuna delle sovvenzioni assegnate supera i tassi di finanziamento di cui all’articolo 10.</div>\n</div>\n<div class=\"norm\">\n<span class=\"no-parag\">6.  </span>\n<div class=\"norm inline-element\">La Commissione, in cooperazione con la Banca europea per gli investimenti (BEI), esamina la possibilità che quest’ultima fornisca sistematicamente garanzie di prima perdita nei meccanismi di finanziamento misto dell’MCE onde consentire e agevolare l’addizionalità e la partecipazione di coinvestitori privati nel settore dei trasporti.</div>\n</div>\n<div class=\"norm\">\n<span class=\"no-parag\">7.  </span>\n<div class=\"norm inline-element\">L’Unione, gli Stato membri e altri investitori possono contribuire ai meccanismi di finanziamento misto dell’MCE, purché la Commissione approvi le specifiche dei criteri di ammissibilità delle operazioni di finanziamento misto e/o la strategia di investimento del meccanismo di finanziamento misto dell’MCE che dovessero eventualmente rendersi necessarie alla luce del contributo aggiuntivo e per soddisfare i requisiti del presente regolamento nell’attuazione di progetti di interesse comune. Queste risorse aggiuntive sono utilizzate dalla Commissione in conformità dell’articolo 6, paragrafo 3.</div>\n</div>\n<div class=\"norm\">\n<span class=\"no-parag\">8.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Le operazioni di finanziamento misto che beneficiano del sostegno erogato mediante un meccanismo di finanziamento misto dell’MCE sono selezionate sulla base della scadenza e perseguono una diversificazione settoriale in conformità degli articoli 3 e 4 e una ripartizione geografica equilibrata tra gli Stati membri. Esse:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">presentano un valore aggiunto europeo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">rispondono agli obiettivi della strategia Europa 2020;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">contribuiscono, ove possibile, alla mitigazione dei cambiamenti climatici e all’adattamento a essi.</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"norm\">\n<span class=\"no-parag\">9.  </span>\n<div class=\"norm inline-element\">I meccanismi di finanziamento misto dell’MCE sono messi a disposizione e le operazioni di finanziamento misto sono selezionate in base ai criteri di selezione e aggiudicazione stabiliti nei programmi pluriennali e annuali adottati a norma dell’articolo 17.</div>\n</div>\n<div class=\"norm\">\n<span class=\"no-parag\">10.  </span>\n<div class=\"norm inline-element\">Le operazioni di finanziamento misto in paesi terzi possono beneficiare del sostegno erogato mediante un meccanismo di finanziamento misto dell’MCE se sono necessarie per la realizzazione di un progetto di interesse comune.</div>\n</div>\n</div>\n</div>"]]}, "276": {"label": "Articolo 276", "heading": "Modifiche del regolamento (UE) n. 223/2014", "anchor": "art_276", "frags": [[null, "<p class=\"norm\">Il regolamento (UE) n. 223/2014 è così modificato:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>1) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 9 è aggiunto il paragrafo seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«4.  </span>\n<div class=\"norm inline-element\">I paragrafi 1, 2 e 3 non si applicano ai fini della modifica di elementi di un programma operativo che rientrano rispettivamente nelle sottosezioni 3.5 e 3.6 e nella sezione 4 dei modelli di programma operativo di cui all’allegato I.</div>\n</div>\n<p class=\"norm\">Gli Stati membri comunicano alla Commissione qualsiasi decisione di modifica degli elementi di cui al primo comma entro un mese dalla data della decisione. La decisione indica la data della sua entrata in vigore, che non è anteriore alla data della sua adozione.»;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>2) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 23, il paragrafo 6 è sostituito dal seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«6.  </span>\n<div class=\"norm inline-element\">Un’operazione può ricevere sostegno da uno o più programmi operativi cofinanziati dal Fondo e da altri strumenti dell’Unione, purché la spesa dichiarata in una domanda di pagamento per il Fondo non sia dichiarata sostegno di un altro strumento dell’Unione, o dello stesso fondo nell’ambito di un altro programma. L’importo della spesa da indicare in una domanda di pagamento del Fondo può essere calcolato per il programma o i programmi interessati su base proporzionale conformemente al documento che specifica le condizioni per il sostegno.»;</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>3) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 25, paragrafo 3, è aggiunta la lettera seguente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>«e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">norme di applicazione delle corrispondenti tabelle di costi unitari, somme forfettarie e tassi forfettari applicabili conformemente alle politiche dell’Unione per tipologie analoghe di operazioni e beneficiari.»;</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>4) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’articolo 26 è così modificato:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">al paragrafo 2, le lettere d) ed e) sono sostituite dalle seguenti:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>«d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le spese sostenute dalle organizzazioni partner per la raccolta, il trasporto, il magazzinaggio e la distribuzione delle donazioni di prodotti alimentari, nonché per le attività di sensibilizzazione direttamente correlate;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le spese per le misure di accompagnamento poste in essere e dichiarate dalle organizzazioni partner che forniscono, direttamente o nell’ambito di accordi di cooperazione, prodotti alimentari e/o assistenza materiale di base alle persone indigenti, a una percentuale forfettaria del 5 % delle spese di cui alla lettera a) del presente comma o del 5 % del valore dei prodotti alimentari smaltiti in conformità dell’articolo 16 del regolamento (UE) n. 1308/2013.»;</p>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">è inserito il paragrafo seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«3 <span class=\"italics\">bis</span>.  </span>\n<div class=\"norm inline-element\">Fatto salvo il paragrafo 2, una riduzione delle spese ammissibili di cui al paragrafo 2, lettera a), dovuta all’inosservanza del diritto applicabile da parte dell’organismo responsabile dell’acquisto di prodotti alimentari e/o assistenza materiale di base non determina una riduzione delle spese ammissibili degli altri organismi di cui al paragrafo 2, lettere c) ed e).»;</div>\n</div>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>5) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 27, il paragrafo 4 è sostituito dal seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«4.  </span>\n<div class=\"norm inline-element\">Su iniziativa degli Stati membri ed entro una soglia del 5 % della dotazione del Fondo al momento dell’adozione del programma operativo, quest’ultimo può finanziare le attività di preparazione, gestione, sorveglianza, assistenza tecnica e amministrativa, audit, informazione, controllo e valutazione necessarie all’attuazione del presente regolamento. Il programma operativo può inoltre finanziare l’assistenza tecnica e lo sviluppo delle capacità delle organizzazioni partner.»;</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>6) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 30, paragrafo 2, il quarto comma è sostituito dal seguente:</p>\n<p class=\"norm\">«Quando un importo indebitamente versato a un beneficiario per un’operazione non può essere recuperato per colpa o negligenza di uno Stato membro, spetta a quest’ultimo rimborsare l’importo in questione al bilancio dell’Unione. Gli Stati membri possono decidere di non recuperare un importo versato indebitamente se l’importo che deve essere recuperato dal beneficiario non supera, al netto degli interessi, 250 EUR di contributo del Fondo a un’operazione in un esercizio contabile.»;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>7) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 32, paragrafo 4, la lettera a) è sostituita dalla seguente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>«a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">verifica che i prodotti e i servizi cofinanziati siano stati forniti e che l’operazione sia conforme al diritto applicabile, al programma operativo e alle condizioni per il sostegno dell’operazione e</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>i) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">qualora i costi debbano essere rimborsati ai sensi dell’articolo 25, paragrafo 1, lettera a), che l’importo della spesa dichiarata dai beneficiari in relazione a tali costi sia stato pagato;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>ii) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">qualora i costi debbano essere rimborsati a norma dell’articolo 25, paragrafo 1, lettere b), c) e d), che siano state rispettate le condizioni per il rimborso della spesa al beneficiario;»;</p>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>8) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 42, il paragrafo 3 è sostituito dal seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Il termine di pagamento di cui al paragrafo 2 può essere sospeso dall’autorità di gestione in uno dei seguenti casi debitamente motivati:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’importo della domanda di pagamento non è dovuto o non sono stati prodotti i documenti giustificativi appropriati, tra cui la documentazione necessaria per le verifiche della gestione a norma dell’articolo 32, paragrafo 4, lettera a);</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">è stata avviata un’indagine in merito a un’eventuale irregolarità che incide sulla spesa in questione.</p>\n</div>\n</div>\n</div>\n</div>\n<p class=\"norm\">Il beneficiario interessato è informato per iscritto della sospensione e dei motivi della stessa. Il rimanente periodo utile per il pagamento riprende a decorrere dalla data di ricezione delle informazioni o dei documenti richiesti o dalla data di esecuzione dell’indagine.»;</p>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>9) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 51, il paragrafo 3 è sostituito dal seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«3.  </span>\n<div class=\"norm inline-element\">I documenti sono conservati sotto forma di originali o di copie autenticate, o su supporti per i dati comunemente accettati, comprese le versioni elettroniche di documenti originali o i documenti esistenti esclusivamente in versione elettronica. Se i documenti sono conservati su supporti per i dati comunemente accettati in conformità della procedura di cui al paragrafo 5, gli originali non sono necessari.».</div>\n</div>\n</div>\n</div>"]]}, "277": {"label": "Articolo 277", "heading": "Modifiche del regolamento (UE) n. 283/2014", "anchor": "art_277", "frags": [[null, "<p class=\"norm\">Il regolamento (UE) n. 283/2014 è così modificato:</p>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>1) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 2, paragrafo 2, la lettera e) è sostituita dalla seguente:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>«e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">“servizi generici”: servizi di gateway che collegano una o più infrastrutture nazionali a piattaforme di servizi chiave e servizi che aumentano la capacità di un’infrastruttura di servizi digitali dando accesso a centri di calcolo e strutture di archiviazione e gestione dati ad alte prestazioni;»;</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>2) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’articolo 5 è così modificato:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">il paragrafo 4 è sostituito dal seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«4.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">Le azioni che contribuiscono a progetti di interesse comune nell’ambito delle infrastrutture di servizi digitali sono sostenute da:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">appalti;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">sovvenzioni; e/o</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">strumenti finanziari di cui al paragrafo 5.»;</p>\n</div>\n</div>\n</div>\n</div>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">è aggiunto il paragrafo seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«4 <span class=\"italics\">bis</span>.  </span>\n<div class=\"norm inline-element\">Il contributo complessivo del bilancio dell’Unione agli strumenti finanziari per le infrastrutture di servizi digitali di cui al paragrafo 4, lettera c), del presente articolo non supera il 10 % della dotazione finanziaria per il settore delle telecomunicazioni di cui all’articolo 5, paragrafo 1, lettera b), del regolamento (UE) n. 1316/2013.»;</div>\n</div>\n</div>\n</div>\n</div>\n</div>"], [null, "<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>3. </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">all’articolo 8, il paragrafo 1 è sostituito dal seguente:</p>\n<div class=\"norm\">\n<span class=\"no-parag\">«1.  </span>\n<div class=\"norm inline-element\">Sulla base delle informazioni pervenute a norma dell’articolo 22, terzo comma, del regolamento (UE) n. 1316/2013, gli Stati membri e la Commissione si scambiano informazioni e migliori prassi sui progressi compiuti nell’attuazione del presente regolamento, compreso l’uso degli strumenti finanziari. Se del caso, gli Stati membri coinvolgono le autorità locali e regionali nel processo. La Commissione pubblica una sintesi annuale di tali informazioni e la trasmette al Parlamento europeo e al Consiglio.».</div>\n</div>\n</div>\n</div>"]]}, "278": {"label": "Articolo 278", "heading": "Modifiche della decisione n. 541/2014/UE", "anchor": "art_278", "frags": [[null, "<p class=\"norm\">All’articolo 4 della decisione n. 541/2014/UE del Parlamento europeo e del Consiglio è aggiunto il paragrafo seguente:</p>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">«3.  </span>\n<div class=\"norm inline-element\">I programmi di finanziamento istituiti dai regolamenti (UE) n. 377/2014 e (UE) n. 1285/2013 e dalla decisione 2013/743/UE possono contribuire al finanziamento delle azioni di cui al paragrafo 1 del presente articolo nell’ambito di questi programmi e in conformità dei loro scopi e obiettivi. I contributi sono spesi in conformità del regolamento (UE) n. 377/2014. Prima del termine del quadro finanziario pluriennale 2014-2020 la Commissione valuta le nuove regole finanziarie semplificate a norma del presente comma e il loro contributo agli obiettivi del quadro di sostegno all’SST.».</div>\n</div>"], [null, "<p>\n<br/>\n<br/>\n</p>"]]}, "279": {"label": "Articolo 279", "heading": "Disposizioni transitorie", "anchor": "art_279", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Gli impegni giuridici relativi alle sovvenzioni che eseguono il bilancio nell’ambito del quadro finanziario pluriennale 2014-2020 possono continuare ad assumere la forma di decisioni di sovvenzione. Le disposizioni del titolo VIII applicabili alle convenzioni di sovvenzione si applicano, <span class=\"italics\">mutatis mutandis</span>, alle decisioni di sovvenzione. La Commissione riesamina il ricorso alle decisioni di sovvenzione nell’ambito del quadro finanziario pluriennale post 2020, tenendo conto, in particolare, dei progressi compiuti a livello di firma elettronica e gestione elettronica delle sovvenzioni.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">All’entrata in vigore del presente regolamento, le decisioni della Commissione che autorizzano l’uso di somme forfettarie, costi unitari o tassi forfettari adottate in conformità dell’articolo 124 del regolamento (UE, Euratom) n. 966/2012 sono modificate dall’ordinatore responsabile a norma dell’articolo 181 del presente regolamento.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">Il regolamento (UE, Euratom) n. 966/2012 e il regolamento delegato (UE) n. 1268/2012 continuano ad applicarsi agli impegni giuridici assunti prima dell’entrata in vigore del presente regolamento. Le attuali valutazioni per pilastro, i modelli esistenti di accordo di contributo e i vigenti accordi quadro di partenariato finanziario possono continuare ad applicarsi e, se del caso, sono soggetti a riesame.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">4.  </span>\n<div class=\"norm inline-element\">Per i contributi finanziari a valere sul FEG, compreso il sostegno ai NEET, relativamente ai quali il periodo specificato all’articolo 16, paragrafo 4, del regolamento (UE) n. 1309/2013 non sia scaduto entro il 1<span class=\"superscript\">o</span> gennaio 2018, la Commissione valuta se i servizi personalizzati forniti ai NEET siano ammissibili al cofinanziamento da parte del FEG oltre il 31 dicembre 2017. Se la Commissione conclude in tal senso, modifica di conseguenza le pertinenti decisioni sul contributo finanziario.</div>\n</div>"]]}, "280": {"label": "Articolo 280", "heading": "Riesame", "anchor": "art_280", "frags": [[null, "<p class=\"norm\">Il presente regolamento è riesaminato ogniqualvolta risulti necessario e comunque al più tardi due anni prima della scadenza di ciascun quadro finanziario pluriennale.</p>"], [null, "<p class=\"norm\">Il riesame riguarda, tra l’altro, l’attuazione dei titoli VIII e X della parte prima e i termini fissati all’articolo 259.</p>"]]}, "281": {"label": "Articolo 281", "heading": "Abrogazione", "anchor": "art_281", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il regolamento (UE, Euratom) n. 966/2012 è abrogato con effetto dal 2 agosto 2018. Esso continua tuttavia ad applicarsi fino al 31 dicembre 2018 ai fini dell’articolo 282, paragrafo 3, lettera c).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Fatto salvo l’articolo 279, paragrafo 3, la Commissione abroga il regolamento delegato (UE) n. 1268/2012 con effetto dal 2 agosto 2018. Tale regolamento delegato continua tuttavia ad applicarsi fino al 31 dicembre 2018 ai fini dell’articolo 282, paragrafo 3, lettera c).</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">I riferimenti al regolamento abrogato si intendono fatti al presente regolamento e si leggono conformemente alla tavola di concordanza di cui all’allegato II.</div>\n</div>"]]}, "282": {"label": "Articolo 282", "heading": "Entrata in vigore e applicazione", "anchor": "art_282", "frags": [[null, "<div class=\"norm\">\n<span class=\"no-parag\">1.  </span>\n<div class=\"norm inline-element\">Il presente regolamento entra in vigore il terzo giorno successivo alla pubblicazione nella <span class=\"italics\">Gazzetta ufficiale dell’Unione europea</span>.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">2.  </span>\n<div class=\"norm inline-element\">Esso si applica a decorrere dal 2 agosto 2018.</div>\n</div>"], [null, "<div class=\"norm\">\n<span class=\"no-parag\">3.  </span>\n<div class=\"norm inline-element\">\n<p class=\"norm inline-element\">In deroga al paragrafo 2 del presente articolo:</p>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>a) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’articolo 271, punto 1), lettera a), l’articolo 272, punto 2), l’articolo 272, punto 10), lettera a), l’articolo 272, punto 11, lettera b), punto i), lettere c), d) ed e), l’articolo 272, punto 12), lettere a), b), punto i), e lettera c), l’articolo 272, punto 14), lettera c), l’articolo 272, punti 15), 17), 18), 22) e 23), l’articolo 272, punto 26), lettera d), l’articolo 272, punto 27), lettera a), punto i), l’articolo 272, punti 53) e 54), l’articolo 272, punto 55), lettera b), punto (i), l’articolo 273, punto 3), l’articolo 276, punto 2), e l’articolo 276, punto 4, lettera b), si applicano a decorrere dal 1<span class=\"superscript\">o</span> gennaio 2014;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>b) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’articolo 272, punto 11), lettere a) e f), l’articolo 272, punto 13), l’articolo 272, punto 14), lettera b), l’articolo 272, punto 16), l’articolo 272, punto 19), lettera a), e l’articolo 274, punto 3), si applicano a decorrere dal 1<span class=\"superscript\">o</span> gennaio 2018;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>c) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">gli articoli da 6 a 60, da 63 a 68, da 73 a 207, da 241 a 253 e da 264 a 268 si applicano a decorrere dal 1<span class=\"superscript\">o</span> gennaio 2019 con riguardo all’esecuzione degli stanziamenti amministrativi delle istituzioni dell’Unione; è fatta salva la lettera h) del presente paragrafo;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>d) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’articolo 2, punto 4), gli articoli da 208 a 211 e l’articolo 214, paragrafo 1, si applicano alle garanzie di bilancio e all’assistenza finanziaria solo a decorrere dalla data di applicazione del quadro finanziario pluriennale post 2020;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>e) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’articolo 250 si applica alle garanzie di bilancio, all’assistenza finanziaria e alle passività potenziali solo a decorrere dalla data di applicazione del quadro finanziario pluriennale post 2020;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>f) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’articolo 2, punto 6, l’articolo 21, paragrafo 3, lettera f), l’articolo 41, paragrafo 4, lettera l), l’articolo 62, paragrafo 2, l’articolo 154, paragrafi 1 e 2, l’articolo 155, paragrafi da 1 a 4, e l’articolo 159 si applicano alle garanzie di bilancio solo a decorrere dalla data di applicazione del quadro finanziario pluriennale post 2020;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>g) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">l’articolo 2, punti 9), 15), 32) e 39), l’articolo 30, paragrafo 1, lettera g), l’articolo 41, paragrafo 5, l’articolo oli 110, paragrafo 3, lettera h), e l’articolo 115, paragrafo 2, lettera c), gli articoli 212 e 213, l’articolo 214, paragrafo 2), gli articoli 218, 219 e 220 si applicano solo a decorrere dalla data di applicazione del quadro finanziario pluriennale post 2020;</p>\n</div>\n</div>\n<div class=\"grid-container grid-list\">\n<div class=\"list grid-list-column-1\">\n<span>h) </span>\n</div>\n<div class=\"grid-list-column-2\">\n<p class=\"norm\">le informazioni relative alla media annuale di equivalenti a tempo pieno di cui all’articolo 41, paragrafo 3, lettera b), punto iii), e le informazioni relative all’importo stimato delle entrate con destinazione specifica riportate dagli esercizi precedenti di cui all’articolo 41, paragrafo 8, lettera b), sono fornite per la prima volta unitamente al progetto di bilancio che sarà presentato nel 2021.</p>\n</div>\n</div>\n</div>\n</div>"], [null, "<p class=\"norm\">Il presente regolamento è obbligatorio in tutti i suoi elementi e direttamente applicabile in ciascuno degli Stati membri.</p>"], [null, "<p>\n<br/>\n</p>"], [null, "<p>\n<br/>\n</p>"]]}}, "recitals": {}};